import React, { useState, useEffect, useCallback, useRef } from 'react';
import { AppState, ProjectFile, FileType } from './types';
import { BRAND_LOGO, INITIAL_FILES, INITIAL_LOGS } from './constants';
import Sidebar from './components/Sidebar';
import Editor from './components/Editor';
import Console from './components/Console';
import Icon from './components/Icon';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    files: INITIAL_FILES as ProjectFile[],
    activeFileId: '1',
    logs: INITIAL_LOGS,
    sidebarWidth: 260,
    bottomPanelHeight: 200,
  });

  const [isResizingSidebar, setIsResizingSidebar] = useState(false);
  const [isResizingBottom, setIsResizingBottom] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);

  // Resize Handlers
  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizingSidebar) {
      const newWidth = Math.max(150, Math.min(500, e.clientX));
      setState(prev => ({ ...prev, sidebarWidth: newWidth }));
    }
    if (isResizingBottom) {
      const newHeight = Math.max(100, Math.min(600, window.innerHeight - e.clientY));
      setState(prev => ({ ...prev, bottomPanelHeight: newHeight }));
    }
  }, [isResizingSidebar, isResizingBottom]);

  const handleMouseUp = useCallback(() => {
    setIsResizingSidebar(false);
    setIsResizingBottom(false);
    document.body.style.cursor = 'default';
  }, []);

  useEffect(() => {
    if (isResizingSidebar || isResizingBottom) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = isResizingSidebar ? 'col-resize' : 'row-resize';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizingSidebar, isResizingBottom, handleMouseMove, handleMouseUp]);

  const handleFileSelect = (id: string) => {
    setState(prev => ({
      ...prev,
      activeFileId: id,
      files: prev.files.map(f => f.id === id ? { ...f, isOpen: true } : f)
    }));
  };

  const handleFileClose = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setState(prev => {
      const newFiles = prev.files.map(f => f.id === id ? { ...f, isOpen: false } : f);
      const openFiles = newFiles.filter(f => f.isOpen);
      let newActiveId = prev.activeFileId;
      if (prev.activeFileId === id) {
        newActiveId = openFiles.length > 0 ? openFiles[0].id : null;
      }
      return { ...prev, files: newFiles, activeFileId: newActiveId };
    });
  };

  if (!isInitialized) {
    return (
      <div className="h-screen w-screen bg-[#FDFDFD] flex flex-col items-center justify-center p-8">
        <div className="max-w-md w-full border border-[#E5E5E5] p-12 bg-white shadow-2xl space-y-8 flex flex-col items-center animate-in fade-in slide-in-from-bottom-4 duration-1000">
          <div className="scale-125 mb-4">{BRAND_LOGO}</div>
          <div className="text-center space-y-4">
            <h1 className="font-serif text-3xl tracking-widest uppercase">Initialize</h1>
            <p className="font-serif text-[10px] tracking-widest uppercase text-neutral-400">Sanctum of Logic</p>
          </div>

          <div className="w-full space-y-6">
            <div className="space-y-1">
              <label className="text-[9px] font-bold uppercase tracking-[0.2em] text-neutral-400 block">Identity</label>
              <input 
                type="text" 
                defaultValue="sanctum_pioneer@reflecterlabs.xyz" 
                className="w-full border-b border-neutral-200 py-2 text-xs font-mono outline-none focus:border-black transition-colors"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[9px] font-bold uppercase tracking-[0.2em] text-neutral-400 block">Cipher</label>
              <input 
                type="password" 
                defaultValue="********" 
                className="w-full border-b border-neutral-200 py-2 text-xs font-mono outline-none focus:border-black transition-colors"
              />
            </div>
          </div>

          <button 
            onClick={() => setIsInitialized(true)}
            className="w-full bg-black text-white py-4 font-serif uppercase tracking-[0.3em] text-xs hover:bg-neutral-800 transition-all active:scale-[0.98]"
          >
            Access Sanctum
          </button>

          <p className="text-[9px] uppercase font-bold tracking-widest text-neutral-300 hover:text-black cursor-pointer transition-colors">
            Register New Core
          </p>
        </div>
        <div className="mt-12 opacity-5 pointer-events-none select-none">
          <h1 className="text-[12rem] font-serif tracking-tighter">REFLECTER</h1>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen flex flex-col bg-[#FDFDFD]">
      {/* Top Header */}
      <header className="h-14 flex items-center px-4 justify-between border-b border-[#E5E5E5] bg-white select-none">
        <div className="flex items-center gap-8">
          <div className="scale-75">{BRAND_LOGO}</div>
          <nav className="flex items-center gap-6 text-[10px] uppercase font-bold tracking-[0.2em] text-neutral-400">
            <span className="text-black cursor-default">File</span>
            <span className="hover:text-black cursor-pointer transition-colors">Edit</span>
            <span className="hover:text-black cursor-pointer transition-colors">Agents</span>
            <span className="hover:text-black cursor-pointer transition-colors">Logic</span>
            <span className="hover:text-black cursor-pointer transition-colors">Sanctum</span>
          </nav>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 text-[10px] uppercase font-bold tracking-widest text-neutral-400 mr-4">
             <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
             CORE ONLINE
          </div>
          <button className="p-2 border border-[#E5E5E5] hover:bg-black hover:text-white transition-all">
            <Icon name="search" size={16} />
          </button>
          <button className="p-2 border border-[#E5E5E5] hover:bg-black hover:text-white transition-all">
            <Icon name="CONFIG" size={16} />
          </button>
        </div>
      </header>

      {/* Main Body */}
      <main className="flex-1 flex overflow-hidden">
        {/* Left Sidebar */}
        <Sidebar 
          files={state.files} 
          activeFileId={state.activeFileId} 
          onFileSelect={handleFileSelect} 
          width={state.sidebarWidth} 
        />

        {/* Sidebar Resizer */}
        <div className="resizer-h" onMouseDown={() => setIsResizingSidebar(true)} />

        {/* Content Area */}
        <div className="flex-1 flex flex-col overflow-hidden relative">
          <Editor 
            files={state.files} 
            activeFileId={state.activeFileId} 
            onFileSelect={handleFileSelect} 
            onFileClose={handleFileClose}
          />

          {/* Bottom Panel Resizer */}
          <div className="resizer-v" onMouseDown={() => setIsResizingBottom(true)} />

          {/* Bottom Console */}
          <Console logs={state.logs} height={state.bottomPanelHeight} />
        </div>
      </main>

      {/* Status Bar */}
      <footer className="h-6 flex items-center px-4 justify-between bg-black text-white text-[9px] uppercase font-bold tracking-[0.2em] select-none">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1.5">
            <div className="w-1.5 h-1.5 bg-green-500 rounded-full" />
            <span>Node Cluster: Primary</span>
          </div>
          <span>UTF-8</span>
          <span>Tab Size: 2</span>
        </div>
        <div className="flex items-center gap-4">
          <span>Sanctum v4.0.1</span>
          <span>Ln 1, Col 1</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

