            </div>;
            if (line.includes('@')) {
               const parts = line.split(/(@\w+)/);
               return <div key={i}>{parts.map((p, j) => p.startsWith('@') ? <span key={j} className="text-green-400">{p}</span> : p)}</div>
            }
            return <div key={i} className="mb-1">{line}</div>;
          })}
        </div>
      )}

      {/* Footer Status */}
      <div className="h-8 border-t border-[#1a1a1a] bg-[#050505] flex items-center justify-between px-4 text-[10px] font-mono text-neutral-600 select-none">
