import React, { useState, useCallback, useEffect } from 'react';
import { AppState, ProjectFile } from './types';
import { INITIAL_FILES } from './constants';
import TerminalPane from './components/TerminalPane';

const App: React.FC = () => {
  const [panes, setPanes] = useState<{ id: string; width: number }[]>([
    { id: 'docs', width: 400 },
    { id: 'main', width: 800 }
  ]);

  const [activePaneId, setActivePaneId] = useState('main');
  const [isResizing, setIsResizing] = useState<number | null>(null);

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        next[isResizing].width += delta;
        // Ensure some minimums
        next[isResizing].width = Math.max(200, next[isResizing].width);
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
    document.body.style.cursor = 'default';
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  return (
    <div className="h-screen w-screen flex flex-col bg-black overflow-hidden">
      {/* Dynamic Panes Area */}
      <div className="flex-1 flex overflow-hidden">
        {panes.map((pane, index) => {
          const file = INITIAL_FILES.find(f => f.id === pane.id) as ProjectFile;
          return (
            <React.Fragment key={pane.id}>
              <TerminalPane 
                file={file}
                width={pane.width}
                isActive={activePaneId === pane.id}
                onFocus={() => setActivePaneId(pane.id)}
              />
              {index < panes.length - 1 && (
                <div 
                  className="resizer-h" 
                  onMouseDown={() => setIsResizing(index)}
                />
              )}
            </React.Fragment>
          );
        })}
        {/* Fill remaining space with empty terminal or expanded last pane */}
        <div className="flex-1 bg-black border-l border-[#1a1a1a]" />
      </div>

      {/* OS Taskbar Simulation (Optional, as seen in image) */}
      <div className="h-10 bg-[#0a0a0a] border-t border-[#1a1a1a] flex items-center justify-center gap-6 px-4">
         <div className="flex gap-4">
            <div className="w-1 h-1 bg-neutral-700 rounded-full"></div>
            <div className="w-1 h-1 bg-neutral-700 rounded-full"></div>
            <div className="w-1 h-1 bg-white rounded-full"></div>
         </div>
      </div>
    </div>
  );
};

