  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  const isDocs = file.id === 'docs';

  return (
    <div 
      style={{ width }} 
      onClick={onFocus}
      className={`h-full flex flex-col border-r border-[#1a1a1a] bg-black overflow-hidden relative transition-all ${isActive ? 'ring-1 ring-inset ring-neutral-800' : ''}`}
