          <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white animate-pulse' : 'bg-neutral-800'}`}></div>
          {file.name}
        </div>
        <div className="flex-1 flex items-center px-4 gap-3">
          {file.resources?.map(res => (
            <span key={res} className="text-[8px] uppercase tracking-tighter text-neutral-500 border border-neutral-800 px-1.5 py-0.5 rounded-sm">
              {res}
            </span>
          ))}
        </div>
        <div className="flex items-center px-2 gap-3 text-neutral-500">
           <Icon name="search" size={12} />
           <Icon name="close" size={12} />
        </div>
      </div>

      {/* Content Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 font-mono text-[12px] leading-relaxed text-neutral-300 selection:bg-white selection:text-black scroll-smooth">
        {isDocs ? (
          <div className="whitespace-pre-wrap">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <div key={i} className="text-white font-bold mb-4 uppercase tracking-[0.2em] font-serif text-lg">{line}</div>;
              if (line.startsWith('■')) return <div key={i} className="bg-neutral-900/50 p-4 mt-8 border-l-2 border-white flex items-center gap-3 text-neutral-100">
                 <span>{line}</span>
              </div>;
              return <div key={i} className="mb-1">{line}</div>;
            })}
          </div>
        ) : (
          <div className="space-y-6">
            {file.messages.map((msg, i) => (
              <div key={i} className="animate-in fade-in slide-in-from-left-2 duration-300">
                <div className="flex items-center gap-2 mb-2">
                  <span className={`text-[9px] font-bold uppercase tracking-widest ${msg.role === 'agent' ? 'text-white' : 'text-neutral-500'}`}>
                    {msg.role === 'agent' ? (file.agent || 'SYSTEM') : 'PIONEER'}
                  </span>
                  <span className="text-[8px] text-neutral-600">[{msg.timestamp}]</span>
                </div>
                <div className={`pl-0 ${msg.role === 'agent' ? 'text-neutral-200' : 'text-neutral-400 border-l border-neutral-800 pl-4'}`}>
                  {msg.content}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Input Area */}
      {!isDocs && (
        <form onSubmit={handleSubmit} className="p-4 border-t border-[#1a1a1a] bg-[#050505]">
          <div className="relative flex items-center bg-neutral-900/40 border border-neutral-800 px-4 py-2 group focus-within:border-neutral-500 transition-all">
            <span className="text-neutral-500 mr-3 text-[10px] font-mono select-none">&gt;</span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Awaiting logical command..."
              className="bg-transparent border-none outline-none flex-1 text-xs font-mono text-white command-input placeholder:text-neutral-700"
            />
            <div className="flex gap-2 items-center opacity-30 group-focus-within:opacity-100 transition-opacity">
               <span className="text-[9px] text-neutral-400 font-mono">enter</span>
            </div>
          </div>
        </form>
      )}

      {/* Pane Footer */}
      <div className="h-7 flex-shrink-0 border-t border-[#1a1a1a] bg-[#050505] flex items-center justify-between px-4 text-[9px] font-mono text-neutral-500 select-none">
        <div className="flex items-center gap-4">
          <span className="hover:text-neutral-300 cursor-pointer">/root/reflecter/{file.id}</span>
        </div>
        <div className="flex items-center gap-4">
          <span className="text-neutral-700 uppercase">{file.agent || 'CORE'}</span>
          <span>4.0.1</span>
        </div>
      </div>
    </div>
  );
};

