const App: React.FC = () => {
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);
  const [activePaneId, setActivePaneId] = useState('chat-1');
  const [panes, setPanes] = useState<{ id: string; width: number }[]>([
    { id: 'docs', width: 380 },
    { id: 'chat-1', width: 700 }
  ]);

  const [isResizing, setIsResizing] = useState<number | null>(null);
  const [showNewModal, setShowNewModal] = useState(false);

  const handleSendMessage = (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    setFiles(prev => prev.map(f => {
      if (f.id === fileId) {
        return {
          ...f,
          messages: [
            ...f.messages,
            { role: 'user', content, timestamp },
            { role: 'agent', content: `Acknowledged. Processing "${content}" under protocol ${f.agent || 'SYSTEM'}. Accessing linked resources...`, timestamp }
          ]
        };
      }
      return f;
    }));
  };

  const handleCreatePane = (config: { agent: string; resources: string[]; name: string }) => {
    const newId = `chat-${Date.now()}`;
    const newFile: ProjectFile = {
      id: newId,
      name: config.name,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: config.agent,
      resources: config.resources,
      messages: [
        { role: 'agent', content: `Session established with ${config.agent}. Neural links verified: ${config.resources.join(', ') || 'none'}.`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);
    setPanes(prev => [...prev, { id: newId, width: 450 }]);
    setActivePaneId(newId);
    setShowNewModal(false);
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        next[isResizing].width += delta;
        next[isResizing].width = Math.max(200, next[isResizing].width);
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
    document.body.style.cursor = 'default';
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  return (
    <div className="h-screen w-screen flex flex-col bg-black overflow-hidden font-inter">
      {/* Top Header Bar */}
      <header className="h-12 border-b border-[#1a1a1a] bg-[#050505] flex items-center justify-between px-6 select-none z-10">
        <div className="flex items-center gap-8">
          <div className="flex flex-col items-start gap-0.5">
            <span className="font-serif font-bold text-sm tracking-tighter text-white uppercase">Reflecter Labs</span>
            <div className="h-[1px] w-full bg-white opacity-20"></div>
          </div>
          <nav className="flex items-center gap-6 text-[9px] uppercase font-bold tracking-[0.2em] text-neutral-500">
            <span className="text-white">Orchestration</span>
            <span className="hover:text-white cursor-pointer transition-colors">Neural Links</span>
            <span className="hover:text-white cursor-pointer transition-colors">Audit Logs</span>
          </nav>
        </div>
        <div className="flex items-center gap-4">
           <button 
             onClick={() => setShowNewModal(true)}
             className="flex items-center gap-2 bg-white text-black px-3 py-1.5 text-[9px] font-bold uppercase tracking-widest hover:bg-neutral-200 transition-all"
           >
             <Icon name="close" size={10} className="rotate-45" />
             Invoke Session
           </button>
        </div>
      </header>

      {/* Main Area */}
      <div className="flex-1 flex overflow-hidden">
        {panes.map((pane, index) => {
          const file = files.find(f => f.id === pane.id);
          if (!file) return null;
          return (
            <React.Fragment key={pane.id}>
              <TerminalPane 
                file={file}
                width={pane.width}
                isActive={activePaneId === pane.id}
                onFocus={() => setActivePaneId(pane.id)}
                onSendMessage={handleSendMessage}
              />
              {index < panes.length - 1 && (
                <div 
                  className="resizer-h w-[1px] bg-[#1a1a1a] hover:bg-white transition-colors cursor-col-resize" 
                  onMouseDown={() => setIsResizing(index)}
                />
              )}
            </React.Fragment>
          );
        })}
        <div className="flex-1 bg-black flex items-center justify-center opacity-10">
           <h1 className="font-serif text-[120px] tracking-tighter text-white pointer-events-none select-none">R</h1>
        </div>
      </div>

      {/* Bottom OS Bar Simulation */}
      <div className="h-10 bg-[#0a0a0a] border-t border-[#1a1a1a] flex items-center justify-between px-6 z-10">
         <div className="flex gap-4">
            <div className="w-1.5 h-1.5 bg-neutral-800 rounded-full"></div>
            <div className="w-1.5 h-1.5 bg-neutral-800 rounded-full"></div>
            <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
         </div>
         <div className="flex gap-6 text-[9px] uppercase font-mono tracking-widest text-neutral-500">
            <span>Cluster: Primary-Sanctum-01</span>
            <span className="text-white">Active Node: Oracle</span>
         </div>
      </div>

      {showNewModal && (
        <NewPaneModal 
          onClose={() => setShowNewModal(false)} 
          onCreate={handleCreatePane} 
        />
      )}
    </div>
  );
};

