            <span className="text-neutral-400 mr-4 text-xs font-mono select-none opacity-50">&gt;</span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Invoke logical command..."
              className="bg-transparent border-none outline-none flex-1 text-sm font-mono text-white command-input"
            />
            <div className="flex gap-3 items-center opacity-0 group-focus-within:opacity-100 transition-opacity">
               <span className="text-[9px] text-neutral-400 font-mono uppercase tracking-widest border border-white/10 px-2 py-0.5">exec</span>
            </div>
          </div>
        </form>
      )}

      {/* Pane Footer */}
      <div className="h-8 flex-shrink-0 border-t border-white/5 bg-black/40 flex items-center justify-between px-5 text-[9px] font-mono text-neutral-300 select-none uppercase tracking-widest">
        <div className="flex items-center gap-4">
          <span className="hover:text-white cursor-pointer opacity-60">/root/reflecter/{file.id}</span>
        </div>
        <div className="flex items-center gap-4">
          <span className="text-white font-bold">{file.agent || 'CORE'}</span>
          <span className="opacity-40">L-VER.4.0.1</span>
        </div>
      </div>
    </div>
  );
};

