import React, { useState, useRef, useEffect } from 'react';
import { ProjectFile } from '../types';
import Icon from './Icon';
import { DOCS_CONTENT } from '../constants';

interface TerminalPaneProps {
  file: ProjectFile;
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (fileId: string, content: string) => void;
  onClose?: () => void;
  isSystemView?: boolean;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ file, isActive, onFocus, width, onSendMessage, onClose, isSystemView = false }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  const isDocs = file.id === 'docs';

  return (
    <div 
      style={{ width }} 
      onClick={onFocus}
      className={`h-full flex flex-col border-r border-white/5 overflow-hidden relative transition-all glass-pane ${isActive ? 'ring-1 ring-inset ring-white/20' : ''}`}
    >
      {/* Header */}
      <div className={`flex bg-black/40 border-b border-white/5 h-9 select-none flex-shrink-0 items-center`}>
        <div className="flex items-center gap-2 px-4 text-[10px] uppercase font-bold tracking-widest text-neutral-200 border-r border-white/5 h-full bg-white/5">
          <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white animate-pulse shadow-[0_0_8px_white]' : 'bg-neutral-600'}`}></div>
          {file.name}
        </div>
        <div className="flex-1 flex items-center px-4 gap-3">
          {file.resources?.map(res => (
            <span key={res} className="text-[8px] uppercase tracking-wider text-neutral-400 border border-white/5 px-2 py-0.5 rounded-sm bg-white/5">
              {res}
            </span>
          ))}
        </div>
        <div className="flex items-center px-4 gap-4 text-neutral-400">
           {!isSystemView && onClose && (
             <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="hover:text-white transition-colors">
               <Icon name="close" size={12} />
             </button>
           )}
        </div>
      </div>

      {/* Content Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 font-mono text-[12px] leading-relaxed text-neutral-200 selection:bg-white selection:text-black scroll-smooth">
        {isDocs ? (
          <div className="whitespace-pre-wrap max-w-4xl mx-auto">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <div key={i} className="text-white font-bold mb-6 uppercase tracking-[0.3em] font-serif text-2xl border-b border-white/10 pb-2">{line.replace('# ', '')}</div>;
              if (line.startsWith('■')) return <div key={i} className="bg-white/5 p-4 my-8 border-l-2 border-white flex items-center gap-3 text-white">
                 <span className="tracking-widest uppercase text-[10px]">{line}</span>
              </div>;
              if (line.startsWith('###')) return <div key={i} className="text-white font-bold mt-8 mb-4 uppercase tracking-widest text-xs border-white/20 border-b w-fit pr-4">{line.replace('### ', '')}</div>;
              return <div key={i} className="mb-2 text-neutral-400">{line}</div>;
            })}
          </div>
        ) : (
          <div className="space-y-6">
            {file.messages.map((msg, i) => (
              <div key={i} className="animate-in fade-in duration-300">
                <div className="flex items-center gap-2 mb-1">
                  <span className={`text-[9px] font-bold uppercase tracking-[0.1em] ${msg.role === 'agent' ? 'text-white/60' : 'text-neutral-500'}`}>
                    {msg.role === 'agent' ? 'RESPONSE' : 'PIONEER'}
                  </span>
                </div>
                <div className={`text-[13px] ${msg.role === 'agent' ? 'text-neutral-100' : 'text-neutral-400 border-l border-white/10 pl-4'}`}>
                  {msg.content}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Input Area */}
