import React, { useState, useCallback, useEffect } from 'react';
import { ProjectFile, FileType } from './types';
import { INITIAL_FILES } from './constants';
import TerminalPane from './components/TerminalPane';
import NewPaneModal from './components/NewPaneModal';
import Icon from './components/Icon';

const App: React.FC = () => {
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);
  const [activePaneId, setActivePaneId] = useState('chat-1');
  const [showSystem, setShowSystem] = useState(false);

  const [panes, setPanes] = useState<{ id: string; width: number }[]>([
    { id: 'chat-1', width: 800 }
  ]);

  const [isResizing, setIsResizing] = useState<number | null>(null);
  const [showNewModal, setShowNewModal] = useState(false);

  const handleSendMessage = (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    setFiles(prev => prev.map(f => {
      if (f.id === fileId) {
        return {
          ...f,
          messages: [
            ...f.messages,
            { role: 'user', content, timestamp },
            { role: 'agent', content: `Processing command...`, timestamp }
          ]
        };
      }
      return f;
    }));
  };

  const handleClosePane = (id: string) => {
    setPanes(prev => {
      const newPanes = prev.filter(p => p.id !== id);
      if (newPanes.length > 0 && activePaneId === id) {
        setActivePaneId(newPanes[0].id);
      }
      return newPanes;
    });
  };

  const handleCreatePane = (config: { agent: string; resources: string[]; name: string }) => {
    const newId = `chat-${Date.now()}`;
    const newFile: ProjectFile = {
      id: newId,
      name: config.name,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: config.agent,
      resources: config.resources,
      messages: [
        { role: 'agent', content: `Connection established.`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);
    setPanes(prev => [...prev, { id: newId, width: 400 }]);
    setActivePaneId(newId);
    setShowNewModal(false);
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        next[isResizing].width += delta;
        next[isResizing].width = Math.max(300, next[isResizing].width);
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
    document.body.style.cursor = 'default';
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  const systemFile = files.find(f => f.id === 'docs') as ProjectFile;

  return (
    <div className="h-screen w-screen flex flex-col bg-transparent overflow-hidden font-inter text-neutral-200">
      {/* Header */}
      <header className="h-14 border-b border-white/10 bg-black/40 backdrop-blur-md flex items-center justify-between px-8 select-none z-30">
        <div className="flex items-center gap-10">
          <div className="flex flex-col items-start">
            <span className="font-serif font-bold text-base tracking-[0.2em] text-white uppercase">Reflecter Labs</span>
          </div>
          <nav className="flex items-center gap-8 text-[10px] uppercase font-bold tracking-[0.3em] text-neutral-400">
            <span className="text-white border-b border-white pb-1">Orchestration</span>
            <button 
              onClick={() => setShowSystem(!showSystem)}
              className={`hover:text-white transition-all ${showSystem ? 'text-white' : ''}`}
            >
              System Guide
            </button>
          </nav>
        </div>
        <div className="flex items-center gap-6">
           <button 
             onClick={() => setShowNewModal(true)}
             className="flex items-center gap-3 bg-white text-black px-5 py-2 text-[10px] font-bold uppercase tracking-[0.2em] hover:bg-neutral-200 transition-all shadow-[0_0_15px_rgba(255,255,255,0.05)]"
           >
             <Icon name="close" size={12} className="rotate-45" />
             Invoke Session
           </button>
        </div>
      </header>

      {/* Main Content */}
      <div className="flex-1 flex overflow-hidden relative">
        <div className="flex w-full h-full">
          {panes.length === 0 ? (
            <div className="flex-1 flex items-center justify-center pointer-events-none">
              <span className="font-serif text-3xl uppercase tracking-[0.5em] opacity-10">REFLECTERS</span>
            </div>
          ) : (
            panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;
              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className="h-full flex flex-col relative"
                    style={{ flex: index === panes.length - 1 ? '1 1 auto' : `0 0 ${pane.width}px` }}
                  >
                    <TerminalPane 
                      file={file}
                      width="100%"
                      isActive={activePaneId === pane.id}
                      onFocus={() => setActivePaneId(pane.id)}
                      onSendMessage={handleSendMessage}
                      onClose={() => handleClosePane(pane.id)}
                    />
                  </div>
                  {index < panes.length - 1 && (
                    <div 
                      className="resizer-h" 
                      onMouseDown={() => setIsResizing(index)}
                    />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </div>

      {/* SYSTEM Drawer */}
      <div 
        className={`absolute bottom-10 left-0 w-full z-40 transition-all duration-500 ease-in-out border-t border-white/20 glass-pane ${
          showSystem ? 'h-[60vh]' : 'h-0 border-transparent'
        } overflow-hidden`}
      >
        <div className="h-full flex flex-col">
          <div className="flex items-center justify-between px-8 py-3 bg-transparent border-b border-white/5">
            <span className="font-serif text-xs uppercase tracking-widest font-bold text-white">System Protocol Documentation</span>
            <button onClick={() => setShowSystem(false)} className="hover:text-white transition-colors">
              <Icon name="close" size={16} />
            </button>
          </div>
          <div className="flex-1 overflow-hidden">
             <TerminalPane 
                file={systemFile} 
                width="100%" 
                isActive={false} 
                onFocus={() => {}} 
                onSendMessage={() => {}} 
                isSystemView
             />
          </div>
        </div>
      </div>

      {/* Footer */}
      <footer className="h-10 bg-black/80 backdrop-blur-lg border-t border-white/5 flex items-center justify-center px-8 z-50">
         <div className="text-[10px] uppercase font-mono tracking-[0.2em] text-neutral-500">
            developed by <span className="text-white/80 font-bold">Reflecter LABS</span> | 2026
         </div>
      </footer>

      {showNewModal && (
        <NewPaneModal 
          onClose={() => setShowNewModal(false)} 
          onCreate={handleCreatePane} 
        />
      )}
    </div>
  );
};

export default App;

