import React, { useState, useCallback, useEffect } from 'react';
import { ProjectFile, FileType } from './types';
import { INITIAL_FILES } from './constants';
import TerminalPane from './components/TerminalPane';
import NewPaneModal from './components/NewPaneModal';
import Icon from './components/Icon';

const App: React.FC = () => {
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);
  const [activePaneId, setActivePaneId] = useState('chat-1');
  const [showSystem, setShowSystem] = useState(false);

  const [panes, setPanes] = useState<{ id: string; width: number }[]>([
    { id: 'chat-1', width: 800 }
  ]);

  const [isResizing, setIsResizing] = useState<number | null>(null);
  const [showNewModal, setShowNewModal] = useState(false);

  const handleSendMessage = (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    setFiles(prev => prev.map(f => {
      if (f.id === fileId) {
        return {
          ...f,
          messages: [
            ...f.messages,
            { role: 'user', content, timestamp },
            { role: 'agent', content: `Processing command...`, timestamp }
          ]
        };
      }
      return f;
    }));
  };

  const handleClosePane = (id: string) => {
    setPanes(prev => {
      const newPanes = prev.filter(p => p.id !== id);
      if (newPanes.length > 0 && activePaneId === id) {
        setActivePaneId(newPanes[0].id);
      }
      return newPanes;
    });
  };

  const handleCreatePane = (config: { agent: string; resources: string[]; name: string }) => {
    const newId = `chat-${Date.now()}`;
    const newFile: ProjectFile = {
      id: newId,
      name: config.name,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: config.agent,
      resources: config.resources,
      messages: [
        { role: 'agent', content: `Connection established.`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);
    setPanes(prev => [...prev, { id: newId, width: 400 }]);
    setActivePaneId(newId);
    setShowNewModal(false);
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        next[isResizing].width += delta;
        next[isResizing].width = Math.max(300, next[isResizing].width);
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
    document.body.style.cursor = 'default';
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  const systemFile = files.find(f => f.id === 'docs') as ProjectFile;

  return (
    <div className="h-screen w-screen flex flex-col bg-transparent overflow-hidden font-inter text-neutral-200">
      {/* Header */}
      <header className="h-14 border-b border-white/10 bg-black flex items-center justify-between px-8 select-none z-50">
        <div className="flex items-center gap-10">
          <div className="flex flex-col items-start">
            <span className="font-serif font-bold text-xs tracking-[0.2em] text-white uppercase">Reflecter Labs</span>
          </div>
          <nav className="flex items-center gap-8 text-[9px] uppercase font-bold tracking-[0.3em] text-neutral-400">
            <span className="text-white border-b border-white pb-1">Orchestration</span>
            <button 
              onClick={() => setShowSystem(!showSystem)}
              className={`hover:text-white transition-all ${showSystem ? 'text-white' : ''}`}
            >
              System Guide
            </button>
          </nav>
        </div>
        <div className="flex items-center gap-6">
           <button 
             onClick={() => setShowNewModal(true)}
             className="flex items-center gap-2 bg-white text-black px-4 py-1.5 text-[9px] font-bold uppercase tracking-[0.2em] hover:bg-neutral-200 transition-all"
           >
             <Icon name="close" size={10} className="rotate-45" />
             Invoke Session
           </button>
        </div>
      </header>

      {/* SYSTEM Drawer (From Top) */}
      <div 
        className={`absolute left-0 w-full z-40 transition-all duration-500 ease-in-out border-b border-white/20 glass-pane ${
          showSystem ? 'top-14 h-[60vh]' : 'top-14 h-0 border-transparent'
        } overflow-hidden`}
      >
        <div className="h-full flex flex-col">
          <div className="flex items-center justify-between px-8 py-2 bg-black/40 border-b border-white/5">
            <span className="font-serif text-[10px] uppercase tracking-widest font-bold text-white">System Protocol Documentation</span>
            <button onClick={() => setShowSystem(false)} className="hover:text-white transition-colors">
              <Icon name="close" size={14} />
            </button>
          </div>
          <div className="flex-1 overflow-hidden">
             <TerminalPane 
                file={systemFile} 
                width="100%" 
                isActive={false} 
                onFocus={() => {}} 
                onSendMessage={() => {}} 
                isSystemView
             />
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex overflow-hidden relative">
        <div className="flex w-full h-full">
          {panes.length === 0 ? (
            <div className="flex-1 flex items-center justify-center pointer-events-none">
              <span className="font-serif text-3xl uppercase tracking-[0.5em] opacity-10">REFLECTERS</span>
            </div>
          ) : (
            panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;
              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className="h-full flex flex-col relative"
                    style={{ flex: index === panes.length - 1 ? '1 1 auto' : `0 0 ${pane.width}px` }}
                  >
                    <TerminalPane 
                      file={file}
                      width="100%"
                      isActive={activePaneId === pane.id}
                      onFocus={() => setActivePaneId(pane.id)}
                      onSendMessage={handleSendMessage}
                      onClose={() => handleClosePane(pane.id)}
                    />
                  </div>
                  {index < panes.length - 1 && (
                    <div 
                      className="resizer-h" 
                      onMouseDown={() => setIsResizing(index)}
                    />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </div>

      {/* Footer */}
      <footer className="h-10 bg-black border-t border-white/5 flex items-center justify-center px-8 z-50">
         <div className="text-[9px] uppercase font-mono tracking-[0.3em] text-neutral-500">
            developed by <span className="text-white font-bold tracking-widest">REFLECTER LABS</span> | 2026
         </div>
      </footer>

      {showNewModal && (
        <NewPaneModal 
          onClose={() => setShowNewModal(false)} 
          onCreate={handleCreatePane} 
        />
      )}
    </div>
  );

import React, { useState, useRef, useEffect } from 'react';
import { ProjectFile } from '../types';
import Icon from './Icon';
import { DOCS_CONTENT } from '../constants';

interface TerminalPaneProps {
  file: ProjectFile;
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (fileId: string, content: string) => void;
  onClose?: () => void;
  isSystemView?: boolean;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ file, isActive, onFocus, width, onSendMessage, onClose, isSystemView = false }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  const isDocs = file.id === 'docs';

  return (
    <div 
      style={{ width }} 
      onClick={onFocus}
      className={`h-full flex flex-col border-r border-white/5 overflow-hidden relative transition-all bg-transparent`}
    >
      {/* Tab Sub-Header */}
      <div className={`flex bg-transparent border-b border-white/10 h-10 select-none flex-shrink-0 items-center`}>
        <div className={`flex items-center gap-2 px-6 text-[9px] uppercase font-bold tracking-widest h-full border-r border-white/10 ${isActive ? 'text-white' : 'text-neutral-600'}`}>
          <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
          {file.name}
        </div>
        <div className="flex-1"></div>
        <div className="flex items-center px-4">
           {!isSystemView && onClose && (
             <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="text-neutral-600 hover:text-white transition-colors p-1">
               <Icon name="close" size={14} />
             </button>
           )}
        </div>
      </div>

      {/* Content Area - Transparente */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-12 font-mono text-[12px] leading-relaxed text-neutral-200 selection:bg-white selection:text-black scroll-smooth">
        {isDocs ? (
          <div className="whitespace-pre-wrap max-w-4xl mx-auto">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <div key={i} className="text-white font-bold mb-6 uppercase tracking-[0.3em] font-serif text-2xl border-b border-white/10 pb-2">{line.replace('# ', '')}</div>;
              if (line.startsWith('■')) return <div key={i} className="bg-white/5 p-4 my-8 border-l-2 border-white flex items-center gap-3 text-white">
                 <span className="tracking-widest uppercase text-[10px]">{line}</span>
              </div>;
              if (line.startsWith('###')) return <div key={i} className="text-white font-bold mt-8 mb-4 uppercase tracking-widest text-xs border-white/20 border-b w-fit pr-4">{line.replace('### ', '')}</div>;
              return <div key={i} className="mb-2 text-neutral-400">{line}</div>;
            })}
          </div>
        ) : (
          <div className="space-y-8 max-w-5xl">
            {file.messages.map((msg, i) => (
              <div key={i} className="animate-in fade-in duration-500">
                <div className="mb-1 opacity-60">
                  <span className={`text-[8px] font-bold uppercase tracking-[0.2em] ${msg.role === 'agent' ? 'text-neutral-400' : 'text-neutral-500'}`}>
                    {msg.role === 'agent' ? 'RESPONSE' : 'PIONEER'}
                  </span>
                </div>
                <div className={`text-[13px] tracking-wide ${msg.role === 'agent' ? 'text-neutral-100' : 'text-neutral-400'}`}>
                  {msg.content}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Input Area (Darker box as requested) */}
      {!isDocs && (
        <div className="px-10 pb-10 pt-4 bg-transparent">
          <form onSubmit={handleSubmit} className="relative flex items-center bg-[#050505]/90 border border-white/10 px-5 py-4 focus-within:border-white/40 transition-all">
            <span className="text-neutral-400 mr-4 text-[10px] font-mono font-bold tracking-[0.2em] select-none uppercase">
              [{file.agent || 'CORE'}] >
            </span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="..."
              className="bg-transparent border-none outline-none flex-1 text-sm font-mono text-white command-input"
              autoFocus={isActive}
            />
          </form>
        </div>
      )}
    </div>
  );
};

