          </div>
          <nav className="hidden sm:flex items-center gap-8 text-[9px] uppercase font-bold tracking-[0.3em] text-neutral-400">
            <span className="text-white border-b border-white pb-1">Orchestration</span>
            <button 
              onClick={() => setShowSystem(!showSystem)}
              className={`hover:text-white transition-all ${showSystem ? 'text-white' : ''}`}
            >
              System Guide
            </button>
          </nav>
        </div>
        <div className="flex items-center gap-4">
           <button 
             onClick={() => setShowNewModal(true)}
             className="flex items-center gap-2 bg-white text-black px-3 sm:px-4 py-1.5 text-[8px] sm:text-[9px] font-bold uppercase tracking-[0.2em] hover:bg-neutral-200 transition-all shadow-lg"
           >
             <Icon name="close" size={10} className="rotate-45" />
             <span className="hidden xs:inline">Invoke Session</span>
             <span className="xs:hidden">Invoke</span>
           </button>
        </div>
