          showSystem ? 'top-14 h-[70vh]' : 'top-14 h-0 border-transparent'
        } overflow-hidden`}
      >
        <div className="h-full flex flex-col">
          <div className="flex items-center justify-between px-8 py-2 bg-black/20 border-b border-white/5">
