import Icon from './components/Icon';

export default function App() {
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);
  const [activePaneId, setActivePaneId] = useState('chat-1');
  const [showSystem, setShowSystem] = useState(false);
  const [showWiki, setShowWiki] = useState(false);
  const [showShortcuts, setShowShortcuts] = useState(false);

  const [panes, setPanes] = useState<{ id: string; width: number; isMinimized: boolean; isExpanded: boolean }[]>([
    { id: 'chat-1', width: 600, isMinimized: false, isExpanded: false }
  ]);

  const [isResizing, setIsResizing] = useState<number | null>(null);

  const handleCreatePane = useCallback(() => {
    const newId = `chat-${Date.now()}`;
    const newFile: ProjectFile = {
      id: newId,
      name: `Session ${panes.length + 1}`,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: 'ElizaOS v1',
      resources: [],
      messages: [
        { role: 'agent', content: `Session protocol established. Waiting for command...`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);
    setPanes(prev => {
      // Si hay uno expandido, lo quitamos
      const resetPanes = prev.map(p => ({ ...p, isExpanded: false }));
      return [...resetPanes, { id: newId, width: 450, isMinimized: false, isExpanded: false }];
    });
    setActivePaneId(newId);
  }, [panes.length]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ctrl + [1-9] para cambiar pestañas
      if (e.ctrlKey && !isNaN(parseInt(e.key)) && e.key !== '0') {
        const index = parseInt(e.key) - 1;
        if (panes[index]) {
          setActivePaneId(panes[index].id);
          setPanes(prev => prev.map((p, i) => i === index ? { ...p, isMinimized: false } : p));
        }
      }
      // Shift + N para nueva sesión
      if (e.shiftKey && (e.key === 'N' || e.key === 'n')) {
        e.preventDefault();
        handleCreatePane();
      }
      // ? para atajos
      if (e.key === '?') {
        setShowShortcuts(prev => !prev);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [panes, handleCreatePane]);

  const handleSendMessage = (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    setFiles(prev => prev.map(f => {
      if (f.id === fileId) {
        return {
          ...f,
          messages: [
            ...f.messages,
            { role: 'user', content, timestamp },
            { role: 'agent', content: `Processing command sequence...`, timestamp }
          ]
        };
      }
      return f;
    }));
  };

  const handleClosePane = (id: string) => {
    setPanes(prev => {
      const newPanes = prev.filter(p => p.id !== id);
      if (newPanes.length > 0 && activePaneId === id) {
        setActivePaneId(newPanes[0].id);
      }
      return newPanes;
    });
  };

  const handleMinimizePane = (id: string) => {
    setPanes(prev => prev.map(p => p.id === id ? { ...p, isMinimized: !p.isMinimized, isExpanded: false } : p));
  };

  const handleExpandPane = (id: string) => {
    setPanes(prev => prev.map(p => p.id === id ? { ...p, isExpanded: !p.isExpanded, isMinimized: false } : { ...p, isExpanded: false }));
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        if (next[isResizing]) {
          next[isResizing].width += delta;
          next[isResizing].width = Math.max(80, next[isResizing].width);
        }
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
    document.body.style.cursor = 'default';
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  const systemFile = files.find(f => f.id === 'docs') as ProjectFile;

  return (
    <div className="h-screen w-screen flex flex-col bg-transparent overflow-hidden font-inter text-neutral-200 relative">
      {/* Header */}
      <header className="h-14 border-b border-white/5 bg-black/40 backdrop-blur-md flex items-center justify-between px-4 sm:px-8 select-none z-50">
        <div className="flex items-center gap-4 sm:gap-10">
          <div className="flex flex-col items-start">
            <span className="font-serif font-bold text-[10px] sm:text-xs tracking-[0.2em] text-white uppercase whitespace-nowrap">Reflecter Labs</span>
          </div>
          <nav className="hidden sm:flex items-center gap-8 text-[9px] uppercase font-bold tracking-[0.3em] text-neutral-400">
            <span className={`transition-all cursor-pointer ${!showWiki && !showSystem ? 'text-white border-b border-white pb-1' : ''}`} onClick={() => {setShowWiki(false); setShowSystem(false)}}>Orchestration</span>
