            <button onClick={() => { setShowWiki(!showWiki); setShowSystem(false); }} className={`hover:text-white transition-all ${showWiki ? 'text-white border-b border-white pb-1' : ''}`}>Wiki</button>
          </nav>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => setShowShortcuts(true)} className="p-2 text-neutral-400 hover:text-white transition-colors">
              <Icon name="search" size={16} className="rotate-0" /> {/* Usando search como ? simulado */}
           </button>
           <button 
             onClick={handleCreatePane}
