           >
             <Icon name="close" size={10} className="rotate-45" />
             <span>Invoke</span>
           </button>
        </div>
      </header>

      {/* Wiki / System Overlays */}
      <div className={`absolute inset-0 z-40 transition-all duration-500 ease-in-out bg-black/80 backdrop-blur-xl ${showWiki || showSystem ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
        <div className="h-full pt-14 flex flex-col items-center justify-center p-8">
           <div className="w-full max-w-4xl glass-pane border border-white/10 p-12">
              <div className="flex justify-between items-start mb-12">
                <h2 className="font-serif text-3xl tracking-[0.3em] uppercase">{showWiki ? 'AIStation' : 'System Guide'}</h2>
                <button onClick={() => {setShowWiki(false); setShowSystem(false)}} className="text-neutral-500 hover:text-white"><Icon name="close" size={24}/></button>
              </div>
              <div className="font-mono text-sm leading-relaxed text-neutral-400 max-h-[60vh] overflow-y-auto pr-8">
                 {showWiki ? (
                   <div className="space-y-8">
                     <p>Welcome to AIStation - The central node of Reflecter Intelligence.</p>
                     <div className="grid grid-cols-2 gap-8">
                        <div className="p-6 border border-white/5 bg-white/5">
                           <h4 className="text-white mb-2 uppercase tracking-widest text-xs">Neural Sync</h4>
                           <p className="text-xs">Real-time agent synchronization across global clusters.</p>
                        </div>
                        <div className="p-6 border border-white/5 bg-white/5">
                           <h4 className="text-white mb-2 uppercase tracking-widest text-xs">Logic Auditing</h4>
                           <p className="text-xs">Automated verification of command sequences.</p>
                        </div>
                     </div>
                   </div>
                 ) : (
                   <TerminalPane file={systemFile} width="100%" isActive={true} onFocus={() => {}} onSendMessage={() => {}} isSystemView />
                 )}
              </div>
           </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex overflow-hidden relative z-10">
        <div className="flex h-full w-full">
          {panes.length === 0 ? (
            <div className="flex-1 flex items-center justify-center pointer-events-none">
              <span className="font-serif text-xl sm:text-3xl uppercase tracking-[0.5em] opacity-30">REFLECTERS</span>
            </div>
          ) : (
            panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;

              const isLast = index === panes.length - 1;
              const anyExpanded = panes.some(p => p.isExpanded);

              if (anyExpanded && !pane.isExpanded) return null;

              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className={`h-full flex flex-col relative glass-pane ${pane.isExpanded || (isLast && !anyExpanded) ? 'flex-1' : 'shrink-0'}`}
                    style={pane.isExpanded || (isLast && !anyExpanded) ? {} : { width: pane.isMinimized ? 40 : pane.width }}
                  >
                    <TerminalPane 
                      file={file}
                      width="100%"
                      isActive={activePaneId === pane.id}
                      isMinimized={pane.isMinimized}
                      isExpanded={pane.isExpanded}
                      onFocus={() => setActivePaneId(pane.id)}
                      onSendMessage={handleSendMessage}
                      onClose={() => handleClosePane(pane.id)}
                      onMinimize={() => handleMinimizePane(pane.id)}
                      onExpand={() => handleExpandPane(pane.id)}
                    />
                  </div>
                  {!isLast && !pane.isMinimized && !pane.isExpanded && !anyExpanded && (
                    <div className="resizer-h shrink-0" onMouseDown={() => setIsResizing(index)} />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </div>

      {/* Keyboard Shortcuts Overlay */}
      {showShortcuts && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-[#0a0a0a] border border-white/10 p-8 w-full max-w-md animate-in fade-in zoom-in-95">
            <div className="flex justify-between items-center mb-6">
               <h3 className="font-serif text-lg tracking-widest uppercase">System Shortcuts</h3>
               <button onClick={() => setShowShortcuts(false)} className="text-neutral-500 hover:text-white"><Icon name="close" size={16}/></button>
            </div>
            <div className="space-y-4 font-mono text-[10px] uppercase tracking-widest">
               <div className="flex justify-between items-center"><span>New Session</span><span className="shortcut-key">Shift + N</span></div>
               <div className="flex justify-between items-center"><span>Switch Tab</span><span className="shortcut-key">Ctrl + [1-9]</span></div>
               <div className="flex justify-between items-center"><span>Toggle Guide</span><span className="shortcut-key">?</span></div>
               <div className="flex justify-between items-center"><span>Invoke</span><span className="shortcut-key">Top Right</span></div>
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="h-10 bg-black/40 backdrop-blur-md border-t border-white/5 flex items-center justify-center px-8 z-50">
         <div className="text-[7px] sm:text-[9px] uppercase font-mono tracking-[0.3em] text-neutral-500 text-center">
            developed by <span className="text-white font-bold tracking-widest">REFLECTER LABS</span> | 2026
         </div>
      </footer>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { ProjectFile } from '../types';
import Icon from './Icon';
import { DOCS_CONTENT } from '../constants';

interface TerminalPaneProps {
  file: ProjectFile;
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (fileId: string, content: string) => void;
  onClose?: () => void;
  onMinimize?: () => void;
  onExpand?: () => void;
  isSystemView?: boolean;
  isMinimized?: boolean;
  isExpanded?: boolean;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  file, isActive, onFocus, width, onSendMessage, onClose, onMinimize, onExpand, 
  isSystemView = false, isMinimized = false, isExpanded = false 
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  const isDocs = file.id === 'docs';

  if (isMinimized) {
    return (
      <div 
        onClick={onMinimize}
        className="h-full w-10 flex flex-col items-center bg-black/60 border-r border-white/10 cursor-pointer hover:bg-black/80 transition-all pt-4 gap-4"
      >
        <div className="w-1.5 h-1.5 rounded-full bg-neutral-600"></div>
        <span className="font-mono text-[8px] uppercase tracking-widest [writing-mode:vertical-lr] rotate-180 text-neutral-500">{file.name}</span>
      </div>
    );
  }

  return (
    <div 
      style={{ width }} 
      onClick={onFocus}
      className={`h-full flex flex-col border-r border-white/5 overflow-hidden relative transition-all bg-transparent ${isActive ? 'z-10' : 'z-0'}`}
    >
      {/* Tab Sub-Header */}
      <div className={`flex bg-black/20 border-b border-white/10 h-10 select-none flex-shrink-0 items-center overflow-hidden transition-all ${isActive ? 'bg-black/40' : ''}`}>
        <div className={`flex items-center gap-2 px-3 sm:px-6 text-[8px] sm:text-[9px] uppercase font-bold tracking-widest h-full border-r border-white/10 ${isActive ? 'text-white' : 'text-neutral-600'} min-w-0 max-w-full flex-1`}>
          <div className={`flex-shrink-0 w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
          <span className="truncate whitespace-nowrap overflow-hidden text-ellipsis">{file.name}</span>
        </div>

        <div className="flex items-center px-1 flex-shrink-0 gap-1 sm:gap-2 pr-2">
           {!isSystemView && (
             <>
               <button onClick={(e) => { e.stopPropagation(); onMinimize?.(); }} className="text-neutral-600 hover:text-white transition-colors p-1">
                 <Icon name="chevron-down" size={14} className="rotate-0" />
               </button>
               <button onClick={(e) => { e.stopPropagation(); onExpand?.(); }} className="text-neutral-600 hover:text-white transition-colors p-1">
                 <Icon name="play" size={10} className={isExpanded ? 'rotate-180' : '-rotate-90'} />
               </button>
               {onClose && (
                 <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="text-neutral-600 hover:text-white transition-colors p-1">
                   <Icon name="close" size={14} />
                 </button>
               )}
             </>
           )}
        </div>
      </div>

      {/* Content Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 sm:p-12 font-mono text-[11px] sm:text-[12px] leading-relaxed text-neutral-200 selection:bg-white selection:text-black scroll-smooth no-scrollbar">
        {isDocs ? (
          <div className="whitespace-pre-wrap max-w-4xl mx-auto">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <div key={i} className="text-white font-bold mb-4 sm:mb-6 uppercase tracking-[0.3em] font-serif text-xl sm:text-2xl border-b border-white/10 pb-2">{line.replace('# ', '')}</div>;
              if (line.startsWith('■')) return <div key={i} className="bg-white/5 p-3 sm:p-4 my-6 sm:my-8 border-l-2 border-white flex items-center gap-3 text-white">
                 <span className="tracking-widest uppercase text-[9px] sm:text-[10px]">{line}</span>
              </div>;
              if (line.startsWith('###')) return <div key={i} className="text-white font-bold mt-6 sm:mt-8 mb-3 sm:mb-4 uppercase tracking-widest text-[10px] sm:text-xs border-white/20 border-b w-fit pr-4">{line.replace('### ', '')}</div>;
              return <div key={i} className="mb-2 text-neutral-400">{line}</div>;
            })}
          </div>
        ) : (
          <div className="space-y-6 sm:space-y-8 max-w-5xl">
            {file.messages.map((msg, i) => (
              <div key={i} className="animate-in fade-in duration-500">
                <div className="mb-1 opacity-60">
                  <span className={`text-[7px] sm:text-[8px] font-bold uppercase tracking-[0.2em] ${msg.role === 'agent' ? 'text-neutral-400' : 'text-neutral-500'}`}>
                    {msg.role === 'agent' ? 'RESPONSE' : 'PIONEER'}
                  </span>
                </div>
                <div className={`text-[12px] sm:text-[13px] tracking-wide ${msg.role === 'agent' ? 'text-neutral-100 font-medium' : 'text-neutral-400'}`}>
                  {msg.content}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Input Area */}
      {!isDocs && (
        <div className="px-3 sm:px-10 pb-3 sm:pb-10 pt-4 bg-transparent overflow-hidden">
          <form onSubmit={handleSubmit} className="relative flex items-center bg-black/40 border border-white/10 px-3 sm:px-5 py-3 sm:py-4 focus-within:border-white/30 transition-all shadow-xl backdrop-blur-md overflow-hidden">
            <span className="command-prefix text-neutral-300 mr-2 sm:mr-4 text-[8px] sm:text-[10px] font-mono font-bold tracking-[0.2em] select-none uppercase whitespace-nowrap overflow-hidden text-ellipsis flex-shrink-0">
              [{file.agent || 'ElizaOS v1'}] >
            </span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="..."
              className="bg-transparent border-none outline-none flex-1 text-[12px] sm:text-sm font-mono text-white command-input min-w-0"
              autoFocus={isActive}
            />
          </form>
        </div>
      )}
    </div>
  );
};

export default TerminalPane;

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { ProjectFile, FileType } from './types';
import { INITIAL_FILES } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';

export default function App() {
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);
  const [activePaneId, setActivePaneId] = useState('chat-1');
  const [showSystem, setShowSystem] = useState(false);
  const [showWiki, setShowWiki] = useState(false);
  const [showHelp, setShowHelp] = useState(false);

  const [panes, setPanes] = useState<{ id: string; width: number; isMinimized: boolean; isExpanded: boolean }[]>([
    { id: 'chat-1', width: 600, isMinimized: false, isExpanded: false }
  ]);

  const [isResizing, setIsResizing] = useState<number | null>(null);

  const handleCreatePane = useCallback(() => {
    const newId = `chat-${Date.now()}`;
    const newFile: ProjectFile = {
      id: newId,
      name: `Session ${panes.length + 1}`,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: 'ElizaOS v1',
      resources: [],
      messages: [
        { role: 'agent', content: `Session protocol established. Waiting for command...`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);
    setPanes(prev => {
      // If any is expanded, collapse it to make room
      const updated = prev.map(p => ({ ...p, isExpanded: false }));
      return [...updated, { id: newId, width: 450, isMinimized: false, isExpanded: false }];
    });
    setActivePaneId(newId);
  }, [panes.length]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ctrl + [1-9] switch tabs
      if (e.ctrlKey && !isNaN(parseInt(e.key)) && e.key !== '0') {
        const index = parseInt(e.key) - 1;
        if (panes[index]) {
          setActivePaneId(panes[index].id);
          setPanes(prev => prev.map((p, i) => i === index ? { ...p, isMinimized: false } : p));
        }
      }
      // Shift + N create new session
      if (e.shiftKey && (e.key === 'N' || e.key === 'n')) {
        e.preventDefault();
        handleCreatePane();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [panes, handleCreatePane]);

  const handleSendMessage = (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    setFiles(prev => prev.map(f => {
      if (f.id === fileId) {
        return {
          ...f,
          messages: [
            ...f.messages,
            { role: 'user', content, timestamp },
            { role: 'agent', content: `Executing command...`, timestamp }
          ]
        };
      }
      return f;
    }));
  };

  const handleClosePane = (id: string) => {
    setPanes(prev => {
      const newPanes = prev.filter(p => p.id !== id);
      if (newPanes.length > 0 && activePaneId === id) {
        setActivePaneId(newPanes[0].id);
      }
      return newPanes;
    });
  };

  const handleMinimizePane = (id: string) => {
    setPanes(prev => prev.map(p => p.id === id ? { ...p, isMinimized: !p.isMinimized, isExpanded: false } : p));
  };

  const handleExpandPane = (id: string) => {
    setPanes(prev => {
      const isCurrentlyExpanded = prev.find(p => p.id === id)?.isExpanded;
      return prev.map(p => p.id === id ? { ...p, isExpanded: !isCurrentlyExpanded, isMinimized: false } : { ...p, isExpanded: false });
    });
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        if (next[isResizing]) {
          next[isResizing].width += delta;
          next[isResizing].width = Math.max(80, next[isResizing].width);
        }
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
    document.body.style.cursor = 'default';
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  const systemFile = useMemo(() => files.find(f => f.id === 'docs') as ProjectFile, [files]);

  return (
    <div className="h-screen w-screen flex flex-col bg-transparent overflow-hidden font-inter text-neutral-200 relative">
      {/* Header */}
      <header className="h-14 border-b border-white/5 bg-black/40 backdrop-blur-md flex items-center justify-between px-4 sm:px-8 select-none z-50">
        <div className="flex items-center gap-4 sm:gap-10">
          <div className="flex flex-col items-start">
            <span className="font-serif font-bold text-[10px] sm:text-xs tracking-[0.2em] text-white uppercase whitespace-nowrap">Reflecter Labs</span>
          </div>
          <nav className="hidden sm:flex items-center gap-8 text-[9px] uppercase font-bold tracking-[0.3em] text-neutral-400">
            <button 
              onClick={() => {setShowWiki(false); setShowSystem(false)}}
              className={`hover:text-white transition-all ${!showWiki && !showSystem ? 'text-white border-b border-white pb-1' : ''}`}
            >
              Orchestration
            </button>
            <button 
              onClick={() => {setShowSystem(!showSystem); setShowWiki(false)}}
              className={`hover:text-white transition-all ${showSystem ? 'text-white border-b border-white pb-1' : ''}`}
            >
              System Guide
            </button>
            <button 
              onClick={() => {setShowWiki(!showWiki); setShowSystem(false)}}
              className={`hover:text-white transition-all ${showWiki ? 'text-white border-b border-white pb-1' : ''}`}
            >
              Wiki
            </button>
          </nav>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => setShowHelp(true)} className="p-2 text-neutral-500 hover:text-white transition-colors">
              <span className="font-bold text-lg">?</span>
           </button>
           <button 
             onClick={handleCreatePane}
             className="flex items-center gap-2 bg-white text-black px-4 py-1.5 text-[9px] font-bold uppercase tracking-[0.2em] hover:bg-neutral-200 transition-all shadow-lg"
           >
             <Icon name="close" size={10} className="rotate-45" />
             <span>Invoke</span>
           </button>
        </div>
      </header>

      {/* Main Content Area - Constrained to Viewport */}
      <div className="flex-1 flex overflow-hidden relative z-10 w-full">
        <div className="flex h-full w-full max-w-full overflow-hidden">
          {panes.length === 0 ? (
            <div className="flex-1 flex items-center justify-center pointer-events-none">
              <span className="font-serif text-xl sm:text-3xl uppercase tracking-[0.5em] opacity-30">REFLECTERS</span>
            </div>
          ) : (
            panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;

              const isLast = index === panes.length - 1;
              const anyExpanded = panes.some(p => p.isExpanded);

              if (anyExpanded && !pane.isExpanded) return null;

              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className={`h-full flex flex-col relative glass-pane ${pane.isExpanded || (isLast && !anyExpanded) ? 'flex-1' : 'shrink-0'}`}
                    style={pane.isExpanded || (isLast && !anyExpanded) ? {} : { width: pane.isMinimized ? 40 : pane.width }}
                  >
                    <TerminalPane 
                      file={file}
                      width="100%"
                      isActive={activePaneId === pane.id}
                      isMinimized={pane.isMinimized}
                      isExpanded={pane.isExpanded}
                      onFocus={() => setActivePaneId(pane.id)}
                      onSendMessage={handleSendMessage}
                      onClose={() => handleClosePane(pane.id)}
                      onMinimize={() => handleMinimizePane(pane.id)}
                      onExpand={() => handleExpandPane(pane.id)}
                    />
                  </div>
                  {!isLast && !pane.isMinimized && !pane.isExpanded && !anyExpanded && (
                    <div 
                      className="resizer-h shrink-0" 
                      onMouseDown={() => setIsResizing(index)}
                    />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </div>

      {/* Wiki / AIStation Overlay */}
      {showWiki && (
        <div className="absolute inset-0 z-[60] bg-black/95 backdrop-blur-2xl flex flex-col items-center justify-center p-12 overflow-y-auto">
          <div className="max-w-4xl w-full space-y-12">
            <div className="flex justify-between items-center">
               <h1 className="font-serif text-5xl tracking-[0.4em] text-white">AISTATION</h1>
               <button onClick={() => setShowWiki(false)} className="text-neutral-500 hover:text-white"><Icon name="close" size={32}/></button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12 font-mono text-sm leading-relaxed text-neutral-400">
               <div className="space-y-4">
                  <h3 className="text-white uppercase tracking-widest font-bold">Protocol Overview</h3>
                  <p>The AIStation serves as the primary neural uplink for agent coordination. By leveraging multi-agent systems, it ensures logical consistency across distributed node clusters.</p>
               </div>
               <div className="space-y-4">
                  <h3 className="text-white uppercase tracking-widest font-bold">Operational Status</h3>
                  <div className="p-4 border border-white/10 bg-white/5 space-y-2">
                    <div className="flex justify-between"><span>Central Core</span><span className="text-green-500">OPTIMAL</span></div>
                    <div className="flex justify-between"><span>Nexus Uplink</span><span className="text-green-500">CONNECTED</span></div>
                    <div className="flex justify-between"><span>Agent Sync</span><span className="text-yellow-500">PENDING</span></div>
                  </div>
               </div>
            </div>
          </div>
        </div>
      )}

      {/* Shortcuts Help Overlay */}
      {showHelp && (
        <div className="absolute inset-0 z-[70] bg-black/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-[#0a0a0a] border border-white/10 p-8 w-full max-w-md">
            <div className="flex justify-between items-center mb-6">
               <h3 className="font-serif text-lg tracking-widest uppercase">System Shortcuts</h3>
               <button onClick={() => setShowHelp(false)} className="text-neutral-500 hover:text-white"><Icon name="close" size={16}/></button>
            </div>
            <div className="space-y-4 font-mono text-[10px] uppercase tracking-widest">
               <div className="flex justify-between items-center"><span>New Session</span><span className="shortcut-key">Shift + N</span></div>
               <div className="flex justify-between items-center"><span>Tab 1-9</span><span className="shortcut-key">Ctrl + [1-9]</span></div>
               <div className="flex justify-between items-center"><span>Expand Pane</span><span className="shortcut-key">UI Toggle</span></div>
               <div className="flex justify-between items-center"><span>Wiki</span><span className="shortcut-key">Top Nav</span></div>
            </div>
          </div>
        </div>
      )}

      {/* System Guide Overlay */}
      {showSystem && (
        <div className="absolute inset-0 z-[60] bg-black/90 backdrop-blur-xl flex flex-col p-8 sm:p-20 overflow-y-auto">
          <div className="max-w-4xl mx-auto w-full">
            <div className="flex justify-between items-center mb-10">
               <h1 className="font-serif text-3xl tracking-[0.2em] text-white">SYSTEM GUIDE</h1>
               <button onClick={() => setShowSystem(false)} className="text-neutral-500 hover:text-white"><Icon name="close" size={24}/></button>
            </div>
            <TerminalPane 
               file={systemFile} 
               width="100%" 
               isActive={true} 
               onFocus={() => {}} 
               onSendMessage={() => {}} 
               isSystemView
            />
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="h-10 bg-black/40 backdrop-blur-md border-t border-white/5 flex items-center justify-center px-8 z-50">
         <div className="text-[7px] sm:text-[9px] uppercase font-mono tracking-[0.3em] text-neutral-500 text-center">
            developed by <span className="text-white font-bold tracking-widest">REFLECTER LABS</span> | 2026
         </div>
      </footer>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { ProjectFile } from '../types';
import Icon from './Icon';
import { DOCS_CONTENT } from '../constants';

interface TerminalPaneProps {
  file: ProjectFile;
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (fileId: string, content: string) => void;
  onClose?: () => void;
  onMinimize?: () => void;
  onExpand?: () => void;
  isSystemView?: boolean;
  isMinimized?: boolean;
  isExpanded?: boolean;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  file, isActive, onFocus, width, onSendMessage, onClose, onMinimize, onExpand,
  isSystemView = false, isMinimized = false, isExpanded = false
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  const isDocs = file.id === 'docs';

  if (isMinimized) {
    return (
      <div 
        onClick={onMinimize}
        className="h-full w-10 flex flex-col items-center bg-black/60 border-r border-white/10 cursor-pointer hover:bg-black/80 transition-all pt-4 gap-4 overflow-hidden"
      >
        <div className="w-1.5 h-1.5 rounded-full bg-neutral-600"></div>
        <span className="font-mono text-[8px] uppercase tracking-widest [writing-mode:vertical-lr] rotate-180 text-neutral-500">{file.name}</span>
      </div>
    );
  }

  return (
    <div 
      style={{ width }} 
      onClick={onFocus}
      className={`h-full flex flex-col border-r border-white/5 overflow-hidden relative transition-all bg-transparent ${isActive ? 'z-10' : 'z-0'}`}
    >
      {/* Header with Smart Truncation */}
      <div className={`flex bg-black/20 border-b border-white/10 h-10 select-none flex-shrink-0 items-center overflow-hidden transition-all ${isActive ? 'bg-black/40' : ''}`}>
        <div className={`flex items-center gap-2 px-3 sm:px-6 text-[8px] sm:text-[9px] uppercase font-bold tracking-widest h-full border-r border-white/10 ${isActive ? 'text-white' : 'text-neutral-600'} min-w-0 flex-1`}>
          <div className={`flex-shrink-0 w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
          <span className="truncate whitespace-nowrap overflow-hidden text-ellipsis">{file.name}</span>
        </div>

        <div className="flex items-center px-1 flex-shrink-0 gap-1 sm:gap-2">
           {!isSystemView && (
             <>
               <button onClick={(e) => { e.stopPropagation(); onMinimize?.(); }} className="text-neutral-600 hover:text-white transition-colors p-1" title="Minimize">
                 <Icon name="chevron-down" size={14} className="rotate-0" />
               </button>
               <button onClick={(e) => { e.stopPropagation(); onExpand?.(); }} className="text-neutral-600 hover:text-white transition-colors p-1" title={isExpanded ? "Restore" : "Expand"}>
                 <Icon name="play" size={10} className={isExpanded ? 'rotate-180' : '-rotate-90'} />
               </button>
               {onClose && (
                 <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="text-neutral-600 hover:text-white transition-colors p-1" title="Close">
                   <Icon name="close" size={14} />
                 </button>
               )}
             </>
           )}
        </div>
      </div>

      {/* Content Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 sm:p-12 font-mono text-[11px] sm:text-[12px] leading-relaxed text-neutral-200 selection:bg-white selection:text-black scroll-smooth no-scrollbar">
        {isDocs ? (
          <div className="whitespace-pre-wrap max-w-4xl mx-auto">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <div key={i} className="text-white font-bold mb-4 sm:mb-6 uppercase tracking-[0.3em] font-serif text-xl sm:text-2xl border-b border-white/10 pb-2">{line.replace('# ', '')}</div>;
              if (line.startsWith('■')) return <div key={i} className="bg-white/5 p-3 sm:p-4 my-6 sm:my-8 border-l-2 border-white flex items-center gap-3 text-white">
                 <span className="tracking-widest uppercase text-[9px] sm:text-[10px]">{line}</span>
              </div>;
              if (line.startsWith('###')) return <div key={i} className="text-white font-bold mt-6 sm:mt-8 mb-3 sm:mb-4 uppercase tracking-widest text-[10px] sm:text-xs border-white/20 border-b w-fit pr-4">{line.replace('### ', '')}</div>;
              return <div key={i} className="mb-2 text-neutral-400">{line}</div>;
            })}
          </div>
        ) : (
          <div className="space-y-6 sm:space-y-8 max-w-5xl">
            {file.messages.map((msg, i) => (
              <div key={i} className="animate-in fade-in duration-500">
                <div className="mb-1 opacity-60">
                  <span className={`text-[7px] sm:text-[8px] font-bold uppercase tracking-[0.2em] ${msg.role === 'agent' ? 'text-neutral-400' : 'text-neutral-500'}`}>
                    {msg.role === 'agent' ? 'RESPONSE' : 'PIONEER'}
                  </span>
                </div>
                <div className={`text-[12px] sm:text-[13px] tracking-wide ${msg.role === 'agent' ? 'text-neutral-100 font-medium' : 'text-neutral-400'}`}>
                  {msg.content}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Input Area with Truncatable Prefix */}
      {!isDocs && (
        <div className="px-3 sm:px-10 pb-3 sm:pb-10 pt-4 bg-transparent overflow-hidden">
          <form onSubmit={handleSubmit} className="relative flex items-center bg-black/40 border border-white/10 px-3 sm:px-5 py-3 sm:py-4 focus-within:border-white/30 transition-all shadow-xl backdrop-blur-md overflow-hidden min-w-0">
            <span className="text-neutral-300 mr-2 sm:mr-4 text-[8px] sm:text-[10px] font-mono font-bold tracking-[0.2em] select-none uppercase whitespace-nowrap truncate overflow-hidden text-ellipsis flex-shrink-0 max-w-[120px]">
              [{file.agent || 'ElizaOS v1'}] >
            </span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="..."
              className="bg-transparent border-none outline-none flex-1 text-[12px] sm:text-sm font-mono text-white command-input min-w-[20px]"
              autoFocus={isActive}
            />
          </form>
        </div>
      )}
    </div>
  );
};

export default TerminalPane;

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { ProjectFile, FileType } from './types';
import { INITIAL_FILES } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';

export default function App() {
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);
  const [activePaneId, setActivePaneId] = useState('chat-1');
  const [showSystem, setShowSystem] = useState(false);
  const [showWiki, setShowWiki] = useState(false);
  const [showHelp, setShowHelp] = useState(false);

  const [panes, setPanes] = useState<{ id: string; width: number; isMinimized: boolean; isExpanded: boolean }[]>([
    { id: 'chat-1', width: 600, isMinimized: false, isExpanded: false }
  ]);

  const [isResizing, setIsResizing] = useState<number | null>(null);

  // Creación directa de sesión sin modal, con nombre incremental
  const handleCreatePane = useCallback(() => {
    const newId = `chat-${Date.now()}`;
    const sessionNumber = panes.length + 1;
    const newFile: ProjectFile = {
      id: newId,
      name: `Session ${sessionNumber}`,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: 'ElizaOS v1',
      resources: [],
      messages: [
        { role: 'agent', content: `Session protocol ${sessionNumber} established. Ready for command sequence.`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);
    setPanes(prev => {
      // Si hay uno expandido, lo colapsamos para ver el nuevo
      const updated = prev.map(p => ({ ...p, isExpanded: false }));
      return [...updated, { id: newId, width: 450, isMinimized: false, isExpanded: false }];
    });
    setActivePaneId(newId);
  }, [panes.length]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ctrl + [1-9] cambio de pestañas (Estándar IDE)
      if (e.ctrlKey && !isNaN(parseInt(e.key)) && e.key !== '0') {
        const index = parseInt(e.key) - 1;
        if (panes[index]) {
          setActivePaneId(panes[index].id);
          setPanes(prev => prev.map((p, i) => i === index ? { ...p, isMinimized: false } : p));
        }
      }
      // Shift + N para nueva sesión rápida
      if (e.shiftKey && (e.key === 'N' || e.key === 'n')) {
        e.preventDefault();
        handleCreatePane();
      }
      // ? para ayuda de atajos
      if (e.key === '?' && !['INPUT', 'TEXTAREA'].includes(document.activeElement?.tagName || '')) {
        setShowHelp(true);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [panes, handleCreatePane]);

  const handleSendMessage = (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    setFiles(prev => prev.map(f => {
      if (f.id === fileId) {
        return {
          ...f,
          messages: [
            ...f.messages,
            { role: 'user', content, timestamp },
            { role: 'agent', content: `Syncing with node cluster... command executed.`, timestamp }
          ]
        };
      }
      return f;
    }));
  };

  const handleClosePane = (id: string) => {
    setPanes(prev => {
      const newPanes = prev.filter(p => p.id !== id);
      if (newPanes.length > 0 && activePaneId === id) {
        setActivePaneId(newPanes[0].id);
      }
      return newPanes;
    });
  };

  const handleMinimizePane = (id: string) => {
    setPanes(prev => prev.map(p => p.id === id ? { ...p, isMinimized: !p.isMinimized, isExpanded: false } : p));
  };

  const handleExpandPane = (id: string) => {
    setPanes(prev => {
      const isCurrentlyExpanded = prev.find(p => p.id === id)?.isExpanded;
      return prev.map(p => p.id === id ? { ...p, isExpanded: !isCurrentlyExpanded, isMinimized: false } : { ...p, isExpanded: false });
    });
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        if (next[isResizing]) {
          next[isResizing].width += delta;
          next[isResizing].width = Math.max(80, next[isResizing].width);
        }
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
    document.body.style.cursor = 'default';
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  const systemFile = useMemo(() => files.find(f => f.id === 'docs') as ProjectFile, [files]);

  return (
    <div className="h-screen w-screen flex flex-col bg-transparent overflow-hidden font-inter text-neutral-200 relative">
      {/* Header */}
      <header className="h-14 border-b border-white/5 bg-black/40 backdrop-blur-md flex items-center justify-between px-4 sm:px-8 select-none z-50">
        <div className="flex items-center gap-4 sm:gap-10">
          <div className="flex flex-col items-start cursor-pointer" onClick={() => {setShowWiki(false); setShowSystem(false)}}>
            <span className="font-serif font-bold text-[10px] sm:text-xs tracking-[0.2em] text-white uppercase whitespace-nowrap">Reflecter Labs</span>
          </div>
          <nav className="hidden sm:flex items-center gap-8 text-[9px] uppercase font-bold tracking-[0.3em] text-neutral-400">
            <button 
              onClick={() => {setShowWiki(false); setShowSystem(false)}}
              className={`hover:text-white transition-all ${!showWiki && !showSystem ? 'text-white border-b border-white pb-1' : ''}`}
            >
              Orchestration
            </button>
            <button 
              onClick={() => {setShowSystem(!showSystem); setShowWiki(false)}}
              className={`hover:text-white transition-all ${showSystem ? 'text-white border-b border-white pb-1' : ''}`}
            >
              System Guide
            </button>
            <button 
              onClick={() => {setShowWiki(!showWiki); setShowSystem(false)}}
              className={`hover:text-white transition-all ${showWiki ? 'text-white border-b border-white pb-1' : ''}`}
            >
              Wiki
            </button>
          </nav>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => setShowHelp(true)} className="p-2 text-neutral-500 hover:text-white transition-colors" title="Keyboard Shortcuts (?)">
              <Icon name="search" size={16} />
           </button>
           <button 
             onClick={handleCreatePane}
             className="flex items-center gap-2 bg-white text-black px-4 py-1.5 text-[9px] font-bold uppercase tracking-[0.2em] hover:bg-neutral-200 transition-all shadow-lg"
           >
             <Icon name="close" size={10} className="rotate-45" />
             <span>Invoke</span>
           </button>
        </div>
      </header>

      {/* Main Content Area - Se ajusta de X0 a Xmax */}
      <div className="flex-1 flex overflow-hidden relative z-10 w-full max-w-full">
        <div className="flex h-full w-full max-w-full overflow-hidden">
          {panes.length === 0 ? (
            <div className="flex-1 flex items-center justify-center pointer-events-none">
              <span className="font-serif text-xl sm:text-3xl uppercase tracking-[0.5em] opacity-30">REFLECTERS</span>
            </div>
          ) : (
            panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;

              const isLast = index === panes.length - 1;
              const anyExpanded = panes.some(p => p.isExpanded);

              if (anyExpanded && !pane.isExpanded) return null;

              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className={`h-full flex flex-col relative glass-pane ${pane.isExpanded || (isLast && !anyExpanded) ? 'flex-1' : 'shrink-0'}`}
                    style={pane.isExpanded || (isLast && !anyExpanded) ? { minWidth: 0 } : { width: pane.isMinimized ? 40 : pane.width, minWidth: 0 }}
                  >
                    <TerminalPane 
                      file={file}
                      width="100%"
                      isActive={activePaneId === pane.id}
                      isMinimized={pane.isMinimized}
                      isExpanded={pane.isExpanded}
                      onFocus={() => setActivePaneId(pane.id)}
                      onSendMessage={handleSendMessage}
                      onClose={() => handleClosePane(pane.id)}
                      onMinimize={() => handleMinimizePane(pane.id)}
                      onExpand={() => handleExpandPane(pane.id)}
                    />
                  </div>
                  {!isLast && !pane.isMinimized && !pane.isExpanded && !anyExpanded && (
                    <div 
                      className="resizer-h shrink-0" 
                      onMouseDown={() => setIsResizing(index)}
                    />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </div>

      {/* Wiki / AIStation Overlay */}
      {showWiki && (
        <div className="absolute inset-0 z-[60] bg-black/95 backdrop-blur-2xl flex flex-col items-center justify-center p-8 overflow-y-auto">
          <div className="max-w-4xl w-full space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex justify-between items-center border-b border-white/10 pb-8">
               <h1 className="font-serif text-4xl sm:text-6xl tracking-[0.4em] text-white">AISTATION</h1>
               <button onClick={() => setShowWiki(false)} className="text-neutral-500 hover:text-white transition-colors p-2"><Icon name="close" size={32}/></button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12 font-mono text-sm leading-relaxed text-neutral-400">
               <div className="space-y-6">
                  <h3 className="text-white uppercase tracking-widest font-bold text-xs">Knowledge Base Index</h3>
                  <p>Central intelligence repository for Reflecter Labs protocols. Access decrypted agent logs, architectural blueprints, and orchestration schematics.</p>
                  <div className="flex gap-4">
                    <span className="text-[10px] text-white border border-white/20 px-3 py-1 uppercase tracking-widest">v4.0.1 Stable</span>
                    <span className="text-[10px] text-green-500 border border-green-500/20 px-3 py-1 uppercase tracking-widest">Nodes Active</span>
                  </div>
               </div>
               <div className="space-y-4">
                  <h3 className="text-white uppercase tracking-widest font-bold text-xs">Decrypted Streams</h3>
                  <div className="space-y-3 p-6 border border-white/10 bg-white/5 font-mono text-[10px] leading-tight">
                    <div className="flex justify-between border-b border-white/5 pb-2"><span>Agent: Guardian</span><span className="text-green-500">Verified</span></div>
                    <div className="flex justify-between border-b border-white/5 pb-2"><span>Node: Nexus-7</span><span className="text-blue-400">Syncing</span></div>
                    <div className="flex justify-between"><span>Protocol: Sanctum</span><span className="text-neutral-500">Idle</span></div>
                  </div>
               </div>
            </div>
          </div>
        </div>
      )}

      {/* Shortcuts Help Overlay */}
      {showHelp && (
        <div className="absolute inset-0 z-[100] bg-black/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-[#0a0a0a] border border-white/10 p-8 w-full max-w-md animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-8 border-b border-white/5 pb-4">
               <h3 className="font-serif text-lg tracking-widest uppercase text-white">Command Shortcuts</h3>
               <button onClick={() => setShowHelp(false)} className="text-neutral-500 hover:text-white"><Icon name="close" size={16}/></button>
            </div>
            <div className="space-y-5 font-mono text-[10px] uppercase tracking-widest text-neutral-400">
               <div className="flex justify-between items-center"><span>Invoke Session</span><span className="shortcut-key">Shift + N</span></div>
               <div className="flex justify-between items-center"><span>Quick Switch Tab</span><span className="shortcut-key">Ctrl + [1-9]</span></div>
               <div className="flex justify-between items-center"><span>Toggle System Help</span><span className="shortcut-key">?</span></div>
               <div className="flex justify-between items-center"><span>Expand View</span><span className="text-[8px] opacity-60">Pane Toggle</span></div>
            </div>
            <button 
              onClick={() => setShowHelp(false)}
              className="w-full mt-8 border border-white/20 py-2 text-[10px] uppercase tracking-[0.2em] hover:bg-white hover:text-black transition-all"
            >
              Close Manual
            </button>
          </div>
        </div>
      )}

      {/* System Guide Overlay */}
      {showSystem && (
        <div className="absolute inset-0 z-[60] bg-black/90 backdrop-blur-xl flex flex-col p-6 sm:p-20 overflow-y-auto">
          <div className="max-w-4xl mx-auto w-full">
            <div className="flex justify-between items-center mb-10 border-b border-white/10 pb-6">
               <h1 className="font-serif text-3xl tracking-[0.2em] text-white">PROTOCOL DOCUMENTATION</h1>
               <button onClick={() => setShowSystem(false)} className="text-neutral-500 hover:text-white p-2 transition-colors"><Icon name="close" size={24}/></button>
            </div>
            <TerminalPane 
               file={systemFile} 
               width="100%" 
               isActive={true} 
               onFocus={() => {}} 
               onSendMessage={() => {}} 
               isSystemView
            />
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="h-10 bg-black/40 backdrop-blur-md border-t border-white/5 flex items-center justify-center px-8 z-50">
         <div className="text-[7px] sm:text-[9px] uppercase font-mono tracking-[0.3em] text-neutral-500 text-center">
            developed by <span className="text-white font-bold tracking-widest">REFLECTER LABS</span> | 2026
         </div>
      </footer>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { ProjectFile } from '../types';
import Icon from './Icon';
import { DOCS_CONTENT } from '../constants';

interface TerminalPaneProps {
  file: ProjectFile;
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (fileId: string, content: string) => void;
  onClose?: () => void;
  onMinimize?: () => void;
  onExpand?: () => void;
  isSystemView?: boolean;
  isMinimized?: boolean;
  isExpanded?: boolean;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  file, isActive, onFocus, width, onSendMessage, onClose, onMinimize, onExpand,
  isSystemView = false, isMinimized = false, isExpanded = false
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  const isDocs = file.id === 'docs';

  // Vista colapsada/minimizada (Estilo sidebar vertical)
  if (isMinimized) {
    return (
      <div 
        onClick={onMinimize}
        className="h-full w-10 flex flex-col items-center bg-black/60 border-r border-white/10 cursor-pointer hover:bg-black/80 transition-all pt-4 gap-4 overflow-hidden group"
      >
        <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-700'}`}></div>
        <span className="font-mono text-[7px] uppercase tracking-[0.2em] [writing-mode:vertical-lr] rotate-180 text-neutral-500 group-hover:text-neutral-300 transition-colors">{file.name}</span>
      </div>
    );
  }

  return (
    <div 
      style={{ width }} 
      onClick={onFocus}
      className={`h-full flex flex-col border-r border-white/5 overflow-hidden relative transition-all bg-transparent ${isActive ? 'z-10 shadow-2xl' : 'z-0'}`}
    >
      {/* Header con Truncamiento Robusto para evitar overflow */}
      <div className={`flex bg-black/30 border-b border-white/10 h-10 select-none flex-shrink-0 items-center overflow-hidden transition-all ${isActive ? 'bg-black/50' : ''}`}>
        <div className={`flex items-center gap-2 px-2 sm:px-4 text-[8px] sm:text-[9px] uppercase font-bold tracking-widest h-full border-r border-white/10 ${isActive ? 'text-white' : 'text-neutral-600'} min-w-0 flex-1`}>
          <div className={`flex-shrink-0 w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
          <span className="truncate whitespace-nowrap overflow-hidden text-ellipsis">{file.name}</span>
        </div>

        <div className="flex items-center px-1 flex-shrink-0 gap-0.5 sm:gap-1">
           {!isSystemView && (
             <>
               <button onClick={(e) => { e.stopPropagation(); onMinimize?.(); }} className="text-neutral-600 hover:text-white transition-colors p-1" title="Minimize">
                 <Icon name="chevron-down" size={12} className="rotate-0" />
               </button>
               <button onClick={(e) => { e.stopPropagation(); onExpand?.(); }} className="text-neutral-600 hover:text-white transition-colors p-1" title={isExpanded ? "Restore" : "Expand"}>
                 <Icon name="play" size={10} className={isExpanded ? 'rotate-180' : '-rotate-90'} />
               </button>
               {onClose && (
                 <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="text-neutral-600 hover:text-red-400 transition-colors p-1" title="Close">
                   <Icon name="close" size={12} />
                 </button>
               )}
             </>
           )}
        </div>
      </div>

      {/* Content Area con scroll oculto */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 sm:p-10 font-mono text-[11px] sm:text-[12px] leading-relaxed text-neutral-300 selection:bg-white selection:text-black scroll-smooth no-scrollbar">
        {isDocs ? (
          <div className="whitespace-pre-wrap max-w-4xl mx-auto">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <div key={i} className="text-white font-bold mb-4 sm:mb-6 uppercase tracking-[0.3em] font-serif text-xl sm:text-2xl border-b border-white/10 pb-2">{line.replace('# ', '')}</div>;
              if (line.startsWith('■')) return <div key={i} className="bg-white/5 p-3 sm:p-4 my-6 sm:my-8 border-l-2 border-white flex items-center gap-3 text-white">
                 <span className="tracking-widest uppercase text-[9px] sm:text-[10px]">{line}</span>
              </div>;
              if (line.startsWith('###')) return <div key={i} className="text-white font-bold mt-6 sm:mt-8 mb-3 sm:mb-4 uppercase tracking-widest text-[10px] sm:text-xs border-white/20 border-b w-fit pr-4">{line.replace('### ', '')}</div>;
              return <div key={i} className="mb-2 text-neutral-500">{line}</div>;
            })}
          </div>
        ) : (
          <div className="space-y-6 sm:space-y-8 max-w-5xl">
            {file.messages.map((msg, i) => (
              <div key={i} className="animate-in fade-in duration-500">
                <div className="mb-1 opacity-50">
                  <span className={`text-[7px] sm:text-[8px] font-bold uppercase tracking-[0.2em] ${msg.role === 'agent' ? 'text-neutral-400' : 'text-neutral-500'}`}>
                    {msg.role === 'agent' ? 'SERVER RESPONSE' : 'USER COMMAND'}
                  </span>
                </div>
                <div className={`text-[12px] tracking-wide ${msg.role === 'agent' ? 'text-neutral-100' : 'text-neutral-400 italic'}`}>
                  {msg.content}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Input Area con prefijo que se trunca inteligentemente */}
      {!isDocs && !isSystemView && (
        <div className="px-4 sm:px-8 pb-4 sm:pb-8 pt-2 bg-transparent overflow-hidden">
          <form onSubmit={handleSubmit} className="relative flex items-center bg-black/60 border border-white/10 px-3 sm:px-4 py-2 sm:py-3 focus-within:border-white/30 transition-all shadow-xl backdrop-blur-md overflow-hidden min-w-0">
            <span className="text-neutral-500 mr-2 sm:mr-3 text-[8px] sm:text-[10px] font-mono font-bold tracking-[0.1em] select-none uppercase whitespace-nowrap truncate overflow-hidden text-ellipsis flex-shrink-0 max-w-[40%]">
              [{file.agent || 'ElizaOS v1'}] >
            </span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="..."
              className="bg-transparent border-none outline-none flex-1 text-[11px] sm:text-xs font-mono text-white command-input min-w-0"
              autoFocus={isActive}
            />
          </form>
        </div>
      )}
    </div>
  );
};

export default TerminalPane;

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { ProjectFile, FileType } from './types';
import { INITIAL_FILES } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';

export default function App() {
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);
  const [activePaneId, setActivePaneId] = useState('chat-1');
  const [showSystem, setShowSystem] = useState(false);
  const [showWiki, setShowWiki] = useState(false);
  const [showHelp, setShowHelp] = useState(false);

  const [panes, setPanes] = useState<{ id: string; width: number; isMinimized: boolean; isExpanded: boolean }[]>([
    { id: 'chat-1', width: 600, isMinimized: false, isExpanded: false }
  ]);

  const [isResizing, setIsResizing] = useState<number | null>(null);

  // Direct session invocation (no modal as requested)
  const handleCreatePane = useCallback(() => {
    const newId = `chat-${Date.now()}`;
    const sessionNum = panes.length + 1;
    const newFile: ProjectFile = {
      id: newId,
      name: `Session ${sessionNum}`,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: 'ElizaOS v1',
      resources: [],
      messages: [
        { role: 'agent', content: `Session protocol ${sessionNum} established. Uplink verified.`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);
    setPanes(prev => {
      // If someone is expanded, we restore it to make room for the new session
      const reset = prev.map(p => ({ ...p, isExpanded: false }));
      return [...reset, { id: newId, width: 450, isMinimized: false, isExpanded: false }];
    });
    setActivePaneId(newId);
  }, [panes.length]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ctrl + [1-9] standard tab switching
      if (e.ctrlKey && !isNaN(parseInt(e.key)) && e.key !== '0') {
        const index = parseInt(e.key) - 1;
        if (panes[index]) {
          setActivePaneId(panes[index].id);
          setPanes(prev => prev.map((p, i) => i === index ? { ...p, isMinimized: false } : p));
        }
      }
      // Shift + N for new session
      if (e.shiftKey && (e.key === 'N' || e.key === 'n')) {
        e.preventDefault();
        handleCreatePane();
      }
      // ? for shortcuts help (don't trigger if inside input)
      if (e.key === '?' && !['INPUT', 'TEXTAREA'].includes(document.activeElement?.tagName || '')) {
        setShowHelp(true);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [panes, handleCreatePane]);

  const handleSendMessage = (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    setFiles(prev => prev.map(f => {
      if (f.id === fileId) {
        return {
          ...f,
          messages: [
            ...f.messages,
            { role: 'user', content, timestamp },
            { role: 'agent', content: `Synthesizing neural response...`, timestamp }
          ]
        };
      }
      return f;
    }));
  };

  const handleClosePane = (id: string) => {
    setPanes(prev => {
      const filtered = prev.filter(p => p.id !== id);
      if (filtered.length > 0 && activePaneId === id) {
        setActivePaneId(filtered[0].id);
      }
      return filtered;
    });
  };

  const handleMinimizePane = (id: string) => {
    setPanes(prev => prev.map(p => p.id === id ? { ...p, isMinimized: !p.isMinimized, isExpanded: false } : p));
  };

  const handleExpandPane = (id: string) => {
    setPanes(prev => {
      const current = prev.find(p => p.id === id);
      const targetState = !current?.isExpanded;
      return prev.map(p => p.id === id ? { ...p, isExpanded: targetState, isMinimized: false } : { ...p, isExpanded: false });
    });
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        if (next[isResizing]) {
          next[isResizing].width += delta;
          next[isResizing].width = Math.max(80, next[isResizing].width);
        }
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
    document.body.style.cursor = 'default';
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  const systemFile = useMemo(() => files.find(f => f.id === 'docs') as ProjectFile, [files]);

  return (
    <div className="h-screen w-screen flex flex-col bg-transparent overflow-hidden font-inter text-neutral-200 relative select-none">
      {/* Navbar */}
      <header className="h-14 border-b border-white/5 bg-black/40 backdrop-blur-md flex items-center justify-between px-4 sm:px-8 z-50">
        <div className="flex items-center gap-10">
          <div className="cursor-pointer" onClick={() => {setShowWiki(false); setShowSystem(false)}}>
            <span className="font-serif font-bold text-xs tracking-[0.2em] text-white uppercase">Reflecter Labs</span>
          </div>
          <nav className="hidden md:flex items-center gap-8 text-[9px] uppercase font-bold tracking-[0.3em] text-neutral-400">
            <button 
              onClick={() => {setShowWiki(false); setShowSystem(false)}}
              className={`hover:text-white transition-all ${!showWiki && !showSystem ? 'text-white border-b border-white pb-1' : ''}`}
            >
              Orchestration
            </button>
            <button 
              onClick={() => {setShowSystem(!showSystem); setShowWiki(false)}}
              className={`hover:text-white transition-all ${showSystem ? 'text-white border-b border-white pb-1' : ''}`}
            >
              System Guide
            </button>
            <button 
              onClick={() => {setShowWiki(!showWiki); setShowSystem(false)}}
              className={`hover:text-white transition-all ${showWiki ? 'text-white border-b border-white pb-1' : ''}`}
            >
              Wiki
            </button>
          </nav>
        </div>
        <div className="flex items-center gap-4">
           <button onClick={() => setShowHelp(true)} className="p-2 text-neutral-500 hover:text-white transition-colors" title="Shortcuts (?)">
              <Icon name="search" size={16} />
           </button>
           <button 
             onClick={handleCreatePane}
             className="flex items-center gap-2 bg-white text-black px-4 py-1.5 text-[9px] font-bold uppercase tracking-[0.2em] hover:bg-neutral-200 transition-all shadow-xl"
           >
             <Icon name="close" size={10} className="rotate-45" />
             <span>Invoke</span>
           </button>
        </div>
      </header>

      {/* Wiki & System Overlays (AIStation) */}
      {(showWiki || showSystem) && (
        <div className="absolute inset-0 z-[60] bg-black/90 backdrop-blur-3xl p-8 sm:p-20 overflow-y-auto animate-in fade-in duration-300">
          <div className="max-w-4xl mx-auto w-full space-y-12">
            <div className="flex justify-between items-center border-b border-white/10 pb-8">
               <h1 className="font-serif text-5xl tracking-[0.4em] text-white">{showWiki ? 'AISTATION' : 'SYSTEM GUIDE'}</h1>
               <button onClick={() => {setShowWiki(false); setShowSystem(false)}} className="text-neutral-500 hover:text-white p-2">
                 <Icon name="close" size={32}/>
               </button>
            </div>
            <div className="font-mono text-sm leading-relaxed text-neutral-400">
              {showWiki ? (
                <div className="space-y-10">
                   <p className="text-lg text-white font-light">The central hub for Reflecter node synchronization. Decrypting intelligence streams...</p>
                   <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                     <div className="p-6 bg-white/5 border border-white/10">
                        <h4 className="text-white text-xs uppercase tracking-widest mb-4">Core Integrity</h4>
                        <div className="space-y-2 text-[10px]">
                           <div className="flex justify-between"><span>Kernel 0.1</span><span className="text-green-500">OPTIMAL</span></div>
                           <div className="flex justify-between"><span>Sanctum Link</span><span className="text-blue-400">ESTABLISHED</span></div>
                        </div>
                     </div>
                     <div className="p-6 bg-white/5 border border-white/10">
                        <h4 className="text-white text-xs uppercase tracking-widest mb-4">Neural Map</h4>
                        <p className="text-[10px]">Access to distributed agent clusters. Status: Latency within acceptable 12ms threshold.</p>
                     </div>
                   </div>
                </div>
              ) : (
                <TerminalPane file={systemFile} width="100%" isActive={true} onFocus={() => {}} onSendMessage={() => {}} isSystemView />
              )}
            </div>
          </div>
        </div>
      )}

      {/* Main Orchestration Area (X0 to Xmax) */}
      <div className="flex-1 flex overflow-hidden relative z-10 w-full">
        <div className="flex h-full w-full max-w-full overflow-hidden">
          {panes.length === 0 ? (
            <div className="flex-1 flex items-center justify-center">
              <span className="font-serif text-3xl uppercase tracking-[0.5em] opacity-20">REFLECTERS</span>
            </div>
          ) : (
            panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;

              const isLast = index === panes.length - 1;
              const anyExpanded = panes.some(p => p.isExpanded);

              if (anyExpanded && !pane.isExpanded) return null;

              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className={`h-full flex flex-col glass-pane ${pane.isExpanded || (isLast && !anyExpanded) ? 'flex-1' : 'shrink-0'}`}
                    style={pane.isExpanded || (isLast && !anyExpanded) ? { minWidth: 0 } : { width: pane.isMinimized ? 40 : pane.width, minWidth: 0 }}
                  >
                    <TerminalPane 
                      file={file}
                      width="100%"
                      isActive={activePaneId === pane.id}
                      isMinimized={pane.isMinimized}
                      isExpanded={pane.isExpanded}
                      onFocus={() => setActivePaneId(pane.id)}
                      onSendMessage={handleSendMessage}
                      onClose={() => handleClosePane(pane.id)}
                      onMinimize={() => handleMinimizePane(pane.id)}
                      onExpand={() => handleExpandPane(pane.id)}
                    />
                  </div>
                  {!isLast && !pane.isMinimized && !pane.isExpanded && !anyExpanded && (
                    <div className="resizer-h shrink-0" onMouseDown={() => setIsResizing(index)} />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </div>

      {/* Shortcuts Modal */}
      {showHelp && (
        <div className="absolute inset-0 z-[100] bg-black/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-[#0a0a0a] border border-white/10 p-8 w-full max-w-sm animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-8 pb-2 border-b border-white/5">
               <h3 className="font-serif text-lg tracking-widest uppercase text-white">Logic Atajos</h3>
               <button onClick={() => setShowHelp(false)} className="text-neutral-500 hover:text-white"><Icon name="close" size={16}/></button>
            </div>
            <div className="space-y-4 font-mono text-[10px] uppercase tracking-[0.2em] text-neutral-400">
               <div className="flex justify-between items-center"><span>New Session</span><span className="shortcut-key">Shift + N</span></div>
               <div className="flex justify-between items-center"><span>Switch Tab</span><span className="shortcut-key">Ctrl + [1-9]</span></div>
               <div className="flex justify-between items-center"><span>Toggle Help</span><span className="shortcut-key">?</span></div>
               <div className="flex justify-between items-center"><span>Maximize Pane</span><span className="text-[8px] opacity-40">UI ICON</span></div>
            </div>
            <button 
              onClick={() => setShowHelp(false)}
              className="w-full mt-8 border border-white/10 py-3 text-[9px] uppercase tracking-[0.2em] hover:bg-white hover:text-black transition-all font-bold"
            >
              Acknowledged
            </button>
          </div>
        </div>
      )}

      {/* Global Footer */}
      <footer className="h-10 bg-black/40 backdrop-blur-md border-t border-white/5 flex items-center justify-center px-8 z-50">
         <div className="text-[7px] sm:text-[9px] uppercase font-mono tracking-[0.3em] text-neutral-500 text-center">
            developed by <span className="text-white font-bold tracking-widest">REFLECTER LABS</span> | 2026
         </div>
      </footer>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { ProjectFile } from '../types';
import Icon from './Icon';
import { DOCS_CONTENT } from '../constants';

interface TerminalPaneProps {
  file: ProjectFile;
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (fileId: string, content: string) => void;
  onClose?: () => void;
  onMinimize?: () => void;
  onExpand?: () => void;
  isSystemView?: boolean;
  isMinimized?: boolean;
  isExpanded?: boolean;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  file, isActive, onFocus, width, onSendMessage, onClose, onMinimize, onExpand,
  isSystemView = false, isMinimized = false, isExpanded = false
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  if (isMinimized) {
    return (
      <div 
        onClick={onMinimize}
        className="h-full w-10 flex flex-col items-center bg-black/60 border-r border-white/10 cursor-pointer hover:bg-black/80 transition-all pt-4 gap-6 overflow-hidden"
      >
        <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
        <span className="font-mono text-[7px] uppercase tracking-[0.2em] [writing-mode:vertical-lr] rotate-180 text-neutral-500">{file.name}</span>
      </div>
    );
  }

  const isDocs = file.id === 'docs';

  return (
    <div 
      style={{ width }} 
      onClick={onFocus}
      className={`h-full flex flex-col overflow-hidden relative transition-all bg-transparent ${isActive ? 'z-10' : 'z-0'}`}
    >
      {/* Pane Header with Controls */}
      <div className={`flex bg-black/20 border-b border-white/5 h-10 select-none flex-shrink-0 items-center overflow-hidden transition-colors ${isActive ? 'bg-black/40' : ''}`}>
        <div className={`flex items-center gap-2 px-3 sm:px-4 text-[8px] sm:text-[9px] uppercase font-bold tracking-widest h-full border-r border-white/5 ${isActive ? 'text-white' : 'text-neutral-600'} min-w-0 flex-1`}>
          <div className={`flex-shrink-0 w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
          <span className="truncate whitespace-nowrap overflow-hidden text-ellipsis">{file.name}</span>
        </div>

        <div className="flex items-center px-1 flex-shrink-0 gap-0.5 sm:gap-1">
           {!isSystemView && (
             <>
               <button onClick={(e) => { e.stopPropagation(); onMinimize?.(); }} className="text-neutral-600 hover:text-white transition-colors p-1.5" title="Minimize">
                 <Icon name="chevron-down" size={12} />
               </button>
               <button onClick={(e) => { e.stopPropagation(); onExpand?.(); }} className="text-neutral-600 hover:text-white transition-colors p-1.5" title={isExpanded ? "Restore" : "Expand"}>
                 <Icon name="play" size={10} className={isExpanded ? 'rotate-180' : '-rotate-90'} />
               </button>
               {onClose && (
                 <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="text-neutral-600 hover:text-red-400 transition-colors p-1.5" title="Close">
                   <Icon name="close" size={12} />
                 </button>
               )}
             </>
           )}
        </div>
      </div>

      {/* Main Content Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 sm:p-12 font-mono text-[11px] sm:text-[12px] leading-relaxed text-neutral-300 selection:bg-white selection:text-black scroll-smooth no-scrollbar">
        {isDocs ? (
          <div className="whitespace-pre-wrap max-w-4xl mx-auto space-y-4">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <div key={i} className="text-white font-bold mb-6 uppercase tracking-[0.3em] font-serif text-2xl border-b border-white/10 pb-2">{line.replace('# ', '')}</div>;
              if (line.startsWith('■')) return <div key={i} className="bg-white/5 p-4 my-8 border-l-2 border-white flex items-center gap-3 text-white text-[10px] uppercase tracking-widest">{line}</div>;
              if (line.startsWith('###')) return <div key={i} className="text-white font-bold mt-10 mb-4 uppercase tracking-widest text-[11px] border-white/20 border-b w-fit pr-4">{line.replace('### ', '')}</div>;
              return <div key={i} className="mb-2 text-neutral-500">{line}</div>;
            })}
          </div>
        ) : (
          <div className="space-y-8 max-w-4xl">
            {file.messages.map((msg, i) => (
              <div key={i} className="animate-in fade-in slide-in-from-left-2 duration-500">
                <div className="mb-2 opacity-40">
                  <span className={`text-[7px] sm:text-[8px] font-bold uppercase tracking-[0.2em] ${msg.role === 'agent' ? 'text-neutral-300' : 'text-neutral-500'}`}>
                    {msg.role === 'agent' ? 'UPLINK RESPONSE' : 'USER COMMAND'}
                  </span>
                </div>
                <div className={`text-[12px] tracking-wide ${msg.role === 'agent' ? 'text-neutral-100' : 'text-neutral-400 italic'}`}>
                  {msg.content}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Command Input Area */}
      {!isDocs && !isSystemView && (
        <div className="px-4 sm:px-10 pb-4 sm:pb-10 pt-2 bg-transparent">
          <form onSubmit={handleSubmit} className="flex items-center bg-black/60 border border-white/5 px-4 py-3 sm:py-4 focus-within:border-white/20 transition-all shadow-2xl backdrop-blur-md min-w-0">
            <span className="text-neutral-500 mr-3 text-[8px] sm:text-[10px] font-mono font-bold tracking-[0.1em] select-none uppercase truncate max-w-[100px] sm:max-w-none">
              [{file.agent || 'ElizaOS v1'}] >
            </span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="..."
              className="bg-transparent border-none outline-none flex-1 text-[11px] sm:text-xs font-mono text-white command-input min-w-[30px]"
              autoFocus={isActive}
            />
          </form>
        </div>
      )}
    </div>
  );
};

