import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { ProjectFile, FileType } from './types';
import { INITIAL_FILES } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';

export default function App() {
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);
  const [activePaneId, setActivePaneId] = useState('chat-1');
  const [showWiki, setShowWiki] = useState(false);
  const [showHelp, setShowHelp] = useState(false);
  const [showSystem, setShowSystem] = useState(false);

  // Sistema de paneles con anchos iniciales controlados
  const [panes, setPanes] = useState<{ id: string; width: number; isMinimized: boolean; isExpanded: boolean }[]>([
    { id: 'chat-1', width: 500, isMinimized: false, isExpanded: false }
  ]);

  const [isResizing, setIsResizing] = useState<number | null>(null);

  // Invocación directa sin configuración manual
  const handleCreatePane = useCallback(() => {
    const newId = `chat-${Date.now()}`;
    const sessionNum = panes.length + 1;
    const newFile: ProjectFile = {
      id: newId,
      name: `Session ${sessionNum}`,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: 'ElizaOS v1',
      resources: [],
      messages: [
        { role: 'agent', content: `Neural link ${sessionNum} established. Awaiting directives.`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);
    setPanes(prev => {
      // Si hay una expandida, la quitamos para que el usuario vea la nueva
      const reset = prev.map(p => ({ ...p, isExpanded: false }));
      return [...reset, { id: newId, width: 400, isMinimized: false, isExpanded: false }];
    });
    setActivePaneId(newId);
  }, [panes.length]);

  // Atajos de teclado inteligentes
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const isInput = ['INPUT', 'TEXTAREA'].includes(document.activeElement?.tagName || '');

      // Ctrl + [1-9] para pestañas
      if (e.ctrlKey && !isNaN(parseInt(e.key)) && e.key !== '0') {
        const index = parseInt(e.key) - 1;
        if (panes[index]) {
          setActivePaneId(panes[index].id);
          setPanes(prev => prev.map((p, i) => i === index ? { ...p, isMinimized: false } : p));
        }
      }
      // Shift + N para nueva sesión
      if (e.shiftKey && (e.key === 'N' || e.key === 'n')) {
        e.preventDefault();
        handleCreatePane();
      }
      // ? para ayuda
      if (e.key === '?' && !isInput) {
        setShowHelp(prev => !prev);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [panes, handleCreatePane]);

  const handleSendMessage = (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    setFiles(prev => prev.map(f => {
      if (f.id === fileId) {
        return {
          ...f,
          messages: [
            ...f.messages,
            { role: 'user', content, timestamp },
            { role: 'agent', content: `Syncing with node cluster... Protocol executed.`, timestamp }
          ]
        };
      }
      return f;
    }));
  };

  const handleClosePane = (id: string) => {
    setPanes(prev => {
      const filtered = prev.filter(p => p.id !== id);
      if (filtered.length > 0 && activePaneId === id) {
        setActivePaneId(filtered[0].id);
      }
      return filtered;
    });
  };

  const handleMinimizePane = (id: string) => {
    setPanes(prev => prev.map(p => p.id === id ? { ...p, isMinimized: !p.isMinimized, isExpanded: false } : p));
  };

  const handleExpandPane = (id: string) => {
    setPanes(prev => {
      const current = prev.find(p => p.id === id);
      const isNowExpanding = !current?.isExpanded;
      return prev.map(p => p.id === id ? { ...p, isExpanded: isNowExpanding, isMinimized: false } : { ...p, isExpanded: false });
    });
  };

  // Manejo de redimensionamiento con límites estrictos
  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        if (next[isResizing]) {
          const newWidth = next[isResizing].width + delta;
          // Impedir que se extienda demasiado o que colapse
          next[isResizing].width = Math.max(100, Math.min(newWidth, window.innerWidth - 100));
        }
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
    document.body.style.cursor = 'default';
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  const systemFile = useMemo(() => files.find(f => f.id === 'docs') as ProjectFile, [files]);

  return (
    <div className="h-screen w-screen flex flex-col bg-transparent overflow-hidden font-inter text-neutral-200 relative">
      {/* Navbar Superior */}
      <header className="h-14 border-b border-white/5 bg-black/40 backdrop-blur-md flex items-center justify-between px-4 sm:px-8 z-50 shrink-0">
        <div className="flex items-center gap-10">
          <div className="cursor-pointer" onClick={() => {setShowWiki(false); setShowSystem(false)}}>
            <span className="font-serif font-bold text-xs tracking-[0.2em] text-white uppercase">Reflecter Labs</span>
          </div>
          <nav className="hidden lg:flex items-center gap-8 text-[9px] uppercase font-bold tracking-[0.3em] text-neutral-400">
            <button 
              onClick={() => {setShowWiki(false); setShowSystem(false)}}
              className={`hover:text-white transition-all ${!showWiki && !showSystem ? 'text-white border-b border-white pb-1' : ''}`}
            >
              Orchestration
            </button>
            <button 
              onClick={() => {setShowSystem(!showSystem); setShowWiki(false)}}
              className={`hover:text-white transition-all ${showSystem ? 'text-white border-b border-white pb-1' : ''}`}
            >
              System Guide
            </button>
            <button 
              onClick={() => {setShowWiki(!showWiki); setShowSystem(false)}}
              className={`hover:text-white transition-all ${showWiki ? 'text-white border-b border-white pb-1' : ''}`}
            >
              Wiki
            </button>
          </nav>
        </div>
        <div className="flex items-center gap-4">
           <button onClick={() => setShowHelp(true)} className="p-2 text-neutral-500 hover:text-white transition-colors" title="Keyboard Shortcuts (?)">
              <span className="font-bold text-lg">?</span>
           </button>
           <div className="flex items-center gap-2">
             <button 
               onClick={handleCreatePane}
               className="flex items-center gap-2 bg-white text-black px-4 py-1.5 text-[9px] font-bold uppercase tracking-[0.2em] hover:bg-neutral-200 transition-all shadow-xl"
             >
               <Icon name="close" size={10} className="rotate-45" />
               <span>Invoke</span>
             </button>
           </div>
        </div>
      </header>

      {/* Área Principal de Contención Estricta (X0 a Xmax) */}
      <main className="flex-1 flex overflow-hidden w-full max-w-full relative z-10 border-x border-white/5">
        <div className="flex h-full w-full max-w-full overflow-hidden items-stretch">
          {panes.length === 0 ? (
            <div className="flex-1 flex items-center justify-center">
              <span className="font-serif text-3xl uppercase tracking-[0.5em] opacity-10">REFLECTERS</span>
            </div>
          ) : (
            panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;

              const isLast = index === panes.length - 1;
              const anyExpanded = panes.some(p => p.isExpanded);

              // Si hay uno expandido, ocultar todos los demás
              if (anyExpanded && !pane.isExpanded) return null;

              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className={`h-full flex flex-col glass-pane ${pane.isExpanded || (isLast && !anyExpanded) ? 'flex-1' : 'shrink-0'}`}
                    style={pane.isExpanded || (isLast && !anyExpanded) ? { minWidth: 0 } : { width: pane.isMinimized ? 40 : pane.width, minWidth: 0 }}
                  >
                    <TerminalPane 
                      file={file}
                      width="100%"
                      isActive={activePaneId === pane.id}
                      isMinimized={pane.isMinimized}
                      isExpanded={pane.isExpanded}
                      onFocus={() => setActivePaneId(pane.id)}
                      onSendMessage={handleSendMessage}
                      onClose={() => handleClosePane(pane.id)}
                      onMinimize={() => handleMinimizePane(pane.id)}
                      onExpand={() => handleExpandPane(pane.id)}
                    />
                  </div>
                  {!isLast && !pane.isMinimized && !pane.isExpanded && !anyExpanded && (
                    <div 
                      className="resizer-h shrink-0" 
                      onMouseDown={(e) => { e.preventDefault(); setIsResizing(index); }} 
                    />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </main>

      {/* Overlay AIStation Wiki */}
      {showWiki && (
        <div className="absolute inset-0 z-[60] bg-black/95 backdrop-blur-3xl p-8 sm:p-20 overflow-y-auto animate-in fade-in duration-500">
           <div className="max-w-4xl mx-auto w-full space-y-16">
              <div className="flex justify-between items-center border-b border-white/10 pb-8">
                 <h1 className="font-serif text-5xl sm:text-7xl tracking-[0.4em] text-white">AISTATION</h1>
                 <button onClick={() => setShowWiki(false)} className="text-neutral-500 hover:text-white transition-colors p-2">
                    <Icon name="close" size={32} />
                 </button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-16 font-mono text-sm leading-relaxed text-neutral-400">
                 <div className="space-y-8">
                    <p className="text-xl text-white font-light tracking-wide">The central coordination terminal for high-performance agent orchestration.</p>
                    <div className="p-8 border border-white/10 bg-white/5 space-y-4">
                       <h3 className="text-white uppercase tracking-widest font-bold text-xs">Protocol: Reflecter Core</h3>
                       <p className="text-xs">Ensuring logical consistency through distributed neural verification nodes. Our ElizaOS v1 architecture allows real-time auditing of multi-agent flows.</p>
                    </div>
                 </div>
                 <div className="space-y-6">
                    <h4 className="text-white text-xs uppercase tracking-widest font-bold">Network Status</h4>
                    <div className="space-y-4 p-6 border border-white/5 bg-black/40">
                       <div className="flex justify-between border-b border-white/5 pb-2"><span>Uplink Alpha</span><span className="text-green-500">VERIFIED</span></div>
                       <div className="flex justify-between border-b border-white/5 pb-2"><span>Nexus-9 Core</span><span className="text-blue-400">SYNCING</span></div>
                       <div className="flex justify-between"><span>Sanctum Access</span><span className="text-neutral-500">STANDBY</span></div>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* Overlay Guía del Sistema */}
      {showSystem && (
        <div className="absolute inset-0 z-[60] bg-black/90 backdrop-blur-xl flex flex-col p-6 sm:p-20 overflow-y-auto">
          <div className="max-w-4xl mx-auto w-full">
            <div className="flex justify-between items-center mb-10 border-b border-white/10 pb-6">
               <h1 className="font-serif text-3xl tracking-[0.2em] text-white uppercase">System Guide</h1>
               <button onClick={() => setShowSystem(false)} className="text-neutral-500 hover:text-white p-2 transition-colors">
                  <Icon name="close" size={24} />
               </button>
            </div>
            <TerminalPane 
               file={systemFile} 
               width="100%" 
               isActive={true} 
               onFocus={() => {}} 
               onSendMessage={() => {}} 
               isSystemView
            />
          </div>
        </div>
      )}

      {/* Modal de Atajos (?) */}
      {showHelp && (
        <div className="absolute inset-0 z-[100] bg-black/70 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-[#0a0a0a] border border-white/10 p-8 w-full max-w-sm animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-10 border-b border-white/5 pb-4">
               <h3 className="font-serif text-lg tracking-widest uppercase text-white">Shortcuts Manual</h3>
               <button onClick={() => setShowHelp(false)} className="text-neutral-500 hover:text-white"><Icon name="close" size={16}/></button>
            </div>
            <div className="space-y-5 font-mono text-[10px] uppercase tracking-[0.2em] text-neutral-400">
               <div className="flex justify-between items-center"><span>New Session</span><span className="shortcut-key">Shift + N</span></div>
               <div className="flex justify-between items-center"><span>Switch Tab</span><span className="shortcut-key">Ctrl + [1-9]</span></div>
               <div className="flex justify-between items-center"><span>Toggle Help</span><span className="shortcut-key">?</span></div>
               <div className="flex justify-between items-center"><span>Expand Pane</span><span className="text-[8px] opacity-40">Header Icon</span></div>
            </div>
            <button 
              onClick={() => setShowHelp(false)}
              className="w-full mt-10 border border-white/20 py-3 text-[10px] uppercase tracking-[0.3em] hover:bg-white hover:text-black transition-all font-bold"
            >
              Close
            </button>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="h-10 bg-black/40 backdrop-blur-md border-t border-white/5 flex items-center justify-center px-8 z-50 shrink-0">
         <div className="text-[7px] sm:text-[9px] uppercase font-mono tracking-[0.3em] text-neutral-500 text-center">
            developed by <span className="text-white font-bold tracking-widest">REFLECTER LABS</span> | 2026
         </div>
      </footer>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { ProjectFile } from '../types';
import Icon from './Icon';
import { DOCS_CONTENT } from '../constants';

interface TerminalPaneProps {
  file: ProjectFile;
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (fileId: string, content: string) => void;
  onClose?: () => void;
  onMinimize?: () => void;
  onExpand?: () => void;
  isSystemView?: boolean;
  isMinimized?: boolean;
  isExpanded?: boolean;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  file, isActive, onFocus, width, onSendMessage, onClose, onMinimize, onExpand,
  isSystemView = false, isMinimized = false, isExpanded = false
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  // Estado minimizado (barra lateral vertical estrecha)
  if (isMinimized) {
    return (
      <div 
        onClick={onMinimize}
        className="h-full w-10 flex flex-col items-center bg-black/70 border-r border-white/5 cursor-pointer hover:bg-black/90 transition-all pt-6 gap-8 overflow-hidden group shrink-0"
      >
        <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
        <span className="font-mono text-[7px] uppercase tracking-[0.2em] [writing-mode:vertical-lr] rotate-180 text-neutral-600 group-hover:text-neutral-400 transition-colors">
          {file.name}
        </span>
      </div>
    );
  }

  const isDocs = file.id === 'docs';

  return (
    <div 
      style={{ width }} 
      onClick={onFocus}
      className={`h-full flex flex-col overflow-hidden relative transition-all bg-transparent ${isActive ? 'z-10 shadow-2xl' : 'z-0'} min-w-0`}
    >
      {/* Cabecera del Panel con Controles */}
      <div className={`flex bg-black/30 border-b border-white/5 h-10 select-none flex-shrink-0 items-center overflow-hidden transition-colors ${isActive ? 'bg-black/50' : ''}`}>
        <div className={`flex items-center gap-2 px-3 sm:px-4 text-[8px] sm:text-[9px] uppercase font-bold tracking-widest h-full border-r border-white/5 ${isActive ? 'text-white' : 'text-neutral-600'} min-w-0 flex-1`}>
          <div className={`flex-shrink-0 w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
          <span className="truncate whitespace-nowrap overflow-hidden text-ellipsis">{file.name}</span>
        </div>

        <div className="flex items-center px-1 flex-shrink-0 gap-0.5 sm:gap-1">
           {!isSystemView && (
             <>
               <button onClick={(e) => { e.stopPropagation(); onMinimize?.(); }} className="text-neutral-600 hover:text-white transition-colors p-1.5" title="Minimize">
                 <Icon name="chevron-down" size={12} />
               </button>
               <button onClick={(e) => { e.stopPropagation(); onExpand?.(); }} className="text-neutral-600 hover:text-white transition-colors p-1.5" title={isExpanded ? "Restore" : "Expand"}>
                 <Icon name="play" size={10} className={isExpanded ? 'rotate-180' : '-rotate-90'} />
               </button>
               {onClose && (
                 <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="text-neutral-600 hover:text-red-400 transition-colors p-1.5" title="Close">
                   <Icon name="close" size={12} />
                 </button>
               )}
             </>
           )}
        </div>
      </div>

      {/* Área de Mensajes / Contenido */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 sm:p-12 font-mono text-[11px] sm:text-[12px] leading-relaxed text-neutral-300 selection:bg-white selection:text-black scroll-smooth no-scrollbar">
        {isDocs ? (
          <div className="whitespace-pre-wrap max-w-4xl mx-auto space-y-6">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <div key={i} className="text-white font-bold mb-8 uppercase tracking-[0.3em] font-serif text-2xl border-b border-white/10 pb-4">{line.replace('# ', '')}</div>;
              if (line.startsWith('■')) return <div key={i} className="bg-white/5 p-6 my-10 border-l-2 border-white flex items-center gap-4 text-white text-[10px] uppercase tracking-widest font-bold">{line}</div>;
              if (line.startsWith('###')) return <div key={i} className="text-white font-bold mt-12 mb-6 uppercase tracking-widest text-[11px] border-white/20 border-b w-fit pr-6">{line.replace('### ', '')}</div>;
              return <div key={i} className="mb-3 text-neutral-500">{line}</div>;
            })}
          </div>
        ) : (
          <div className="space-y-10 max-w-4xl">
            {file.messages.map((msg, i) => (
              <div key={i} className="animate-in fade-in slide-in-from-left-2 duration-500">
                <div className="mb-2 opacity-30">
                  <span className={`text-[7px] sm:text-[8px] font-bold uppercase tracking-[0.2em] ${msg.role === 'agent' ? 'text-neutral-300' : 'text-neutral-500'}`}>
                    {msg.role === 'agent' ? 'SERVER RESPONSE' : 'USER COMMAND'}
                  </span>
                </div>
                <div className={`text-[12px] tracking-wide ${msg.role === 'agent' ? 'text-neutral-100 font-medium' : 'text-neutral-400 italic'}`}>
                  {msg.content}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Línea de Comandos */}
      {!isDocs && !isSystemView && (
        <div className="px-4 sm:px-10 pb-6 sm:pb-10 pt-2 bg-transparent shrink-0">
          <form onSubmit={handleSubmit} className="flex items-center bg-black/60 border border-white/10 px-4 py-3 sm:py-4 focus-within:border-white/30 transition-all shadow-2xl backdrop-blur-md min-w-0">
            <span className="text-neutral-500 mr-3 text-[8px] sm:text-[10px] font-mono font-bold tracking-[0.1em] select-none uppercase truncate max-w-[120px] shrink-0">
              [{file.agent || 'ElizaOS v1'}] >
            </span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="..."
              className="bg-transparent border-none outline-none flex-1 text-[11px] sm:text-xs font-mono text-white command-input min-w-[20px]"
              autoFocus={isActive}
            />
          </form>
        </div>
      )}
    </div>
  );
};

export default TerminalPane;

import React, { useState, useCallback, useEffect, useMemo } from 'react';
