import React, { useState, useCallback, useEffect } from 'react';
import { ProjectFile, FileType } from './types';
import { INITIAL_FILES } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';
import WikiView from './components/WikiView';
import LandingView from './components/LandingView';

export default function App() {
  const [view, setView] = useState<'landing' | 'ide'>('landing');
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);
  const [activePaneId, setActivePaneId] = useState('chat-1');
  const [showWiki, setShowWiki] = useState(false);
  const [showHelp, setShowHelp] = useState(false);

  const [panes, setPanes] = useState<{ id: string; flex: number; isMinimized: boolean; isExpanded: boolean }[]>([
    { id: 'chat-1', flex: 1, isMinimized: false, isExpanded: false }
  ]);

  const [isResizing, setIsResizing] = useState<number | null>(null);

  const handleCreatePane = useCallback(() => {
    const newId = `chat-${Date.now()}`;
    const sessionNum = panes.length + 1;
    const newFile: ProjectFile = {
      id: newId,
      name: `Session ${sessionNum}`,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: 'ElizaOS v1',
      resources: [],
      messages: [
        { role: 'agent', content: `Neural link ${sessionNum} established. Space dynamically allocated.`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);
    setPanes(prev => {
      const reset = prev.map(p => ({ ...p, isExpanded: false }));
      return [...reset, { id: newId, flex: 1, isMinimized: false, isExpanded: false }];
    });
    setActivePaneId(newId);
  }, [panes.length]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (view !== 'ide') return;
      const isInput = ['INPUT', 'TEXTAREA'].includes(document.activeElement?.tagName || '');
      if (e.ctrlKey && !isNaN(parseInt(e.key)) && e.key !== '0') {
        const index = parseInt(e.key) - 1;
        if (panes[index]) {
          setActivePaneId(panes[index].id);
          setPanes(prev => prev.map((p, i) => i === index ? { ...p, isMinimized: false } : p));
        }
      }
      if (e.shiftKey && (e.key === 'N' || e.key === 'n')) {
        e.preventDefault();
        handleCreatePane();
      }
      if (e.key === '?' && !isInput) {
        setShowHelp(prev => !prev);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [panes, handleCreatePane, view]);

  const handleSendMessage = (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    setFiles(prev => prev.map(f => {
      if (f.id === fileId) {
        return {
          ...f,
          messages: [
            ...f.messages,
            { role: 'user', content, timestamp },
            { role: 'agent', content: `Command received. Processing in allocated segment.`, timestamp }
          ]
        };
      }
      return f;
    }));
  };

  const handleClosePane = (id: string) => {
    setPanes(prev => {
      const filtered = prev.filter(p => p.id !== id);
      if (filtered.length > 0 && activePaneId === id) {
        setActivePaneId(filtered[0].id);
      }
      return filtered;
    });
  };

  const handleMinimizePane = (id: string) => {
    setPanes(prev => prev.map(p => p.id === id ? { ...p, isMinimized: !p.isMinimized, isExpanded: false } : p));
  };

  const handleExpandPane = (id: string) => {
    setPanes(prev => {
      const current = prev.find(p => p.id === id);
      const isNowExpanding = !current?.isExpanded;
      return prev.map(p => p.id === id ? { ...p, isExpanded: isNowExpanding, isMinimized: false } : { ...p, isExpanded: false });
    });
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        const leftPane = next[isResizing];
        const rightPane = next[isResizing + 1];
        if (leftPane && rightPane && !leftPane.isMinimized && !rightPane.isMinimized) {
          const factor = 0.002;
          const newLeftFlex = Math.max(0.1, leftPane.flex + (delta * factor));
          const newRightFlex = Math.max(0.1, rightPane.flex - (delta * factor));
          next[isResizing] = { ...leftPane, flex: newLeftFlex };
          next[isResizing + 1] = { ...rightPane, flex: newRightFlex };
        }
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  if (view === 'landing') {
    return <LandingView onEnterIDE={() => setView('ide')} />;
  }

  return (
    <div className="h-screen w-screen flex flex-col bg-transparent overflow-hidden font-inter text-neutral-200 relative animate-in fade-in duration-700">
      <header className="h-14 border-b border-white/5 bg-black/40 backdrop-blur-md flex items-center justify-between px-4 sm:px-8 z-50 shrink-0">
        <div className="flex items-center gap-10">
          <div className="cursor-pointer" onClick={() => {setShowWiki(false); setView('landing')}}>
            <span className="font-serif font-bold text-lg tracking-[0.4em] text-white uppercase hover:opacity-70 transition-all">AISTATION</span>
          </div>
          <nav className="hidden lg:flex items-center gap-8 text-[9px] uppercase font-bold tracking-[0.3em] text-neutral-300">
            <button onClick={() => setShowWiki(false)} className={`hover:text-white transition-all ${!showWiki ? 'text-white border-b border-white pb-1' : ''}`}>Orchestration</button>
            <button onClick={() => setShowWiki(true)} className={`hover:text-white transition-all ${showWiki ? 'text-white border-b border-white pb-1' : ''}`}>Wiki</button>
          </nav>
        </div>
        <div className="flex items-center gap-4">
           <button onClick={() => setShowHelp(true)} className="p-2 text-neutral-400 hover:text-white transition-colors"><span className="font-bold text-lg">?</span></button>
           <button onClick={handleCreatePane} className="flex items-center gap-2 bg-white text-black px-4 py-1.5 text-[9px] font-bold uppercase tracking-[0.2em] hover:bg-neutral-200 transition-all shadow-xl">
             <Icon name="close" size={10} className="rotate-45" />
             <span>Invoke</span>
           </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden w-full max-w-full relative z-10 border-x border-white/5 bg-transparent">
        <div className="flex h-full w-full max-w-full overflow-hidden items-stretch justify-start">
          {panes.length === 0 ? (
            <div className="flex-1 flex items-center justify-center">
              <span className="font-serif text-3xl uppercase tracking-[0.5em] opacity-10">REFLECTERS</span>
            </div>
          ) : (
            panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;
              const isLast = index === panes.length - 1;
              const anyExpanded = panes.some(p => p.isExpanded);
              if (anyExpanded && !pane.isExpanded) return null;
              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className="h-full flex flex-col glass-pane overflow-hidden transition-[flex] duration-300 ease-out"
                    style={{ flex: pane.isMinimized ? '0 0 40px' : (pane.isExpanded ? '1 1 100%' : `${pane.flex} 1 0%`), minWidth: pane.isMinimized ? '40px' : '0' }}
                  >
                    <TerminalPane file={file} width="100%" isActive={activePaneId === pane.id} isMinimized={pane.isMinimized} isExpanded={pane.isExpanded} onFocus={() => setActivePaneId(pane.id)} onSendMessage={handleSendMessage} onClose={() => handleClosePane(pane.id)} onMinimize={() => handleMinimizePane(pane.id)} onExpand={() => handleExpandPane(pane.id)} />
                  </div>
                  {!isLast && !pane.isMinimized && !pane.isExpanded && !anyExpanded && (
                    <div className="resizer-h shrink-0" onMouseDown={(e) => { e.preventDefault(); setIsResizing(index); }} />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </main>

      {showWiki && <WikiView onClose={() => setShowWiki(false)} />}
      {showHelp && (
        <div className="absolute inset-0 z-[100] bg-black/70 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-[#0a0a0a] border border-white/10 p-8 w-full max-w-sm">
            <div className="flex justify-between items-center mb-10 border-b border-white/5 pb-4">
               <h3 className="font-serif text-lg tracking-widest uppercase text-white">Shortcuts</h3>
               <button onClick={() => setShowHelp(false)} className="text-neutral-400 hover:text-white"><Icon name="close" size={16}/></button>
            </div>
            <div className="space-y-5 font-mono text-[10px] uppercase tracking-[0.2em] text-neutral-300">
               <div className="flex justify-between items-center"><span>New Session</span><span className="shortcut-key">Shift + N</span></div>
               <div className="flex justify-between items-center"><span>Switch Tab</span><span className="shortcut-key">Ctrl + [1-9]</span></div>
            </div>
          </div>
        </div>
      )}

      <footer className="h-10 bg-black/40 backdrop-blur-md border-t border-white/5 flex items-center justify-center px-8 z-50 shrink-0">
         <div className="text-[7px] sm:text-[9px] uppercase font-mono tracking-[0.3em] text-neutral-400 text-center">
            developed by <span className="text-white font-bold tracking-widest">REFLECTER LABS</span> | 2026
         </div>
