import React, { useState, useRef, useEffect } from 'react';
import { ProjectFile } from '../types';
import Icon from './Icon';
import { DOCS_CONTENT, AVAILABLE_RESOURCES } from '../constants';

interface TerminalPaneProps {
  file: ProjectFile;
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (fileId: string, content: string) => void;
  onClose?: () => void;
  onMinimize?: () => void;
  onExpand?: () => void;
  isSystemView?: boolean;
  isMinimized?: boolean;
  isExpanded?: boolean;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  file, isActive, onFocus, width, onSendMessage, onClose, onMinimize, onExpand,
  isSystemView = false, isMinimized = false, isExpanded = false
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  if (isMinimized) {
    return (
      <div 
        onClick={onMinimize}
        className="h-full w-full flex flex-col items-center bg-black/70 border-r border-white/5 cursor-pointer hover:bg-black/90 transition-all pt-6 gap-8 overflow-hidden group shrink-0"
      >
        <div className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
        <span className="font-mono text-[7px] uppercase tracking-[0.2em] [writing-mode:vertical-lr] rotate-180 text-neutral-400 group-hover:text-neutral-200 transition-colors whitespace-nowrap">
          {file.name}
        </span>
      </div>
    );
  }

  const isDocs = file.id === 'docs';

  return (
    <div 
      onClick={onFocus}
      className={`h-full w-full flex flex-col overflow-hidden relative transition-all bg-transparent ${isActive ? 'z-10 shadow-2xl' : 'z-0'} min-w-0`}
    >
      {/* Header */}
      <div className={`flex bg-black/30 border-b border-white/5 h-10 select-none flex-shrink-0 items-center overflow-hidden transition-colors ${isActive ? 'bg-black/50' : ''}`}>
        <div className={`flex items-center gap-2 px-3 sm:px-4 text-[8px] sm:text-[9px] uppercase font-bold tracking-widest h-full border-r border-white/5 ${isActive ? 'text-white' : 'text-neutral-400'} min-w-0 flex-1`}>
          <div className={`flex-shrink-0 w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
          <span className="truncate whitespace-nowrap overflow-hidden text-ellipsis">{file.name}</span>
        </div>

        <div className="flex items-center px-1 flex-shrink-0 gap-0.5 sm:gap-1">
           {!isSystemView && (
             <>
               <button onClick={(e) => { e.stopPropagation(); onMinimize?.(); }} className="text-neutral-500 hover:text-white transition-colors p-1.5" title="Minimize">
                 <Icon name="chevron-down" size={12} />
               </button>
               <button onClick={(e) => { e.stopPropagation(); onExpand?.(); }} className="text-neutral-500 hover:text-white transition-colors p-1.5" title={isExpanded ? "Restore" : "Expand"}>
                 <Icon name="play" size={10} className={isExpanded ? 'rotate-180' : '-rotate-90'} />
               </button>
               {onClose && (
                 <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="text-neutral-500 hover:text-red-400 transition-colors p-1.5" title="Close">
                   <Icon name="close" size={12} />
                 </button>
               )}
             </>
           )}
        </div>
      </div>

      {/* Content */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 sm:p-10 font-mono text-[11px] sm:text-[12px] leading-relaxed text-neutral-200 selection:bg-white selection:text-black scroll-smooth no-scrollbar min-w-0">
        {isDocs ? (
          <div className="whitespace-pre-wrap max-w-full mx-auto space-y-6">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <div key={i} className="text-white font-bold mb-8 uppercase tracking-[0.3em] font-serif text-2xl border-b border-white/10 pb-4 break-words">{line.replace('# ', '')}</div>;
              if (line.startsWith('■')) return <div key={i} className="bg-white/5 p-4 my-10 border-l-2 border-white flex items-center gap-4 text-white text-[10px] uppercase tracking-widest font-bold break-words">{line}</div>;
              if (line.startsWith('###')) return <div key={i} className="text-white font-bold mt-12 mb-6 uppercase tracking-widest text-[11px] border-white/20 border-b w-fit pr-6 break-words">{line.replace('### ', '')}</div>;
              return <div key={i} className="mb-3 text-neutral-300 break-words">{line}</div>;
            })}
          </div>
        ) : (
          <div className="space-y-10 max-w-full">
            {file.messages.map((msg, i) => (
              <div key={i} className="animate-in fade-in slide-in-from-left-2 duration-500 max-w-full overflow-hidden">
                <div className="mb-2 opacity-50">
                  <span className={`text-[7px] sm:text-[8px] font-bold uppercase tracking-[0.2em] ${msg.role === 'agent' ? 'text-neutral-200' : 'text-neutral-400'}`}>
                    {msg.role === 'agent' ? 'SERVER RESPONSE' : 'USER COMMAND'}
                  </span>
                </div>
                <div className={`text-[12px] tracking-wide break-words overflow-wrap-anywhere ${msg.role === 'agent' ? 'text-neutral-100 font-medium' : 'text-neutral-300 italic'}`} style={{ overflowWrap: 'anywhere' }}>
                  {msg.content}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Optimized Input & Metadata Column */}
      {!isDocs && !isSystemView && (
        <div className="px-4 sm:px-6 pb-6 shrink-0 min-w-0 animate-in slide-up duration-300">
          <div className="flex gap-2 items-stretch h-12">
            <form onSubmit={handleSubmit} className="flex-1 flex items-center bg-black/40 border border-white/10 px-4 focus-within:border-white/30 transition-all shadow-xl backdrop-blur-md overflow-hidden">
              <span className="text-white/20 mr-3 text-[10px] font-mono font-bold select-none uppercase">{'>'}</span>
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="COMMAND_IDENTIFIER"
                className="bg-transparent border-none outline-none flex-1 text-[11px] font-mono text-white command-input min-w-0"
                autoFocus={isActive}
              />
            </form>

            {/* Metadata Column */}
            <div className="w-32 sm:w-40 flex flex-col justify-between p-2 border border-white/10 bg-black/60 backdrop-blur-md">
              <div className="flex justify-between items-center text-[7px] font-mono text-neutral-400 uppercase tracking-widest leading-none mb-1">
                <span>Agent</span>
                <span className="text-green-500/80">Active</span>
              </div>
              <div className="truncate text-[9px] font-bold text-white uppercase tracking-wider mb-1">
                {file.agent || 'SYSTEM'}
              </div>
              <div className="flex gap-1 overflow-hidden">
                {file.resources?.map(resId => {
                  const res = AVAILABLE_RESOURCES.find(r => r.id === resId);
                  return (
                    <div key={resId} title={res?.name} className="w-4 h-4 flex items-center justify-center bg-white/5 border border-white/5">
                      <Icon name={res?.icon || 'tool'} size={10} className="text-neutral-300" />
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

