                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Optimized Input & Metadata Stack (Two Rows) */}
      {!isDocs && !isSystemView && (
        <div className="px-4 sm:px-6 pb-6 shrink-0 min-w-0 animate-in slide-up duration-300 flex flex-col gap-0.5">
          {/* Row 1: Compact Metadata Bar */}
          <div className="flex items-center justify-between px-3 py-1.5 border border-white/5 bg-black/60 backdrop-blur-md rounded-t-sm">
            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2">
                <span className="text-[7px] font-mono text-neutral-500 uppercase tracking-widest">Agent</span>
                <span className="text-[9px] font-bold text-white uppercase tracking-wider">{file.agent || 'SYSTEM'}</span>
                <div className="w-1.5 h-1.5 rounded-full bg-green-500/60 animate-pulse"></div>
              </div>
              <div className="h-3 w-px bg-white/10 hidden sm:block"></div>
              <div className="flex items-center gap-2">
                <span className="text-[7px] font-mono text-neutral-500 uppercase tracking-widest">Links</span>
                <div className="flex gap-1">
                  {file.resources?.length ? file.resources.map(resId => {
                    const res = AVAILABLE_RESOURCES.find(r => r.id === resId);
                    return (
                      <div key={resId} title={res?.name} className="flex items-center px-1 py-0.5 bg-white/[0.03] border border-white/5">
                        <Icon name={res?.icon || 'tool'} size={8} className="text-neutral-400" />
                      </div>
                    );
                  }) : <span className="text-[8px] text-neutral-600 font-mono italic">No context links</span>}
                </div>
              </div>
            </div>
            <div className="text-[7px] font-mono text-neutral-600 uppercase tracking-widest hidden lg:block">
              Neural_Segment::{file.id.slice(-4).toUpperCase()}
            </div>
          </div>

          {/* Row 2: Full-Width Command Input */}
          <form onSubmit={handleSubmit} className="flex h-11 items-center bg-black/40 border border-white/10 px-4 focus-within:border-white/30 transition-all shadow-xl backdrop-blur-md overflow-hidden rounded-b-sm">
            <span className="text-white/20 mr-3 text-[10px] font-mono font-bold select-none uppercase">{'>'}</span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="INITIALIZE_PROTOCOL..."
              className="bg-transparent border-none outline-none flex-1 text-[11px] font-mono text-white command-input min-w-0 placeholder:opacity-20"
              autoFocus={isActive}
            />
          </form>
        </div>
      )}
    </div>
  );
};

export default TerminalPane;

export enum FileType {
  AGENT = 'AGENT',
  FLOW = 'FLOW',
  TOOL = 'TOOL',
  CONFIG = 'CONFIG',
  CHAT = 'CHAT'
}

export interface Message {
  role: 'user' | 'agent';
  content: string;
  timestamp: string;
}

export interface ProjectFile {
  id: string;
  name: string;
  type: FileType;
  content: string;
  isOpen: boolean;
  agent?: string;
  resources?: string[];
  previewUrl?: string;
  isThinking?: boolean;
  messages: Message[];
}

export interface AgentLog {
  id: string;
  timestamp: string;
  agentName: string;
  message: string;
  status: 'info' | 'success' | 'warning' | 'error';
}

export interface AppState {
  files: ProjectFile[];
  activeFileId: string | null;
  logs: AgentLog[];
  sidebarWidth: number;
  bottomPanelHeight: number;
}

import React, { useState, useCallback, useEffect } from 'react';
import { ProjectFile, FileType } from './types';
import { INITIAL_FILES } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';
import WikiView from './components/WikiView';
import NewPaneModal from './components/NewPaneModal';
import { GoogleGenAI } from "@google/genai";

export default function App() {
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);
  const [activePaneId, setActivePaneId] = useState('chat-1');
  const [showWiki, setShowWiki] = useState(false);
  const [showHelp, setShowHelp] = useState(false);
  const [showNewModal, setShowNewModal] = useState(false);

  const [panes, setPanes] = useState<{ id: string; flex: number; isMinimized: boolean; isExpanded: boolean }[]>([
    { id: 'chat-1', flex: 1, isMinimized: false, isExpanded: false }
  ]);

  const [isResizing, setIsResizing] = useState<number | null>(null);

  const handleCreatePane = useCallback((config: { agent: string; resources: string[]; name: string; previewUrl: string }) => {
    const newId = `chat-${Date.now()}`;
    const newFile: ProjectFile = {
      id: newId,
      name: config.name,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: config.agent,
      resources: config.resources,
      previewUrl: config.previewUrl,
      messages: [
        { role: 'agent', content: `Neural link established with ${config.agent}. Status: Operational.`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);
    setPanes(prev => {
      const reset = prev.map(p => ({ ...p, isExpanded: false }));
      return [...reset, { id: newId, flex: 1, isMinimized: false, isExpanded: false }];
    });
    setActivePaneId(newId);
    setShowNewModal(false);
  }, [panes.length]);

  const handleSendMessage = async (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    const targetFile = files.find(f => f.id === fileId);
    if (!targetFile) return;

    // Add user message and set thinking state
    setFiles(prev => prev.map(f => {
      if (f.id === fileId) {
        return {
          ...f,
          isThinking: true,
          messages: [...f.messages, { role: 'user', content, timestamp }]
        };
      }
      return f;
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // Construct context from previous messages for better chat experience
      const history = targetFile.messages.slice(-5).map(m => `${m.role === 'agent' ? 'Agent' : 'User'}: ${m.content}`).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a high-integrity AI agent named ${targetFile.agent || 'Reflecter'}. 
        You are part of the Reflecter Labs Orchestration Layer. 
        Current Context: ${targetFile.resources?.join(', ') || 'General'}.
        User Instruction: ${content}
        Previous History:
        ${history}

        Keep your response concise, technical, and professional. Stay in character as a sovereign orchestration agent.`,
        config: {
          temperature: 0.7,
          topP: 0.9,
          maxOutputTokens: 512,
        }
      });

      const aiText = response.text || "PROTOCOL_ERROR: Connection timed out.";

      setFiles(prev => prev.map(f => {
        if (f.id === fileId) {
          return {
            ...f,
            isThinking: false,
            messages: [...f.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5) }]
          };
        }
        return f;
      }));
    } catch (error) {
      console.error("AI Error:", error);
      setFiles(prev => prev.map(f => {
        if (f.id === fileId) {
          return {
            ...f,
            isThinking: false,
            messages: [...f.messages, { role: 'agent', content: "SYSTEM_FAILURE: Could not reach neural gateway.", timestamp }]
          };
        }
        return f;
      }));
    }
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const isInput = ['INPUT', 'TEXTAREA'].includes(document.activeElement?.tagName || '');

      if (e.shiftKey && !isNaN(parseInt(e.key)) && e.key !== '0' && !isInput) {
        const index = parseInt(e.key) - 1;
        if (panes[index]) {
          setActivePaneId(panes[index].id);
          setPanes(prev => prev.map((p, i) => i === index ? { ...p, isMinimized: false } : p));
        }
      }

      if (e.shiftKey && (e.key === 'N' || e.key === 'n') && !isInput) {
        e.preventDefault();
        setShowNewModal(true);
      }

      if (e.key === '?' && !isInput) {
        setShowHelp(prev => !prev);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [panes]);

  const handleClosePane = (id: string) => {
    setPanes(prev => {
      const filtered = prev.filter(p => p.id !== id);
      if (filtered.length > 0 && activePaneId === id) {
        setActivePaneId(filtered[0].id);
      }
      return filtered;
    });
  };

  const handleMinimizePane = (id: string) => {
    setPanes(prev => prev.map(p => p.id === id ? { ...p, isMinimized: !p.isMinimized, isExpanded: false } : p));
  };

  const handleExpandPane = (id: string) => {
    setPanes(prev => {
      const current = prev.find(p => p.id === id);
      const isNowExpanding = !current?.isExpanded;
      return prev.map(p => p.id === id ? { ...p, isExpanded: isNowExpanding, isMinimized: false } : { ...p, isExpanded: false });
    });
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setPanes(prev => {
        const next = [...prev];
        const leftPane = next[isResizing];
        const rightPane = next[isResizing + 1];
        if (leftPane && rightPane && !leftPane.isMinimized && !rightPane.isMinimized) {
          const factor = 0.002;
          const newLeftFlex = Math.max(0.1, leftPane.flex + (delta * factor));
          const newRightFlex = Math.max(0.1, rightPane.flex - (delta * factor));
          next[isResizing] = { ...leftPane, flex: newLeftFlex };
          next[isResizing + 1] = { ...rightPane, flex: newRightFlex };
        }
        return next;
      });
    }
  }, [isResizing]);

  const handleMouseUp = useCallback(() => {
    setIsResizing(null);
  }, []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  return (
    <div className="h-screen w-screen flex flex-col bg-transparent overflow-hidden font-inter text-neutral-200 relative animate-in fade-in duration-700">
      <header className="h-14 border-b border-white/5 bg-black/40 backdrop-blur-md flex items-center justify-between px-4 sm:px-8 z-50 shrink-0">
        <div className="flex items-center gap-10">
          <div className="cursor-pointer">
            <span className="font-serif font-bold text-lg tracking-[0.4em] text-white uppercase opacity-90 transition-all">AISTATION</span>
          </div>
          <nav className="hidden lg:flex items-center gap-8 text-[9px] uppercase font-bold tracking-[0.3em] text-neutral-400">
            <button onClick={() => setShowWiki(false)} className={`hover:text-white transition-all ${!showWiki ? 'text-white border-b border-white pb-1' : ''}`}>Workspace</button>
            <button onClick={() => setShowWiki(true)} className={`hover:text-white transition-all ${showWiki ? 'text-white border-b border-white pb-1' : ''}`}>System Manual</button>
          </nav>
        </div>
        <div className="flex items-center gap-4">
           <button onClick={() => setShowHelp(true)} className="p-2 text-neutral-400 hover:text-white transition-colors"><span className="font-bold text-lg">?</span></button>
           <button onClick={() => setShowNewModal(true)} className="flex items-center gap-2 bg-white text-black px-4 py-1.5 text-[9px] font-bold uppercase tracking-[0.2em] hover:bg-neutral-200 transition-all shadow-xl">
             <Icon name="close" size={10} className="rotate-45" />
             <span>Create Chat</span>
           </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden w-full max-w-full relative z-10 border-x border-white/5 bg-transparent">
        <div className="flex h-full w-full max-w-full overflow-hidden items-stretch justify-start">
          {panes.length === 0 ? (
            <div className="flex-1 flex items-center justify-center">
              <span className="font-serif text-3xl uppercase tracking-[0.5em] opacity-10">NO SESSIONS ACTIVE</span>
            </div>
          ) : (
            panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;
              const isLast = index === panes.length - 1;
              const anyExpanded = panes.some(p => p.isExpanded);
              if (anyExpanded && !pane.isExpanded) return null;
              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className="h-full flex flex-col glass-pane overflow-hidden transition-[flex] duration-300 ease-out"
                    style={{ flex: pane.isMinimized ? '0 0 40px' : (pane.isExpanded ? '1 1 100%' : `${pane.flex} 1 0%`), minWidth: pane.isMinimized ? '40px' : '0' }}
                  >
                    <TerminalPane file={file} width="100%" isActive={activePaneId === pane.id} isMinimized={pane.isMinimized} isExpanded={pane.isExpanded} onFocus={() => setActivePaneId(pane.id)} onSendMessage={handleSendMessage} onClose={() => handleClosePane(pane.id)} onMinimize={() => handleMinimizePane(pane.id)} onExpand={() => handleExpandPane(pane.id)} />
                  </div>
                  {!isLast && !pane.isMinimized && !pane.isExpanded && !anyExpanded && (
                    <div className="resizer-h shrink-0" onMouseDown={(e) => { e.preventDefault(); setIsResizing(index); }} />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </main>

      {showWiki && <WikiView onClose={() => setShowWiki(false)} />}
      {showNewModal && <NewPaneModal onClose={() => setShowNewModal(false)} onCreate={handleCreatePane} />}
      {showHelp && (
        <div className="absolute inset-0 z-[100] bg-black/70 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-[#0a0a0a] border border-neutral-800 p-8 w-full max-w-sm">
            <div className="flex justify-between items-center mb-10 border-b border-white/5 pb-4">
               <h3 className="font-serif text-lg tracking-widest uppercase text-white">Interface Commands</h3>
               <button onClick={() => setShowHelp(false)} className="text-neutral-400 hover:text-white"><Icon name="close" size={16}/></button>
            </div>
            <div className="space-y-5 font-mono text-[10px] uppercase tracking-[0.2em] text-neutral-300">
               <div className="flex justify-between items-center"><span>New Session</span><span className="shortcut-key">Shift + N</span></div>
               <div className="flex justify-between items-center"><span>Select Tab</span><span className="shortcut-key">Shift + [1-9]</span></div>
            </div>
          </div>
        </div>
      )}

      <footer className="h-10 bg-black/40 backdrop-blur-md border-t border-white/5 flex items-center justify-center px-8 z-50 shrink-0">
         <div className="text-[7px] sm:text-[9px] uppercase font-mono tracking-[0.3em] text-neutral-500 text-center">
            powered by <span className="text-white font-bold tracking-widest">REFLECTER SYSTEM UI</span> | 2026
         </div>
      </footer>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { ProjectFile } from '../types';
import Icon from './Icon';
import { DOCS_CONTENT, AVAILABLE_RESOURCES } from '../constants';

interface TerminalPaneProps {
  file: ProjectFile;
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (fileId: string, content: string) => void;
  onClose?: () => void;
  onMinimize?: () => void;
  onExpand?: () => void;
  isSystemView?: boolean;
  isMinimized?: boolean;
  isExpanded?: boolean;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  file, isActive, onFocus, width, onSendMessage, onClose, onMinimize, onExpand,
  isSystemView = false, isMinimized = false, isExpanded = false
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages, file.isThinking]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !file.isThinking) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  const handleResourceClick = (resId: string) => {
    // If resource is web-related or if we have a previewUrl, open it.
    if (file.previewUrl) {
      window.open(file.previewUrl, '_blank');
    } else {
      console.log(`Resource ${resId} clicked. No preview URL configured.`);
    }
  };

  if (isMinimized) {
    return (
      <div 
        onClick={onMinimize}
        className="h-full w-full flex flex-col items-center bg-black/70 border-r border-white/5 cursor-pointer hover:bg-black/90 transition-all pt-6 gap-8 overflow-hidden group shrink-0"
      >
        <div className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
        <span className="font-mono text-[7px] uppercase tracking-[0.2em] [writing-mode:vertical-lr] rotate-180 text-neutral-400 group-hover:text-neutral-200 transition-colors whitespace-nowrap">
          {file.name}
        </span>
      </div>
    );
  }

  const isDocs = file.id === 'docs';

  return (
    <div 
      onClick={onFocus}
      className={`h-full w-full flex flex-col overflow-hidden relative transition-all bg-transparent ${isActive ? 'z-10 shadow-2xl' : 'z-0'} min-w-0`}
    >
      {/* Header */}
      <div className={`flex bg-black/30 border-b border-white/5 h-10 select-none flex-shrink-0 items-center overflow-hidden transition-colors ${isActive ? 'bg-black/50' : ''}`}>
        <div className={`flex items-center gap-2 px-3 sm:px-4 text-[8px] sm:text-[9px] uppercase font-bold tracking-widest h-full border-r border-white/5 ${isActive ? 'text-white' : 'text-neutral-400'} min-w-0 flex-1`}>
          <div className={`flex-shrink-0 w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_8px_white]' : 'bg-neutral-800'}`}></div>
          <span className="truncate whitespace-nowrap overflow-hidden text-ellipsis">{file.name}</span>
        </div>

        <div className="flex items-center px-1 flex-shrink-0 gap-0.5 sm:gap-1">
           {!isSystemView && (
             <>
               <button onClick={(e) => { e.stopPropagation(); onMinimize?.(); }} className="text-neutral-500 hover:text-white transition-colors p-1.5" title="Minimize">
                 <Icon name="chevron-down" size={12} />
               </button>
               <button onClick={(e) => { e.stopPropagation(); onExpand?.(); }} className="text-neutral-500 hover:text-white transition-colors p-1.5" title={isExpanded ? "Restore" : "Expand"}>
                 <Icon name="play" size={10} className={isExpanded ? 'rotate-180' : '-rotate-90'} />
               </button>
               {onClose && (
                 <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="text-neutral-500 hover:text-red-400 transition-colors p-1.5" title="Close">
                   <Icon name="close" size={12} />
                 </button>
               )}
             </>
           )}
        </div>
      </div>

      {/* Content Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 sm:p-10 font-mono text-[11px] sm:text-[12px] leading-relaxed text-neutral-200 selection:bg-white selection:text-black scroll-smooth no-scrollbar min-w-0">
        {isDocs ? (
          <div className="whitespace-pre-wrap max-w-full mx-auto space-y-6">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <div key={i} className="text-white font-bold mb-8 uppercase tracking-[0.3em] font-serif text-2xl border-b border-white/10 pb-4 break-words">{line.replace('# ', '')}</div>;
              if (line.startsWith('■')) return <div key={i} className="bg-white/5 p-4 my-10 border-l-2 border-white flex items-center gap-4 text-white text-[10px] uppercase tracking-widest font-bold break-words">{line}</div>;
              if (line.startsWith('###')) return <div key={i} className="text-white font-bold mt-12 mb-6 uppercase tracking-widest text-[11px] border-white/20 border-b w-fit pr-6 break-words">{line.replace('### ', '')}</div>;
              return <div key={i} className="mb-3 text-neutral-300 break-words">{line}</div>;
            })}
          </div>
        ) : (
          <div className="space-y-10 max-w-full">
            {file.messages.map((msg, i) => (
              <div key={i} className="animate-in fade-in slide-in-from-left-2 duration-500 max-w-full overflow-hidden">
                <div className="mb-2 opacity-50">
                  <span className={`text-[7px] sm:text-[8px] font-bold uppercase tracking-[0.2em] ${msg.role === 'agent' ? 'text-neutral-200' : 'text-neutral-400'}`}>
                    {msg.role === 'agent' ? 'SERVER RESPONSE' : 'USER COMMAND'}
                  </span>
                </div>
                <div className={`text-[12px] tracking-wide break-words overflow-wrap-anywhere ${msg.role === 'agent' ? 'text-neutral-100 font-medium' : 'text-neutral-300 italic'}`} style={{ overflowWrap: 'anywhere' }}>
                  {msg.content}
                </div>
              </div>
            ))}
            {file.isThinking && (
              <div className="flex gap-2 items-center text-neutral-500 italic text-[10px] tracking-widest animate-pulse">
                <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
                AGENT_PROCESS_ACTIVE...
              </div>
            )}
          </div>
        )}
      </div>

      {/* Optimized Input & Metadata Stack (Two Rows) */}
      {!isDocs && !isSystemView && (
        <div className="px-4 sm:px-6 pb-6 shrink-0 min-w-0 animate-in slide-up duration-300 flex flex-col gap-0.5">
          {/* Row 1: Compact Metadata Bar */}
          <div className="flex items-center justify-between px-3 py-1.5 border border-white/5 bg-black/60 backdrop-blur-md rounded-t-sm">
            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2">
                <span className="text-[7px] font-mono text-neutral-500 uppercase tracking-widest">Agent</span>
                <span className="text-[9px] font-bold text-white uppercase tracking-wider">{file.agent || 'SYSTEM'}</span>
                <div className={`w-1.5 h-1.5 rounded-full ${file.isThinking ? 'bg-yellow-500 animate-spin' : 'bg-green-500/60 animate-pulse'}`}></div>
              </div>
              <div className="h-3 w-px bg-white/10 hidden sm:block"></div>
              <div className="flex items-center gap-2">
                <span className="text-[7px] font-mono text-neutral-500 uppercase tracking-widest">Links</span>
                <div className="flex gap-1">
                  {file.resources?.length ? file.resources.map(resId => {
                    const res = AVAILABLE_RESOURCES.find(r => r.id === resId);
                    return (
                      <button 
                        key={resId} 
                        title={`Open ${res?.name || 'Link'}`} 
                        onClick={() => handleResourceClick(resId)}
                        className="flex items-center px-1 py-0.5 bg-white/[0.03] border border-white/5 hover:bg-white/10 transition-colors"
                      >
                        <Icon name={res?.icon || 'tool'} size={8} className="text-neutral-400" />
                      </button>
                    );
                  }) : <span className="text-[8px] text-neutral-600 font-mono italic">No context links</span>}
                </div>
              </div>
            </div>
            <div className="text-[7px] font-mono text-neutral-600 uppercase tracking-widest hidden lg:block">
              Neural_Segment::{file.id.slice(-4).toUpperCase()}
            </div>
          </div>

          {/* Row 2: Full-Width Command Input */}
          <form onSubmit={handleSubmit} className="flex h-11 items-center bg-black/40 border border-white/10 px-4 focus-within:border-white/30 transition-all shadow-xl backdrop-blur-md overflow-hidden rounded-b-sm">
            <span className="text-white/20 mr-3 text-[10px] font-mono font-bold select-none uppercase">{'>'}</span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              disabled={file.isThinking}
              placeholder={file.isThinking ? "AWAITING_AGENT_FLUSH..." : "INITIALIZE_PROTOCOL..."}
              className="bg-transparent border-none outline-none flex-1 text-[11px] font-mono text-white command-input min-w-0 placeholder:opacity-20 disabled:opacity-50"
              autoFocus={isActive}
            />
          </form>
        </div>
      )}
    </div>
  );
};

