        <div className="pt-4 border-t border-black/5 dark:border-neutral-800 flex items-center justify-between">
          <input 
            type="text" 
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="bg-transparent border-b border-black/10 dark:border-neutral-800 focus:border-black dark:focus:border-white text-xs font-mono text-black dark:text-white py-1 outline-none w-1/3"
            placeholder="Identifier"
          />
          <button 
            onClick={() => onCreate({ agent: selectedAgent, resources: selectedResources, name, previewUrl })}
            className="bg-black dark:bg-white text-white dark:text-black px-8 py-3 text-[10px] font-serif uppercase tracking-[0.3em] font-bold hover:opacity-80 transition-all"
          >
            Invoke Sanctum
          </button>
        </div>
      </div>
    </div>
  );
};

