import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { ProjectFile, FileType, Organization, Project, CodeSpace } from './types';
import { INITIAL_FILES, INITIAL_ORG } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';
import WikiView from './components/WikiView';
import NewPaneModal from './components/NewPaneModal';
import { GoogleGenAI } from "@google/genai";

export default function App() {
  const [org, setOrg] = useState<Organization>(INITIAL_ORG);
  const [activeProjectId, setActiveProjectId] = useState('proj-1');
  const [activeCodeSpaceId, setActiveCodeSpaceId] = useState('cs-1');
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);

  const [showWiki, setShowWiki] = useState(false);
  const [showHelp, setShowHelp] = useState(false);
  const [showNewModal, setShowNewModal] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isResizing, setIsResizing] = useState<number | null>(null);

  const activeProject = useMemo(() => org.projects.find(p => p.id === activeProjectId)!, [org, activeProjectId]);
  const activeCodeSpace = useMemo(() => activeProject.codeSpaces.find(cs => cs.id === activeCodeSpaceId)!, [activeProject, activeCodeSpaceId]);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
      document.documentElement.classList.add('light');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleCreatePane = useCallback((config: { agent: string; resources: string[]; name: string; previewUrl: string }) => {
    const newId = `chat-${Date.now()}`;
    const newFile: ProjectFile = {
      id: newId,
      name: config.name || `Session ${activeCodeSpace.panes.length + 1}`,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: config.agent,
      resources: config.resources,
      previewUrl: config.previewUrl,
      messages: [
        { role: 'agent', content: `Environment Ready. Organization: ${org.name}. Project: ${activeProject.name}. CodeSpace: ${activeCodeSpace.name}. Linked to ${config.agent}.`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);

    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          panes: cs.panes.map(pane => ({ ...pane, isExpanded: false })).concat([{ id: newId, flex: 1, isMinimized: false, isExpanded: false }]),
          fileIds: [...cs.fileIds, newId]
        } : cs)
      } : p)
    }));

    setShowNewModal(false);
  }, [org.name, activeProject.name, activeCodeSpace.name, activeCodeSpace.panes.length, activeProjectId, activeCodeSpaceId]);

  const handleSendMessage = async (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    const targetFile = files.find(f => f.id === fileId);
    if (!targetFile) return;

    setFiles(prev => prev.map(f => f.id === fileId ? { ...f, isThinking: true, messages: [...f.messages, { role: 'user', content, timestamp }] } : f));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const history = targetFile.messages.slice(-8).map(m => `${m.role === 'agent' ? 'Assistant' : 'User'}: ${m.content}`).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a high-performance orchestration agent named ${targetFile.agent || 'Reflecter'}. 
        User Environment: ${org.name} / ${activeProject.name} / ${activeCodeSpace.name}.
        Task: ${content}
        History: ${history}
        Maintain professional technical excellence. Format using Markdown.`,
      });

      const aiText = response.text || "Operational fault: neural bridge failed.";

      setFiles(prev => prev.map(f => f.id === fileId ? {
        ...f,
        isThinking: false,
        messages: [...f.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5) }]
      } : f));
    } catch (error) {
      setFiles(prev => prev.map(f => f.id === fileId ? { ...f, isThinking: false, messages: [...f.messages, { role: 'agent', content: "CRITICAL_FAILURE: Neural disconnect.", timestamp }] } : f));
    }
  };

  const handleClosePane = (id: string) => {
    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          panes: cs.panes.filter(pane => pane.id !== id)
        } : cs)
      } : p)
    }));
  };

  const updatePaneState = (id: string, updates: Partial<{ flex: number; isMinimized: boolean; isExpanded: boolean }>) => {
    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          panes: cs.panes.map(pane => pane.id === id ? { ...pane, ...updates } : (updates.isExpanded ? { ...pane, isExpanded: false } : pane))
        } : cs)
      } : p)
    }));
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setOrg(prev => {
        const next = { ...prev };
        const project = next.projects.find(p => p.id === activeProjectId)!;
        const codeSpace = project.codeSpaces.find(cs => cs.id === activeCodeSpaceId)!;
        const leftPane = codeSpace.panes[isResizing];
        const rightPane = codeSpace.panes[isResizing + 1];
        if (leftPane && rightPane && !leftPane.isMinimized && !rightPane.isMinimized) {
          const factor = 0.002;
          leftPane.flex = Math.max(0.1, leftPane.flex + (delta * factor));
          rightPane.flex = Math.max(0.1, rightPane.flex - (delta * factor));
        }
        return next;
      });
    }
  }, [isResizing, activeProjectId, activeCodeSpaceId]);

  const handleMouseUp = useCallback(() => setIsResizing(null), []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  return (
    <div className="h-screen w-screen flex flex-col bg-transparent overflow-hidden font-inter text-black dark:text-neutral-200 relative">
      {/* Hierarchical Header */}
      <header className="h-20 border-b border-black/5 dark:border-white/5 bg-white/50 dark:bg-black/50 backdrop-blur-2xl flex items-center justify-between px-10 z-50 shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-4 group cursor-pointer">
            <span className="font-serif font-bold text-2xl tracking-[0.4em] text-black dark:text-white uppercase">REFLECTER</span>
          </div>

          <div className="h-8 w-px bg-black/5 dark:bg-white/5 hidden md:block"></div>

          {/* Breadcrumb Navigation */}
          <div className="hidden md:flex items-center gap-3 text-[10px] uppercase font-bold tracking-[0.2em] text-neutral-400">
             <button className="hover:text-black dark:hover:text-white transition-colors">{org.name}</button>
             <span>/</span>
             <button className="hover:text-black dark:hover:text-white transition-colors text-black dark:text-white underline decoration-black/20 underline-offset-4">{activeProject.name}</button>
             <span>/</span>
             <div className="flex items-center gap-2 px-3 py-1 bg-black/[0.03] dark:bg-white/[0.03] border border-black/5 dark:border-white/5 rounded-full text-black dark:text-white">
                <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                {activeCodeSpace.name}
             </div>
          </div>
        </div>

        <nav className="hidden xl:flex items-center gap-8 text-[10px] uppercase font-bold tracking-[0.2em] text-neutral-400">
          <button onClick={() => setShowWiki(false)} className={`transition-all ${!showWiki ? 'text-black dark:text-white' : ''}`}>Dashboard</button>
          <button onClick={() => setShowWiki(true)} className={`transition-all ${showWiki ? 'text-black dark:text-white' : ''}`}>Manual</button>
        </nav>

        <div className="flex items-center gap-6">
           <button onClick={toggleTheme} className="w-10 h-10 flex items-center justify-center rounded-full text-neutral-400 hover:bg-black/5 dark:hover:bg-white/5 transition-all">
             <Icon name={isDarkMode ? 'action' : 'security'} size={18} />
           </button>
           <button onClick={() => setShowNewModal(true)} className="flex items-center gap-3 bg-black dark:bg-white text-white dark:text-black px-6 py-3 rounded-full text-[10px] font-bold uppercase tracking-[0.2em] hover:scale-105 active:scale-95 transition-all shadow-xl">
             <Icon name="close" size={12} className="rotate-45" />
             <span>Deploy Session</span>
           </button>
        </div>
      </header>

      <main className="flex-1 p-4 overflow-hidden w-full max-w-full relative z-10 flex items-stretch">
        <div className="flex h-full w-full max-w-full overflow-hidden items-stretch gap-2">
          {activeCodeSpace.panes.length === 0 ? (
            <div className="flex-1 flex flex-col items-center justify-center gap-8">
              <span className="font-serif text-5xl uppercase tracking-[0.5em] opacity-5 text-black dark:text-white">CODESPACE_EMPTY</span>
              <button onClick={() => setShowNewModal(true)} className="px-10 py-5 border border-black/10 dark:border-white/10 rounded-full text-[11px] font-bold uppercase tracking-[0.4em] hover:bg-black hover:text-white transition-all">Deploy New CodeSpace Agent</button>
            </div>
          ) : (
            activeCodeSpace.panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;
              const isLast = index === activeCodeSpace.panes.length - 1;
              const anyExpanded = activeCodeSpace.panes.some(p => p.isExpanded);
              if (anyExpanded && !pane.isExpanded) return null;
              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className="h-full flex flex-col transition-[flex] duration-500 ease-in-out"
                    style={{ flex: pane.isMinimized ? '0 0 60px' : (pane.isExpanded ? '1 1 100%' : `${pane.flex} 1 0%`), minWidth: pane.isMinimized ? '60px' : '0' }}
                  >
                    <TerminalPane 
                      file={file} 
                      width="100%" 
                      isActive={true} 
                      isMinimized={pane.isMinimized} 
                      isExpanded={pane.isExpanded} 
                      onFocus={() => {}} 
                      onSendMessage={handleSendMessage} 
                      onClose={() => handleClosePane(pane.id)} 
                      onMinimize={() => updatePaneState(pane.id, { isMinimized: !pane.isMinimized, isExpanded: false })} 
                      onExpand={() => updatePaneState(pane.id, { isExpanded: !pane.isExpanded, isMinimized: false })} 
                    />
                  </div>
                  {!isLast && !pane.isMinimized && !pane.isExpanded && !anyExpanded && (
                    <div className="resizer-h shrink-0" onMouseDown={(e) => { e.preventDefault(); setIsResizing(index); }} />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </main>

      {showWiki && <WikiView onClose={() => setShowWiki(false)} />}
      {showNewModal && <NewPaneModal onClose={() => setShowNewModal(false)} onCreate={handleCreatePane} />}

      <footer className="h-12 bg-transparent flex items-center justify-between px-10 z-50 shrink-0 border-t border-black/5 dark:border-white/5 backdrop-blur-md">
         <div className="text-[9px] uppercase font-bold tracking-[0.5em] text-neutral-400">
            Node: REFLECTER_OS_PRO • Deployment v4.2.1
         </div>
         <div className="flex items-center gap-8 text-[9px] uppercase font-bold tracking-[0.5em] text-neutral-400">
            <span>Latency: 24ms</span>
            <div className="w-1.5 h-1.5 rounded-full bg-green-500"></div>
            <span>Uptime: 99.99%</span>
         </div>
      </footer>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { ProjectFile } from '../types';
import Icon from './Icon';
import { DOCS_CONTENT, AVAILABLE_RESOURCES } from '../constants';

interface TerminalPaneProps {
  file: ProjectFile;
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (fileId: string, content: string) => void;
  onClose?: () => void;
  onMinimize?: () => void;
  onExpand?: () => void;
  isSystemView?: boolean;
  isMinimized?: boolean;
  isExpanded?: boolean;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  file, isActive, onFocus, width, onSendMessage, onClose, onMinimize, onExpand,
  isSystemView = false, isMinimized = false, isExpanded = false
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages, file.isThinking]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !file.isThinking) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  const handleResourceClick = (resId: string) => {
    if (file.previewUrl) {
      window.open(file.previewUrl, '_blank');
    }
  };

  if (isMinimized) {
    return (
      <div 
        onClick={onMinimize}
        className="h-full w-full flex flex-col items-center bg-black/5 dark:bg-black/40 border-r border-black/5 dark:border-white/5 cursor-pointer hover:bg-black/10 transition-all pt-8 gap-10 overflow-hidden group shrink-0"
      >
        <div className={`w-2 h-2 rounded-full flex-shrink-0 ${isActive ? 'bg-black dark:bg-white' : 'bg-neutral-200 dark:bg-neutral-800'}`}></div>
        <span className="font-serif text-[10px] font-bold uppercase tracking-[0.4em] [writing-mode:vertical-lr] rotate-180 text-neutral-400 group-hover:text-black dark:group-hover:text-white transition-colors whitespace-nowrap">
          {file.name}
        </span>
      </div>
    );
  }

  const isDocs = file.id === 'docs';

  return (
    <div 
      onClick={onFocus}
      className={`h-full w-full flex flex-col overflow-hidden relative transition-all rounded-xl m-1 glass-pane ${isActive ? 'z-10 ring-2 ring-black/5 dark:ring-white/10 shadow-2xl' : 'z-0'} min-w-0`}
    >
      {/* CodeSpace Context Header */}
      <div className={`flex items-center justify-between h-14 px-5 border-b border-black/5 dark:border-white/5 bg-white/40 dark:bg-black/40 backdrop-blur-xl shrink-0 transition-colors ${isActive ? 'bg-white/60 dark:bg-black/60' : ''}`}>
        <div className="flex items-center gap-3 min-w-0 flex-1">
          <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-black dark:bg-white animate-pulse' : 'bg-neutral-300 dark:bg-neutral-800'}`}></div>
          <div className="flex flex-col truncate">
            <span className={`text-[11px] font-serif font-bold uppercase tracking-widest truncate ${isActive ? 'text-black dark:text-white' : 'text-neutral-500'}`}>{file.name}</span>
            <span className="text-[9px] text-neutral-400 font-medium uppercase tracking-tighter">CodeSpace Instance Active</span>
          </div>
        </div>

        <div className="flex items-center gap-1">
           {!isSystemView && (
             <>
               <button onClick={(e) => { e.stopPropagation(); onMinimize?.(); }} className="text-neutral-400 hover:text-black dark:hover:text-white p-2 transition-all" title="Minimize">
                 <Icon name="chevron-down" size={14} />
               </button>
               <button onClick={(e) => { e.stopPropagation(); onExpand?.(); }} className="text-neutral-400 hover:text-black dark:hover:text-white p-2 transition-all" title={isExpanded ? "Collapse" : "Expand"}>
                 <Icon name="play" size={12} className={isExpanded ? 'rotate-180' : '-rotate-90'} />
               </button>
               {onClose && (
                 <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="text-neutral-400 hover:text-red-500 p-2 transition-all" title="Close Session">
                   <Icon name="close" size={14} />
                 </button>
               )}
             </>
           )}
        </div>
      </div>

      {/* Modern Chat Content */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 sm:p-10 scroll-smooth no-scrollbar min-w-0 bg-transparent">
        {isDocs ? (
          <div className="whitespace-pre-wrap max-w-2xl mx-auto space-y-8 font-inter text-[14px]">
            {DOCS_CONTENT.split('\n').map((line, i) => {
              if (line.startsWith('#')) return <h1 key={i} className="text-black dark:text-white font-serif text-3xl font-bold mb-10 border-b border-black/5 pb-4">{line.replace('# ', '')}</h1>;
              if (line.startsWith('■')) return <div key={i} className="bg-black/5 dark:bg-white/5 p-6 rounded-xl border-l-4 border-black dark:border-white font-bold tracking-wide">{line}</div>;
              if (line.startsWith('###')) return <h3 key={i} className="text-black dark:text-white font-bold text-lg mt-12 mb-4">{line.replace('### ', '')}</h3>;
              return <p key={i} className="text-neutral-600 dark:text-neutral-400 leading-relaxed">{line}</p>;
            })}
          </div>
        ) : (
          <div className="space-y-8 max-w-3xl mx-auto">
            {file.messages.map((msg, i) => (
              <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-500`}>
                <div className={`max-w-[85%] rounded-2xl px-5 py-4 text-[13px] leading-relaxed ${
                  msg.role === 'user' 
                  ? 'bg-black dark:bg-white text-white dark:text-black shadow-lg' 
                  : 'bg-black/5 dark:bg-white/5 text-neutral-800 dark:text-neutral-200'
                }`}>
                  {msg.content}
                </div>
                <span className="text-[8px] uppercase font-bold tracking-widest mt-2 text-neutral-400 px-1">
                  {msg.role === 'agent' ? `${file.agent} • ${msg.timestamp}` : `Authorized User • ${msg.timestamp}`}
                </span>
              </div>
            ))}
            {file.isThinking && (
              <div className="flex items-center gap-3 text-neutral-400 text-[11px] font-medium tracking-wide animate-pulse ml-1">
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-neutral-300 dark:bg-neutral-600 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                  <div className="w-1.5 h-1.5 bg-neutral-300 dark:bg-neutral-600 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                  <div className="w-1.5 h-1.5 bg-neutral-300 dark:bg-neutral-600 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
                </div>
                <span>Syncing Neural Link...</span>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Production Input Area */}
      {!isDocs && !isSystemView && (
        <div className="px-6 pb-8 shrink-0 min-w-0 animate-in slide-up duration-500">
          <div className="max-w-3xl mx-auto flex flex-col gap-3">
            <div className="flex items-center justify-between px-2">
              <div className="flex items-center gap-6">
                 <div className="flex items-center gap-2">
                    <span className="text-[8px] font-bold text-neutral-400 uppercase tracking-widest">Runtime</span>
                    <span className="text-[10px] font-bold text-black dark:text-white uppercase tracking-tight">{file.agent}</span>
                 </div>
                 <div className="flex items-center gap-3">
                    <span className="text-[8px] font-bold text-neutral-400 uppercase tracking-widest">MCP Uplinks</span>
                    <div className="flex gap-1.5">
                      {file.resources?.map(resId => {
                        const res = AVAILABLE_RESOURCES.find(r => r.id === resId);
                        return (
                          <button 
                            key={resId} 
                            onClick={() => handleResourceClick(resId)}
                            className="w-6 h-6 flex items-center justify-center bg-black/5 dark:bg-white/5 rounded-full hover:bg-black dark:hover:bg-white hover:text-white dark:hover:text-black transition-all shadow-sm"
                            title={`Open Linked ${res?.name}`}
                          >
                            <Icon name={res?.icon || 'tool'} size={10} />
                          </button>
                        );
                      })}
                    </div>
                 </div>
              </div>
              {file.previewUrl && (
                <button 
                  onClick={() => window.open(file.previewUrl, '_blank')}
                  className="flex items-center gap-1.5 text-[9px] font-bold text-neutral-400 hover:text-black dark:hover:text-white uppercase tracking-widest transition-colors border-b border-transparent hover:border-current"
                >
                  <Icon name="action" size={10} />
                  Open Live Preview
                </button>
              )}
            </div>

            <form onSubmit={handleSubmit} className="flex gap-2 items-center bg-white dark:bg-black/60 border border-black/5 dark:border-white/10 p-2 rounded-2xl shadow-xl focus-within:ring-4 ring-black/5 dark:ring-white/5 transition-all">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                disabled={file.isThinking}
                placeholder={file.isThinking ? "Awaiting neural feedback..." : "Input command for CodeSpace agent..."}
                className="bg-transparent border-none outline-none flex-1 px-4 text-[14px] text-black dark:text-white placeholder:text-neutral-300 dark:placeholder:text-neutral-700 font-inter py-2 disabled:opacity-50"
                autoFocus={isActive}
              />
              <button 
                type="submit" 
                disabled={!input.trim() || file.isThinking}
                className="w-10 h-10 flex items-center justify-center bg-black dark:bg-white text-white dark:text-black rounded-xl hover:scale-105 active:scale-95 disabled:opacity-20 disabled:scale-100 transition-all shadow-lg"
              >
                <Icon name="play" size={14} />
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TerminalPane;

