import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { ProjectFile, FileType, Organization, Project, CodeSpace } from './types';
import { INITIAL_FILES, INITIAL_ORG } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';
import WikiView from './components/WikiView';
import NewPaneModal from './components/NewPaneModal';
import LandingView from './components/LandingView';
import { GoogleGenAI } from "@google/genai";

export default function App() {
  const [hasStarted, setHasStarted] = useState(false);
  const [org, setOrg] = useState<Organization>(INITIAL_ORG);
  const [activeProjectId, setActiveProjectId] = useState('proj-1');
  const [activeCodeSpaceId, setActiveCodeSpaceId] = useState('cs-1');
  const [files, setFiles] = useState<ProjectFile[]>(INITIAL_FILES);

  const [showWiki, setShowWiki] = useState(false);
  const [showHelp, setShowHelp] = useState(false);
  const [showNewModal, setShowNewModal] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isResizing, setIsResizing] = useState<number | null>(null);

  const activeProject = useMemo(() => 
    org.projects.find(p => p.id === activeProjectId) || org.projects[0]
  , [org, activeProjectId]);

  const activeCodeSpace = useMemo(() => 
    activeProject.codeSpaces.find(cs => cs.id === activeCodeSpaceId) || activeProject.codeSpaces[0]
  , [activeProject, activeCodeSpaceId]);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
      document.documentElement.classList.add('light');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleCreatePane = useCallback((config: { agent: string; resources: string[]; name: string; previewUrl: string }) => {
    const newId = `chat-${Date.now()}`;
    const newFile: ProjectFile = {
      id: newId,
      name: config.name || `Session ${activeCodeSpace.panes.length + 1}`,
      type: FileType.CHAT,
      content: '',
      isOpen: true,
      agent: config.agent,
      resources: config.resources,
      previewUrl: config.previewUrl,
      messages: [
        { role: 'agent', content: `Environment Ready. Organization: ${org.name}. Project: ${activeProject.name}. CodeSpace: ${activeCodeSpace.name}. Linked to ${config.agent}. How can I assist with your orchestration today?`, timestamp: '--:--' }
      ]
    };

    setFiles(prev => [...prev, newFile]);

    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          panes: cs.panes.map(pane => ({ ...pane, isExpanded: false })).concat([{ id: newId, flex: 1, isMinimized: false, isExpanded: false }]),
          fileIds: [...cs.fileIds, newId]
        } : cs)
      } : p)
    }));

    setShowNewModal(false);
  }, [org.name, activeProject.name, activeCodeSpace.name, activeCodeSpace.panes.length, activeProjectId, activeCodeSpaceId]);

  const handleSendMessage = async (fileId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);
    const targetFile = files.find(f => f.id === fileId);
    if (!targetFile) return;

    setFiles(prev => prev.map(f => f.id === fileId ? { ...f, isThinking: true, messages: [...f.messages, { role: 'user', content, timestamp }] } : f));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const history = targetFile.messages.slice(-8).map(m => `${m.role === 'agent' ? 'Assistant' : 'User'}: ${m.content}`).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a high-performance orchestration agent named ${targetFile.agent || 'Reflecter'}. 
        User Environment: ${org.name} / ${activeProject.name} / ${activeCodeSpace.name}.
        Current Message: ${content}
        Context History:
        ${history}

        Maintain professional technical excellence. Respond in clean Markdown. Keep it user-friendly but robust.`,
      });

      const aiText = response.text || "Operational fault: neural bridge failed. Please retry initialization.";

      setFiles(prev => prev.map(f => f.id === fileId ? {
        ...f,
        isThinking: false,
        messages: [...f.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5) }]
      } : f));
    } catch (error) {
      setFiles(prev => prev.map(f => f.id === fileId ? { ...f, isThinking: false, messages: [...f.messages, { role: 'agent', content: "CRITICAL_FAILURE: Neural disconnect. Check system logs.", timestamp }] } : f));
    }
  };

  const handleClosePane = (id: string) => {
    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          panes: cs.panes.filter(pane => pane.id !== id)
        } : cs)
      } : p)
    }));
  };

  const updatePaneState = (id: string, updates: Partial<{ flex: number; isMinimized: boolean; isExpanded: boolean }>) => {
    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          panes: cs.panes.map(pane => pane.id === id ? { ...pane, ...updates } : (updates.isExpanded ? { ...pane, isExpanded: false } : pane))
        } : cs)
      } : p)
    }));
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing !== null) {
      const delta = e.movementX;
      setOrg(prev => {
        const next = { ...prev };
        const project = next.projects.find(p => p.id === activeProjectId)!;
        const codeSpace = project.codeSpaces.find(cs => cs.id === activeCodeSpaceId)!;
        const leftPane = codeSpace.panes[isResizing];
        const rightPane = codeSpace.panes[isResizing + 1];
        if (leftPane && rightPane && !leftPane.isMinimized && !rightPane.isMinimized) {
          const factor = 0.002;
          leftPane.flex = Math.max(0.1, leftPane.flex + (delta * factor));
          rightPane.flex = Math.max(0.1, rightPane.flex - (delta * factor));
        }
        return next;
      });
    }
  }, [isResizing, activeProjectId, activeCodeSpaceId]);

  const handleMouseUp = useCallback(() => setIsResizing(null), []);

  useEffect(() => {
    if (isResizing !== null) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing, handleMouseMove, handleMouseUp]);

  if (!hasStarted) {
    return <LandingView onEnterIDE={() => setHasStarted(true)} />;
  }

  return (
    <div className="h-screen w-screen flex flex-col bg-[#fdfdfd] dark:bg-[#0a0a0a] overflow-hidden font-inter text-black dark:text-neutral-200 relative">
      {/* Hierarchical Header */}
      <header className="h-20 border-b border-black/5 dark:border-white/5 bg-white/50 dark:bg-black/50 backdrop-blur-2xl flex items-center justify-between px-10 z-50 shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-4 group cursor-pointer" onClick={() => setHasStarted(false)}>
            <span className="font-serif font-bold text-2xl tracking-[0.4em] text-black dark:text-white uppercase">REFLECTER</span>
          </div>

          <div className="h-8 w-px bg-black/5 dark:bg-white/5 hidden md:block"></div>

          {/* Breadcrumb Navigation - Production Model */}
          <div className="hidden md:flex items-center gap-3 text-[10px] uppercase font-bold tracking-[0.2em] text-neutral-400">
             <button className="hover:text-black dark:hover:text-white transition-colors">{org.name}</button>
             <span>/</span>
             <div className="relative group/proj">
                <button className="hover:text-black dark:hover:text-white transition-colors text-black dark:text-white underline decoration-black/20 underline-offset-4 font-bold">
                  {activeProject.name}
                </button>
                <div className="absolute top-full left-0 mt-2 w-48 bg-white dark:bg-neutral-900 border border-black/10 dark:border-white/10 rounded-xl shadow-2xl opacity-0 invisible group-hover/proj:opacity-100 group-hover/proj:visible transition-all p-2 z-[60]">
                  {org.projects.map(p => (
                    <button 
                      key={p.id} 
                      onClick={() => setActiveProjectId(p.id)}
                      className="w-full text-left px-4 py-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-lg text-[9px] uppercase tracking-widest font-bold"
                    >
                      {p.name}
                    </button>
                  ))}
                </div>
             </div>
             <span>/</span>
             <div className="relative group/cs">
                <div className="flex items-center gap-2 px-3 py-1 bg-black/[0.03] dark:bg-white/[0.03] border border-black/5 dark:border-white/5 rounded-full text-black dark:text-white cursor-pointer hover:border-black/20 transition-all">
                  <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                  {activeCodeSpace.name}
                </div>
                <div className="absolute top-full left-0 mt-2 w-48 bg-white dark:bg-neutral-900 border border-black/10 dark:border-white/10 rounded-xl shadow-2xl opacity-0 invisible group-hover/cs:opacity-100 group-hover/cs:visible transition-all p-2 z-[60]">
                  {activeProject.codeSpaces.map(cs => (
                    <button 
                      key={cs.id} 
                      onClick={() => setActiveCodeSpaceId(cs.id)}
                      className="w-full text-left px-4 py-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-lg text-[9px] uppercase tracking-widest font-bold"
                    >
                      {cs.name}
                    </button>
                  ))}
                </div>
             </div>
          </div>
        </div>

        <nav className="hidden xl:flex items-center gap-8 text-[10px] uppercase font-bold tracking-[0.2em] text-neutral-400">
          <button onClick={() => setShowWiki(false)} className={`transition-all hover:text-black dark:hover:text-white ${!showWiki ? 'text-black dark:text-white border-b-2 border-black dark:border-white pb-1' : ''}`}>Workspace</button>
          <button onClick={() => setShowWiki(true)} className={`transition-all hover:text-black dark:hover:text-white ${showWiki ? 'text-black dark:text-white border-b-2 border-black dark:border-white pb-1' : ''}`}>Protocol Manual</button>
        </nav>

        <div className="flex items-center gap-6">
           <button onClick={toggleTheme} className="w-10 h-10 flex items-center justify-center rounded-full text-neutral-400 hover:bg-black/5 dark:hover:bg-white/5 transition-all shadow-sm border border-black/5 dark:border-white/5">
             <Icon name={isDarkMode ? 'action' : 'security'} size={18} />
           </button>
           <button onClick={() => setShowNewModal(true)} className="flex items-center gap-3 bg-black dark:bg-white text-white dark:text-black px-6 py-3 rounded-full text-[10px] font-bold uppercase tracking-[0.2em] hover:scale-105 active:scale-95 transition-all shadow-xl">
             <Icon name="close" size={12} className="rotate-45" />
             <span>Deploy Session</span>
           </button>
        </div>
      </header>

      <main className="flex-1 p-4 overflow-hidden w-full max-w-full relative z-10 flex items-stretch bg-neutral-50/30 dark:bg-neutral-950/30">
        <div className="flex h-full w-full max-w-full overflow-hidden items-stretch gap-3">
          {activeCodeSpace.panes.length === 0 ? (
            <div className="flex-1 flex flex-col items-center justify-center gap-10 animate-in fade-in zoom-in-95 duration-700">
              <div className="w-32 h-32 border-2 border-black/5 dark:border-white/5 flex items-center justify-center rounded-full">
                <Icon name="terminal" size={48} className="opacity-10" />
              </div>
              <div className="text-center space-y-4">
                <span className="font-serif text-5xl uppercase tracking-[0.5em] opacity-5 text-black dark:text-white block">CODESPACE_EMPTY</span>
                <p className="text-[10px] uppercase font-bold tracking-[0.4em] text-neutral-400">Provision a new agent to begin orchestration</p>
              </div>
              <button onClick={() => setShowNewModal(true)} className="px-12 py-5 bg-black dark:bg-white text-white dark:text-black rounded-full text-[11px] font-bold uppercase tracking-[0.4em] hover:scale-105 active:scale-95 transition-all shadow-2xl">
                Deploy CodeSpace Agent
              </button>
            </div>
          ) : (
            activeCodeSpace.panes.map((pane, index) => {
              const file = files.find(f => f.id === pane.id);
              if (!file) return null;
              const isLast = index === activeCodeSpace.panes.length - 1;
              const anyExpanded = activeCodeSpace.panes.some(p => p.isExpanded);
              if (anyExpanded && !pane.isExpanded) return null;
              return (
                <React.Fragment key={pane.id}>
                  <div 
                    className="h-full flex flex-col transition-[flex] duration-500 ease-in-out"
                    style={{ flex: pane.isMinimized ? '0 0 70px' : (pane.isExpanded ? '1 1 100%' : `${pane.flex} 1 0%`), minWidth: pane.isMinimized ? '70px' : '0' }}
                  >
                    <TerminalPane 
                      file={file} 
                      width="100%" 
                      isActive={true} 
                      isMinimized={pane.isMinimized} 
                      isExpanded={pane.isExpanded} 
                      onFocus={() => {}} 
                      onSendMessage={handleSendMessage} 
                      onClose={() => handleClosePane(pane.id)} 
                      onMinimize={() => updatePaneState(pane.id, { isMinimized: !pane.isMinimized, isExpanded: false })} 
                      onExpand={() => updatePaneState(pane.id, { isExpanded: !pane.isExpanded, isMinimized: false })} 
                    />
                  </div>
                  {!isLast && !pane.isMinimized && !pane.isExpanded && !anyExpanded && (
                    <div className="resizer-h shrink-0" onMouseDown={(e) => { e.preventDefault(); setIsResizing(index); }} />
                  )}
                </React.Fragment>
              );
            })
          )}
        </div>
      </main>

      {showWiki && <WikiView onClose={() => setShowWiki(false)} />}
      {showNewModal && <NewPaneModal onClose={() => setShowNewModal(false)} onCreate={handleCreatePane} />}

      <footer className="h-12 bg-white/80 dark:bg-black/80 flex items-center justify-between px-10 z-50 shrink-0 border-t border-black/5 dark:border-white/5 backdrop-blur-md">
         <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
               <div className="w-1.5 h-1.5 rounded-full bg-green-500"></div>
               <span className="text-[9px] uppercase font-bold tracking-[0.4em] text-neutral-400">System Ready</span>
            </div>
            <div className="h-3 w-px bg-black/10 dark:bg-white/10"></div>
            <div className="text-[9px] uppercase font-bold tracking-[0.4em] text-neutral-400">
               Node: REF_PRO_v4.2.1 • Latency: 18ms
            </div>
         </div>
         <div className="text-[9px] uppercase font-bold tracking-[0.6em] text-neutral-300 dark:text-neutral-700 select-none">
            REFLECTER SECURE INFRASTRUCTURE
         </div>
      </footer>
    </div>
  );
}

