import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { AgentInstance, User, Organization, Project, CodeSpace } from './types';
import { INITIAL_ORG, COMPUTE_OPTIONS } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';
import WikiView from './components/WikiView';
import DeployModal from './components/DeployModal';
import LandingView from './components/LandingView';
import LoginView from './components/LoginView';
import { GoogleGenAI } from "@google/genai";

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [hasStarted, setHasStarted] = useState(false);
  const [org, setOrg] = useState<Organization>(INITIAL_ORG);
  const [activeProjectId, setActiveProjectId] = useState('proj-1');
  const [activeCodeSpaceId, setActiveCodeSpaceId] = useState('cs-1');

  const [showWiki, setShowWiki] = useState(false);
  const [showDeployModal, setShowDeployModal] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [activePaneId, setActivePaneId] = useState<string | null>(null);

  const activeProject = useMemo(() => 
    org.projects.find(p => p.id === activeProjectId) || org.projects[0]
  , [org, activeProjectId]);

  const activeCodeSpace = useMemo(() => 
    activeProject.codeSpaces.find(cs => cs.id === activeCodeSpaceId) || activeProject.codeSpaces[0]
  , [activeProject, activeCodeSpaceId]);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
      document.documentElement.classList.add('light');
    }
  }, [isDarkMode]);

  const handleLogin = (mockUser: User) => setUser(mockUser);
  const handleLogout = () => {
    setUser(null);
    setHasStarted(false);
  };

  const handleDeployAgents = useCallback((config: { type: string; compute: string; quantity: number; namePrefix: string }) => {
    const newInstances: AgentInstance[] = Array.from({ length: config.quantity }).map((_, i) => ({
      id: `agent-${Date.now()}-${i}`,
      name: `${config.namePrefix} ${i + 1}`,
      type: config.type,
      compute: config.compute as any,
      status: 'running',
      messages: [
        { role: 'agent', content: `Instance deployed. System: ${config.compute} Compute. Type: ${config.type}. Status: Online.`, timestamp: new Date().toLocaleTimeString().slice(0, 5) }
      ]
    }));

    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: [...cs.instances, ...newInstances]
        } : cs)
      } : p)
    }));

    setShowDeployModal(false);
    if (newInstances.length > 0) setActivePaneId(newInstances[0].id);
  }, [activeProjectId, activeCodeSpaceId]);

  const handleKillAgent = (agentId: string) => {
    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: cs.instances.filter(a => a.id !== agentId)
        } : cs)
      } : p)
    }));
    if (activePaneId === agentId) setActivePaneId(null);
  };

  const handleSendMessage = async (agentId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);

    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: cs.instances.map(a => a.id === agentId ? {
            ...a,
            isThinking: true,
            messages: [...a.messages, { role: 'user', content, timestamp }]
          } : a)
        } : cs)
      } : p)
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const agent = activeCodeSpace.instances.find(a => a.id === agentId)!;
      const history = agent.messages.slice(-6).map(m => `${m.role === 'agent' ? 'Agent' : 'User'}: ${m.content}`).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a professional assistant agent named ${agent.name}. 
        Deployment Info: ${agent.type} model on ${agent.compute} compute.
        User request: ${content}
        History: ${history}
        Be precise and helpful. Respond in Markdown.`,
      });

      const aiText = response.text || "Connection to agent compute was lost.";

      setOrg(prev => ({
        ...prev,
        projects: prev.projects.map(p => p.id === activeProjectId ? {
          ...p,
          codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
            ...cs,
            instances: cs.instances.map(a => a.id === agentId ? {
              ...a,
              isThinking: false,
              messages: [...a.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }]
            } : a)
          } : cs)
        } : p)
      }));
    } catch (error) {
      setOrg(prev => ({
        ...prev,
        projects: prev.projects.map(p => p.id === activeProjectId ? {
          ...p,
          codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
            ...cs,
            instances: cs.instances.map(a => a.id === agentId ? {
              ...a,
              isThinking: false,
              messages: [...a.messages, { role: 'agent', content: "Error communicating with the deployed agent.", timestamp }]
            } : a)
          } : cs)
        } : p)
      }));
    }
  };

  if (!hasStarted) {
    return <LandingView onEnterIDE={() => setHasStarted(true)} />;
  }

  if (!user) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="h-screen w-screen flex flex-col bg-[#fdfdfd] dark:bg-[#0a0a0a] overflow-hidden font-inter text-black dark:text-neutral-200">
      <header className="h-16 border-b border-black/5 dark:border-white/5 bg-white/70 dark:bg-black/70 backdrop-blur-xl flex items-center justify-between px-8 shrink-0 z-50">
        <div className="flex items-center gap-6">
          <button className="font-serif font-bold text-xl tracking-[0.3em] uppercase" onClick={() => setHasStarted(false)}>REFLECTER</button>
          <div className="h-6 w-px bg-black/10 dark:bg-white/10"></div>
          <div className="flex items-center gap-2 text-[10px] uppercase font-bold tracking-widest text-neutral-400">
             <span>{org.name}</span>
             <Icon name="chevron-right" size={10} />
             <span className="text-black dark:text-white">{activeCodeSpace.name}</span>
          </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="flex items-center gap-3 mr-4">
              <div className="flex flex-col items-end">
                <span className="text-[10px] font-bold text-black dark:text-white uppercase tracking-tighter">{user.name}</span>
                <span className="text-[8px] text-neutral-400 uppercase font-mono">Credits: $124.50</span>
              </div>
              <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.email}`} className="w-8 h-8 rounded-full border border-black/5" alt="Avatar" />
           </div>
           <button onClick={() => setShowDeployModal(true)} className="bg-black dark:bg-white text-white dark:text-black px-5 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest hover:scale-105 transition-all shadow-lg">
             Deploy Agents
           </button>
           <button onClick={handleLogout} className="p-2 text-neutral-400 hover:text-red-500 transition-colors">
             <Icon name="close" size={16} />
           </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden bg-neutral-50/50 dark:bg-neutral-950/50">
        {/* Agent Instance Sidebar */}
        <aside className="w-64 border-r border-black/5 dark:border-white/5 bg-white/40 dark:bg-black/40 backdrop-blur-md flex flex-col shrink-0">
          <div className="p-4 border-b border-black/5 dark:border-white/5 flex items-center justify-between">
             <span className="text-[10px] font-bold uppercase tracking-[0.2em] text-neutral-400">Active Instances</span>
             <span className="text-[10px] font-mono text-black dark:text-white">{activeCodeSpace.instances.length}</span>
          </div>
          <div className="flex-1 overflow-y-auto p-2 space-y-1 no-scrollbar">
            {activeCodeSpace.instances.length === 0 && (
              <div className="p-10 text-center space-y-2 opacity-30">
                <Icon name="terminal" size={24} className="mx-auto" />
                <p className="text-[10px] uppercase font-bold tracking-widest">No active agents</p>
              </div>
            )}
            {activeCodeSpace.instances.map(agent => (
              <div 
                key={agent.id}
                onClick={() => setActivePaneId(agent.id)}
                className={`group flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all border ${
                  activePaneId === agent.id 
                  ? 'bg-white dark:bg-neutral-900 border-black/10 dark:border-white/10 shadow-sm' 
                  : 'border-transparent hover:bg-black/5 dark:hover:bg-white/5'
                }`}
              >
                <div className="flex items-center gap-3 min-w-0">
                  <div className={`w-2 h-2 rounded-full ${agent.status === 'running' ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.5)]' : 'bg-neutral-300 animate-pulse'}`}></div>
                  <div className="flex flex-col min-w-0">
                    <span className={`text-[11px] font-bold uppercase truncate ${activePaneId === agent.id ? 'text-black dark:text-white' : 'text-neutral-500'}`}>{agent.name}</span>
                    <span className="text-[8px] text-neutral-400 font-mono uppercase truncate">{agent.compute} Compute</span>
                  </div>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleKillAgent(agent.id); }}
                  className="opacity-0 group-hover:opacity-100 p-1.5 hover:bg-red-500 hover:text-white rounded-lg transition-all text-neutral-400"
                  title="Kill Instance"
                >
                  <Icon name="close" size={12} />
                </button>
              </div>
            ))}
          </div>
          <div className="p-4 border-t border-black/5 dark:border-white/5 bg-black/[0.02] dark:bg-white/[0.02]">
             <button onClick={() => setShowDeployModal(true)} className="w-full py-3 border border-dashed border-black/10 dark:border-white/10 rounded-xl text-[9px] uppercase font-bold tracking-widest text-neutral-400 hover:text-black dark:hover:text-white hover:border-black/30 transition-all">
                + Deploy Instance
             </button>
          </div>
        </aside>

        {/* Main Workspace */}
        <section className="flex-1 flex flex-col overflow-hidden relative">
          {activePaneId ? (
            <TerminalPane 
              file={{ 
                id: activePaneId, 
                name: activeCodeSpace.instances.find(a => a.id === activePaneId)?.name || '', 
                messages: activeCodeSpace.instances.find(a => a.id === activePaneId)?.messages || [],
                agent: activeCodeSpace.instances.find(a => a.id === activePaneId)?.type,
                isThinking: activeCodeSpace.instances.find(a => a.id === activePaneId)?.isThinking
              } as any}
              isActive={true}
              onFocus={() => {}}
              width="100%"
              onSendMessage={handleSendMessage}
              onClose={() => handleKillAgent(activePaneId)}
              isSystemView={false}
            />
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center space-y-10 animate-in fade-in duration-1000">
               <div className="w-24 h-24 border-2 border-black/5 rounded-full flex items-center justify-center opacity-10">
                  <Icon name="AGENT" size={48} />
               </div>
               <div className="text-center space-y-3">
                  <h2 className="font-serif text-3xl uppercase tracking-[0.4em] opacity-10">Select an Agent</h2>
                  <p className="text-[10px] uppercase font-bold tracking-[0.3em] text-neutral-400">Launch a new instance to start communication</p>
               </div>
               <button onClick={() => setShowDeployModal(true)} className="px-10 py-4 border border-black dark:border-white rounded-full text-[10px] font-bold uppercase tracking-[0.3em] hover:bg-black dark:hover:bg-white hover:text-white dark:hover:text-black transition-all">
                 Launch New Deployment
               </button>
            </div>
          )}
        </section>
      </main>

      {showDeployModal && <DeployModal onClose={() => setShowDeployModal(false)} onDeploy={handleDeployAgents} />}
    </div>
  );
}

