import React, { useState, useRef, useEffect } from 'react';
import Icon from './Icon';

interface TerminalPaneProps {
  file: {
    id: string;
    name: string;
    messages: { role: string; content: string; timestamp: string }[];
    agent?: string;
    isThinking?: boolean;
  };
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (id: string, content: string) => void;
  onClose?: () => void;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  file, isActive, onFocus, onSendMessage, onClose
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages, file.isThinking]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !file.isThinking) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  return (
    <div 
      onClick={onFocus}
      className={`h-full w-full flex flex-col overflow-hidden relative transition-all rounded-3xl m-2 glass-pane border border-black/5 dark:border-white/5 shadow-2xl bg-white/60 dark:bg-black/60 backdrop-blur-3xl`}
    >
      {/* Agent Instance Header */}
      <div className="flex items-center justify-between h-20 px-8 border-b border-black/5 dark:border-white/5 shrink-0">
        <div className="flex items-center gap-4">
          <div className="w-3 h-3 rounded-full bg-green-500 shadow-[0_0_12px_rgba(34,197,94,0.4)]"></div>
          <div className="flex flex-col">
            <span className="text-xs font-serif font-bold uppercase tracking-widest text-black dark:text-white">{file.name}</span>
            <span className="text-[9px] text-neutral-400 font-bold uppercase tracking-tighter">Communication Uplink Active</span>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <button onClick={onClose} className="p-3 text-neutral-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-950/30 rounded-full transition-all" title="Terminate Instance">
             <Icon name="close" size={18} />
           </button>
        </div>
      </div>

      {/* Instance Dialogue */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-10 scroll-smooth no-scrollbar">
        <div className="max-w-3xl mx-auto space-y-10">
          {file.messages.map((msg, i) => (
            <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-500`}>
              <div className={`max-w-[90%] rounded-3xl px-6 py-5 text-[14px] leading-relaxed shadow-sm ${
                msg.role === 'user' 
                ? 'bg-black text-white dark:bg-white dark:text-black shadow-xl' 
                : 'bg-black/[0.03] text-neutral-800 dark:bg-white/[0.03] dark:text-neutral-200 border border-black/5 dark:border-white/5'
              }`}>
                {msg.content}
              </div>
              <span className="text-[9px] uppercase font-bold tracking-widest mt-3 text-neutral-400 px-2 font-mono">
                {msg.role === 'agent' ? `${file.name} • ${msg.timestamp}` : `You • ${msg.timestamp}`}
              </span>
            </div>
          ))}
          {file.isThinking && (
            <div className="flex items-center gap-4 text-neutral-400 text-[11px] font-bold tracking-widest animate-pulse ml-2 uppercase">
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-neutral-300 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-neutral-300 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                <div className="w-1.5 h-1.5 bg-neutral-300 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
              </div>
              Processing Request
            </div>
          )}
        </div>
      </div>

      {/* Communication Command Area */}
      <div className="px-10 pb-10 shrink-0">
        <div className="max-w-3xl mx-auto flex flex-col gap-4">
          <form onSubmit={handleSubmit} className="flex gap-3 items-center bg-white dark:bg-neutral-900 border border-black/5 dark:border-white/10 p-3 rounded-3xl shadow-2xl focus-within:ring-4 ring-black/5 dark:ring-white/5 transition-all">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              disabled={file.isThinking}
              placeholder={file.isThinking ? "Awaiting agent response..." : "Type your command..."}
              className="bg-transparent border-none outline-none flex-1 px-5 text-[14px] text-black dark:text-white placeholder:text-neutral-300 dark:placeholder:text-neutral-700 font-inter py-3 disabled:opacity-50"
              autoFocus
            />
            <button 
              type="submit" 
              disabled={!input.trim() || file.isThinking}
              className="w-14 h-14 flex items-center justify-center bg-black dark:bg-white text-white dark:text-black rounded-2xl hover:scale-105 active:scale-95 disabled:opacity-20 disabled:scale-100 transition-all shadow-xl"
            >
              <Icon name="play" size={18} />
            </button>
          </form>
          <div className="flex justify-center">
             <span className="text-[8px] uppercase font-bold tracking-[0.4em] text-neutral-300 dark:text-neutral-700">Reflecter Secure Uplink Node</span>
          </div>
        </div>
      </div>
    </div>
  );
};

