import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { AgentInstance, User, Organization, Project, CodeSpace } from './types';
import { INITIAL_ORG } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';
import DeployModal from './components/DeployModal';
import LandingView from './components/LandingView';
import LoginView from './components/LoginView';
import { GoogleGenAI } from "@google/genai";

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [hasStarted, setHasStarted] = useState(false);
  const [org, setOrg] = useState<Organization>(INITIAL_ORG);
  const [activeProjectId, setActiveProjectId] = useState('proj-1');
  const [activeCodeSpaceId, setActiveCodeSpaceId] = useState('cs-1');

  const [showDeployModal, setShowDeployModal] = useState(false);
  const [activePaneId, setActivePaneId] = useState<string | null>(null);

  const activeProject = useMemo(() => 
    org.projects.find(p => p.id === activeProjectId) || org.projects[0]
  , [org, activeProjectId]);

  const activeCodeSpace = useMemo(() => 
    activeProject.codeSpaces.find(cs => cs.id === activeCodeSpaceId) || activeProject.codeSpaces[0]
  , [activeProject, activeCodeSpaceId]);

  const handleLogin = (mockUser: User) => setUser(mockUser);
  const handleLogout = () => {
    setUser(null);
    setHasStarted(false);
  };

  const handleDeployAgents = useCallback((config: { provider: string; vCPU: string; ram: string; region: string; quantity: number; namePrefix: string }) => {
    const newInstances: AgentInstance[] = Array.from({ length: config.quantity }).map((_, i) => ({
      id: `agent-${Date.now()}-${i}`,
      name: `${config.namePrefix}-${i + 1}`,
      provider: config.provider,
      vCPU: config.vCPU,
      ram: config.ram,
      region: config.region,
      status: 'running',
      messages: [
        { role: 'agent', content: `Provisioning complete. \n- VM: ${config.vCPU}, ${config.ram}\n- Region: ${config.region}\n- Intelligence: ${config.provider}\n\nUplink ready. How can I assist?`, timestamp: new Date().toLocaleTimeString().slice(0, 5) }
      ]
    }));

    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: [...cs.instances, ...newInstances]
        } : cs)
      } : p)
    }));

    setShowDeployModal(false);
    if (newInstances.length > 0) setActivePaneId(newInstances[0].id);
  }, [activeProjectId, activeCodeSpaceId]);

  const handleKillAgent = (agentId: string) => {
    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: cs.instances.filter(a => a.id !== agentId)
        } : cs)
      } : p)
    }));
    if (activePaneId === agentId) setActivePaneId(null);
  };

  const handleSendMessage = async (agentId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);

    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: cs.instances.map(a => a.id === agentId ? {
            ...a,
            isThinking: true,
            messages: [...a.messages, { role: 'user', content, timestamp }]
          } : a)
        } : cs)
      } : p)
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const agent = activeCodeSpace.instances.find(a => a.id === agentId)!;
      const history = agent.messages.slice(-8).map(m => `${m.role === 'agent' ? 'Agent' : 'User'}: ${m.content}`).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are an AI Agent with these specs:
        Instance: ${agent.name}
        Intelligence Provider: ${agent.provider}
        Compute: ${agent.vCPU}, ${agent.ram}
        Region: ${agent.region}

        Task: ${content}
        History: ${history}

        Provide professional, technical assistance.`,
      });

      const aiText = response.text || "Communication timeout with the instance.";

      setOrg(prev => ({
        ...prev,
        projects: prev.projects.map(p => p.id === activeProjectId ? {
          ...p,
          codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
            ...cs,
            instances: cs.instances.map(a => a.id === agentId ? {
              ...a,
              isThinking: false,
              messages: [...a.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }]
            } : a)
          } : cs)
        } : p)
      }));
    } catch (error) {
      setOrg(prev => ({
        ...prev,
        projects: prev.projects.map(p => p.id === activeProjectId ? {
          ...p,
          codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
            ...cs,
            instances: cs.instances.map(a => a.id === agentId ? {
              ...a,
              isThinking: false,
              messages: [...a.messages, { role: 'agent', content: "Instance logic error. Connectivity disrupted.", timestamp }]
            } : a)
          } : cs)
        } : p)
      }));
    }
  };

  if (!hasStarted) {
    return <LandingView onEnterIDE={() => setHasStarted(true)} />;
  }

  if (!user) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="h-screen w-screen flex flex-col bg-[#fdfdfd] dark:bg-[#0a0a0a] overflow-hidden font-inter text-black dark:text-neutral-200">
      <header className="h-16 border-b border-black/5 dark:border-white/5 bg-white/70 dark:bg-black/70 backdrop-blur-xl flex items-center justify-between px-8 shrink-0 z-50">
        <div className="flex items-center gap-6">
          <button className="font-serif font-bold text-xl tracking-[0.3em] uppercase" onClick={() => setHasStarted(false)}>REFLECTER</button>
          <div className="h-6 w-px bg-black/10 dark:bg-white/10"></div>
          <div className="flex items-center gap-2 text-[10px] uppercase font-bold tracking-widest text-neutral-400">
             <span>{org.name}</span>
             <Icon name="chevron-right" size={10} />
             <span className="text-black dark:text-white">{activeCodeSpace.name}</span>
          </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="flex items-center gap-3 mr-4">
              <div className="flex flex-col items-end">
                <span className="text-[10px] font-bold text-black dark:text-white uppercase tracking-tighter">{user.name}</span>
                <span className="text-[8px] text-neutral-400 uppercase font-mono">Credits: $4,240.12</span>
              </div>
              <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.email}`} className="w-8 h-8 rounded-full border border-black/5" alt="Avatar" />
           </div>
           <button onClick={() => setShowDeployModal(true)} className="bg-black dark:bg-white text-white dark:text-black px-5 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest hover:scale-105 transition-all shadow-lg border border-transparent hover:border-black/10 dark:hover:border-white/20">
             Deploy Instances
           </button>
           <button onClick={handleLogout} className="p-2 text-neutral-400 hover:text-red-500 transition-colors">
             <Icon name="close" size={16} />
           </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden bg-neutral-50/50 dark:bg-neutral-950/50">
        <aside className="w-72 border-r border-black/5 dark:border-white/5 bg-white/40 dark:bg-black/40 backdrop-blur-md flex flex-col shrink-0">
          <div className="p-4 border-b border-black/5 dark:border-white/5 flex items-center justify-between">
             <span className="text-[10px] font-bold uppercase tracking-[0.2em] text-neutral-400">Deployed Fleet</span>
             <span className="text-[10px] font-mono text-black dark:text-white">{activeCodeSpace.instances.length} Active</span>
          </div>
          <div className="flex-1 overflow-y-auto p-2 space-y-1 no-scrollbar">
            {activeCodeSpace.instances.map(agent => (
              <div 
                key={agent.id}
                onClick={() => setActivePaneId(agent.id)}
                className={`group flex items-center justify-between p-3 rounded-2xl cursor-pointer transition-all border ${
                  activePaneId === agent.id 
                  ? 'bg-white dark:bg-neutral-900 border-black/10 dark:border-white/10 shadow-md' 
                  : 'border-transparent hover:bg-black/[0.03] dark:hover:bg-white/[0.03]'
                }`}
              >
                <div className="flex items-center gap-3 min-w-0">
                  <div className={`w-2 h-2 rounded-full ${agent.status === 'running' ? 'bg-green-500' : 'bg-neutral-300'}`}></div>
                  <div className="flex flex-col min-w-0">
                    <span className={`text-[11px] font-bold uppercase truncate ${activePaneId === agent.id ? 'text-black dark:text-white' : 'text-neutral-500'}`}>{agent.name}</span>
                    <span className="text-[8px] text-neutral-400 font-mono uppercase truncate">{agent.vCPU} | {agent.ram}</span>
                    <span className="text-[7px] text-neutral-300 dark:text-neutral-600 font-bold uppercase truncate">{agent.provider}</span>
                  </div>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleKillAgent(agent.id); }}
                  className="opacity-0 group-hover:opacity-100 p-2 hover:bg-red-500 hover:text-white rounded-xl transition-all text-neutral-400"
                >
                  <Icon name="close" size={12} />
                </button>
              </div>
            ))}
          </div>
          <div className="p-4 border-t border-black/5 dark:border-white/5 bg-black/[0.02] dark:bg-white/[0.02]">
             <button onClick={() => setShowDeployModal(true)} className="w-full py-4 border border-dashed border-black/10 dark:border-white/10 rounded-2xl text-[9px] uppercase font-bold tracking-widest text-neutral-400 hover:text-black dark:hover:text-white hover:border-black/30 transition-all flex items-center justify-center gap-2">
                <Icon name="close" size={10} className="rotate-45" />
                New Deployment
             </button>
          </div>
        </aside>

        <section className="flex-1 flex flex-col overflow-hidden relative">
          {activePaneId ? (
            <TerminalPane 
              file={{ 
                id: activePaneId, 
                name: activeCodeSpace.instances.find(a => a.id === activePaneId)?.name || '', 
                messages: activeCodeSpace.instances.find(a => a.id === activePaneId)?.messages || [],
                agent: activeCodeSpace.instances.find(a => a.id === activePaneId)?.provider,
                isThinking: activeCodeSpace.instances.find(a => a.id === activePaneId)?.isThinking
              } as any}
              isActive={true}
              onFocus={() => {}}
              width="100%"
              onSendMessage={handleSendMessage}
              onClose={() => handleKillAgent(activePaneId)}
            />
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center space-y-12 animate-in fade-in duration-700 p-10">
               <div className="w-24 h-24 border-2 border-black/5 dark:border-white/5 rounded-full flex items-center justify-center">
                  <Icon name="AGENT" size={48} className="opacity-10" />
               </div>
               <div className="text-center space-y-4">
                  <h2 className="font-serif text-3xl uppercase tracking-[0.5em] text-neutral-200 dark:text-neutral-800">Orchestration View</h2>
                  <p className="text-[10px] uppercase font-bold tracking-[0.4em] text-neutral-400 max-w-sm mx-auto">Select a running instance or provision new compute nodes from the cloud console.</p>
               </div>
               <button onClick={() => setShowDeployModal(true)} className="px-12 py-5 bg-black dark:bg-white text-white dark:text-black rounded-full text-[11px] font-bold uppercase tracking-[0.4em] hover:scale-105 active:scale-95 transition-all shadow-2xl">
                 Provision New Nodes
               </button>
            </div>
          )}
        </section>
      </main>

      {showDeployModal && <DeployModal onClose={() => setShowDeployModal(false)} onDeploy={handleDeployAgents} />}
    </div>
  );
}

import React, { useState } from 'react';
import { AGENT_PROVIDERS, COMPUTE_OPTIONS, REGIONS } from '../constants';
import Icon from './Icon';

interface DeployModalProps {
  onClose: () => void;
  onDeploy: (config: { provider: string; vCPU: string; ram: string; region: string; quantity: number; namePrefix: string }) => void;
}

const DeployModal: React.FC<DeployModalProps> = ({ onClose, onDeploy }) => {
  const [providerId, setProviderId] = useState(AGENT_PROVIDERS[0].id);
  const [computeId, setComputeId] = useState(COMPUTE_OPTIONS[1].id);
  const [region, setRegion] = useState(REGIONS[0]);
  const [quantity, setQuantity] = useState(1);
  const [namePrefix, setNamePrefix] = useState('Instance-Node');

  const selectedProvider = AGENT_PROVIDERS.find(p => p.id === providerId)!;
  const selectedCompute = COMPUTE_OPTIONS.find(c => c.id === computeId)!;

  // Simulated monthly price assuming full availability
  const totalPriceMonthly = selectedCompute.price * quantity * 24 * 30;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-white/70 dark:bg-black/90 backdrop-blur-md p-4 overflow-y-auto">
      <div className="w-full max-w-4xl bg-white dark:bg-[#0d0d0d] border border-black/10 dark:border-neutral-800 p-10 flex flex-col gap-10 animate-in fade-in zoom-in-95 duration-200 shadow-[0_0_100px_rgba(0,0,0,0.1)] rounded-[2.5rem] my-auto">

        <div className="flex justify-between items-start">
          <div className="space-y-1">
            <h2 className="font-serif text-3xl tracking-widest text-black dark:text-white uppercase">Cloud Console</h2>
            <p className="text-[10px] font-mono text-neutral-400 uppercase tracking-widest">Provisioning Compute Engine v4.2</p>
          </div>
          <button onClick={onClose} className="text-neutral-400 hover:text-black dark:hover:text-white transition-colors p-3 bg-neutral-100 dark:bg-neutral-900 rounded-full">
            <Icon name="close" size={24} />
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

          {/* Left Column: VM Config */}
          <div className="lg:col-span-7 space-y-10">

            {/* Intelligence Provider */}
            <div className="space-y-4">
              <label className="text-[10px] font-bold uppercase tracking-[0.2em] text-neutral-400">Intelligence Provider (LLM Model)</label>
              <div className="grid grid-cols-2 gap-3">
                {AGENT_PROVIDERS.map(p => (
                  <div 
                    key={p.id}
