                      : 'border-black/5 dark:border-neutral-800 hover:border-black/20'
                    }`}
                  >
                    <div className="text-[11px] font-bold text-black dark:text-white uppercase tracking-wider">{p.name}</div>
                    <div className="text-[8px] text-neutral-500 mt-1 uppercase font-mono">{p.provider}</div>
                    <div className="text-[8px] text-neutral-400 mt-2 italic">{p.capabilities}</div>
                  </div>
                ))}
              </div>
            </div>

            {/* Machine Type */}
            <div className="space-y-4">
              <label className="text-[10px] font-bold uppercase tracking-[0.2em] text-neutral-400">Machine Type</label>
              <div className="space-y-2">
                {COMPUTE_OPTIONS.map(opt => (
                  <div 
                    key={opt.id}
                    onClick={() => setComputeId(opt.id)}
                    className={`flex items-center justify-between p-5 border rounded-3xl cursor-pointer transition-all ${
                      computeId === opt.id 
                      ? 'border-black dark:border-white bg-black/[0.02] dark:bg-neutral-900 shadow-sm' 
                      : 'border-black/5 dark:border-neutral-800 hover:border-black/20'
                    }`}
                  >
                    <div className="flex flex-col">
                      <span className={`text-[12px] font-bold uppercase tracking-tight ${computeId === opt.id ? 'text-black dark:text-white' : 'text-neutral-500'}`}>{opt.name}</span>
                      <span className="text-[9px] text-neutral-400 uppercase font-mono">{opt.vCPU} | {opt.ram}</span>
                    </div>
                    <div className="text-right">
                      <span className="text-[10px] font-mono text-black dark:text-white">${opt.price.toFixed(2)} / {opt.unit}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

          </div>

          {/* Right Column: Deployment & Price */}
          <div className="lg:col-span-5 flex flex-col justify-between space-y-10">

            <div className="space-y-8">
              {/* Region */}
              <div className="space-y-4">
                <label className="text-[10px] font-bold uppercase tracking-[0.2em] text-neutral-400">Deployment Region</label>
                <select 
                  value={region}
                  onChange={(e) => setRegion(e.target.value)}
                  className="w-full bg-neutral-50 dark:bg-neutral-900 border border-black/5 dark:border-neutral-800 text-[11px] font-bold uppercase tracking-widest p-5 rounded-3xl outline-none focus:border-black dark:focus:border-white appearance-none"
