                <input 
                  type="range" 
                  min="1" 
                  max="50" 
                  value={quantity} 
                  onChange={(e) => setQuantity(parseInt(e.target.value))}
                  className="w-full h-1.5 bg-neutral-100 dark:bg-neutral-800 rounded-full appearance-none cursor-pointer accent-black dark:accent-white"
                />
              </div>

              {/* Base Name */}
              <div className="space-y-4">
                <label className="text-[10px] font-bold uppercase tracking-[0.2em] text-neutral-400">Instance Name Prefix</label>
                <input 
                  type="text" 
                  value={namePrefix}
                  onChange={(e) => setNamePrefix(e.target.value)}
                  className="w-full bg-neutral-50 dark:bg-neutral-900 border border-black/5 dark:border-neutral-800 focus:border-black dark:focus:border-white text-xs font-mono text-black dark:text-white p-5 outline-none rounded-3xl shadow-inner"
                  placeholder="Instance-Node"
                />
              </div>
            </div>

            {/* Total Section */}
            <div className="bg-neutral-50 dark:bg-neutral-900 p-8 rounded-[2rem] border border-black/5 dark:border-white/5 space-y-6 shadow-2xl">
               <div className="space-y-2">
                 <div className="flex justify-between items-center text-[10px] uppercase font-bold tracking-widest text-neutral-400">
                    <span>Hourly Rate</span>
                    <span className="font-mono text-black dark:text-white">${(selectedCompute.price * quantity).toFixed(2)} / hr</span>
                 </div>
                 <div className="flex justify-between items-center text-[11px] uppercase font-bold tracking-[0.2em] text-black dark:text-white pt-2 border-t border-black/5 dark:border-white/5">
                    <span>Est. Monthly Usage</span>
                    <span className="text-xl font-mono">${totalPriceMonthly.toFixed(2)}</span>
                 </div>
               </div>

               <button 
                  onClick={() => onDeploy({ 
                    provider: selectedProvider.name, 
                    vCPU: selectedCompute.vCPU, 
                    ram: selectedCompute.ram, 
                    region, 
                    quantity, 
                    namePrefix 
                  })}
                  className="w-full bg-black dark:bg-white text-white dark:text-black py-6 rounded-3xl text-[12px] font-bold uppercase tracking-[0.4em] hover:scale-[1.02] active:scale-95 transition-all shadow-[0_20px_40px_-15px_rgba(0,0,0,0.3)]"
               >
                  Create and Launch
               </button>
               <p className="text-[8px] text-center text-neutral-400 uppercase tracking-widest font-mono italic">Configuration verified. Ready for VM instance provisioning.</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DeployModal;

import React, { useState, useRef, useEffect } from 'react';
import Icon from './Icon';

interface TerminalPaneProps {
  file: {
    id: string;
    name: string;
    messages: { role: string; content: string; timestamp: string }[];
    agent?: string; // This is the Provider
    isThinking?: boolean;
  };
  isActive: boolean;
  onFocus: () => void;
  width: string | number;
  onSendMessage: (id: string, content: string) => void;
  onClose?: () => void;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  file, isActive, onFocus, onSendMessage, onClose
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [file.messages, file.isThinking]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !file.isThinking) {
      onSendMessage(file.id, input);
      setInput('');
    }
  };

  return (
    <div 
      onClick={onFocus}
      className={`h-full w-full flex flex-col overflow-hidden relative transition-all rounded-[2.5rem] m-2 glass-pane border border-black/5 dark:border-white/5 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] bg-white/60 dark:bg-black/60 backdrop-blur-3xl`}
    >
      {/* Agent Instance Header */}
      <div className="flex items-center justify-between h-24 px-10 border-b border-black/5 dark:border-white/5 shrink-0 bg-white/40 dark:bg-black/40">
        <div className="flex items-center gap-5">
          <div className="w-4 h-4 rounded-full bg-green-500 shadow-[0_0_20px_rgba(34,197,94,0.5)] flex items-center justify-center">
            <div className="w-1.5 h-1.5 rounded-full bg-white animate-pulse"></div>
          </div>
          <div className="flex flex-col">
            <div className="flex items-center gap-3">
              <span className="text-sm font-serif font-bold uppercase tracking-[0.2em] text-black dark:text-white">{file.name}</span>
              <span className="px-2 py-0.5 rounded-full bg-black/5 dark:bg-white/5 text-[8px] font-mono text-neutral-400 font-bold uppercase">{file.agent}</span>
            </div>
            <span className="text-[10px] text-neutral-400 font-bold uppercase tracking-widest mt-0.5">Direct VM Console Uplink</span>
          </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="hidden md:flex flex-col items-end text-[9px] font-mono text-neutral-400 uppercase tracking-tighter">
              <span>Status: Optimal</span>
              <span>Encrypted Session</span>
           </div>
           <button onClick={onClose} className="p-4 text-neutral-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-950/30 rounded-full transition-all" title="Terminate VM Instance">
             <Icon name="close" size={20} />
           </button>
        </div>
      </div>

      {/* Instance Dialogue */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-12 scroll-smooth no-scrollbar">
        <div className="max-w-3xl mx-auto space-y-12">
          {file.messages.map((msg, i) => (
            <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-700`}>
              <div className={`max-w-[85%] rounded-[2rem] px-8 py-6 text-[15px] leading-relaxed shadow-sm ${
                msg.role === 'user' 
                ? 'bg-black text-white dark:bg-white dark:text-black shadow-2xl' 
                : 'bg-black/[0.03] text-neutral-800 dark:bg-white/[0.03] dark:text-neutral-200 border border-black/5 dark:border-white/5'
              }`}>
                {msg.content}
              </div>
              <span className="text-[10px] uppercase font-bold tracking-widest mt-4 text-neutral-400 px-4 font-mono">
                {msg.role === 'agent' ? `${file.name} • ${msg.timestamp}` : `Authorized User • ${msg.timestamp}`}
              </span>
            </div>
          ))}
          {file.isThinking && (
            <div className="flex items-center gap-5 text-neutral-400 text-[12px] font-bold tracking-[0.3em] animate-pulse ml-4 uppercase">
              <div className="flex gap-1.5">
                <div className="w-2 h-2 bg-neutral-300 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-neutral-300 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                <div className="w-2 h-2 bg-neutral-300 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
              </div>
              Remote Instance Calculating
            </div>
          )}
        </div>
      </div>

      {/* Communication Command Area */}
      <div className="px-12 pb-12 shrink-0">
        <div className="max-w-3xl mx-auto flex flex-col gap-5">
          <form onSubmit={handleSubmit} className="flex gap-4 items-center bg-white dark:bg-neutral-900 border border-black/5 dark:border-white/10 p-4 rounded-[2.5rem] shadow-[0_20px_50px_-15px_rgba(0,0,0,0.2)] focus-within:ring-8 ring-black/5 dark:ring-white/5 transition-all">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              disabled={file.isThinking}
              placeholder={file.isThinking ? "Awaiting remote telemetry..." : "Execute command on VM..."}
              className="bg-transparent border-none outline-none flex-1 px-6 text-[15px] text-black dark:text-white placeholder:text-neutral-300 dark:placeholder:text-neutral-700 font-inter py-4 disabled:opacity-50"
              autoFocus
            />
            <button 
              type="submit" 
              disabled={!input.trim() || file.isThinking}
              className="w-16 h-16 flex items-center justify-center bg-black dark:bg-white text-white dark:text-black rounded-[1.5rem] hover:scale-110 active:scale-95 disabled:opacity-20 disabled:scale-100 transition-all shadow-2xl group"
            >
              <Icon name="play" size={24} className="group-hover:translate-x-0.5 transition-transform" />
            </button>
          </form>
          <div className="flex justify-between items-center px-4">
             <span className="text-[8px] uppercase font-bold tracking-[0.5em] text-neutral-300 dark:text-neutral-700">Reflecter Secure Uplink Node v4.2.0</span>
             <div className="flex gap-2">
                <div className="w-1 h-1 rounded-full bg-black/10 dark:bg-white/10"></div>
                <div className="w-1 h-1 rounded-full bg-black/10 dark:bg-white/10"></div>
                <div className="w-1 h-1 rounded-full bg-black/10 dark:bg-white/10"></div>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

