            <section className="space-y-8">
               <div className="space-y-4">
                  <label className="text-[10px] font-bold uppercase tracking-[0.3em] text-neutral-400">03. Deployment Region</label>
                  <select 
                    value={region}
                    onChange={(e) => setRegion(e.target.value)}
                    className="w-full bg-neutral-100 dark:bg-neutral-900 border-none text-[11px] font-bold uppercase tracking-widest p-6 rounded-[2rem] outline-none appearance-none"
                  >
                    {REGIONS.map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
               </div>

               <div className="space-y-4">
                  <div className="flex justify-between items-center">
                    <label className="text-[10px] font-bold uppercase tracking-[0.3em] text-neutral-400">04. Quantity</label>
                    <span className="font-mono text-lg font-bold text-black dark:text-white">{quantity} Nodes</span>
                  </div>
                  <input 
                    type="range" 
                    min="1" 
                    max="20" 
                    value={quantity} 
                    onChange={(e) => setQuantity(parseInt(e.target.value))}
                    className="w-full h-2 bg-neutral-200 dark:bg-neutral-800 rounded-full appearance-none cursor-pointer accent-black dark:accent-white"
                  />
               </div>
            </section>

            <div className="bg-neutral-50 dark:bg-neutral-900/50 p-10 rounded-[3rem] border border-black/5 dark:border-white/5 space-y-8 shadow-inner">
               <div className="space-y-4">
                 <div className="flex justify-between items-center text-[10px] uppercase font-bold tracking-widest text-neutral-400">
                    <span>Hourly Burn Rate</span>
                    <span className="font-mono text-black dark:text-white">${hourlyPrice.toFixed(2)}</span>
                 </div>
                 <div className="flex justify-between items-center text-[12px] uppercase font-bold tracking-[0.3em] text-black dark:text-white pt-4 border-t border-black/5 dark:border-white/5">
                    <span>Monthly Estimate</span>
                    <span className="text-2xl font-mono">${monthlyPrice.toFixed(0)}</span>
                 </div>
               </div>

               <button 
                  onClick={() => onDeploy({ 
                    provider: selectedProvider.name, 
                    vCPU: selectedCompute.vCPU, 
                    ram: selectedCompute.ram, 
                    region, 
                    quantity, 
                    namePrefix,
                    hourlyPrice
                  })}
                  className="w-full bg-black dark:bg-white text-white dark:text-black py-8 rounded-[2rem] text-[12px] font-bold uppercase tracking-[0.5em] hover:scale-[1.02] active:scale-95 transition-all shadow-2xl"
               >
                  Authorize & Launch
               </button>
               <p className="text-[8px] text-center text-neutral-400 uppercase tracking-widest font-mono leading-relaxed">
                  Transaction will be processed via Credits. <br/> Instant provisioning across Reflecter High-Audit zones.
               </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

