import React, { useState, useCallback, useMemo } from 'react';
import { AgentInstance, User, Organization, ChatSession } from './types';
import { INITIAL_ORG } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';
import DeployModal from './components/DeployModal';
import LandingView from './components/LandingView';
import LoginView from './components/LoginView';
import FleetMatrix from './components/FleetMatrix';
import { GoogleGenAI } from "@google/genai";

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [hasStarted, setHasStarted] = useState(false);
  const [org, setOrg] = useState<Organization>(INITIAL_ORG);
  const [activeProjectId] = useState('proj-1');
  const [activeCodeSpaceId] = useState('cs-1');
  const [viewMode, setViewMode] = useState<'matrix' | 'terminal'>('matrix');
  const [activeInstanceId, setActiveInstanceId] = useState<string | null>(null);
  const [showDeployModal, setShowDeployModal] = useState(false);
  const [credits, setCredits] = useState(4240.12);

  const activeProject = useMemo(() => 
    org.projects.find(p => p.id === activeProjectId) || org.projects[0]
  , [org, activeProjectId]);

  const activeCodeSpace = useMemo(() => 
    activeProject.codeSpaces.find(cs => cs.id === activeCodeSpaceId) || activeProject.codeSpaces[0]
  , [activeProject, activeCodeSpaceId]);

  const activeInstance = useMemo(() => 
    activeCodeSpace.instances.find(i => i.id === activeInstanceId)
  , [activeCodeSpace.instances, activeInstanceId]);

  const handleLogin = (mockUser: User) => setUser(mockUser);
  const handleLogout = () => {
    setUser(null);
    setHasStarted(false);
  };

  const handleDeployAgents = useCallback((config: { provider: string; vCPU: string; ram: string; region: string; quantity: number; namePrefix: string; hourlyPrice: number }) => {
    const newInstances: AgentInstance[] = Array.from({ length: config.quantity }).map((_, i) => {
      const chatId = `chat-${Date.now()}-${i}`;
      return {
        id: `agent-${Date.now()}-${i}`,
        name: `${config.namePrefix}-${String(i + 1).padStart(2, '0')}`,
        provider: config.provider,
        vCPU: config.vCPU,
        ram: config.ram,
        region: config.region,
        status: 'running',
        activeChatId: chatId,
        chats: [
          {
            id: chatId,
            name: 'Default Session',
            lastUpdate: new Date().toLocaleTimeString().slice(0, 5),
            messages: [
              { role: 'agent', content: `[SYSTEM] Instance provisioned. Intelligence: ${config.provider}. Ready for tasks.`, timestamp: new Date().toLocaleTimeString().slice(0, 5) }
            ]
          }
        ]
      };
    });

    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: [...cs.instances, ...newInstances]
        } : cs)
      } : p)
    }));

    setShowDeployModal(false);
    setViewMode('matrix');
  }, [activeProjectId, activeCodeSpaceId]);

  const handleKillAgent = (agentId: string) => {
    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: cs.instances.filter(a => a.id !== agentId)
        } : cs)
      } : p)
    }));
    if (activeInstanceId === agentId) {
      setActiveInstanceId(null);
      setViewMode('matrix');
    }
  };

  const handleCreateChat = (instanceId: string) => {
    const newChat: ChatSession = {
      id: `chat-${Date.now()}`,
      name: `Session ${activeInstance?.chats.length || 0 + 1}`,
      messages: [{ role: 'agent', content: 'New session started. How can I help?', timestamp: new Date().toLocaleTimeString().slice(0, 5) }],
      lastUpdate: new Date().toLocaleTimeString().slice(0, 5)
    };

    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: cs.instances.map(i => i.id === instanceId ? {
            ...i,
            chats: [...i.chats, newChat],
            activeChatId: newChat.id
          } : i)
        } : cs)
      } : p)
    }));
  };

  const handleSwitchChat = (instanceId: string, chatId: string) => {
    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: cs.instances.map(i => i.id === instanceId ? { ...i, activeChatId: chatId } : i)
        } : cs)
      } : p)
    }));
  };

  const handleSendMessage = async (instanceId: string, chatId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);

    setOrg(prev => ({
      ...prev,
      projects: prev.projects.map(p => p.id === activeProjectId ? {
        ...p,
        codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
          ...cs,
          instances: cs.instances.map(i => i.id === instanceId ? {
            ...i,
            chats: i.chats.map(c => c.id === chatId ? {
              ...c,
              isThinking: true,
              messages: [...c.messages, { role: 'user', content, timestamp }]
            } : c)
          } : i)
        } : cs)
      } : p)
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const instance = activeCodeSpace.instances.find(i => i.id === instanceId)!;
      const chat = instance.chats.find(c => c.id === chatId)!;
      const history = chat.messages.slice(-6).map(m => `${m.role === 'agent' ? 'Agent' : 'User'}: ${m.content}`).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are intelligence ${instance.provider} running on ${instance.vCPU}/${instance.ram}.
        Session Name: ${chat.name}.
        Request: ${content}
        Context: ${history}`,
      });

      const aiText = response.text || "Compute session timed out.";

      setOrg(prev => ({
        ...prev,
        projects: prev.projects.map(p => p.id === activeProjectId ? {
          ...p,
          codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
            ...cs,
            instances: cs.instances.map(i => i.id === instanceId ? {
              ...i,
              chats: i.chats.map(c => c.id === chatId ? {
                ...c,
                isThinking: false,
                messages: [...c.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }],
                lastUpdate: new Date().toLocaleTimeString().slice(0, 5)
              } : c)
            } : i)
          } : cs)
        } : p)
      }));
      setCredits(c => c - 0.05);
    } catch (error) {
       setOrg(prev => ({
        ...prev,
        projects: prev.projects.map(p => p.id === activeProjectId ? {
          ...p,
          codeSpaces: p.codeSpaces.map(cs => cs.id === activeCodeSpaceId ? {
            ...cs,
            instances: cs.instances.map(i => i.id === instanceId ? {
              ...i,
              chats: i.chats.map(c => c.id === chatId ? { ...c, isThinking: false } : c)
            } : i)
          } : cs)
        } : p)
      }));
    }
  };

  const totalVCPU = useMemo(() => activeCodeSpace.instances.reduce((acc, curr) => acc + parseInt(curr.vCPU), 0), [activeCodeSpace.instances]);
  const totalRAM = useMemo(() => activeCodeSpace.instances.reduce((acc, curr) => acc + parseInt(curr.ram), 0), [activeCodeSpace.instances]);

  if (!hasStarted) return <LandingView onEnterIDE={() => setHasStarted(true)} />;
  if (!user) return <LoginView onLogin={handleLogin} />;

  return (
    <div className="h-screen w-screen flex flex-col bg-[#fdfdfd] dark:bg-[#050505] overflow-hidden font-inter text-black dark:text-neutral-200">
      <header className="h-20 border-b border-black/5 dark:border-white/5 bg-white/70 dark:bg-black/70 backdrop-blur-2xl flex items-center justify-between px-10 shrink-0 z-50">
        <div className="flex items-center gap-8">
          <button className="font-serif font-bold text-2xl tracking-[0.4em] uppercase" onClick={() => setHasStarted(false)}>Reflecter</button>
          <div className="h-8 w-px bg-black/10 dark:bg-white/10"></div>
          <div className="flex items-center gap-6 text-[10px] uppercase font-bold tracking-[0.3em] text-neutral-400">
             <div className="flex flex-col">
                <span className="text-black dark:text-white">Fleet Manager</span>
                <span className="text-[8px] opacity-50 font-mono tracking-widest uppercase">Orchestrator_v2</span>
             </div>
             <button 
               onClick={() => setViewMode('matrix')} 
               className={`transition-all ${viewMode === 'matrix' ? 'text-black dark:text-white underline underline-offset-8 decoration-2' : 'hover:text-black dark:hover:text-white'}`}
             >
               Instance Matrix
             </button>
             <button 
               onClick={() => activeInstanceId && setViewMode('terminal')} 
               className={`transition-all ${activeInstanceId ? 'opacity-100' : 'opacity-20 cursor-not-allowed'} ${viewMode === 'terminal' ? 'text-black dark:text-white underline underline-offset-8 decoration-2' : 'hover:text-black dark:hover:text-white'}`}
             >
               Direct Uplink
             </button>
          </div>
        </div>

        <div className="flex items-center gap-8">
           <div className="hidden xl:flex items-center gap-6 border-r border-black/10 dark:border-white/10 pr-8 mr-2">
              <div className="flex flex-col items-end">
                 <span className="text-[8px] uppercase tracking-widest text-neutral-400 font-bold">Allocated Compute</span>
                 <span className="text-[11px] font-mono text-black dark:text-white">{totalVCPU} vCPU • {totalRAM} GB RAM</span>
              </div>
              <div className="flex flex-col items-end">
                 <span className="text-[8px] uppercase tracking-widest text-neutral-400 font-bold">Credit Balance</span>
                 <span className="text-[11px] font-mono text-green-500 font-bold">${credits.toFixed(2)}</span>
              </div>
           </div>

           <button onClick={() => setShowDeployModal(true)} className="bg-black dark:bg-white text-white dark:text-black px-8 py-3 rounded-full text-[10px] font-bold uppercase tracking-[0.3em] hover:scale-105 transition-all shadow-2xl active:scale-95">
             Deploy Instances
           </button>

           <div className="flex items-center gap-4 ml-4">
              <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.email}`} className="w-10 h-10 rounded-full border border-black/10 dark:border-white/10 bg-neutral-100 dark:bg-neutral-900" alt="Avatar" />
              <button onClick={handleLogout} className="p-2 text-neutral-400 hover:text-red-500 transition-colors">
                 <Icon name="close" size={20} />
              </button>
           </div>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        {viewMode === 'matrix' ? (
          <FleetMatrix 
            instances={activeCodeSpace.instances} 
            onSelect={(id) => { setActiveInstanceId(id); setViewMode('terminal'); }}
            onKill={handleKillAgent}
            onDeploy={() => setShowDeployModal(true)}
          />
        ) : (
          <section className="flex-1 flex flex-col overflow-hidden p-6 bg-neutral-50/50 dark:bg-neutral-950/50">
            {activeInstance ? (
              <TerminalPane 
                instance={activeInstance}
                onSendMessage={(chatId, msg) => handleSendMessage(activeInstance.id, chatId, msg)}
                onNewChat={() => handleCreateChat(activeInstance.id)}
                onSwitchChat={(id) => handleSwitchChat(activeInstance.id, id)}
                onClose={() => { setViewMode('matrix'); setActiveInstanceId(null); }}
              />
            ) : (
              <div className="flex-1 flex items-center justify-center">
                 <p className="text-[10px] uppercase font-bold tracking-[0.5em] text-neutral-400">Uplink terminated. Return to matrix.</p>
              </div>
            )}
          </section>
        )}
      </main>

      <footer className="h-10 border-t border-black/5 dark:border-white/5 bg-white/80 dark:bg-black/80 flex items-center justify-between px-10 z-50 shrink-0 backdrop-blur-md">
         <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
               <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
               <span className="text-[8px] uppercase font-bold tracking-[0.4em] text-neutral-500">Fleet Link: Optimal</span>
            </div>
            <span className="text-[8px] uppercase font-mono text-neutral-400">Protocol: Ref_Secure_v4.2.0</span>
         </div>
         <div className="text-[8px] uppercase font-bold tracking-[0.6em] text-neutral-300 dark:text-neutral-700">
            Sovereign Orchestration Infrastructure
         </div>
      </footer>

      {showDeployModal && <DeployModal onClose={() => setShowDeployModal(false)} onDeploy={handleDeployAgents} />}
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import Icon from './Icon';
import { AgentInstance, ChatSession } from '../types';

interface TerminalPaneProps {
  instance: AgentInstance;
  onSendMessage: (chatId: string, content: string) => void;
  onNewChat: () => void;
  onSwitchChat: (chatId: string) => void;
  onClose?: () => void;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  instance, onSendMessage, onNewChat, onSwitchChat, onClose
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const activeChat = instance.chats.find(c => c.id === instance.activeChatId) || instance.chats[0];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [activeChat.messages, activeChat.isThinking]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !activeChat.isThinking) {
      onSendMessage(activeChat.id, input);
      setInput('');
    }
  };

  return (
    <div className="h-full w-full flex overflow-hidden relative rounded-[2.5rem] glass-pane border border-black/5 dark:border-white/5 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] bg-white/60 dark:bg-black/60 backdrop-blur-3xl">

      {/* Session Navigation Sidebar */}
      <aside className="w-64 border-r border-black/5 dark:border-white/5 flex flex-col shrink-0 bg-white/40 dark:bg-black/40">
        <div className="p-6 border-b border-black/5 dark:border-white/5 flex flex-col gap-1">
          <span className="text-[8px] uppercase font-bold tracking-[0.4em] text-neutral-400">Intelligence Node</span>
          <span className="text-[10px] font-serif font-bold uppercase tracking-widest text-black dark:text-white">{instance.name}</span>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-2 no-scrollbar">
          {instance.chats.map(chat => (
            <div 
              key={chat.id}
              onClick={() => onSwitchChat(chat.id)}
              className={`p-4 rounded-2xl cursor-pointer transition-all border ${
                instance.activeChatId === chat.id 
                ? 'bg-black text-white dark:bg-white dark:text-black border-transparent shadow-lg' 
                : 'bg-transparent border-transparent hover:bg-black/[0.03] dark:hover:bg-white/[0.03] text-neutral-500'
              }`}
            >
              <div className="text-[10px] font-bold uppercase tracking-wider truncate">{chat.name}</div>
              <div className={`text-[8px] mt-1 font-mono uppercase opacity-50 ${instance.activeChatId === chat.id ? 'text-white dark:text-black' : 'text-neutral-400'}`}>
                {chat.lastUpdate}
              </div>
            </div>
          ))}
        </div>

        <div className="p-4 border-t border-black/5 dark:border-white/5">
           <button 
             onClick={onNewChat}
             className="w-full py-4 border border-dashed border-black/20 dark:border-white/20 rounded-2xl text-[9px] uppercase font-bold tracking-widest text-neutral-400 hover:text-black dark:hover:text-white hover:border-black/40 transition-all flex items-center justify-center gap-2"
           >
              <Icon name="close" size={10} className="rotate-45" />
              New Session
           </button>
        </div>
      </aside>

      {/* Main Dialogue Space */}
      <div className="flex-1 flex flex-col overflow-hidden relative">
        {/* Header */}
        <div className="flex items-center justify-between h-20 px-10 border-b border-black/5 dark:border-white/5 shrink-0 bg-white/20 dark:bg-black/20">
          <div className="flex items-center gap-5">
            <div className="w-3 h-3 rounded-full bg-green-500 shadow-[0_0_15px_rgba(34,197,94,0.4)]"></div>
            <div className="flex flex-col">
              <span className="text-[11px] font-bold uppercase tracking-[0.2em] text-black dark:text-white">{activeChat.name}</span>
              <span className="text-[8px] text-neutral-400 font-bold uppercase tracking-widest">Uplink: Secure Session v4</span>
            </div>
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden lg:flex flex-col items-end text-[8px] font-mono text-neutral-400 uppercase tracking-tighter">
                <span>Memory usage: Normal</span>
                <span>Encrypted Path</span>
             </div>
             <button onClick={onClose} className="p-3 text-neutral-400 hover:text-red-500 transition-all" title="Detach Interface">
               <Icon name="close" size={18} />
             </button>
          </div>
        </div>

        {/* Messages */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-12 scroll-smooth no-scrollbar">
          <div className="max-w-3xl mx-auto space-y-12">
            {activeChat.messages.map((msg, i) => (
              <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-700`}>
                <div className={`max-w-[85%] rounded-[1.8rem] px-8 py-5 text-[14px] leading-relaxed shadow-sm ${
                  msg.role === 'user' 
                  ? 'bg-black text-white dark:bg-white dark:text-black shadow-2xl' 
                  : 'bg-black/[0.04] text-neutral-800 dark:bg-white/[0.04] dark:text-neutral-200 border border-black/5 dark:border-white/5'
                }`}>
                  {msg.content}
                </div>
                <span className="text-[9px] uppercase font-bold tracking-widest mt-4 text-neutral-400 px-4 font-mono">
                  {msg.role === 'agent' ? `${instance.name} • ${msg.timestamp}` : `Operator • ${msg.timestamp}`}
                </span>
              </div>
            ))}
            {activeChat.isThinking && (
              <div className="flex items-center gap-4 text-neutral-400 text-[11px] font-bold tracking-[0.3em] animate-pulse ml-4 uppercase">
                <div className="flex gap-1.5">
                  <div className="w-1.5 h-1.5 bg-neutral-300 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-neutral-300 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                  <div className="w-1.5 h-1.5 bg-neutral-300 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
                </div>
                Instance_Reasoning...
              </div>
            )}
          </div>
        </div>

        {/* Input */}
        <div className="px-12 pb-12 shrink-0">
          <div className="max-w-3xl mx-auto flex flex-col gap-5">
            <form onSubmit={handleSubmit} className="flex gap-4 items-center bg-white dark:bg-neutral-900 border border-black/5 dark:border-white/10 p-4 rounded-[2.5rem] shadow-[0_20px_50px_-15px_rgba(0,0,0,0.2)] focus-within:ring-4 ring-black/5 dark:ring-white/5 transition-all">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                disabled={activeChat.isThinking}
                placeholder={activeChat.isThinking ? "Observing instance telemetry..." : "Broadcast command..."}
                className="bg-transparent border-none outline-none flex-1 px-6 text-[14px] text-black dark:text-white placeholder:text-neutral-300 dark:placeholder:text-neutral-700 font-inter py-4 disabled:opacity-50"
                autoFocus
              />
              <button 
                type="submit" 
                disabled={!input.trim() || activeChat.isThinking}
                className="w-14 h-14 flex items-center justify-center bg-black dark:bg-white text-white dark:text-black rounded-[1.2rem] hover:scale-110 active:scale-95 disabled:opacity-20 disabled:scale-100 transition-all shadow-2xl group"
              >
                <Icon name="play" size={20} />
              </button>
            </form>
            <div className="flex justify-between items-center px-4">
               <span className="text-[8px] uppercase font-bold tracking-[0.4em] text-neutral-300 dark:text-neutral-700">Compute Provider: {instance.provider}</span>
               <div className="flex gap-2">
                  <div className="w-1 h-1 rounded-full bg-black/10 dark:bg-white/10"></div>
                  <div className="w-1 h-1 rounded-full bg-black/10 dark:bg-white/10"></div>
                  <div className="w-1 h-1 rounded-full bg-black/10 dark:bg-white/10"></div>
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

