import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { AgentInstance, User, Organization, ChatSession, FactoryGroup } from './types';
import { INITIAL_ORG } from './constants';
import TerminalPane from './components/TerminalPane';
import Icon from './components/Icon';
import DeployModal from './components/DeployModal';
import LandingView from './components/LandingView';
import LoginView from './components/LoginView';
import FleetMatrix from './components/FleetMatrix';
import FactorySidebar from './components/FactorySidebar';
import { GoogleGenAI } from "@google/genai";

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [hasStarted, setHasStarted] = useState(false);
  const [isDark, setIsDark] = useState(true);
  const [org, setOrg] = useState<Organization>(INITIAL_ORG);
  const [viewMode, setViewMode] = useState<'matrix' | 'terminal'>('matrix');
  const [activeInstanceId, setActiveInstanceId] = useState<string | null>(null);
  const [showDeployModal, setShowDeployModal] = useState(false);
  const [credits, setCredits] = useState(4240.12);

  // Sync dark mode class
  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDark);
    document.documentElement.classList.toggle('light', !isDark);
  }, [isDark]);

  const activeInstance = useMemo(() => 
    org.instances.find(i => i.id === activeInstanceId)
  , [org.instances, activeInstanceId]);

  const handleLogin = (mockUser: User) => setUser(mockUser);
  const handleLogout = () => {
    setUser(null);
    setHasStarted(false);
  };

  const handleDeployAgents = useCallback((config: { provider: string; vCPU: string; ram: string; region: string; quantity: number; namePrefix: string; factoryId: string }) => {
    const newInstances: AgentInstance[] = Array.from({ length: config.quantity }).map((_, i) => {
      const chatId = `chat-${Date.now()}-${i}`;
      return {
        id: `agent-${Date.now()}-${i}`,
        name: `${config.namePrefix}-${String(i + 1).padStart(2, '0')}`,
        provider: config.provider,
        vCPU: config.vCPU,
        ram: config.ram,
        region: config.region,
        status: 'running',
        groupId: config.factoryId,
        activeChatId: chatId,
        chats: [
          {
            id: chatId,
            name: 'Primary Link',
            lastUpdate: new Date().toLocaleTimeString().slice(0, 5),
            messages: [{ role: 'agent', content: `[SYSTEM] Instance online in ${config.factoryId}. Uplink established.`, timestamp: new Date().toLocaleTimeString().slice(0, 5) }]
          }
        ]
      };
    });

    setOrg(prev => ({
      ...prev,
      instances: [...prev.instances, ...newInstances],
      factories: prev.factories.map(f => f.id === config.factoryId ? {
        ...f,
        instances: [...f.instances, ...newInstances.map(ni => ni.id)]
      } : f)
    }));

    setShowDeployModal(false);
    if (newInstances.length > 0) {
      setActiveInstanceId(newInstances[0].id);
      setViewMode('terminal');
    }
  }, []);

  const handleKillAgent = (agentId: string) => {
    setOrg(prev => ({
      ...prev,
      instances: prev.instances.filter(a => a.id !== agentId),
      factories: prev.factories.map(f => ({ ...f, instances: f.instances.filter(id => id !== agentId) }))
    }));
    if (activeInstanceId === agentId) {
      setActiveInstanceId(null);
      setViewMode('matrix');
    }
  };

  const handleSendMessage = async (instanceId: string, chatId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);

    setOrg(prev => ({
      ...prev,
      instances: prev.instances.map(i => i.id === instanceId ? {
        ...i,
        chats: i.chats.map(c => c.id === chatId ? {
          ...c,
          isThinking: true,
          messages: [...c.messages, { role: 'user', content, timestamp }]
        } : c)
      } : i)
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const instance = org.instances.find(i => i.id === instanceId)!;
      const chat = instance.chats.find(c => c.id === chatId)!;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Factory Context: ${instance.name} (${instance.provider}). Line: ${instance.groupId}. Request: ${content}`,
      });

      const aiText = response.text || "Communication timeout.";

      setOrg(prev => ({
        ...prev,
        instances: prev.instances.map(i => i.id === instanceId ? {
          ...i,
          chats: i.chats.map(c => c.id === chatId ? {
            ...c,
            isThinking: false,
            messages: [...c.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }],
            lastUpdate: new Date().toLocaleTimeString().slice(0, 5)
          } : c)
        } : i)
      }));
      setCredits(c => c - 0.05);
    } catch (error) {
       setOrg(prev => ({
        ...prev,
        instances: prev.instances.map(i => i.id === instanceId ? {
          ...i,
          chats: i.chats.map(c => c.id === chatId ? { ...c, isThinking: false } : c)
        } : i)
      }));
    }
  };

  const totalVCPU = useMemo(() => org.instances.reduce((acc, curr) => acc + parseInt(curr.vCPU), 0), [org.instances]);
  const totalRAM = useMemo(() => org.instances.reduce((acc, curr) => acc + parseInt(curr.ram), 0), [org.instances]);

  if (!hasStarted) return <LandingView onEnterIDE={() => setHasStarted(true)} />;
  if (!user) return <LoginView onLogin={handleLogin} />;

  return (
    <div className="h-screen w-screen flex flex-col bg-white dark:bg-[#050505] overflow-hidden font-inter text-black dark:text-neutral-200 transition-colors duration-500">

      {/* Dynamic Header / Breadcrumbs */}
      <header className="h-16 border-b border-black/5 dark:border-white/5 bg-white/50 dark:bg-black/50 backdrop-blur-3xl flex items-center justify-between px-6 shrink-0 z-50">
        <div className="flex items-center gap-6">
          <button className="font-serif font-bold text-lg tracking-[0.2em] uppercase" onClick={() => setHasStarted(false)}>Reflecter</button>
          <div className="h-6 w-px bg-black/10 dark:bg-white/10"></div>

          <nav className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-neutral-400">
             <button onClick={() => setViewMode('matrix')} className="hover:text-black dark:hover:text-white transition-colors">FACTORY_FLOOR</button>
             {activeInstance && (
               <>
                 <Icon name="chevron-right" size={10} className="opacity-30" />
                 <span className="text-blue-500">{org.factories.find(f => f.id === activeInstance.groupId)?.name}</span>
                 <Icon name="chevron-right" size={10} className="opacity-30" />
                 <span className="text-black dark:text-white">{activeInstance.name}</span>
               </>
             )}
          </nav>
        </div>

        <div className="flex items-center gap-6">
           <div className="hidden lg:flex items-center gap-4 text-[10px] font-mono border-r border-black/10 dark:border-white/10 pr-6">
              <span className="text-neutral-500 uppercase">Balance:</span>
              <span className="text-green-500 font-bold">${credits.toFixed(2)}</span>
           </div>

           <button onClick={() => setIsDark(!isDark)} className="p-2 text-neutral-400 hover:text-black dark:hover:text-white">
              <Icon name={isDark ? "CONFIG" : "action"} size={16} />
           </button>

           <button onClick={() => setShowDeployModal(true)} className="bg-black dark:bg-white text-white dark:text-black px-5 py-2 rounded-lg text-[10px] font-bold uppercase tracking-widest hover:scale-105 active:scale-95 transition-all">
             Provision
           </button>

           <div className="flex items-center gap-3 ml-2 border-l border-black/10 dark:border-white/10 pl-6">
              <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.email}`} className="w-8 h-8 rounded-full border border-black/10 dark:border-white/10" alt="Avatar" />
              <button onClick={handleLogout} className="p-2 text-neutral-400 hover:text-red-500 transition-colors">
                 <Icon name="close" size={16} />
              </button>
           </div>
        </div>
      </header>

      {/* Main Orchestration Space */}
      <div className="flex-1 flex overflow-hidden">

        {/* VSCode Style Factory Sidebar */}
        <FactorySidebar 
          org={org}
          activeId={activeInstanceId}
          onSelect={(id) => { setActiveInstanceId(id); setViewMode('terminal'); }}
          onKill={handleKillAgent}
        />

        <main className="flex-1 flex flex-col overflow-hidden relative bg-neutral-50/30 dark:bg-neutral-950/30">
          {viewMode === 'matrix' ? (
            <FleetMatrix 
              org={org}
              onSelect={(id) => { setActiveInstanceId(id); setViewMode('terminal'); }}
              onKill={handleKillAgent}
              onDeploy={() => setShowDeployModal(true)}
            />
          ) : (
            <section className="flex-1 flex flex-col overflow-hidden p-4">
              {activeInstance ? (
                <TerminalPane 
                  instance={activeInstance}
                  onSendMessage={(chatId, msg) => handleSendMessage(activeInstance.id, chatId, msg)}
                  onNewChat={() => {}} // Simplified for brevity
                  onSwitchChat={() => {}} 
                  onClose={() => { setViewMode('matrix'); setActiveInstanceId(null); }}
                />
              ) : (
                <div className="flex-1 flex flex-col items-center justify-center space-y-4 opacity-30">
                   <Icon name="AGENT" size={48} />
                   <p className="text-[10px] uppercase font-bold tracking-[0.5em]">Select Production Node</p>
                </div>
              )}
            </section>
          )}
        </main>
      </div>

      <footer className="h-8 border-t border-black/5 dark:border-white/5 bg-white dark:bg-black flex items-center justify-between px-6 z-50 shrink-0 text-[8px] uppercase font-bold tracking-[0.3em] text-neutral-400">
         <div className="flex gap-4">
            <span className="flex items-center gap-2"><div className="w-1.5 h-1.5 bg-green-500 rounded-full pulse-running"></div>FACTORY_STATUS: OPTIMAL</span>
            <span>COMPUTE: {totalVCPU} vCPU / {totalRAM} GB</span>
         </div>
         <div className="flex gap-4">
            <span>MASTER_UPLINK: ACTIVE</span>
            <span>v5.0.0_STABLE</span>
         </div>
      </footer>

      {showDeployModal && <DeployModal onClose={() => setShowDeployModal(false)} onDeploy={handleDeployAgents} factories={org.factories} />}
    </div>
  );
}

import React, { useState } from 'react';
import { Organization, FactoryGroup } from '../types';
import Icon from './Icon';

interface FactorySidebarProps {
  org: Organization;
  activeId: string | null;
  onSelect: (id: string) => void;
  onKill: (id: string) => void;
}

const FactorySidebar: React.FC<FactorySidebarProps> = ({ org, activeId, onSelect, onKill }) => {
  const [collapsedFactories, setCollapsedFactories] = useState<string[]>([]);

  const toggleFactory = (id: string) => {
    setCollapsedFactories(prev => 
      prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]
    );
  };

  return (
    <aside className="w-64 border-r border-black/5 dark:border-white/5 bg-white/40 dark:bg-black/60 backdrop-blur-3xl flex flex-col shrink-0 select-none">
      <div className="p-4 border-b border-black/5 dark:border-white/5 flex items-center justify-between">
         <span className="text-[10px] font-bold uppercase tracking-[0.2em] text-neutral-500">Production Lines</span>
         <button className="text-neutral-400 hover:text-black dark:hover:text-white"><Icon name="search" size={14}/></button>
      </div>

      <div className="flex-1 overflow-y-auto p-2 space-y-2 no-scrollbar">
        {org.factories.map(factory => (
          <div key={factory.id} className="space-y-1">
            <div 
              onClick={() => toggleFactory(factory.id)}
              className="flex items-center gap-2 px-3 py-2 cursor-pointer group hover:bg-black/5 dark:hover:bg-white/5 rounded-lg transition-all"
            >
              <Icon 
                name={collapsedFactories.includes(factory.id) ? "chevron-right" : "chevron-down"} 
                size={10} 
                className="text-neutral-500" 
              />
              <span className="text-[10px] font-bold uppercase tracking-widest text-neutral-400 group-hover:text-black dark:group-hover:text-white">
                {factory.name}
              </span>
              <span className="ml-auto text-[8px] font-mono opacity-30">{factory.instances.length}</span>
            </div>

            {!collapsedFactories.includes(factory.id) && (
              <div className="ml-2 pl-3 border-l border-black/5 dark:border-white/10 space-y-0.5">
                {org.instances.filter(i => i.groupId === factory.id).map(instance => (
                  <div 
                    key={instance.id}
                    onClick={() => onSelect(instance.id)}
                    className={`group flex items-center justify-between p-2 rounded-lg cursor-pointer transition-all border ${
                      activeId === instance.id 
                      ? 'bg-blue-500/10 border-blue-500/20 text-blue-500' 
                      : 'border-transparent hover:bg-black/5 dark:hover:bg-white/5 text-neutral-500'
                    }`}
                  >
                    <div className="flex items-center gap-3 min-w-0">
                      <div className={`w-1.5 h-1.5 rounded-full ${instance.status === 'running' ? 'bg-green-500 pulse-running' : 'bg-neutral-300'}`}></div>
                      <span className="text-[11px] font-medium truncate uppercase tracking-tighter">{instance.name}</span>
                    </div>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onKill(instance.id); }}
                      className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-500 transition-all"
                    >
                      <Icon name="close" size={12} />
                    </button>
                  </div>
                ))}
                {factory.instances.length === 0 && (
                   <p className="text-[8px] text-neutral-500 italic p-2 uppercase tracking-widest opacity-30">No active nodes</p>
                )}
              </div>
            )}
          </div>
        ))}
      </div>

      <div className="p-4 border-t border-black/5 dark:border-white/5">
         <div className="bg-black/5 dark:bg-white/5 rounded-xl p-4 space-y-3">
            <div className="flex justify-between items-center text-[8px] uppercase font-bold tracking-widest text-neutral-400">
               <span>Fleet Capacity</span>
               <span>78%</span>
            </div>
            <div className="h-1 bg-black/10 dark:bg-white/10 rounded-full overflow-hidden">
               <div className="h-full bg-blue-500 w-[78%]"></div>
            </div>
         </div>
      </div>
    </aside>
  );
};

