import React, { useState, useRef, useEffect } from 'react';
import Icon from './Icon';
import { AgentInstance, ChatSession } from '../types';

interface TerminalPaneProps {
  instance: AgentInstance;
  onSendMessage: (chatId: string, content: string) => void;
  onNewChat: () => void;
  onSwitchChat: (chatId: string) => void;
  onClose?: () => void;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  instance, onSendMessage, onNewChat, onSwitchChat, onClose
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const activeChat = instance.chats.find(c => c.id === instance.activeChatId) || instance.chats[0];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [activeChat.messages, activeChat.isThinking]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !activeChat.isThinking) {
      onSendMessage(activeChat.id, input);
      setInput('');
    }
  };

  return (
    <div className="h-full w-full flex overflow-hidden relative rounded-2xl glass-pane border border-black/5 dark:border-white/5 shadow-2xl bg-white dark:bg-black/40">

      {/* Session Browser (Left Sidebar in Terminal) */}
      <aside className="w-56 border-r border-black/5 dark:border-white/5 flex flex-col shrink-0 bg-black/[0.02] dark:bg-white/[0.01]">
        <div className="p-5 border-b border-black/5 dark:border-white/5">
          <span className="text-[9px] font-bold uppercase tracking-[0.3em] text-neutral-500">Node Sessions</span>
        </div>

        <div className="flex-1 overflow-y-auto p-2 space-y-1 no-scrollbar">
          {instance.chats.map(chat => (
            <div 
              key={chat.id}
              onClick={() => onSwitchChat(chat.id)}
              className={`px-4 py-3 rounded-xl cursor-pointer transition-all border ${
                instance.activeChatId === chat.id 
                ? 'bg-black text-white dark:bg-white dark:text-black border-transparent shadow-lg' 
                : 'border-transparent hover:bg-black/5 dark:hover:bg-white/5 text-neutral-500'
              }`}
            >
              <div className="text-[10px] font-bold uppercase tracking-tight truncate">{chat.name}</div>
              <div className="text-[7px] mt-1 font-mono uppercase opacity-40">{chat.lastUpdate}</div>
            </div>
          ))}
        </div>

        <button 
          onClick={onNewChat}
          className="m-4 py-3 border border-dashed border-black/10 dark:border-white/10 rounded-xl text-[9px] uppercase font-bold tracking-widest text-neutral-400 hover:text-black dark:hover:text-white transition-all flex items-center justify-center gap-2"
        >
          <Icon name="close" size={10} className="rotate-45" />
          Branch Link
        </button>
      </aside>

      {/* Direct Uplink Console */}
      <div className="flex-1 flex flex-col overflow-hidden relative">
        <header className="flex items-center justify-between h-16 px-8 border-b border-black/5 dark:border-white/5 shrink-0 bg-white/10 dark:bg-black/10 backdrop-blur-md">
          <div className="flex items-center gap-4">
            <div className="w-2.5 h-2.5 rounded-full bg-green-500 shadow-[0_0_10px_rgba(34,197,94,0.5)] pulse-running"></div>
            <div className="flex flex-col">
              <span className="text-[11px] font-bold uppercase tracking-[0.2em] text-black dark:text-white">Uplink: {instance.name}</span>
              <span className="text-[8px] text-neutral-500 font-bold uppercase tracking-widest">Protocol: RSA-4096 Factory Standard</span>
            </div>
          </div>

          <button onClick={onClose} className="p-2 text-neutral-400 hover:text-red-500 transition-all">
             <Icon name="close" size={18} />
          </button>
        </header>

        {/* Message Stream */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-10 scroll-smooth no-scrollbar">
          <div className="max-w-2xl mx-auto space-y-10">
            {activeChat.messages.map((msg, i) => (
              <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in duration-500`}>
                <div className={`max-w-[90%] rounded-2xl px-6 py-4 text-[13px] leading-relaxed ${
                  msg.role === 'user' 
                  ? 'bg-blue-600 text-white shadow-xl' 
                  : 'bg-black/5 dark:bg-white/5 text-neutral-800 dark:text-neutral-200 border border-black/5 dark:border-white/5'
                }`}>
                  {msg.content}
                </div>
                <span className="text-[8px] uppercase font-bold tracking-[0.4em] mt-3 text-neutral-400 font-mono px-2">
                  {msg.role === 'agent' ? `${instance.name}` : `Master_Operator`} • {msg.timestamp}
                </span>
              </div>
            ))}
            {activeChat.isThinking && (
              <div className="flex items-center gap-3 text-blue-500 text-[10px] font-bold tracking-[0.4em] animate-pulse ml-2 uppercase">
                <Icon name="play" size={12} className="animate-spin" />
                Processing_Neural_Weights...
              </div>
            )}
          </div>
        </div>

        {/* Command Input */}
        <div className="p-8 shrink-0">
          <form onSubmit={handleSubmit} className="max-w-2xl mx-auto flex gap-4 items-center bg-white dark:bg-neutral-900 border border-black/5 dark:border-white/10 p-3 rounded-2xl shadow-xl focus-within:ring-2 ring-blue-500/20 transition-all">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              disabled={activeChat.isThinking}
              placeholder={activeChat.isThinking ? "Node busy..." : "Broadcast command..."}
              className="bg-transparent border-none outline-none flex-1 px-5 text-[13px] text-black dark:text-white placeholder:text-neutral-400 dark:placeholder:text-neutral-700 font-inter py-3 disabled:opacity-50"
              autoFocus
            />
            <button 
              type="submit" 
              disabled={!input.trim() || activeChat.isThinking}
              className="w-12 h-12 flex items-center justify-center bg-blue-600 text-white rounded-xl hover:bg-blue-700 active:scale-95 disabled:opacity-20 transition-all"
            >
              <Icon name="play" size={18} />
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

