    setHasStarted(false);
  };

  const handleDeployAgents = useCallback((config: { provider: string; vCPU: string; ram: string; region: string; quantity: number; namePrefix: string; factoryId: string }) => {
    const newInstances: AgentInstance[] = Array.from({ length: config.quantity }).map((_, i) => {
      const chatId = `chat-${Date.now()}-${i}`;
      return {
        id: `agent-${Date.now()}-${i}`,
        name: `${config.namePrefix}-${String(i + 1).padStart(2, '0')}`,
        provider: config.provider,
        vCPU: config.vCPU,
        ram: config.ram,
        region: config.region,
        status: 'running',
        groupId: config.factoryId,
        activeChatId: chatId,
        chats: [
          {
            id: chatId,
            name: 'Primary Stream',
            lastUpdate: new Date().toLocaleTimeString().slice(0, 5),
            messages: [{ role: 'agent', content: `[SYSTEM] Uplink established for ${config.namePrefix}-${i+1}. Factory node online.`, timestamp: new Date().toLocaleTimeString().slice(0, 5) }]
          }
        ]
      };
    });

    setOrg(prev => ({
      ...prev,
      instances: [...prev.instances, ...newInstances],
      factories: prev.factories.map(f => f.id === config.factoryId ? {
        ...f,
        instances: [...f.instances, ...newInstances.map(ni => ni.id)]
      } : f)
    }));

    setShowDeployModal(false);
    if (newInstances.length > 0) {
      setActiveInstanceId(newInstances[0].id);
      setViewMode('terminal');
    }
  }, []);

  const handleKillAgent = (agentId: string) => {
    setOrg(prev => ({
      ...prev,
      instances: prev.instances.filter(a => a.id !== agentId),
      factories: prev.factories.map(f => ({ ...f, instances: f.instances.filter(id => id !== agentId) }))
    }));
    if (activeInstanceId === agentId) {
      setActiveInstanceId(null);
      setViewMode('matrix');
    }
  };

  const handleSendMessage = async (instanceId: string, chatId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString('en-GB', { hour12: false }).slice(0, 5);

    setOrg(prev => ({
      ...prev,
      instances: prev.instances.map(i => i.id === instanceId ? {
        ...i,
        chats: i.chats.map(c => c.id === chatId ? {
          ...c,
          isThinking: true,
          messages: [...c.messages, { role: 'user', content, timestamp }]
        } : c)
      } : i)
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const instance = org.instances.find(i => i.id === instanceId)!;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Factory Instance: ${instance.name}. Prompt: ${content}`,
      });

      const aiText = response.text || "Node connection unstable.";

      setOrg(prev => ({
        ...prev,
        instances: prev.instances.map(i => i.id === instanceId ? {
          ...i,
          chats: i.chats.map(c => c.id === chatId ? {
            ...c,
            isThinking: false,
            messages: [...c.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }],
            lastUpdate: new Date().toLocaleTimeString().slice(0, 5)
          } : c)
        } : i)
      }));
      setCredits(c => c - 0.05);
    } catch (error) {
       setOrg(prev => ({
        ...prev,
        instances: prev.instances.map(i => i.id === instanceId ? {
          ...i,
          chats: i.chats.map(c => c.id === chatId ? { ...c, isThinking: false } : c)
        } : i)
      }));
    }
  };

  const totalVCPU = useMemo(() => org.instances.reduce((acc, curr) => acc + parseInt(curr.vCPU), 0), [org.instances]);
  const totalRAM = useMemo(() => org.instances.reduce((acc, curr) => acc + parseInt(curr.ram), 0), [org.instances]);

  if (!hasStarted) return <LandingView onEnterIDE={() => setHasStarted(true)} />;
  if (!user) return <LoginView onLogin={handleLogin} />;

  return (
    <div className="h-screen w-screen flex flex-col bg-white dark:bg-[#000000] overflow-hidden font-sans text-slate-900 dark:text-slate-100">

      <header className="h-14 border-b border-black/5 dark:border-white/5 bg-white/50 dark:bg-black/40 backdrop-blur-xl flex items-center justify-between px-6 shrink-0 z-50">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3 group cursor-pointer" onClick={() => setHasStarted(false)}>
            <div className="w-7 h-7 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-500/20 group-hover:rotate-12 transition-transform">
               <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
            </div>
            <span className="font-heading font-bold text-lg tracking-tight">REFLECTER</span>
          </div>

          <div className="h-5 w-px bg-slate-200 dark:bg-white/10"></div>

          <nav className="flex items-center gap-2 text-[11px] font-semibold tracking-wide text-slate-400">
             <button onClick={() => setViewMode('matrix')} className={`hover:text-blue-500 transition-colors ${viewMode === 'matrix' ? 'text-blue-500' : ''}`}>FLOOR</button>
             {activeInstance && (
               <>
                 <Icon name="chevron-right" size={12} className="opacity-30" />
                 <span className="text-slate-900 dark:text-slate-200">{activeInstance.name}</span>
               </>
             )}
          </nav>
        </div>

        <div className="flex items-center gap-5">
           <div className="hidden md:flex items-center gap-2 px-3 py-1.5 bg-slate-100 dark:bg-white/5 rounded-full border border-black/5 dark:border-white/5">
              <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
              <span className="text-[10px] font-mono font-bold text-slate-500 dark:text-slate-400">${credits.toFixed(2)}</span>
           </div>

           <button onClick={() => setIsDark(!isDark)} className="p-2 text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors">
              <Icon name={isDark ? "CONFIG" : "action"} size={16} />
           </button>

           <button onClick={() => setShowDeployModal(true)} className="bg-slate-900 dark:bg-white text-white dark:text-black px-4 py-1.5 rounded-lg text-[11px] font-bold hover:opacity-90 active:scale-95 transition-all shadow-sm">
             Deploy
           </button>

           <div className="flex items-center gap-2 border-l border-black/5 dark:border-white/5 pl-5">
              <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.email}`} className="w-7 h-7 rounded-full bg-slate-200 dark:bg-slate-800" alt="User" />
           </div>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        <FactorySidebar 
          org={org}
          activeId={activeInstanceId}
          onSelect={(id) => { setActiveInstanceId(id); setViewMode('terminal'); }}
          onKill={handleKillAgent}
        />

        <main className="flex-1 flex flex-col overflow-hidden relative">
          {viewMode === 'matrix' ? (
            <FleetMatrix 
              org={org}
              onSelect={(id) => { setActiveInstanceId(id); setViewMode('terminal'); }}
              onKill={handleKillAgent}
              onDeploy={() => setShowDeployModal(true)}
            />
          ) : (
            <section className="flex-1 flex flex-col overflow-hidden p-5">
              {activeInstance ? (
                <TerminalPane 
                  instance={activeInstance}
                  onSendMessage={(chatId, msg) => handleSendMessage(activeInstance.id, chatId, msg)}
                  onNewChat={() => {}}
                  onSwitchChat={() => {}} 
                  onClose={() => { setViewMode('matrix'); setActiveInstanceId(null); }}
                />
              ) : (
                <div className="flex-1 flex flex-col items-center justify-center opacity-20">
                   <Icon name="AGENT" size={64} className="mb-4 text-slate-400" />
                   <p className="font-heading font-medium tracking-[0.2em] text-xs">AWAITING INSTANCE SELECTION</p>
                </div>
              )}
            </section>
          )}
        </main>
      </div>

      <footer className="h-6 border-t border-black/5 dark:border-white/5 bg-white dark:bg-black/60 flex items-center justify-between px-6 shrink-0 text-[9px] font-mono font-medium text-slate-400 tracking-wider">
         <div className="flex gap-4">
            <span className="flex items-center gap-1.5"><div className="w-1 h-1 bg-green-500 rounded-full ring-pulse"></div>SYSTEM: ACTIVE</span>
            <span>CAPACITY: {totalVCPU}v / {totalRAM}GB</span>
         </div>
         <div className="flex gap-4 opacity-50">
            <span>STABLE_RELD_5.1.0</span>
         </div>
      </footer>

      {showDeployModal && <DeployModal onClose={() => setShowDeployModal(false)} onDeploy={handleDeployAgents} factories={org.factories} />}
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import Icon from './Icon';
import { AgentInstance, ChatSession } from '../types';

interface TerminalPaneProps {
  instance: AgentInstance;
  onSendMessage: (chatId: string, content: string) => void;
  onNewChat: () => void;
  onSwitchChat: (chatId: string) => void;
  onClose?: () => void;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  instance, onSendMessage, onNewChat, onSwitchChat, onClose
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const activeChat = instance.chats.find(c => c.id === instance.activeChatId) || instance.chats[0];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [activeChat.messages, activeChat.isThinking]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !activeChat.isThinking) {
      onSendMessage(activeChat.id, input);
      setInput('');
    }
  };

  return (
    <div className="h-full w-full flex overflow-hidden relative rounded-3xl glass-pane shadow-2xl overflow-hidden">

      {/* Session Navigation */}
      <aside className="w-52 border-r border-black/5 dark:border-white/5 flex flex-col shrink-0 bg-slate-50/50 dark:bg-black/20">
        <div className="p-5">
          <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Contexts</span>
        </div>

        <div className="flex-1 overflow-y-auto p-2 space-y-1 no-scrollbar">
          {instance.chats.map(chat => (
            <div 
              key={chat.id}
              onClick={() => onSwitchChat(chat.id)}
              className={`px-4 py-2.5 rounded-xl cursor-pointer transition-all ${
                instance.activeChatId === chat.id 
                ? 'bg-slate-900 text-white dark:bg-white dark:text-black shadow-md' 
                : 'text-slate-500 hover:bg-slate-200/50 dark:hover:bg-white/5'
              }`}
            >
              <div className="text-[11px] font-bold truncate">{chat.name}</div>
              <div className="text-[8px] font-mono opacity-40">{chat.lastUpdate}</div>
            </div>
          ))}
        </div>

        <div className="p-3">
           <button 
             onClick={onNewChat}
             className="w-full py-2.5 bg-slate-100 dark:bg-white/5 rounded-xl text-[10px] font-bold uppercase tracking-widest text-slate-500 hover:text-slate-900 dark:hover:text-white transition-all flex items-center justify-center gap-2"
           >
              <Icon name="close" size={12} className="rotate-45" />
              New Stream
           </button>
        </div>
      </aside>

      {/* Interface */}
      <div className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-14 px-6 border-b border-black/5 dark:border-white/5 flex items-center justify-between bg-white/30 dark:bg-black/10">
          <div className="flex items-center gap-3">
            <div className="w-2 h-2 rounded-full bg-blue-500 ring-pulse"></div>
            <div className="flex flex-col">
              <span className="text-[11px] font-bold tracking-tight text-slate-900 dark:text-white">UPLINK: {instance.name}</span>
              <span className="text-[9px] font-medium text-slate-400 uppercase tracking-tighter">{instance.provider} • SECURE</span>
            </div>
          </div>

          <button onClick={onClose} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
             <Icon name="close" size={18} />
          </button>
        </header>

        {/* Messaging Area */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 scroll-smooth no-scrollbar">
          <div className="max-w-2xl mx-auto space-y-8">
            {activeChat.messages.map((msg, i) => (
              <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[85%] px-5 py-3.5 rounded-2xl text-[13px] leading-relaxed ${
                  msg.role === 'user' 
                  ? 'bg-blue-600 text-white shadow-lg' 
                  : 'bg-slate-100 dark:bg-white/5 text-slate-800 dark:text-slate-200 border border-black/5 dark:border-white/5'
                }`}>
                  {msg.content}
                </div>
                <span className="text-[9px] font-bold tracking-wider mt-2.5 text-slate-400 uppercase font-mono px-1">
                  {msg.role === 'agent' ? instance.name : 'Master'} • {msg.timestamp}
                </span>
              </div>
            ))}
            {activeChat.isThinking && (
              <div className="flex items-center gap-2.5 text-blue-500 text-[10px] font-bold tracking-widest ml-1 animate-pulse">
                <div className="flex gap-1">
                   <div className="w-1 h-1 bg-current rounded-full"></div>
                   <div className="w-1 h-1 bg-current rounded-full"></div>
                </div>
                NEURAL_SYNTHESIS...
              </div>
            )}
          </div>
        </div>

        {/* Modern Input */}
        <div className="px-8 pb-8">
          <form onSubmit={handleSubmit} className="max-w-2xl mx-auto flex gap-3 items-center bg-white dark:bg-slate-900 border border-black/5 dark:border-white/10 p-2.5 rounded-2xl shadow-xl focus-within:ring-2 ring-blue-500/20 transition-all">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              disabled={activeChat.isThinking}
              placeholder={activeChat.isThinking ? "Node processing..." : "Direct command..."}
              className="bg-transparent border-none outline-none flex-1 px-4 text-sm text-slate-900 dark:text-white placeholder:text-slate-300 dark:placeholder:text-slate-700 py-2.5"
              autoFocus
            />
            <button 
              type="submit" 
              disabled={!input.trim() || activeChat.isThinking}
              className="w-10 h-10 flex items-center justify-center bg-slate-900 dark:bg-white text-white dark:text-black rounded-xl hover:opacity-90 active:scale-95 disabled:opacity-20 transition-all"
            >
              <Icon name="play" size={16} />
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

