import React, { useState, useCallback, useEffect } from 'react';
import { User, AgentInstance, Message } from './types';
import Icon from './components/Icon';
import { GoogleGenAI } from "@google/genai";
import LandingView from './components/LandingView';
import LoginModal from './components/LoginModal';
import FactoryFloor from './components/FactoryFloor';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'entry' | 'active'>('entry');
  const [instances, setInstances] = useState<AgentInstance[]>([]);
  const [showLogin, setShowLogin] = useState(false);
  const [pendingCount, setPendingCount] = useState(1);

  const handleLaunchRequest = (count: number) => {
    setPendingCount(count);
    if (!user) {
      setShowLogin(true);
    } else {
      deployInstances(count);
    }
  };

  const deployInstances = (count: number) => {
    const newInstances: AgentInstance[] = Array.from({ length: count }).map((_, i) => {
      const id = `node-${Math.random().toString(36).substr(2, 9)}`;
      const timestamp = new Date().toLocaleTimeString().slice(0, 5);
      const initialMessage = { 
        role: 'agent' as const, 
        content: `Node initialized. Synchronizing neural weights...`, 
        timestamp 
      };

      return {
        id,
        name: `AGENT_${String(instances.length + i + 1).padStart(3, '0')}`,
        status: 'booting',
        provider: 'Gemini 3.0 Flash',
        vCPU: '2 vCPU',
        ram: '2 GB RAM',
        region: 'us-central1 (Iowa)',
        messages: [initialMessage],
        chats: [{
          id: 'chat-default',
          name: 'Main Stream',
          lastUpdate: timestamp,
          messages: [initialMessage]
        }],
        activeChatId: 'chat-default'
      };
    });

    setInstances(prev => [...prev, ...newInstances]);
    setView('active');

    // Simulate boot sequence
    newInstances.forEach(ni => {
      setTimeout(() => {
        setInstances(prev => prev.map(inst => inst.id === ni.id ? { ...inst, status: 'online' } : inst));
      }, 1000 + Math.random() * 2000);
    });
  };

  const handleSendMessage = async (id: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);
    setInstances(prev => prev.map(inst => inst.id === id ? {
      ...inst,
      isThinking: true,
      messages: [...inst.messages, { role: 'user', content, timestamp }]
    } : inst));

    try {
      // Create a new instance right before making an API call
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: content,
      });

      const aiText = response.text || "Connection lost.";
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        isThinking: false,
        messages: [...inst.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }]
      } : inst));
    } catch (e) {
      setInstances(prev => prev.map(inst => inst.id === id ? { ...inst, isThinking: false } : inst));
    }
  };

  return (
    <div className="h-screen w-screen bg-black text-white font-sans overflow-hidden selection:bg-white selection:text-black">
      {view === 'entry' ? (
        <LandingView onLaunch={handleLaunchRequest} />
      ) : (
        <FactoryFloor 
          instances={instances} 
          onSendMessage={handleSendMessage} 
          onBack={() => setView('entry')}
          onAddMore={() => handleLaunchRequest(1)}
        />
      )}

      {showLogin && (
        <LoginModal 
          onClose={() => setShowLogin(false)} 
          onSuccess={(u) => {
            setUser(u);
            setShowLogin(false);
            deployInstances(pendingCount);
          }} 
        />
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import Icon from './Icon';
