interface TerminalPaneProps {
  instance: AgentInstance;
  onSendMessage: (chatId: string, content: string) => void;
  onNewChat: () => void;
  onSwitchChat: (chatId: string) => void;
  onClose?: () => void;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  instance, onSendMessage, onNewChat, onSwitchChat, onClose
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // Guard against missing chats array or activeChatId
  const activeChat = (instance.chats && instance.chats.length > 0) 
    ? (instance.chats.find(c => c.id === instance.activeChatId) || instance.chats[0])
    : null;

  useEffect(() => {
    if (scrollRef.current && activeChat) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [activeChat?.messages, activeChat?.isThinking]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && activeChat && !activeChat.isThinking) {
      onSendMessage(activeChat.id, input);
      setInput('');
    }
  };

  if (!activeChat) {
    return (
      <div className="h-full w-full flex items-center justify-center bg-slate-50/50 dark:bg-black/20 text-slate-400 font-mono text-xs rounded-3xl">
        INITIALIZING NEURAL STREAM...
