        </div>

        <div className="flex-1 overflow-y-auto p-2 space-y-1 no-scrollbar">
          {instance.chats.map(chat => (
            <div 
              key={chat.id}
              onClick={() => onSwitchChat(chat.id)}
              className={`px-4 py-2.5 rounded-xl cursor-pointer transition-all ${
                instance.activeChatId === chat.id 
                ? 'bg-slate-900 text-white dark:bg-white dark:text-black shadow-md' 
                : 'text-slate-500 hover:bg-slate-200/50 dark:hover:bg-white/5'
              }`}
            >
              <div className="text-[11px] font-bold truncate">{chat.name}</div>
              <div className="text-[8px] font-mono opacity-40">{chat.lastUpdate}</div>
            </div>
          ))}
        </div>

        <div className="p-3">
           <button 
             onClick={onNewChat}
             className="w-full py-2.5 bg-slate-100 dark:bg-white/5 rounded-xl text-[10px] font-bold uppercase tracking-widest text-slate-500 hover:text-slate-900 dark:hover:text-white transition-all flex items-center justify-center gap-2"
           >
              <Icon name="close" size={12} className="rotate-45" />
              New Stream
           </button>
        </div>
      </aside>

      {/* Interface */}
      <div className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-14 px-6 border-b border-black/5 dark:border-white/5 flex items-center justify-between bg-white/30 dark:bg-black/10">
          <div className="flex items-center gap-3">
            <div className="w-2 h-2 rounded-full bg-blue-500 ring-pulse"></div>
            <div className="flex flex-col">
              <span className="text-[11px] font-bold tracking-tight text-slate-900 dark:text-white">UPLINK: {instance.name}</span>
              <span className="text-[9px] font-medium text-slate-400 uppercase tracking-tighter">{instance.provider} • SECURE</span>
            </div>
          </div>

          <button onClick={onClose} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
             <Icon name="close" size={18} />
          </button>
        </header>

        {/* Messaging Area */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 scroll-smooth no-scrollbar">
          <div className="max-w-2xl mx-auto space-y-8">
            {activeChat.messages.map((msg, i) => (
              <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[85%] px-5 py-3.5 rounded-2xl text-[13px] leading-relaxed ${
                  msg.role === 'user' 
                  ? 'bg-blue-600 text-white shadow-lg' 
                  : 'bg-slate-100 dark:bg-white/5 text-slate-800 dark:text-slate-200 border border-black/5 dark:border-white/5'
                }`}>
                  {msg.content}
                </div>
                <span className="text-[9px] font-bold tracking-wider mt-2.5 text-slate-400 uppercase font-mono px-1">
                  {msg.role === 'agent' ? instance.name : 'Master'} • {msg.timestamp}
                </span>
              </div>
            ))}
            {activeChat.isThinking && (
              <div className="flex items-center gap-2.5 text-blue-500 text-[10px] font-bold tracking-widest ml-1 animate-pulse">
                <div className="flex gap-1">
                   <div className="w-1 h-1 bg-current rounded-full"></div>
                   <div className="w-1 h-1 bg-current rounded-full"></div>
                </div>
                NEURAL_SYNTHESIS...
              </div>
            )}
          </div>
        </div>

        {/* Modern Input */}
        <div className="px-8 pb-8">
          <form onSubmit={handleSubmit} className="max-w-2xl mx-auto flex gap-3 items-center bg-white dark:bg-slate-900 border border-black/5 dark:border-white/10 p-2.5 rounded-2xl shadow-xl focus-within:ring-2 ring-blue-500/20 transition-all">
            <input 
              type="text" 
              value={input}
