interface FactoryFloorProps {
  instances: AgentInstance[];
  onSendMessage: (id: string, content: string) => void;
  onBulkMessage: (ids: string[], content: string) => void;
  onBulkTag: (ids: string[], tag: string) => void;
  onBack: () => void;
  onAddMore: () => void;
}

const FactoryFloor: React.FC<FactoryFloorProps> = ({ 
  instances, onSendMessage, onBulkMessage, onBulkTag, onBack, onAddMore 
}) => {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [bulkMode, setBulkMode] = useState<'message' | 'tag' | null>(null);
  const [bulkValue, setBulkValue] = useState('');

  const toggleSelection = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]
    );
  };

  const selectAll = () => {
    if (selectedIds.length === instances.length) setSelectedIds([]);
    else setSelectedIds(instances.map(i => i.id));
  };

  const handleBulkAction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!bulkValue.trim()) return;

    if (bulkMode === 'message') {
      onBulkMessage(selectedIds, bulkValue);
    } else if (bulkMode === 'tag') {
      onBulkTag(selectedIds, bulkValue);
    }

    setBulkValue('');
    setBulkMode(null);
    setSelectedIds([]);
  };

  return (
    <div className="h-full w-full flex flex-col overflow-hidden animate-in fade-in duration-500 relative">
      <header className="h-16 border-b border-white/5 flex items-center justify-between px-8 shrink-0 bg-black/50 backdrop-blur-md z-30">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="group flex items-center gap-2 text-neutral-500 hover:text-white transition-all">
            <Icon name="chevron-right" size={14} className="rotate-180" />
            <span className="text-[10px] font-bold uppercase tracking-[0.3em]">Vault</span>
          </button>
          <div className="h-4 w-px bg-white/10"></div>
          <div className="flex items-center gap-4">
            <span className="text-[11px] font-heading font-bold uppercase tracking-widest text-white/90">Fleet Operation Center</span>
            <button 
              onClick={selectAll}
              className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1 rounded-full border transition-all ${
                selectedIds.length > 0 ? 'bg-white text-black border-white' : 'text-neutral-500 border-white/10 hover:border-white/30'
              }`}
            >
              {selectedIds.length === instances.length ? 'Deselect All' : 'Select Fleet'}
            </button>
          </div>
        </div>

        <button onClick={onAddMore} className="bg-white/5 hover:bg-white hover:text-black border border-white/10 px-4 py-1.5 rounded-full text-[9px] font-bold uppercase tracking-widest transition-all">
          Deploy Node
        </button>
      </header>

      <main className="flex-1 overflow-y-auto p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 no-scrollbar pb-32">
        {instances.map(instance => (
          <TerminalPane 
            key={instance.id} 
            instance={instance} 
            isSelected={selectedIds.includes(instance.id)}
            onSelect={() => toggleSelection(instance.id)}
            onSend={(msg) => onSendMessage(instance.id, msg)} 
          />
        ))}
      </main>

      {/* Floating Bulk Action Bar */}
      {selectedIds.length > 0 && (
        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-full max-w-2xl px-6 z-50 animate-in slide-in-from-bottom-10 duration-500">
          <div className="bg-neutral-900 border border-white/20 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/5 bg-white/5">
              <span className="text-[10px] font-bold uppercase tracking-[0.3em] text-blue-400">
                Bulk Action: {selectedIds.length} Nodes Selected
              </span>
              <div className="flex gap-2">
                <button 
                  onClick={() => setBulkMode('message')}
                  className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-all ${
                    bulkMode === 'message' ? 'bg-white text-black' : 'hover:bg-white/10'
                  }`}
                >
                  Broadcast
                </button>
                <button 
                  onClick={() => setBulkMode('tag')}
                  className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-all ${
                    bulkMode === 'tag' ? 'bg-white text-black' : 'hover:bg-white/10'
                  }`}
                >
                  Add Tag
                </button>
                <button 
                  onClick={() => { setSelectedIds([]); setBulkMode(null); }}
                  className="text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg hover:bg-red-500/20 text-red-400"
                >
                  Cancel
                </button>
              </div>
            </div>

            {bulkMode && (
              <form onSubmit={handleBulkAction} className="p-4 flex gap-4 animate-in fade-in duration-300">
                <input 
                  type="text"
                  value={bulkValue}
                  onChange={(e) => setBulkValue(e.target.value)}
                  placeholder={bulkMode === 'message' ? "Broadcast command to all selected..." : "Identifier (ej: dev-backend)..."}
                  className="flex-1 bg-black/50 border border-white/10 rounded-xl px-5 py-3 text-xs font-mono outline-none focus:border-blue-500 transition-all"
                  autoFocus
                />
                <button 
                  type="submit"
                  className="bg-white text-black px-6 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:scale-105 active:scale-95 transition-all"
                >
                  Execute
                </button>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

const TerminalPane: React.FC<{ 
  instance: AgentInstance, 
  onSend: (msg: string) => void,
  isSelected: boolean,
  onSelect: () => void
}> = ({ instance, onSend, isSelected, onSelect }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [instance.messages, instance.isThinking]);

  return (
    <div className={`h-[400px] bg-neutral-900/40 border rounded-2xl flex flex-col overflow-hidden group transition-all duration-500 ${
      isSelected ? 'border-blue-500 shadow-[0_0_30px_rgba(59,130,246,0.15)] ring-1 ring-blue-500/50' : 'border-white/5 hover:border-white/20'
    }`}>
      <div className="h-12 px-4 border-b border-white/5 flex items-center justify-between shrink-0 bg-black/20">
        <div className="flex items-center gap-3">
          <button 
            onClick={(e) => { e.stopPropagation(); onSelect(); }}
            className={`w-4 h-4 rounded border transition-all flex items-center justify-center ${
              isSelected ? 'bg-blue-500 border-blue-500' : 'border-white/20 group-hover:border-white/40'
            }`}
          >
            {isSelected && <Icon name="action" size={10} className="text-white" />}
          </button>

          <div className="flex flex-col">
            <div className="flex items-center gap-2">
              <div className={`w-1 h-1 rounded-full ${instance.status === 'online' ? 'bg-green-500 shadow-[0_0_5px_green]' : 'bg-yellow-500'}`}></div>
              <span className="text-[10px] font-mono font-bold text-neutral-400 group-hover:text-white transition-colors">{instance.name}</span>
            </div>

            {/* Tags Display */}
            {instance.tags.length > 0 && (
              <div className="flex gap-1.5 mt-1">
                {instance.tags.map(tag => (
                  <span key={tag} className="text-[7px] font-mono font-bold uppercase tracking-widest text-blue-400 bg-blue-400/10 px-1 rounded">
                    #{tag}
                  </span>
                ))}
              </div>
            )}
          </div>
        </div>
        <span className="text-[8px] font-mono text-neutral-600 uppercase tracking-widest">Node_{instance.id.slice(0,4)}</span>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-4 no-scrollbar font-mono text-[11px] leading-relaxed">
        {instance.messages.map((m, i) => (
          <div key={i} className={`animate-in fade-in slide-in-from-left-2 duration-300 ${m.role === 'user' ? 'text-blue-400' : 'text-neutral-400'}`}>
            <div className="flex items-center gap-2 opacity-30 text-[8px] mb-1">
              <span className="uppercase">{m.role === 'user' ? 'Operator' : 'Agent'}</span>
              <span>•</span>
              <span>{m.timestamp}</span>
            </div>
            {m.content}
          </div>
        ))}
        {instance.isThinking && (
          <div className="text-white/40 flex gap-1 animate-pulse">
            <span className="w-1 h-1 bg-white rounded-full"></span>
            <span className="w-1 h-1 bg-white rounded-full opacity-60"></span>
            <span className="w-1 h-1 bg-white rounded-full opacity-30"></span>
          </div>
        )}
      </div>

      <form 
        onSubmit={(e) => { e.preventDefault(); if (input.trim()) { onSend(input); setInput(''); } }}
        className="p-4 bg-black/60 border-t border-white/5"
      >
        <div className="flex items-center gap-3 bg-white/5 border border-white/5 rounded-xl px-4 py-2 group-focus-within:border-white/20 transition-all">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Command..."
            className="flex-1 bg-transparent border-none outline-none text-[11px] font-mono text-white placeholder:text-neutral-700"
            autoFocus={false}
          />
          <Icon name="terminal" size={12} className="text-neutral-700" />
        </div>
      </form>
    </div>
  );
};

