export default DeployModal;

import React, { useState, useCallback } from 'react';
import { User, AgentInstance, ChatSession } from './types';
import { GoogleGenAI } from "@google/genai";
import LandingView from './components/LandingView';
import LoginModal from './components/LoginModal';
import FactoryFloor from './components/FactoryFloor';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'entry' | 'active'>('entry');
  const [instances, setInstances] = useState<AgentInstance[]>([]);
  const [showLogin, setShowLogin] = useState(false);
  const [pendingCount, setPendingCount] = useState(1);

  const handleLaunchRequest = (count: number) => {
    setPendingCount(count);
    if (!user) {
      setShowLogin(true);
    } else {
      deployInstances(count);
    }
  };

  const deployInstances = (count: number, config?: any) => {
    const isCloudflare = config?.provider?.toLowerCase().includes('cloudflare') || false;

    const newInstances: AgentInstance[] = Array.from({ length: count || pendingCount }).map((_, i) => {
      const id = `node-${Math.random().toString(36).substr(2, 9)}`;
      const timestamp = new Date().toLocaleTimeString().slice(0, 5);
      const provider = config?.provider || 'Qwen 2.5 (Cloudflare)';
      const modelName = provider.includes('Qwen') ? 'Qwen-2.5-7B' : 'Gemini-3.0';

      const initialMessage = { 
        role: 'agent' as const, 
        content: isCloudflare 
            ? `Worker initialized at Edge. Neural engine ${modelName} online.` 
            : `Node initialized. Synchronizing neural weights...`, 
        timestamp 
      };

      const tags = isCloudflare ? ['edge', 'qwen', 'worker'] : [];
      if (config?.factoryId) tags.push(config.factoryId.toLowerCase());

      return {
        id,
        name: `${config?.namePrefix || (isCloudflare ? 'WORKER' : 'AGENT')}_${String(instances.length + i + 1).padStart(3, '0')}`,
        status: 'booting',
        provider: provider,
        vCPU: config?.vCPU || (isCloudflare ? 'Shared CPU' : '2 vCPU'),
        ram: config?.ram || (isCloudflare ? '128MB' : '2 GB RAM'),
        region: config?.region || (isCloudflare ? 'MAD (Madrid, Spain)' : 'us-central1'),
        messages: [initialMessage],
        chats: [{
          id: 'chat-default',
          name: isCloudflare ? 'Edge Stream' : 'Main Stream',
          lastUpdate: timestamp,
          messages: [initialMessage]
        }],
        activeChatId: 'chat-default',
        tags: tags
      };
    });

    setInstances(prev => [...prev, ...newInstances]);
    setView('active');

    newInstances.forEach(ni => {
      setTimeout(() => {
        setInstances(prev => prev.map(inst => inst.id === ni.id ? { ...inst, status: 'online' } : inst));
      }, 1000 + Math.random() * 2000);
    });
  };

  const handleSendMessage = async (id: string, chatId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);

    setInstances(prev => prev.map(inst => inst.id === id ? {
      ...inst,
      chats: inst.chats.map(chat => chat.id === chatId ? {
        ...chat,
        isThinking: true,
        messages: [...chat.messages, { role: 'user', content, timestamp }]
      } : chat)
    } : inst));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: content,
      });

      const aiText = response.text || "Connection lost.";
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        chats: inst.chats.map(chat => chat.id === chatId ? {
          ...chat,
          isThinking: false,
          messages: [...chat.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }]
        } : chat)
      } : inst));
    } catch (e) {
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        chats: inst.chats.map(chat => chat.id === chatId ? { ...chat, isThinking: false } : chat)
      } : inst));
    }
  };

  const handleNewChat = (instanceId: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);
    const inst = instances.find(i => i.id === instanceId);
    const isCloudflare = inst?.provider.toLowerCase().includes('cloudflare');

    const newChat: ChatSession = {
      id: `chat-${Math.random().toString(36).substr(2, 5)}`,
      name: isCloudflare ? `Edge Context ${Math.random().toString(36).substr(2, 2).toUpperCase()}` : `Stream ${Math.random().toString(36).substr(2, 3).toUpperCase()}`,
      lastUpdate: timestamp,
      messages: [{ role: 'agent', content: 'New session context established.', timestamp }]
    };

    setInstances(prev => prev.map(inst => inst.id === instanceId ? {
      ...inst,
      chats: [...inst.chats, newChat],
      activeChatId: newChat.id
    } : inst));
  };

  const handleSwitchChat = (instanceId: string, chatId: string) => {
    setInstances(prev => prev.map(inst => inst.id === instanceId ? {
      ...inst,
      activeChatId: chatId
    } : inst));
  };

  const handleBulkMessage = (ids: string[], content: string) => {
    ids.forEach(id => {
      const instance = instances.find(i => i.id === id);
      if (instance) {
        handleSendMessage(id, instance.activeChatId || instance.chats[0].id, content);
      }
    });
  };

  const handleBulkTag = (ids: string[], tag: string) => {
    const cleanTag = tag.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
    if (!cleanTag) return;

    setInstances(prev => prev.map(inst => 
      ids.includes(inst.id) && !inst.tags.includes(cleanTag)
      ? { ...inst, tags: [...inst.tags, cleanTag] }
      : inst
    ));
  };

  return (
    <div className="h-screen w-screen bg-black text-white font-sans overflow-hidden selection:bg-white selection:text-black">
      {view === 'entry' ? (
        <LandingView onLaunch={handleLaunchRequest} />
      ) : (
        <FactoryFloor 
          instances={instances} 
          onSendMessage={handleSendMessage}
          onNewChat={handleNewChat}
          onSwitchChat={handleSwitchChat}
          onBulkMessage={handleBulkMessage}
          onBulkTag={handleBulkTag}
          onBack={() => setView('entry')}
          onAddMore={() => handleLaunchRequest(1)}
          onDeploy={(config) => deployInstances(config.quantity, config)}
        />
      )}

      {showLogin && (
        <LoginModal 
          onClose={() => setShowLogin(false)} 
          onSuccess={(u) => {
            setUser(u);
            setShowLogin(false);
            deployInstances(pendingCount);
          }} 
        />
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { AgentInstance } from '../types';
import Icon from './Icon';
import TerminalPane from './TerminalPane';

interface FactoryFloorProps {
  instances: AgentInstance[];
  onSendMessage: (id: string, chatId: string, content: string) => void;
  onNewChat: (id: string) => void;
  onSwitchChat: (id: string, chatId: string) => void;
  onBulkMessage: (ids: string[], content: string) => void;
  onBulkTag: (ids: string[], tag: string) => void;
  onBack: () => void;
  onAddMore: () => void;
  onShowBilling: () => void;
}

const FactoryFloor: React.FC<FactoryFloorProps> = ({ 
  instances, onSendMessage, onNewChat, onSwitchChat, onBulkMessage, onBulkTag, onBack, onAddMore, onShowBilling
}) => {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [bulkMode, setBulkMode] = useState<'message' | 'tag' | null>(null);
  const [bulkValue, setBulkValue] = useState('');
  const [activeFilterTag, setActiveFilterTag] = useState<string | null>(null);
  const [fullscreenId, setFullscreenId] = useState<string | null>(null);

  // Obtener todos los tags únicos
  const allTags = Array.from(new Set(instances.flatMap(i => i.tags)));

  // Filtrar instancias visibles
  const visibleInstances = activeFilterTag 
    ? instances.filter(i => i.tags.includes(activeFilterTag)) 
    : instances;

  const toggleSelection = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]
    );
  };

  const selectVisible = () => {
    const visibleIds = visibleInstances.map(i => i.id);
    const allVisibleSelected = visibleIds.every(id => selectedIds.includes(id));

    if (allVisibleSelected) {
      setSelectedIds(prev => prev.filter(id => !visibleIds.includes(id)));
    } else {
      setSelectedIds(prev => Array.from(new Set([...prev, ...visibleIds])));
    }
  };

  const handleBulkAction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!bulkValue.trim()) return;

    if (bulkMode === 'message') {
      onBulkMessage(selectedIds, bulkValue);
    } else if (bulkMode === 'tag') {
      onBulkTag(selectedIds, bulkValue);
    }

    setBulkValue('');
    setBulkMode(null);
    setSelectedIds([]);
  };

  return (
    <div className="h-full w-full flex flex-col overflow-hidden animate-in fade-in duration-500 relative bg-[#050505]">
      <header className="h-20 border-b border-white/5 flex items-center justify-between px-8 shrink-0 bg-black/50 backdrop-blur-md z-30">
        <div className="flex flex-col gap-2">
          <div className="flex items-center gap-6">
            <button onClick={onBack} className="group flex items-center gap-2 text-neutral-500 hover:text-white transition-all">
              <Icon name="chevron-right" size={14} className="rotate-180" />
              <span className="text-[10px] font-bold uppercase tracking-[0.3em]">Vault</span>
            </button>
            <div className="h-4 w-px bg-white/10"></div>
            <div className="flex items-center gap-4">
              <span className="text-[11px] font-heading font-bold uppercase tracking-widest text-white/90">Production Floor</span>
              <button 
                onClick={selectVisible}
                className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1 rounded-full border transition-all ${
                  selectedIds.length > 0 ? 'bg-blue-600 border-blue-600 text-white shadow-[0_0_15px_rgba(37,99,235,0.4)]' : 'text-neutral-500 border-white/10 hover:border-white/30'
                }`}
              >
                {activeFilterTag ? `Select Visible (${visibleInstances.length})` : `Select Fleet (${instances.length})`}
              </button>
            </div>
          </div>

          <div className="flex items-center gap-3 overflow-x-auto no-scrollbar py-1">
            <button 
              onClick={() => setActiveFilterTag(null)}
              className={`text-[8px] font-bold uppercase tracking-widest px-2.5 py-0.5 rounded transition-all ${
                activeFilterTag === null ? 'bg-white text-black' : 'text-neutral-500 hover:text-neutral-300'
              }`}
            >
              All_Nodes
            </button>
            {allTags.map(tag => (
              <button 
                key={tag}
                onClick={() => setActiveFilterTag(tag)}
                className={`text-[8px] font-bold uppercase tracking-widest px-2.5 py-0.5 rounded transition-all border ${
                  activeFilterTag === tag ? 'bg-blue-500 border-blue-500 text-white' : 'text-neutral-600 border-white/5 hover:border-white/20'
                }`}
              >
                #{tag}
              </button>
            ))}
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={onShowBilling}
            className="text-[9px] font-bold uppercase tracking-widest text-neutral-400 hover:text-white px-4 py-1.5 transition-colors border border-transparent hover:border-white/10 rounded-full"
          >
            BILLING
          </button>
          <button 
            onClick={onAddMore} 
            className="bg-white/5 hover:bg-white hover:text-black border border-white/10 px-6 py-1.5 rounded-full text-[9px] font-bold uppercase tracking-[0.2em] transition-all"
          >
            ADD
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 no-scrollbar pb-32">
        {visibleInstances.map(instance => (
          <TerminalPane 
            key={instance.id} 
            instance={instance} 
            isSelected={selectedIds.includes(instance.id)}
            onSelect={() => toggleSelection(instance.id)}
            onSend={(chatId, msg) => onSendMessage(instance.id, chatId, msg)}
            onNewChat={() => onNewChat(instance.id)}
            onSwitchChat={(chatId) => onSwitchChat(instance.id, chatId)}
            onToggleFullscreen={() => setFullscreenId(instance.id)}
          />
        ))}
      </main>

      {fullscreenId && (
        <div className="fixed inset-0 z-[100] bg-black p-4 md:p-10 animate-in zoom-in-95 duration-300">
          <div className="h-full w-full">
            <TerminalPane 
              instance={instances.find(i => i.id === fullscreenId)!} 
              isSelected={false}
              onSelect={() => {}}
              onSend={(chatId, msg) => onSendMessage(fullscreenId, chatId, msg)}
              onNewChat={() => onNewChat(fullscreenId)}
              onSwitchChat={(chatId) => onSwitchChat(fullscreenId, chatId)}
              isFullscreen={true}
              onToggleFullscreen={() => setFullscreenId(null)}
            />
          </div>
        </div>
      )}

      {selectedIds.length > 0 && !fullscreenId && (
        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-full max-w-2xl px-6 z-50 animate-in slide-in-from-bottom-10 duration-500">
          <div className="bg-neutral-900 border border-white/20 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/5 bg-white/5">
              <span className="text-[10px] font-bold uppercase tracking-[0.3em] text-blue-400">
                Bulk Action: {selectedIds.length} Nodes Selected
              </span>
              <div className="flex gap-2">
                <button onClick={() => setBulkMode('message')} className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-all ${bulkMode === 'message' ? 'bg-white text-black' : 'hover:bg-white/10'}`}>Broadcast</button>
                <button onClick={() => setBulkMode('tag')} className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-all ${bulkMode === 'tag' ? 'bg-white text-black' : 'hover:bg-white/10'}`}>Add Tag</button>
                <button onClick={() => { setSelectedIds([]); setBulkMode(null); }} className="text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg hover:bg-red-500/20 text-red-400">Cancel</button>
              </div>
            </div>
            {bulkMode && (
              <form onSubmit={handleBulkAction} className="p-4 flex gap-4 animate-in fade-in duration-300">
                <input type="text" value={bulkValue} onChange={(e) => setBulkValue(e.target.value)} placeholder={bulkMode === 'message' ? "Command fleet..." : "Tag name..."} className="flex-1 bg-black/50 border border-white/10 rounded-xl px-5 py-3 text-xs font-mono outline-none focus:border-blue-500 transition-all" autoFocus />
                <button type="submit" className="bg-white text-black px-6 rounded-xl text-[10px] font-bold uppercase tracking-widest">Execute</button>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default FactoryFloor;

import React, { useState } from 'react';
import { User, AgentInstance, ChatSession } from './types';
import { GoogleGenAI } from "@google/genai";
import LandingView from './components/LandingView';
import LoginModal from './components/LoginModal';
import FactoryFloor from './components/FactoryFloor';
import BillingModal from './components/BillingModal';
import DeployModal from './components/DeployModal';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'entry' | 'active'>('entry');
  const [instances, setInstances] = useState<AgentInstance[]>([]);
  const [showLogin, setShowLogin] = useState(false);
  const [showBilling, setShowBilling] = useState(false);
  const [showDeploy, setShowDeploy] = useState(false);
  const [pendingCount, setPendingCount] = useState(1);

  const handleLaunchRequest = (count: number) => {
    setPendingCount(count);
    if (!user) {
      setShowLogin(true);
    } else {
      setShowDeploy(true);
    }
  };

  const deployInstances = (count: number, config?: any) => {
    const isCloudflare = config?.provider?.toLowerCase().includes('cloudflare') || false;

    const newInstances: AgentInstance[] = Array.from({ length: count || pendingCount }).map((_, i) => {
      const id = `node-${Math.random().toString(36).substr(2, 9)}`;
      const timestamp = new Date().toLocaleTimeString().slice(0, 5);
      const provider = config?.provider || (isCloudflare ? 'Qwen 2.5 (Cloudflare)' : 'Gemini 3.0 Flash');
      const modelName = provider.includes('Qwen') ? 'Qwen-2.5-7B' : 'Gemini-3.0';

      const initialMessage = { 
        role: 'agent' as const, 
        content: isCloudflare 
            ? `Worker initialized at Edge. Neural engine ${modelName} online.` 
            : `Node initialized. Synchronizing neural weights...`, 
        timestamp 
      };

      const tags = isCloudflare ? ['edge', 'qwen', 'worker'] : [];
      if (config?.factoryId) tags.push(config.factoryId.toLowerCase());

      return {
        id,
        name: `${config?.namePrefix || (isCloudflare ? 'WORKER' : 'AGENT')}_${String(instances.length + i + 1).padStart(3, '0')}`,
        status: 'booting',
        provider: provider,
        vCPU: config?.vCPU || (isCloudflare ? 'Shared CPU' : '2 vCPU'),
        ram: config?.ram || (isCloudflare ? '128MB' : '2 GB RAM'),
        region: config?.region || (isCloudflare ? 'MAD (Madrid, Spain)' : 'us-central1'),
        messages: [initialMessage],
        chats: [{
          id: 'chat-default',
          name: isCloudflare ? 'Edge Stream' : 'Main Stream',
          lastUpdate: timestamp,
          messages: [initialMessage]
        }],
        activeChatId: 'chat-default',
        tags: tags
      };
    });

    setInstances(prev => [...prev, ...newInstances]);
    setView('active');
    setShowDeploy(false);

    newInstances.forEach(ni => {
      setTimeout(() => {
        setInstances(prev => prev.map(inst => inst.id === ni.id ? { ...inst, status: 'online' } : inst));
      }, 1000 + Math.random() * 2000);
    });
  };

  const handleSendMessage = async (id: string, chatId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);

    setInstances(prev => prev.map(inst => inst.id === id ? {
      ...inst,
      chats: inst.chats.map(chat => chat.id === chatId ? {
        ...chat,
        isThinking: true,
        messages: [...chat.messages, { role: 'user', content, timestamp }]
      } : chat)
    } : inst));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: content,
      });

      const aiText = response.text || "Connection lost.";
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        chats: inst.chats.map(chat => chat.id === chatId ? {
          ...chat,
          isThinking: false,
          messages: [...chat.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }]
        } : chat)
      } : inst));
    } catch (e) {
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        chats: inst.chats.map(chat => chat.id === chatId ? { ...chat, isThinking: false } : chat)
      } : inst));
    }
  };

  const handleNewChat = (instanceId: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);
    const inst = instances.find(i => i.id === instanceId);
    const isCloudflare = inst?.provider.toLowerCase().includes('cloudflare');

    const newChat: ChatSession = {
      id: `chat-${Math.random().toString(36).substr(2, 5)}`,
      name: isCloudflare ? `Edge Context ${Math.random().toString(36).substr(2, 2).toUpperCase()}` : `Stream ${Math.random().toString(36).substr(2, 3).toUpperCase()}`,
      lastUpdate: timestamp,
      messages: [{ role: 'agent', content: 'New session context established.', timestamp }]
    };

    setInstances(prev => prev.map(inst => inst.id === instanceId ? {
      ...inst,
      chats: [...inst.chats, newChat],
      activeChatId: newChat.id
    } : inst));
  };

  const handleSwitchChat = (instanceId: string, chatId: string) => {
    setInstances(prev => prev.map(inst => inst.id === instanceId ? {
      ...inst,
      activeChatId: chatId
    } : inst));
  };

  const handleBulkMessage = (ids: string[], content: string) => {
    ids.forEach(id => {
      const instance = instances.find(i => i.id === id);
      if (instance) {
        handleSendMessage(id, instance.activeChatId || instance.chats[0].id, content);
      }
    });
  };

  const handleBulkTag = (ids: string[], tag: string) => {
    const cleanTag = tag.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
    if (!cleanTag) return;

    setInstances(prev => prev.map(inst => 
      ids.includes(inst.id) && !inst.tags.includes(cleanTag)
      ? { ...inst, tags: [...inst.tags, cleanTag] }
      : inst
    ));
  };

  const mockFactories = [
    { id: 'f1', name: 'Frontend Squad', description: 'UX/UI Generation', instances: [] },
    { id: 'f2', name: 'Backend Logic', description: 'API Architectures', instances: [] }
  ];

  return (
    <div className="h-screen w-screen bg-black text-white font-sans overflow-hidden selection:bg-white selection:text-black">
      {view === 'entry' ? (
        <LandingView onLaunch={handleLaunchRequest} />
      ) : (
        <FactoryFloor 
          instances={instances} 
          onSendMessage={handleSendMessage}
          onNewChat={handleNewChat}
          onSwitchChat={handleSwitchChat}
          onBulkMessage={handleBulkMessage}
          onBulkTag={handleBulkTag}
          onBack={() => setView('entry')}
          onAddMore={() => setShowDeploy(true)}
          onShowBilling={() => setShowBilling(true)}
          onDeploy={(config) => deployInstances(config.quantity, config)}
        />
      )}

      {showLogin && (
        <LoginModal 
          onClose={() => setShowLogin(false)} 
          onSuccess={(u) => {
            setUser(u);
            setShowLogin(false);
            setShowDeploy(true);
          }} 
        />
      )}

      {showDeploy && (
        <DeployModal 
          onClose={() => setShowDeploy(false)}
          onDeploy={(config) => deployInstances(config.quantity, config)}
          factories={mockFactories}
        />
      )}

      {showBilling && (
        <BillingModal onClose={() => setShowBilling(false)} />
      )}
    </div>
  );
}

