import React, { useState } from 'react';
import { User, AgentInstance, ChatSession } from './types';
import { GoogleGenAI } from "@google/genai";
import LandingView from './components/LandingView';
import LoginModal from './components/LoginModal';
import FactoryFloor from './components/FactoryFloor';
import BillingModal from './components/BillingModal';
import DeployModal from './components/DeployModal';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'entry' | 'active'>('entry');
  const [instances, setInstances] = useState<AgentInstance[]>([]);
  const [showLogin, setShowLogin] = useState(false);
  const [showBilling, setShowBilling] = useState(false);
  const [showDeploy, setShowDeploy] = useState(false);
  const [pendingCount, setPendingCount] = useState(1);

  const handleLaunchRequest = (count: number) => {
    setPendingCount(count);
    if (!user) {
      setShowLogin(true);
    } else {
      setShowDeploy(true);
    }
  };

  const deployInstances = (distributions: any[]) => {
    const newInstances: AgentInstance[] = [];

    distributions.forEach(dist => {
      for (let i = 0; i < dist.count; i++) {
        const id = `node-${Math.random().toString(36).substr(2, 9)}`;
        const timestamp = new Date().toLocaleTimeString().slice(0, 5);
        const isCloudflare = dist.provider.provider.includes('Cloudflare');

        const initialMessage = { 
          role: 'agent' as const, 
          content: `Node initialized on ${dist.region.name}. Using ${dist.provider.name} via ${dist.compute.name}.`, 
          timestamp 
        };

        const tags = [
          dist.provider.tag,
          dist.compute.tag,
          dist.region.tag,
          isCloudflare ? 'edge' : 'cloud'
        ];

        newInstances.push({
          id,
          name: `${isCloudflare ? 'WORKER' : 'NODE'}_${String(instances.length + newInstances.length + 1).padStart(3, '0')}`,
          status: 'booting',
          provider: dist.provider.name,
          vCPU: dist.compute.vCPU,
          ram: dist.compute.ram,
          region: dist.region.name,
          messages: [initialMessage],
          chats: [{
            id: 'chat-default',
            name: 'Primary Link',
            lastUpdate: timestamp,
            messages: [initialMessage]
          }],
          activeChatId: 'chat-default',
          tags: tags
        });
      }
    });

    setInstances(prev => [...prev, ...newInstances]);
    setView('active');
    setShowDeploy(false);

    newInstances.forEach(ni => {
      setTimeout(() => {
        setInstances(prev => prev.map(inst => inst.id === ni.id ? { ...inst, status: 'online' } : inst));
      }, 800 + Math.random() * 1500);
    });
  };

  const handleSendMessage = async (id: string, chatId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);
    setInstances(prev => prev.map(inst => inst.id === id ? {
      ...inst,
      chats: inst.chats.map(chat => chat.id === chatId ? {
        ...chat,
        isThinking: true,
        messages: [...chat.messages, { role: 'user', content, timestamp }]
      } : chat)
    } : inst));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: content,
      });
      const aiText = response.text || "Connection failed.";
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        chats: inst.chats.map(chat => chat.id === chatId ? {
          ...chat,
          isThinking: false,
          messages: [...chat.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }]
        } : chat)
      } : inst));
    } catch (e) {
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        chats: inst.chats.map(chat => chat.id === chatId ? { ...chat, isThinking: false } : chat)
      } : inst));
    }
  };

  const handleNewChat = (instanceId: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);
    const newChat: ChatSession = {
      id: `chat-${Math.random().toString(36).substr(2, 5)}`,
      name: `Session ${Math.random().toString(36).substr(2, 2).toUpperCase()}`,
      lastUpdate: timestamp,
      messages: [{ role: 'agent', content: 'Context layer established.', timestamp }]
    };
    setInstances(prev => prev.map(inst => inst.id === instanceId ? {
      ...inst,
      chats: [...inst.chats, newChat],
      activeChatId: newChat.id
    } : inst));
  };

  return (
    <div className="h-screen w-screen bg-black text-white font-sans overflow-hidden selection:bg-white selection:text-black">
      {view === 'entry' ? (
        <LandingView onLaunch={handleLaunchRequest} />
      ) : (
        <FactoryFloor 
          instances={instances} 
          onSendMessage={handleSendMessage}
          onNewChat={handleNewChat}
          onSwitchChat={(id, chatId) => setInstances(prev => prev.map(i => i.id === id ? { ...i, activeChatId: chatId } : i))}
          onBulkMessage={(ids, msg) => ids.forEach(id => {
            const inst = instances.find(i => i.id === id);
            if (inst) handleSendMessage(id, inst.activeChatId || inst.chats[0].id, msg);
          })}
          onBulkTag={(ids, tag) => setInstances(prev => prev.map(inst => ids.includes(inst.id) ? { ...inst, tags: Array.from(new Set([...inst.tags, tag])) } : inst))}
          onBack={() => setView('entry')}
          onAddMore={() => setShowDeploy(true)}
          onShowBilling={() => setShowBilling(true)}
        />
      )}

      {showLogin && (
        <LoginModal onClose={() => setShowLogin(false)} onSuccess={(u) => { setUser(u); setShowLogin(false); setShowDeploy(true); }} />
      )}

      {showDeploy && (
        <DeployModal 
          onClose={() => setShowDeploy(false)} 
          onDeploy={deployInstances} 
          initialCount={pendingCount} 
        />
      )}

      {showBilling && <BillingModal onClose={() => setShowBilling(false)} />}
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { AGENT_PROVIDERS, COMPUTE_OPTIONS, REGIONS } from '../constants';
import Icon from './Icon';

interface DeployModalProps {
  onClose: () => void;
  onDeploy: (distributions: any[]) => void;
  initialCount: number;
}

const DeployModal: React.FC<DeployModalProps> = ({ onClose, onDeploy, initialCount }) => {
  const [totalNodes, setTotalNodes] = useState(initialCount);
  const [distributions, setDistributions] = useState([
    { 
      id: Math.random().toString(), 
      provider: AGENT_PROVIDERS[0], 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[0], 
      percentage: 100 
    }
  ]);

  const addDistribution = () => {
    if (distributions.length >= AGENT_PROVIDERS.length) return;
    const remaining = 0;
    setDistributions([...distributions, { 
      id: Math.random().toString(), 
      provider: AGENT_PROVIDERS[1] || AGENT_PROVIDERS[0], 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[0], 
      percentage: remaining 
    }]);
  };

  const removeDistribution = (id: string) => {
    if (distributions.length === 1) return;
    setDistributions(distributions.filter(d => d.id !== id));
  };

  const updateDist = (id: string, field: string, value: any) => {
    setDistributions(distributions.map(d => d.id === id ? { ...d, [field]: value } : d));
  };

  const calculatedDistributions = useMemo(() => {
    const totalPercentage = distributions.reduce((acc, d) => acc + d.percentage, 0);
    let remainingNodes = totalNodes;

    return distributions.map((d, idx) => {
      let count = 0;
      if (totalPercentage === 0) {
         count = idx === 0 ? totalNodes : 0;
      } else {
         count = Math.floor((d.percentage / totalPercentage) * totalNodes);
      }

      // Ensure the last one gets the remainder
      if (idx === distributions.length - 1) {
        count = remainingNodes;
      } else {
        remainingNodes -= count;
      }

      return { ...d, count };
    });
  }, [distributions, totalNodes]);

  const handleFinalDeploy = () => {
    onDeploy(calculatedDistributions.filter(d => d.count > 0));
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 overflow-y-auto">
      <div className="w-full max-w-5xl bg-[#0a0a0a] border border-white/10 p-12 flex flex-col gap-10 animate-in fade-in zoom-in-95 duration-300 rounded-[2.5rem] shadow-2xl">

        <header className="flex justify-between items-start">
          <div className="space-y-2">
            <h2 className="font-serif text-3xl tracking-[0.2em] text-white uppercase">Provisioning Engine</h2>
            <p className="text-[10px] font-mono text-neutral-500 uppercase tracking-widest">Distributed Intelligence Architecture</p>
          </div>
          <button onClick={onClose} className="text-neutral-500 hover:text-white transition-all p-3 bg-neutral-900 rounded-full">
            <Icon name="close" size={20} />
          </button>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

          <div className="lg:col-span-8 space-y-8">
            <div className="flex items-center justify-between">
              <label className="text-[10px] font-bold uppercase tracking-[0.3em] text-neutral-400">Model Orchestration</label>
              <button 
                onClick={addDistribution}
                disabled={distributions.length >= AGENT_PROVIDERS.length}
                className="text-[9px] font-bold uppercase tracking-widest text-blue-400 hover:text-blue-300 disabled:opacity-30"
              >
                + Add Neural Profile
              </button>
            </div>

            <div className="space-y-4">
              {distributions.map((dist, index) => (
                <div key={dist.id} className="p-6 bg-white/5 border border-white/5 rounded-3xl space-y-6 relative group">
                  {distributions.length > 1 && (
                    <button 
                      onClick={() => removeDistribution(dist.id)}
                      className="absolute top-4 right-4 text-neutral-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all"
                    >
                      <Icon name="close" size={14} />
                    </button>
                  )}

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="space-y-2">
                      <span className="text-[8px] uppercase font-bold text-neutral-600 tracking-widest">Model Engine</span>
                      <select 
                        value={dist.provider.id}
                        onChange={(e) => updateDist(dist.id, 'provider', AGENT_PROVIDERS.find(p => p.id === e.target.value))}
                        className="w-full bg-black border border-white/10 rounded-xl px-4 py-2.5 text-xs font-mono text-white outline-none focus:border-blue-500 transition-colors"
                      >
                        {AGENT_PROVIDERS.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                      </select>
                    </div>

                    <div className="space-y-2">
                      <span className="text-[8px] uppercase font-bold text-neutral-600 tracking-widest">Compute Layer</span>
                      <select 
                        value={dist.compute.id}
                        onChange={(e) => updateDist(dist.id, 'compute', COMPUTE_OPTIONS.find(c => c.id === e.target.value))}
                        className="w-full bg-black border border-white/10 rounded-xl px-4 py-2.5 text-xs font-mono text-white outline-none focus:border-blue-500 transition-colors"
                      >
                        {COMPUTE_OPTIONS.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>

                    <div className="space-y-2">
                      <span className="text-[8px] uppercase font-bold text-neutral-600 tracking-widest">Global Region</span>
                      <select 
                        value={dist.region.id}
                        onChange={(e) => updateDist(dist.id, 'region', REGIONS.find(r => r.id === e.target.value))}
                        className="w-full bg-black border border-white/10 rounded-xl px-4 py-2.5 text-xs font-mono text-white outline-none focus:border-blue-500 transition-colors"
                      >
                        {REGIONS.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                      </select>
                    </div>
                  </div>

                  <div className="flex items-center gap-6 pt-4 border-t border-white/5">
                    <div className="flex-1 space-y-2">
                      <div className="flex justify-between text-[9px] font-mono text-neutral-500 uppercase tracking-widest">
                        <span>Allocation Weight</span>
                        <span className="text-white">{dist.percentage}%</span>
                      </div>
                      <input 
                        type="range"
                        value={dist.percentage}
                        onChange={(e) => updateDist(dist.id, 'percentage', parseInt(e.target.value))}
                        className="w-full h-1 bg-neutral-800 rounded-full appearance-none accent-blue-500 cursor-pointer"
                      />
                    </div>
                    <div className="text-center min-w-[80px] p-3 bg-black rounded-2xl border border-white/5">
                      <div className="text-xl font-mono text-blue-400 leading-none">
                        {calculatedDistributions.find(d => d.id === dist.id)?.count}
                      </div>
                      <div className="text-[7px] uppercase font-bold text-neutral-600 mt-1">Nodes</div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="lg:col-span-4 flex flex-col gap-8">
            <div className="bg-neutral-900/50 border border-white/5 rounded-[2.5rem] p-8 space-y-10">
              <div className="space-y-4">
                <label className="text-[10px] font-bold uppercase tracking-[0.3em] text-neutral-400">Total Fleet Scale</label>
                <div className="flex justify-between items-end">
                  <span className="text-6xl font-serif text-white">{totalNodes}</span>
                  <span className="text-[10px] font-mono text-neutral-500 pb-2">NODES</span>
                </div>
                <input 
                  type="range"
                  min="1"
                  max="50"
                  value={totalNodes}
                  onChange={(e) => setTotalNodes(parseInt(e.target.value))}
                  className="w-full h-2 bg-neutral-800 rounded-full appearance-none accent-white cursor-pointer"
                />
              </div>

              <div className="space-y-4 pt-4 border-t border-white/5">
                <label className="text-[10px] font-bold uppercase tracking-[0.3em] text-neutral-400">Auto-Tagging Logic</label>
                <div className="flex flex-wrap gap-2">
                  <span className="px-2 py-1 bg-blue-500/10 border border-blue-500/20 text-[8px] font-mono text-blue-400 rounded uppercase">#distributed</span>
                  <span className="px-2 py-1 bg-white/5 border border-white/10 text-[8px] font-mono text-neutral-400 rounded uppercase">#scaling</span>
                  <span className="px-2 py-1 bg-white/5 border border-white/10 text-[8px] font-mono text-neutral-400 rounded uppercase">#logic-cluster</span>
                </div>
              </div>

              <button 
                onClick={handleFinalDeploy}
                className="w-full py-6 bg-white text-black text-[12px] font-bold uppercase tracking-[0.5em] rounded-3xl hover:scale-[1.02] active:scale-95 transition-all shadow-2xl"
              >
                Execute ADD
              </button>
            </div>

            <p className="text-[8px] font-mono text-neutral-600 text-center uppercase leading-loose tracking-widest px-4">
              All nodes will be automatically provisioned with identity tags based on compute, model, and geolocation selection.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

