  const [distributions, setDistributions] = useState<Distribution[]>([
    { 
      id: 'initial-dist', 
      provider: AGENT_PROVIDERS[0], 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[0], 
      percentage: 100 
    }
  ]);

  const addDistribution = () => {
    if (distributions.length >= AGENT_PROVIDERS.length) return;

    // Add a new profile and take 0% initially, or take some from the first one
    const newDist: Distribution = { 
      id: Math.random().toString(36).substr(2, 9), 
      provider: AGENT_PROVIDERS.find(p => !distributions.find(d => d.provider.id === p.id)) || AGENT_PROVIDERS[0], 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[0], 
      percentage: 0 
    };

    setDistributions([...distributions, newDist]);
  };

  const removeDistribution = (id: string) => {
    if (distributions.length <= 1) return;
    const removedDist = distributions.find(d => d.id === id);
    const remainingDists = distributions.filter(d => d.id !== id);

    if (removedDist) {
      // Add back the removed percentage to the first remaining dist to keep it at 100%
      remainingDists[0].percentage = Math.min(100, remainingDists[0].percentage + removedDist.percentage);
    }

    setDistributions(remainingDists);
  };

  const handlePercentageChange = (id: string, newValue: number) => {
    if (distributions.length === 1) return; // Cannot change if only one exists

    const targetIdx = distributions.findIndex(d => d.id === id);
    const oldValue = distributions[targetIdx].percentage;
    const delta = newValue - oldValue;

    let newDists = [...distributions];
    newDists[targetIdx].percentage = newValue;

    // We need to subtract 'delta' from other distributions
    // Filter out the one we just changed
    const others = newDists.filter((_, idx) => idx !== targetIdx);
    const totalOthers = others.reduce((sum, d) => sum + d.percentage, 0);

    if (totalOthers > 0) {
      // Proportional decrease/increase
      let distributedSoFar = 0;
      others.forEach((dist, idx) => {
        const othersIdx = newDists.findIndex(d => d.id === dist.id);
        if (idx === others.length - 1) {
          // Last one gets the exact remainder to avoid rounding drift
          newDists[othersIdx].percentage = 100 - newValue - distributedSoFar;
        } else {
          const share = Math.round((dist.percentage / totalOthers) * (100 - newValue));
          newDists[othersIdx].percentage = share;
          distributedSoFar += share;
        }
      });
    } else {
      // If others were all 0, distribute evenly among them
      const sharePerOther = Math.floor((100 - newValue) / others.length);
      let distributedSoFar = 0;
      others.forEach((dist, idx) => {
        const othersIdx = newDists.findIndex(d => d.id === dist.id);
        if (idx === others.length - 1) {
          newDists[othersIdx].percentage = 100 - newValue - distributedSoFar;
        } else {
          newDists[othersIdx].percentage = sharePerOther;
          distributedSoFar += sharePerOther;
        }
      });
    }

    // Sanity check: ensure no negatives and sum is exactly 100
    // This can happen if newValue is high. We clamp others to 0 and re-adjust.
    newDists = newDists.map(d => ({ ...d, percentage: Math.max(0, d.percentage) }));
    const currentSum = newDists.reduce((s, d) => s + d.percentage, 0);
    if (currentSum !== 100) {
        // Adjust the first one that is NOT the target if possible, else the target
        const adjustIdx = targetIdx === 0 ? 1 : 0;
        newDists[adjustIdx].percentage += (100 - currentSum);
    }

    setDistributions(newDists);
  };

  const updateDistSettings = (id: string, field: keyof Distribution, value: any) => {
    setDistributions(distributions.map(d => d.id === id ? { ...d, [field]: value } : d));
  };

  const calculatedNodes = useMemo(() => {
    let remaining = totalNodes;
    return distributions.map((d, idx) => {
      let count = 0;
      if (idx === distributions.length - 1) {
        count = remaining;
      } else {
        count = Math.floor((d.percentage / 100) * totalNodes);
        remaining -= count;
      }
      return { ...d, count };
    });
  }, [distributions, totalNodes]);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-3xl p-4 overflow-y-auto selection:bg-white selection:text-black">
      <div className="w-full max-w-6xl bg-[#050505] border border-white/10 p-12 flex flex-col gap-10 animate-in fade-in zoom-in-95 duration-500 rounded-[3rem] shadow-[0_0_100px_rgba(0,0,0,1)]">

        <header className="flex justify-between items-start">
          <div className="space-y-3">
            <h2 className="font-serif text-4xl tracking-[0.25em] text-white uppercase leading-none">Provisioning Console</h2>
            <div className="flex items-center gap-3">
                <div className="px-2 py-0.5 bg-white/5 border border-white/10 rounded text-[8px] font-mono text-neutral-500 uppercase tracking-widest">Distributed_System_v4</div>
                <div className="h-px w-12 bg-white/10"></div>
                <p className="text-[10px] font-mono text-neutral-600 uppercase tracking-[0.2em]">Scale Fleet Intelligence Intelligence</p>
            </div>
          </div>
          <button onClick={onClose} className="text-neutral-500 hover:text-white transition-all p-3 hover:bg-white/5 rounded-full border border-transparent hover:border-white/10">
            <Icon name="close" size={24} />
          </button>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">

          <div className="lg:col-span-8 space-y-10">
            <div className="flex items-center justify-between border-b border-white/5 pb-4">
              <label className="text-[10px] font-bold uppercase tracking-[0.4em] text-neutral-500">Neural Profiles Logic</label>
              <button 
                onClick={addDistribution}
                disabled={distributions.length >= AGENT_PROVIDERS.length}
                className="text-[9px] font-bold uppercase tracking-[0.2em] text-white/40 hover:text-white transition-all disabled:opacity-10"
              >
                + Initialize New Profile
              </button>
            </div>

            <div className="space-y-6 max-h-[500px] overflow-y-auto pr-4 no-scrollbar">
              {distributions.map((dist) => {
                const nodeCount = calculatedNodes.find(n => n.id === dist.id)?.count || 0;
                return (
                  <div key={dist.id} className="p-8 bg-neutral-900/20 border border-white/5 rounded-[2rem] space-y-8 relative group transition-all hover:border-white/10">
                    {distributions.length > 1 && (
                      <button 
                        onClick={() => removeDistribution(dist.id)}
                        className="absolute top-6 right-6 text-neutral-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all p-2 rounded-full hover:bg-red-500/10"
                      >
                        <Icon name="close" size={14} />
                      </button>
                    )}

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                      <div className="space-y-3">
                        <span className="text-[8px] uppercase font-bold text-neutral-600 tracking-[0.3em]">Model Matrix</span>
                        <select 
                          value={dist.provider.id}
                          onChange={(e) => updateDistSettings(dist.id, 'provider', AGENT_PROVIDERS.find(p => p.id === e.target.value))}
                          className="w-full bg-black border border-white/10 rounded-xl px-5 py-3.5 text-[11px] font-mono text-white outline-none focus:border-white/30 transition-all appearance-none cursor-pointer"
                        >
                          {AGENT_PROVIDERS.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                        </select>
                      </div>

                      <div className="space-y-3">
                        <span className="text-[8px] uppercase font-bold text-neutral-600 tracking-[0.3em]">Compute Fabric</span>
                        <select 
                          value={dist.compute.id}
                          onChange={(e) => updateDistSettings(dist.id, 'compute', COMPUTE_OPTIONS.find(c => c.id === e.target.value))}
                          className="w-full bg-black border border-white/10 rounded-xl px-5 py-3.5 text-[11px] font-mono text-white outline-none focus:border-white/30 transition-all appearance-none cursor-pointer"
                        >
                          {COMPUTE_OPTIONS.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                      </div>

                      <div className="space-y-3">
                        <span className="text-[8px] uppercase font-bold text-neutral-600 tracking-[0.3em]">Geographic Colo</span>
                        <select 
                          value={dist.region.id}
                          onChange={(e) => updateDistSettings(dist.id, 'region', REGIONS.find(r => r.id === e.target.value))}
                          className="w-full bg-black border border-white/10 rounded-xl px-5 py-3.5 text-[11px] font-mono text-white outline-none focus:border-white/30 transition-all appearance-none cursor-pointer"
                        >
                          {REGIONS.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                        </select>
                      </div>
                    </div>

                    <div className="flex items-center gap-10 pt-6 border-t border-white/5">
                      <div className="flex-1 space-y-4">
                        <div className="flex justify-between items-center text-[10px] font-mono text-neutral-500 uppercase tracking-widest">
                          <div className="flex items-center gap-2">
                            <span className="text-white font-bold">{dist.percentage}%</span>
                            <span>Fleet Weight</span>
                          </div>
                          <span className="opacity-50">#IntelligentBalance</span>
                        </div>
                        <div className="relative h-1.5 w-full bg-neutral-900 rounded-full group/slider">
                            <input 
                                type="range"
                                min="0"
                                max="100"
                                step="1"
                                value={dist.percentage}
                                disabled={distributions.length === 1}
                                onChange={(e) => handlePercentageChange(dist.id, parseInt(e.target.value))}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10 disabled:cursor-not-allowed"
                            />
                            <div 
                                className="absolute left-0 top-0 h-full bg-white rounded-full transition-all duration-300"
                                style={{ width: `${dist.percentage}%` }}
                            />
                        </div>
                      </div>
                      <div className="text-right min-w-[100px] p-4 bg-black/40 rounded-[1.5rem] border border-white/5">
                        <div className="text-3xl font-serif text-white leading-none tabular-nums">
                          {nodeCount}
                        </div>
                        <div className="text-[7px] uppercase font-bold text-neutral-600 mt-2 tracking-[0.2em]">Target Nodes</div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="lg:col-span-4 flex flex-col gap-10">
            <div className="bg-neutral-900/30 border border-white/5 rounded-[3rem] p-10 space-y-12 shadow-inner">
              <div className="space-y-6">
                <label className="text-[10px] font-bold uppercase tracking-[0.4em] text-neutral-500 block">Fleet Scale Total</label>
                <div className="flex justify-between items-baseline">
                  <span className="text-8xl font-serif text-white tracking-tighter tabular-nums">{totalNodes}</span>
                  <span className="text-[12px] font-mono text-neutral-700 tracking-[0.3em] font-bold uppercase">Instance_Count</span>
                </div>
                <div className="relative h-2 w-full bg-neutral-900 rounded-full">
                    <input 
                    type="range"
                    min="1"
                    max="100"
                    value={totalNodes}
                    onChange={(e) => setTotalNodes(parseInt(e.target.value))}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                    />
                    <div 
                        className="absolute left-0 top-0 h-full bg-blue-500 shadow-[0_0_20px_rgba(59,130,246,0.5)] rounded-full transition-all"
                        style={{ width: `${(totalNodes/100)*100}%` }}
                    />
