              </div>

              <div className="space-y-6 pt-10 border-t border-white/5">
                <label className="text-[10px] font-bold uppercase tracking-[0.4em] text-neutral-500 block">Derived Taxonomy</label>
                <div className="flex flex-wrap gap-3">
                  <span className="px-3 py-1.5 bg-white/5 border border-white/10 text-[9px] font-mono text-neutral-400 rounded-lg uppercase tracking-widest">#distributed</span>
                  <span className="px-3 py-1.5 bg-blue-500/5 border border-blue-500/20 text-[9px] font-mono text-blue-400 rounded-lg uppercase tracking-widest">#multi-region</span>
