                  <span className="px-3 py-1.5 bg-white/5 border border-white/10 text-[9px] font-mono text-neutral-400 rounded-lg uppercase tracking-widest">#qwen-optimized</span>
                </div>
              </div>

              <div className="pt-6">
                <button 
                    onClick={() => onDeploy(calculatedNodes.filter(d => d.count > 0))}
                    className="w-full py-7 bg-white text-black text-[13px] font-bold uppercase tracking-[0.6em] rounded-[2rem] hover:scale-[1.03] active:scale-[0.98] transition-all shadow-[0_20px_50px_rgba(255,255,255,0.1)] group flex items-center justify-center gap-4"
                >
                    Initialize ADD
                    <Icon name="action" size={16} className="transition-transform group-hover:rotate-12" />
