export default DeployModal;

import React, { useState } from 'react';
import { User, AgentInstance, ChatSession } from './types';
import { GoogleGenAI } from "@google/genai";
import LandingView from './components/LandingView';
import LoginModal from './components/LoginModal';
import FactoryFloor from './components/FactoryFloor';
import BillingModal from './components/BillingModal';
import DeployModal from './components/DeployModal';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'entry' | 'active'>('entry');
  const [instances, setInstances] = useState<AgentInstance[]>([]);
  const [showLogin, setShowLogin] = useState(false);
  const [showBilling, setShowBilling] = useState(false);
  const [showDeploy, setShowDeploy] = useState(false);
  const [pendingCount, setPendingCount] = useState(1);

  const handleLaunchRequest = (count: number) => {
    setPendingCount(count);
    if (!user) {
      setShowLogin(true);
    } else {
      setShowDeploy(true);
    }
  };

  const deployInstances = (distributions: any[]) => {
    const newInstances: AgentInstance[] = [];

    distributions.forEach(dist => {
      for (let i = 0; i < dist.count; i++) {
        const id = `node-${Math.random().toString(36).substr(2, 9)}`;
        const timestamp = new Date().toLocaleTimeString().slice(0, 5);
        const isCloudflare = dist.provider.provider.includes('Cloudflare');

        const initialMessage = { 
          role: 'agent' as const, 
          content: `Node established in ${dist.region.name}. Running ${dist.provider.name} engine. System integrity verified.`, 
          timestamp 
        };

        // Comprehensive tagging based on deployment choices
        const tags = Array.from(new Set([
          dist.provider.tag,
          dist.compute.tag,
          dist.region.tag,
          isCloudflare ? 'edge' : 'cloud',
          'production-v4'
        ]));

        newInstances.push({
          id,
          name: `${isCloudflare ? 'WORKER' : 'NODE'}_${String(instances.length + newInstances.length + 1).padStart(3, '0')}`,
          status: 'booting',
          provider: dist.provider.name,
          vCPU: dist.compute.vCPU,
          ram: dist.compute.ram,
          region: dist.region.name,
          messages: [initialMessage],
          chats: [{
            id: 'chat-default',
            name: 'Primary Uplink',
            lastUpdate: timestamp,
            messages: [initialMessage]
          }],
          activeChatId: 'chat-default',
          tags: tags
        });
      }
    });

    setInstances(prev => [...prev, ...newInstances]);
    setView('active');
    setShowDeploy(false);

    // Progressive status update
    newInstances.forEach(ni => {
      setTimeout(() => {
        setInstances(prev => prev.map(inst => inst.id === ni.id ? { ...inst, status: 'online' } : inst));
      }, 500 + Math.random() * 1000);
    });
  };

  const handleSendMessage = async (id: string, chatId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);
    setInstances(prev => prev.map(inst => inst.id === id ? {
      ...inst,
      chats: inst.chats.map(chat => chat.id === chatId ? {
        ...chat,
        isThinking: true,
        messages: [...chat.messages, { role: 'user', content, timestamp }]
      } : chat)
    } : inst));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: content,
      });
      const aiText = response.text || "Connection failed. Please verify neural uplink.";
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        chats: inst.chats.map(chat => chat.id === chatId ? {
          ...chat,
          isThinking: false,
          messages: [...chat.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }]
        } : chat)
      } : inst));
    } catch (e) {
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        chats: inst.chats.map(chat => chat.id === chatId ? { ...chat, isThinking: false } : chat)
      } : inst));
    }
  };

  const handleNewChat = (instanceId: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);
    const newChat: ChatSession = {
      id: `chat-${Math.random().toString(36).substr(2, 5)}`,
      name: `Stream ${Math.random().toString(36).substr(2, 2).toUpperCase()}`,
      lastUpdate: timestamp,
      messages: [{ role: 'agent', content: 'New context stream initialized. Waiting for input...', timestamp }]
    };
    setInstances(prev => prev.map(inst => inst.id === instanceId ? {
      ...inst,
      chats: [...inst.chats, newChat],
      activeChatId: newChat.id
    } : inst));
  };

  const handleBulkTag = (ids: string[], tag: string) => {
    const cleanTag = tag.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
    if (!cleanTag) return;
    setInstances(prev => prev.map(inst => ids.includes(inst.id) ? { ...inst, tags: Array.from(new Set([...inst.tags, cleanTag])) } : inst));
  };

  return (
    <div className="h-screen w-screen bg-black text-white font-sans overflow-hidden selection:bg-white selection:text-black">
      {view === 'entry' ? (
        <LandingView onLaunch={handleLaunchRequest} />
      ) : (
        <FactoryFloor 
          instances={instances} 
          onSendMessage={handleSendMessage}
          onNewChat={handleNewChat}
          onSwitchChat={(id, chatId) => setInstances(prev => prev.map(i => i.id === id ? { ...i, activeChatId: chatId } : i))}
          onBulkMessage={(ids, msg) => ids.forEach(id => {
            const inst = instances.find(i => i.id === id);
            if (inst) handleSendMessage(id, inst.activeChatId || inst.chats[0].id, msg);
          })}
          onBulkTag={handleBulkTag}
          onBack={() => setView('entry')}
          onAddMore={() => setShowDeploy(true)}
          onShowBilling={() => setShowBilling(true)}
        />
      )}

      {showLogin && (
        <LoginModal onClose={() => setShowLogin(false)} onSuccess={(u) => { setUser(u); setShowLogin(false); setShowDeploy(true); }} />
      )}

      {showDeploy && (
        <DeployModal 
          onClose={() => setShowDeploy(false)} 
          onDeploy={deployInstances} 
          initialCount={pendingCount} 
        />
      )}

      {showBilling && <BillingModal onClose={() => setShowBilling(false)} />}
    </div>
  );
}

import React, { useState } from 'react';
import { AgentInstance } from '../types';
import Icon from './Icon';
import TerminalPane from './TerminalPane';

interface FactoryFloorProps {
  instances: AgentInstance[];
  onSendMessage: (id: string, chatId: string, content: string) => void;
  onNewChat: (id: string) => void;
  onSwitchChat: (id: string, chatId: string) => void;
  onBulkMessage: (ids: string[], content: string) => void;
  onBulkTag: (ids: string[], tag: string) => void;
  onBack: () => void;
  onAddMore: () => void;
  onShowBilling: () => void;
  onShowDocs: () => void;
}

const FactoryFloor: React.FC<FactoryFloorProps> = ({ 
  instances, onSendMessage, onNewChat, onSwitchChat, onBulkMessage, onBulkTag, onBack, onAddMore, onShowBilling, onShowDocs
}) => {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [bulkMode, setBulkMode] = useState<'message' | 'tag' | null>(null);
  const [bulkValue, setBulkValue] = useState('');
  const [activeFilterTag, setActiveFilterTag] = useState<string | null>(null);
  const [fullscreenId, setFullscreenId] = useState<string | null>(null);

  // Obtener todos los tags únicos
  const allTags = Array.from(new Set(instances.flatMap(i => i.tags)));

  // Filtrar instancias visibles
  const visibleInstances = activeFilterTag 
    ? instances.filter(i => i.tags.includes(activeFilterTag)) 
    : instances;

  const toggleSelection = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]
    );
  };

  const selectVisible = () => {
    const visibleIds = visibleInstances.map(i => i.id);
    const allVisibleSelected = visibleIds.every(id => selectedIds.includes(id));

    if (allVisibleSelected) {
      setSelectedIds(prev => prev.filter(id => !visibleIds.includes(id)));
    } else {
      setSelectedIds(prev => Array.from(new Set([...prev, ...visibleIds])));
    }
  };

  const handleBulkAction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!bulkValue.trim()) return;

    if (bulkMode === 'message') {
      onBulkMessage(selectedIds, bulkValue);
    } else if (bulkMode === 'tag') {
      onBulkTag(selectedIds, bulkValue);
    }

    setBulkValue('');
    setBulkMode(null);
    setSelectedIds([]);
  };

  return (
    <div className="h-full w-full flex flex-col overflow-hidden animate-in fade-in duration-500 relative bg-[#050505]">
      {/* Navbar: Fractal Station */}
      <header className="h-20 border-b border-white/5 flex items-center justify-between px-8 shrink-0 bg-black/50 backdrop-blur-md z-30">
        <div className="flex flex-col gap-2">
          <div className="flex items-center gap-6">
            <button onClick={onBack} className="group flex items-center gap-2 text-neutral-500 hover:text-white transition-all">
              <Icon name="chevron-right" size={14} className="rotate-180" />
              <span className="text-[10px] font-bold uppercase tracking-[0.3em]">Vault</span>
            </button>
            <div className="h-4 w-px bg-white/10"></div>
            <div className="flex items-center gap-4">
              <div className="flex flex-col">
                <span className="text-[12px] font-heading font-bold uppercase tracking-[0.4em] text-white">Fractal Station</span>
                <span className="text-[7px] font-mono uppercase tracking-[0.2em] text-neutral-500">Autonomous Orchestrator</span>
              </div>
              <button 
                onClick={selectVisible}
                className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1 rounded-full border transition-all ${
                  selectedIds.length > 0 ? 'bg-blue-600 border-blue-600 text-white shadow-[0_0_15px_rgba(37,99,235,0.4)]' : 'text-neutral-500 border-white/10 hover:border-white/30'
                }`}
              >
                {activeFilterTag ? `Select Visible (${visibleInstances.length})` : `Select Fleet (${instances.length})`}
              </button>
            </div>
          </div>

          <div className="flex items-center gap-3 overflow-x-auto no-scrollbar py-1">
            <button 
              onClick={() => setActiveFilterTag(null)}
              className={`text-[8px] font-bold uppercase tracking-widest px-2.5 py-0.5 rounded transition-all ${
                activeFilterTag === null ? 'bg-white text-black' : 'text-neutral-500 hover:text-neutral-300'
              }`}
            >
              All_Nodes
            </button>
            {allTags.map(tag => (
              <button 
                key={tag}
                onClick={() => setActiveFilterTag(tag)}
                className={`text-[8px] font-bold uppercase tracking-widest px-2.5 py-0.5 rounded transition-all border ${
