import React, { useState, useMemo } from 'react';
import { AGENT_PROVIDERS, COMPUTE_OPTIONS, REGIONS } from '../constants';
import Icon from './Icon';

interface DeployModalProps {
  onClose: () => void;
  onDeploy: (distributions: any[]) => void;
  initialCount: number;
}

interface Distribution {
  id: string;
  provider: typeof AGENT_PROVIDERS[0];
  compute: typeof COMPUTE_OPTIONS[0];
  region: typeof REGIONS[0];
  count: number;
}

const DeployModal: React.FC<DeployModalProps> = ({ onClose, onDeploy, initialCount }) => {
  const [totalNodes, setTotalNodes] = useState(initialCount);
  const [distributions, setDistributions] = useState<Distribution[]>([
    { 
      id: 'initial-dist', 
      provider: AGENT_PROVIDERS[0], 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[0], 
      count: initialCount 
    }
  ]);

  const addDistribution = () => {
    const usedProviderIds = distributions.map(d => d.provider.id);
    const nextProvider = AGENT_PROVIDERS.find(p => !usedProviderIds.includes(p.id)) 
      || AGENT_PROVIDERS[distributions.length % AGENT_PROVIDERS.length];

    const newDist: Distribution = { 
      id: Math.random().toString(36).substr(2, 9), 
      provider: nextProvider, 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[distributions.length % REGIONS.length], 
      count: 0 
    };

    setDistributions([...distributions, newDist]);
  };

  const removeDistribution = (id: string) => {
    if (distributions.length <= 1) return;
    setDistributions(distributions.filter(d => d.id !== id));
  };

  const updateDistCount = (id: string, val: string) => {
    const num = parseInt(val) || 0;
    setDistributions(distributions.map(d => d.id === id ? { ...d, count: Math.max(0, num) } : d));
  };

  const updateDistSettings = (id: string, field: keyof Distribution, value: any) => {
    setDistributions(distributions.map(d => d.id === id ? { ...d, [field]: value } : d));
  };

  const currentAssigned = useMemo(() => 
    distributions.reduce((sum, d) => sum + d.count, 0)
  , [distributions]);

  const remaining = totalNodes - currentAssigned;
  const isValid = currentAssigned === totalNodes;

  const handleDeploy = () => {
    if (!isValid) return;
    onDeploy(distributions.filter(d => d.count > 0));
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-3xl p-4 overflow-y-auto selection:bg-white selection:text-black">
      <div className="w-full max-w-6xl bg-[#050505] border border-white/10 p-10 flex flex-col gap-8 animate-in fade-in zoom-in-95 duration-500 rounded-[2.5rem] shadow-[0_0_80px_rgba(0,0,0,1)]">

        <header className="flex justify-between items-start">
          <div className="space-y-2">
            <h2 className="font-serif text-3xl tracking-[0.25em] text-white uppercase leading-none">Provisioning Console</h2>
            <div className="flex items-center gap-3">
                <div className="px-2 py-0.5 bg-white/5 border border-white/10 rounded text-[7px] font-mono text-neutral-600 uppercase tracking-widest">Distributed_System_v4</div>
                <div className="h-px w-8 bg-white/10"></div>
                <p className="text-[9px] font-mono text-neutral-500 uppercase tracking-[0.2em]">Scale Fleet Intelligence</p>
            </div>
          </div>
          <button onClick={onClose} className="text-neutral-500 hover:text-white transition-all p-2.5 hover:bg-white/5 rounded-full border border-transparent hover:border-white/10">
            <Icon name="close" size={20} />
          </button>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

          <div className="lg:col-span-8 space-y-8">
            <div className="flex items-center justify-between border-b border-white/5 pb-3">
              <label className="text-[9px] font-bold uppercase tracking-[0.4em] text-neutral-500">Neural Configuration Groups</label>
              <button 
                onClick={addDistribution}
                className="text-[8px] font-bold uppercase tracking-[0.2em] text-white/40 hover:text-white transition-all"
              >
                + Add Neural Group
              </button>
            </div>

            <div className="space-y-4 max-h-[480px] overflow-y-auto pr-2 no-scrollbar">
              {distributions.map((dist) => (
                <div key={dist.id} className="p-6 bg-neutral-900/20 border border-white/5 rounded-3xl space-y-6 relative group transition-all hover:border-white/10">
                  {distributions.length > 1 && (
                    <button 
                      onClick={() => removeDistribution(dist.id)}
                      className="absolute top-5 right-5 text-neutral-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all p-1.5 rounded-full hover:bg-red-500/10"
                    >
                      <Icon name="close" size={12} />
                    </button>
                  )}

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="space-y-2">
                      <span className="text-[7px] uppercase font-bold text-neutral-600 tracking-[0.3em]">Engine Matrix</span>
                      <select 
                        value={dist.provider.id}
                        onChange={(e) => updateDistSettings(dist.id, 'provider', AGENT_PROVIDERS.find(p => p.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-xl px-4 py-3 text-[10px] font-mono text-white outline-none focus:border-white/20 transition-all cursor-pointer"
                      >
                        {AGENT_PROVIDERS.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                      </select>
                    </div>

                    <div className="space-y-2">
                      <span className="text-[7px] uppercase font-bold text-neutral-600 tracking-[0.3em]">Compute Layer</span>
                      <select 
                        value={dist.compute.id}
                        onChange={(e) => updateDistSettings(dist.id, 'compute', COMPUTE_OPTIONS.find(c => c.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-xl px-4 py-3 text-[10px] font-mono text-white outline-none focus:border-white/20 transition-all cursor-pointer"
                      >
                        {COMPUTE_OPTIONS.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>

                    <div className="space-y-2">
                      <span className="text-[7px] uppercase font-bold text-neutral-600 tracking-[0.3em]">Geographic Region</span>
                      <select 
                        value={dist.region.id}
                        onChange={(e) => updateDistSettings(dist.id, 'region', REGIONS.find(r => r.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-xl px-4 py-3 text-[10px] font-mono text-white outline-none focus:border-white/20 transition-all cursor-pointer"
                      >
                        {REGIONS.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                      </select>
                    </div>
                  </div>

                  <div className="flex items-center justify-between pt-5 border-t border-white/5">
                    <div className="flex flex-col gap-1">
                      <span className="text-[7px] font-mono text-neutral-500 uppercase tracking-widest">Manual Allocation</span>
                      <p className="text-[9px] text-neutral-600 uppercase tracking-tight">Set number of instances for this profile</p>
                    </div>
                    <div className="flex items-center gap-4">
                      <input 
                        type="number"
                        min="0"
                        value={dist.count}
                        onChange={(e) => updateDistCount(dist.id, e.target.value)}
                        className="w-20 bg-black border border-white/10 rounded-lg px-3 py-2 text-center text-sm font-mono text-white outline-none focus:border-blue-500/50 transition-all"
                      />
                      <span className="text-[10px] font-mono text-neutral-700 uppercase">Nodes</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="lg:col-span-4 flex flex-col gap-6">
            <div className="bg-neutral-900/30 border border-white/5 rounded-[2rem] p-8 space-y-10 shadow-inner">
              <div className="space-y-4">
                <label className="text-[9px] font-bold uppercase tracking-[0.4em] text-neutral-500 block">Fleet Target Scale</label>
                <div className="flex justify-between items-baseline">
                  <span className="text-6xl font-serif text-white tracking-tighter tabular-nums">{totalNodes}</span>
                  <span className="text-[10px] font-mono text-neutral-700 tracking-[0.2em] font-bold uppercase">Uplinks</span>
                </div>
                <div className="relative h-1.5 w-full bg-neutral-900 rounded-full">
                    <input 
                    type="range"
                    min="1"
                    max="100"
                    value={totalNodes}
                    onChange={(e) => setTotalNodes(parseInt(e.target.value))}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                    />
                    <div 
                        className="absolute left-0 top-0 h-full bg-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.3)] rounded-full transition-all"
                        style={{ width: `${(totalNodes/100)*100}%` }}
                    />
                </div>
              </div>

              <div className="space-y-4 pt-6 border-t border-white/5">
                <div className="flex justify-between items-center text-[10px] font-mono uppercase tracking-widest">
                   <span className="text-neutral-500">Currently Assigned</span>
                   <span className={isValid ? "text-green-500" : "text-yellow-500"}>{currentAssigned} / {totalNodes}</span>
                </div>
                {!isValid && (
                  <div className="p-3 bg-yellow-500/5 border border-yellow-500/20 rounded-xl text-center">
                    <span className="text-[9px] font-mono text-yellow-500 uppercase tracking-widest">
                      {remaining > 0 ? `Faltan ${remaining} nodos por Asignar` : `Exceso de ${Math.abs(remaining)} nodos`}
                    </span>
                  </div>
                )}
              </div>

              <div className="pt-2">
                <button 
                    onClick={handleDeploy}
                    disabled={!isValid}
                    className={`w-full py-4 text-[11px] font-bold uppercase tracking-[0.4em] rounded-2xl transition-all flex items-center justify-center gap-3 ${
                      isValid 
                      ? 'bg-white text-black hover:scale-[1.02] active:scale-[0.98] shadow-lg' 
                      : 'bg-neutral-800 text-neutral-600 cursor-not-allowed opacity-50'
                    }`}
                >
                    {isValid ? 'INITIALIZE ADD' : 'AWAITING CONFIG'}
                    <Icon name="action" size={14} />
                </button>
              </div>
            </div>

            <div className="px-4 space-y-4">
                <div className="flex items-center gap-3">
                    <div className="w-1 h-1 bg-blue-500 rounded-full animate-pulse"></div>
                    <span className="text-[8px] font-mono text-neutral-600 uppercase tracking-widest">Protocol: Manual Dist. Mode</span>
                </div>
                <p className="text-[8px] font-mono text-neutral-700 uppercase leading-relaxed tracking-wider">
                  Manual allocation ensures precise control over distributed workloads. Assignment verification required for execution.
                </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

