  const [showDocs, setShowDocs] = useState(false);
  const [pendingCount, setPendingCount] = useState(1);

  const handleLaunchRequest = (count: number) => {
    setPendingCount(count);
    if (!user) {
      setShowLogin(true);
    } else {
      setShowDeploy(true);
    }
  };

  const deployInstances = (distributions: any[]) => {
    const newInstances: AgentInstance[] = [];

    distributions.forEach(dist => {
      for (let i = 0; i < dist.count; i++) {
        const id = `node-${Math.random().toString(36).substr(2, 9)}`;
        const timestamp = new Date().toLocaleTimeString().slice(0, 5);
        const isCloudflare = dist.provider.provider.includes('Cloudflare');

        const initialMessage = { 
          role: 'agent' as const, 
          content: `Node established in ${dist.region.name}. Running ${dist.provider.name} engine. System integrity verified.`, 
          timestamp 
        };

        // Comprehensive tagging based on deployment choices
        const tags = Array.from(new Set([
          dist.provider.tag,
          dist.compute.tag,
          dist.region.tag,
          isCloudflare ? 'edge' : 'cloud',
          'production-v4'
        ]));

        newInstances.push({
          id,
          name: `${isCloudflare ? 'WORKER' : 'NODE'}_${String(instances.length + newInstances.length + 1).padStart(3, '0')}`,
          status: 'booting',
          provider: dist.provider.name,
          vCPU: dist.compute.vCPU,
          ram: dist.compute.ram,
          region: dist.region.name,
          messages: [initialMessage],
          chats: [{
            id: 'chat-default',
            name: 'Primary Uplink',
            lastUpdate: timestamp,
            messages: [initialMessage]
          }],
          activeChatId: 'chat-default',
          tags: tags
        });
      }
    });

    setInstances(prev => [...prev, ...newInstances]);
    setView('active');
    setShowDeploy(false);

    // Progressive status update
    newInstances.forEach(ni => {
      setTimeout(() => {
        setInstances(prev => prev.map(inst => inst.id === ni.id ? { ...inst, status: 'online' } : inst));
      }, 500 + Math.random() * 1000);
    });
  };

  const handleSendMessage = async (id: string, chatId: string, content: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);
    setInstances(prev => prev.map(inst => inst.id === id ? {
      ...inst,
      chats: inst.chats.map(chat => chat.id === chatId ? {
        ...chat,
        isThinking: true,
        messages: [...chat.messages, { role: 'user', content, timestamp }]
      } : chat)
    } : inst));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: content,
      });
      const aiText = response.text || "Connection failed. Please verify neural uplink.";
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        chats: inst.chats.map(chat => chat.id === chatId ? {
          ...chat,
          isThinking: false,
          messages: [...chat.messages, { role: 'agent', content: aiText, timestamp: new Date().toLocaleTimeString().slice(0, 5) }]
        } : chat)
      } : inst));
    } catch (e) {
      setInstances(prev => prev.map(inst => inst.id === id ? {
        ...inst,
        chats: inst.chats.map(chat => chat.id === chatId ? { ...chat, isThinking: false } : chat)
      } : inst));
    }
  };

  const handleNewChat = (instanceId: string) => {
    const timestamp = new Date().toLocaleTimeString().slice(0, 5);
    const newChat: ChatSession = {
      id: `chat-${Math.random().toString(36).substr(2, 5)}`,
      name: `Stream ${Math.random().toString(36).substr(2, 2).toUpperCase()}`,
      lastUpdate: timestamp,
      messages: [{ role: 'agent', content: 'New context stream initialized. Waiting for input...', timestamp }]
    };
    setInstances(prev => prev.map(inst => inst.id === instanceId ? {
      ...inst,
      chats: [...inst.chats, newChat],
      activeChatId: newChat.id
    } : inst));
  };

  const handleBulkTag = (ids: string[], tag: string) => {
    const cleanTag = tag.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
    if (!cleanTag) return;
    setInstances(prev => prev.map(inst => ids.includes(inst.id) ? { ...inst, tags: Array.from(new Set([...inst.tags, cleanTag])) } : inst));
  };

  return (
    <div className="h-screen w-screen bg-black text-white font-sans overflow-hidden selection:bg-white selection:text-black">
      {view === 'entry' ? (
        <LandingView 
          onLaunch={handleLaunchRequest} 
          onShowDocs={() => setShowDocs(true)}
        />
      ) : (
        <FactoryFloor 
          instances={instances} 
          onSendMessage={handleSendMessage}
          onNewChat={handleNewChat}
          onSwitchChat={(id, chatId) => setInstances(prev => prev.map(i => i.id === id ? { ...i, activeChatId: chatId } : i))}
          onBulkMessage={(ids, msg) => ids.forEach(id => {
            const inst = instances.find(i => i.id === id);
            if (inst) handleSendMessage(id, inst.activeChatId || inst.chats[0].id, msg);
          })}
          onBulkTag={handleBulkTag}
          onBack={() => setView('entry')}
          onAddMore={() => setShowDeploy(true)}
          onShowBilling={() => setShowBilling(true)}
          onShowDocs={() => setShowDocs(true)}
        />
      )}

      {showLogin && (
        <LoginModal onClose={() => setShowLogin(false)} onSuccess={(u) => { setUser(u); setShowLogin(false); setShowDeploy(true); }} />
      )}

      {showDeploy && (
        <DeployModal 
          onClose={() => setShowDeploy(false)} 
          onDeploy={deployInstances} 
          initialCount={pendingCount} 
        />
      )}

      {showBilling && <BillingModal onClose={() => setShowBilling(false)} />}

      {showDocs && <WikiView onClose={() => setShowDocs(false)} />}
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { AGENT_PROVIDERS, COMPUTE_OPTIONS, REGIONS } from '../constants';
import Icon from './Icon';

interface DeployModalProps {
  onClose: () => void;
  onDeploy: (distributions: any[]) => void;
  initialCount: number;
}

interface Distribution {
  id: string;
  provider: typeof AGENT_PROVIDERS[0];
  compute: typeof COMPUTE_OPTIONS[0];
  region: typeof REGIONS[0];
  count: number;
}

const DeployModal: React.FC<DeployModalProps> = ({ onClose, onDeploy, initialCount }) => {
  const [totalNodes, setTotalNodes] = useState(initialCount);
  const [distributions, setDistributions] = useState<Distribution[]>([
    { 
      id: 'initial-dist', 
      provider: AGENT_PROVIDERS[0], 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[0], 
      count: initialCount 
    }
  ]);

  const addDistribution = () => {
    const usedProviderIds = distributions.map(d => d.provider.id);
    const nextProvider = AGENT_PROVIDERS.find(p => !usedProviderIds.includes(p.id)) 
      || AGENT_PROVIDERS[distributions.length % AGENT_PROVIDERS.length];

    const newDist: Distribution = { 
      id: Math.random().toString(36).substr(2, 9), 
      provider: nextProvider, 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[distributions.length % REGIONS.length], 
      count: 0 
    };

    setDistributions([...distributions, newDist]);
  };

  const removeDistribution = (id: string) => {
    if (distributions.length <= 1) return;
    setDistributions(distributions.filter(d => d.id !== id));
  };

  const updateDistCount = (id: string, val: string) => {
    const num = parseInt(val) || 0;
    setDistributions(distributions.map(d => d.id === id ? { ...d, count: Math.max(0, num) } : d));
  };

  const updateDistSettings = (id: string, field: keyof Distribution, value: any) => {
    setDistributions(distributions.map(d => d.id === id ? { ...d, [field]: value } : d));
  };

  const currentAssigned = useMemo(() => 
    distributions.reduce((sum, d) => sum + d.count, 0)
  , [distributions]);

  const remaining = totalNodes - currentAssigned;
  const isValid = currentAssigned === totalNodes;

  const handleDeploy = () => {
    if (!isValid) return;
    onDeploy(distributions.filter(d => d.count > 0));
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-4 overflow-y-auto selection:bg-white selection:text-black">
      <div className="w-full max-w-5xl bg-[#050505] border border-white/10 p-8 flex flex-col gap-6 animate-in fade-in zoom-in-95 duration-500 rounded-3xl shadow-[0_0_60px_rgba(0,0,0,1)]">

        <header className="flex justify-between items-center border-b border-white/5 pb-6">
          <div className="flex items-center gap-4">
            <h2 className="font-serif text-xl tracking-[0.3em] text-white uppercase leading-none">Provisioning</h2>
            <div className="px-2 py-0.5 bg-white/5 border border-white/10 rounded-[4px] text-[7px] font-mono text-neutral-600 uppercase tracking-widest">v4.0_MANUAL</div>
          </div>
          <button onClick={onClose} className="text-neutral-600 hover:text-white transition-all p-2 hover:bg-white/5 rounded-full border border-transparent">
            <Icon name="close" size={18} />
          </button>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          <div className="lg:col-span-8 space-y-6">
            <div className="flex items-center justify-between">
              <label className="text-[8px] font-bold uppercase tracking-[0.4em] text-neutral-500">Node Configuration</label>
              <button 
                onClick={addDistribution}
                className="text-[8px] font-bold uppercase tracking-[0.2em] text-white/30 hover:text-white transition-all"
              >
                + Add Group
              </button>
            </div>

            <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 no-scrollbar">
              {distributions.map((dist) => (
                <div key={dist.id} className="p-5 bg-neutral-900/10 border border-white/5 rounded-2xl flex flex-col md:flex-row items-end md:items-center gap-6 relative group hover:border-white/10 transition-all">
                  {distributions.length > 1 && (
                    <button 
                      onClick={() => removeDistribution(dist.id)}
                      className="absolute -top-2 -right-2 text-neutral-700 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-1.5 bg-[#050505] border border-white/10 rounded-full"
                    >
                      <Icon name="close" size={10} />
                    </button>
                  )}

                  <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-4 w-full">
                    <div className="space-y-1.5">
                      <span className="text-[7px] uppercase font-bold text-neutral-600 tracking-[0.2em]">Engine</span>
                      <select 
                        value={dist.provider.id}
                        onChange={(e) => updateDistSettings(dist.id, 'provider', AGENT_PROVIDERS.find(p => p.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-lg px-3 py-2 text-[9px] font-mono text-white outline-none focus:border-white/20 appearance-none cursor-pointer"
                      >
                        {AGENT_PROVIDERS.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                      </select>
                    </div>

                    <div className="space-y-1.5">
                      <span className="text-[7px] uppercase font-bold text-neutral-600 tracking-[0.2em]">Layer</span>
                      <select 
                        value={dist.compute.id}
                        onChange={(e) => updateDistSettings(dist.id, 'compute', COMPUTE_OPTIONS.find(c => c.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-lg px-3 py-2 text-[9px] font-mono text-white outline-none focus:border-white/20 appearance-none cursor-pointer"
                      >
                        {COMPUTE_OPTIONS.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>

                    <div className="space-y-1.5">
                      <span className="text-[7px] uppercase font-bold text-neutral-600 tracking-[0.2em]">Region</span>
                      <select 
                        value={dist.region.id}
                        onChange={(e) => updateDistSettings(dist.id, 'region', REGIONS.find(r => r.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-lg px-3 py-2 text-[9px] font-mono text-white outline-none focus:border-white/20 appearance-none cursor-pointer"
                      >
                        {REGIONS.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                      </select>
                    </div>
                  </div>

                  <div className="flex items-center gap-3 shrink-0 pt-4 md:pt-0">
                    <input 
                      type="number"
                      min="0"
                      value={dist.count}
                      onChange={(e) => updateDistCount(dist.id, e.target.value)}
                      className="w-14 bg-black border border-white/10 rounded-lg px-2 py-2 text-center text-[11px] font-mono text-white outline-none focus:border-blue-500/50 transition-all"
                    />
                    <span className="text-[7px] font-mono text-neutral-700 uppercase tracking-widest">Qty</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="lg:col-span-4 flex flex-col justify-between py-2">
            <div className="bg-neutral-900/30 border border-white/5 rounded-2xl p-6 space-y-8">
              <div className="space-y-4">
                <label className="text-[8px] font-bold uppercase tracking-[0.4em] text-neutral-600 block">Total Scale</label>
                <div className="flex justify-between items-baseline">
                  <span className="text-5xl font-serif text-white tracking-tighter tabular-nums">{totalNodes}</span>
                  <span className="text-[8px] font-mono text-neutral-700 tracking-[0.2em] uppercase">Instances</span>
                </div>
                <input 
                  type="range"
                  min="1"
                  max="100"
                  value={totalNodes}
                  onChange={(e) => setTotalNodes(parseInt(e.target.value))}
                  className="w-full h-1 bg-neutral-900 rounded-full appearance-none cursor-pointer accent-white"
                />
              </div>

              <div className="space-y-4 pt-6 border-t border-white/5">
                <div className="flex justify-between items-center text-[8px] font-mono uppercase tracking-widest">
                   <span className="text-neutral-500">Allocated</span>
                   <span className={isValid ? "text-green-500" : "text-neutral-400"}>{currentAssigned} / {totalNodes}</span>
                </div>
                {!isValid && (
                  <div className="text-right">
                    <span className="text-[8px] font-mono text-yellow-500/80 uppercase tracking-widest">
                      {remaining > 0 ? `Pending: ${remaining} nodes` : `Excess: ${Math.abs(remaining)} nodes`}
                    </span>
                  </div>
                )}
              </div>

              <button 
                onClick={handleDeploy}
                disabled={!isValid}
                className={`w-full py-4 text-[10px] font-bold uppercase tracking-[0.4em] rounded-xl transition-all flex items-center justify-center gap-3 ${
                  isValid 
                  ? 'bg-white text-black hover:scale-[1.02] active:scale-[0.98]' 
                  : 'bg-neutral-800 text-neutral-600 cursor-not-allowed'
                }`}
              >
                {isValid ? 'Initialize ADD' : 'Config Incomplete'}
              </button>
            </div>

            <div className="flex items-center gap-2 opacity-30 mt-6 px-2">
              <div className="w-1 h-1 bg-neutral-500 rounded-full"></div>
              <span className="text-[7px] font-mono text-neutral-500 uppercase tracking-widest leading-none">Status: Ready for Provisioning</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DeployModal;

import React, { useState } from 'react';
import { AgentInstance } from '../types';
import Icon from './Icon';
import TerminalPane from './TerminalPane';

interface FactoryFloorProps {
  instances: AgentInstance[];
  onSendMessage: (id: string, chatId: string, content: string) => void;
  onNewChat: (id: string) => void;
  onSwitchChat: (id: string, chatId: string) => void;
  onBulkMessage: (ids: string[], content: string) => void;
  onBulkTag: (ids: string[], tag: string) => void;
  onBack: () => void;
  onAddMore: () => void;
  onShowBilling: () => void;
  onShowDocs: () => void;
}

const FactoryFloor: React.FC<FactoryFloorProps> = ({ 
  instances, onSendMessage, onNewChat, onSwitchChat, onBulkMessage, onBulkTag, onBack, onAddMore, onShowBilling, onShowDocs
}) => {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [bulkMode, setBulkMode] = useState<'message' | 'tag' | null>(null);
  const [bulkValue, setBulkValue] = useState('');
  const [activeFilterTag, setActiveFilterTag] = useState<string | null>(null);
  const [fullscreenId, setFullscreenId] = useState<string | null>(null);

  // Obtener todos los tags únicos
  const allTags = Array.from(new Set(instances.flatMap(i => i.tags)));

  // Filtrar instancias visibles
  const visibleInstances = activeFilterTag 
    ? instances.filter(i => i.tags.includes(activeFilterTag)) 
    : instances;

  const toggleSelection = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]
    );
  };

  const selectVisible = () => {
    const visibleIds = visibleInstances.map(i => i.id);
    const allVisibleSelected = visibleIds.every(id => selectedIds.includes(id));

    if (allVisibleSelected) {
      setSelectedIds(prev => prev.filter(id => !visibleIds.includes(id)));
    } else {
      setSelectedIds(prev => Array.from(new Set([...prev, ...visibleIds])));
    }
  };

  const handleBulkAction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!bulkValue.trim()) return;

    if (bulkMode === 'message') {
      onBulkMessage(selectedIds, bulkValue);
    } else if (bulkMode === 'tag') {
      onBulkTag(selectedIds, bulkValue);
    }

    setBulkValue('');
    setBulkMode(null);
    setSelectedIds([]);
  };

  return (
    <div className="h-full w-full flex flex-col overflow-hidden animate-in fade-in duration-500 relative bg-[#050505]">
      {/* Navbar: Agentz Factory */}
      <header className="h-20 border-b border-white/5 flex items-center justify-between px-8 shrink-0 bg-black/50 backdrop-blur-md z-30">
        <div className="flex flex-col gap-2">
          <div className="flex items-center gap-6">
            <button onClick={onBack} className="group flex items-center gap-2 text-neutral-500 hover:text-white transition-all">
              <Icon name="chevron-right" size={14} className="rotate-180" />
              <span className="text-[10px] font-bold uppercase tracking-[0.3em]">Vault</span>
            </button>
            <div className="h-4 w-px bg-white/10"></div>
            <div className="flex items-center gap-4">
              <div className="flex flex-col">
                <span className="text-[12px] font-heading font-bold uppercase tracking-[0.4em] factory-gradient-text">Agentz Factory</span>
                <span className="text-[7px] font-mono uppercase tracking-[0.2em] text-neutral-500">Autonomous Orchestrator</span>
              </div>
              <button 
                onClick={selectVisible}
                className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1 rounded-full border transition-all ${
                  selectedIds.length > 0 ? 'bg-blue-600 border-blue-600 text-white shadow-[0_0_15px_rgba(37,99,235,0.4)]' : 'text-neutral-500 border-white/10 hover:border-white/30'
                }`}
              >
                {activeFilterTag ? `Select Visible (${visibleInstances.length})` : `Select Fleet (${instances.length})`}
              </button>
            </div>
          </div>

          <div className="flex items-center gap-3 overflow-x-auto no-scrollbar py-1">
            <button 
              onClick={() => setActiveFilterTag(null)}
              className={`text-[8px] font-bold uppercase tracking-widest px-2.5 py-0.5 rounded transition-all ${
                activeFilterTag === null ? 'bg-white text-black' : 'text-neutral-500 hover:text-neutral-300'
              }`}
            >
              All_Nodes
            </button>
            {allTags.map(tag => (
              <button 
                key={tag}
                onClick={() => setActiveFilterTag(tag)}
                className={`text-[8px] font-bold uppercase tracking-widest px-2.5 py-0.5 rounded transition-all border ${
                  activeFilterTag === tag ? 'bg-violet-600 border-violet-600 text-white shadow-[0_0_10px_rgba(139,92,246,0.2)]' : 'text-neutral-600 border-white/5 hover:border-white/20'
                }`}
              >
                #{tag}
              </button>
            ))}
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={onShowDocs}
            className="text-[9px] font-bold uppercase tracking-widest text-neutral-400 hover:text-white px-4 py-1.5 transition-colors border border-transparent hover:border-white/10 rounded-full"
          >
            DOCS
          </button>
          <button 
            onClick={onShowBilling}
            className="text-[9px] font-bold uppercase tracking-widest text-neutral-400 hover:text-white px-4 py-1.5 transition-colors border border-transparent hover:border-white/10 rounded-full"
          >
            BILLING
          </button>
          <button 
            onClick={onAddMore} 
            className="bg-white/5 hover:bg-white hover:text-black border border-white/10 px-6 py-1.5 rounded-full text-[9px] font-bold uppercase tracking-[0.2em] transition-all"
          >
            ADD
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 no-scrollbar pb-32">
        {visibleInstances.map(instance => (
          <TerminalPane 
            key={instance.id} 
            instance={instance} 
            isSelected={selectedIds.includes(instance.id)}
            onSelect={() => toggleSelection(instance.id)}
            onSend={(chatId, msg) => onSendMessage(instance.id, chatId, msg)}
            onNewChat={() => onNewChat(instance.id)}
            onSwitchChat={(chatId) => onSwitchChat(instance.id, chatId)}
            onToggleFullscreen={() => setFullscreenId(instance.id)}
          />
        ))}
      </main>

      {/* Fullscreen Overlay */}
      {fullscreenId && (
        <div className="fixed inset-0 z-[100] bg-black p-4 md:p-10 animate-in zoom-in-95 duration-300">
          <div className="h-full w-full">
            <TerminalPane 
              instance={instances.find(i => i.id === fullscreenId)!} 
              isSelected={false}
              onSelect={() => {}}
              onSend={(chatId, msg) => onSendMessage(fullscreenId, chatId, msg)}
              onNewChat={() => onNewChat(fullscreenId)}
              onSwitchChat={(chatId) => onSwitchChat(fullscreenId, chatId)}
              isFullscreen={true}
              onToggleFullscreen={() => setFullscreenId(null)}
            />
          </div>
        </div>
      )}

      {/* Bulk Action Bar */}
      {selectedIds.length > 0 && !fullscreenId && (
        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-full max-w-2xl px-6 z-50 animate-in slide-in-from-bottom-10 duration-500">
          <div className="bg-neutral-900 border border-white/20 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/5 bg-white/5">
              <span className="text-[10px] font-bold uppercase tracking-[0.3em] factory-gradient-text">
                Bulk Action: {selectedIds.length} Nodes Selected
              </span>
              <div className="flex gap-2">
                <button onClick={() => setBulkMode('message')} className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-all ${bulkMode === 'message' ? 'bg-white text-black' : 'hover:bg-white/10'}`}>Broadcast</button>
                <button onClick={() => setBulkMode('tag')} className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-all ${bulkMode === 'tag' ? 'bg-white text-black' : 'hover:bg-white/10'}`}>Add Tag</button>
                <button onClick={() => { setSelectedIds([]); setBulkMode(null); }} className="text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg hover:bg-red-500/20 text-red-400">Cancel</button>
              </div>
            </div>
            {bulkMode && (
              <form onSubmit={handleBulkAction} className="p-4 flex gap-4 animate-in fade-in duration-300">
                <input type="text" value={bulkValue} onChange={(e) => setBulkValue(e.target.value)} placeholder={bulkMode === 'message' ? "Command fleet..." : "Tag name..."} className="flex-1 bg-black/50 border border-white/10 rounded-xl px-5 py-3 text-xs font-mono outline-none focus:border-blue-500 transition-all" autoFocus />
                <button type="submit" className="bg-white text-black px-6 rounded-xl text-[10px] font-bold uppercase tracking-widest">Execute</button>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default FactoryFloor;

import React, { useState, useMemo } from 'react';
import { AGENT_PROVIDERS, COMPUTE_OPTIONS, REGIONS } from '../constants';
import Icon from './Icon';

interface DeployModalProps {
  onClose: () => void;
  onDeploy: (distributions: any[]) => void;
  initialCount: number;
}

interface Distribution {
  id: string;
  provider: typeof AGENT_PROVIDERS[0];
  compute: typeof COMPUTE_OPTIONS[0];
  region: typeof REGIONS[0];
  count: number;
}

const DeployModal: React.FC<DeployModalProps> = ({ onClose, onDeploy, initialCount }) => {
  const [totalNodes, setTotalNodes] = useState(initialCount);
  const [distributions, setDistributions] = useState<Distribution[]>([
    { 
      id: 'initial-dist', 
      provider: AGENT_PROVIDERS[0], 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[0], 
      count: initialCount 
    }
  ]);

  const addDistribution = () => {
    const usedProviderIds = distributions.map(d => d.provider.id);
    const nextProvider = AGENT_PROVIDERS.find(p => !usedProviderIds.includes(p.id)) 
      || AGENT_PROVIDERS[distributions.length % AGENT_PROVIDERS.length];

    const newDist: Distribution = { 
      id: Math.random().toString(36).substr(2, 9), 
      provider: nextProvider, 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[distributions.length % REGIONS.length], 
      count: 0 
    };

    setDistributions([...distributions, newDist]);
  };

  const removeDistribution = (id: string) => {
    if (distributions.length <= 1) return;
    setDistributions(distributions.filter(d => d.id !== id));
  };

  const updateDistCount = (id: string, val: string) => {
    const num = parseInt(val) || 0;
    setDistributions(distributions.map(d => d.id === id ? { ...d, count: Math.max(0, num) } : d));
  };

  const updateDistSettings = (id: string, field: keyof Distribution, value: any) => {
    setDistributions(distributions.map(d => d.id === id ? { ...d, [field]: value } : d));
  };

  const currentAssigned = useMemo(() => 
    distributions.reduce((sum, d) => sum + d.count, 0)
  , [distributions]);

  const remaining = totalNodes - currentAssigned;
  const isValid = currentAssigned === totalNodes;

  const handleDeploy = () => {
    if (!isValid) return;
    onDeploy(distributions.filter(d => d.count > 0));
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-4 overflow-y-auto selection:bg-white selection:text-black">
      <div className="w-full max-w-5xl bg-[#050505] border border-white/10 p-8 flex flex-col gap-6 animate-in fade-in zoom-in-95 duration-500 rounded-3xl shadow-[0_0_60px_rgba(0,0,0,1)]">

        <header className="flex justify-between items-center border-b border-white/5 pb-6">
          <div className="flex items-center gap-4">
            <h2 className="font-serif text-xl tracking-[0.3em] factory-gradient-text uppercase leading-none">Provisioning</h2>
            <div className="px-2 py-0.5 bg-white/5 border border-white/10 rounded-[4px] text-[7px] font-mono text-neutral-600 uppercase tracking-widest">v4.0_MANUAL</div>
          </div>
          <button onClick={onClose} className="text-neutral-600 hover:text-white transition-all p-2 hover:bg-white/5 rounded-full border border-transparent">
            <Icon name="close" size={18} />
          </button>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          <div className="lg:col-span-8 space-y-6">
            <div className="flex items-center justify-between">
              <label className="text-[8px] font-bold uppercase tracking-[0.4em] text-neutral-500">Node Configuration</label>
              <button 
                onClick={addDistribution}
                className="text-[8px] font-bold uppercase tracking-[0.2em] text-blue-500 hover:text-white transition-all"
              >
                + Add Group
              </button>
            </div>

            <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 no-scrollbar">
              {distributions.map((dist) => (
                <div key={dist.id} className="p-5 bg-neutral-900/10 border border-white/5 rounded-2xl flex flex-col md:flex-row items-end md:items-center gap-6 relative group hover:border-white/10 transition-all">
                  {distributions.length > 1 && (
                    <button 
                      onClick={() => removeDistribution(dist.id)}
                      className="absolute -top-2 -right-2 text-neutral-700 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-1.5 bg-[#050505] border border-white/10 rounded-full"
                    >
                      <Icon name="close" size={10} />
                    </button>
                  )}

                  <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-4 w-full">
                    <div className="space-y-1.5">
                      <span className="text-[7px] uppercase font-bold text-neutral-600 tracking-[0.2em]">Engine</span>
                      <select 
                        value={dist.provider.id}
                        onChange={(e) => updateDistSettings(dist.id, 'provider', AGENT_PROVIDERS.find(p => p.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-lg px-3 py-2 text-[9px] font-mono text-white outline-none focus:border-blue-500/40 appearance-none cursor-pointer"
                      >
                        {AGENT_PROVIDERS.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                      </select>
                    </div>

                    <div className="space-y-1.5">
                      <span className="text-[7px] uppercase font-bold text-neutral-600 tracking-[0.2em]">Layer</span>
                      <select 
                        value={dist.compute.id}
                        onChange={(e) => updateDistSettings(dist.id, 'compute', COMPUTE_OPTIONS.find(c => c.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-lg px-3 py-2 text-[9px] font-mono text-white outline-none focus:border-blue-500/40 appearance-none cursor-pointer"
                      >
                        {COMPUTE_OPTIONS.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>

                    <div className="space-y-1.5">
                      <span className="text-[7px] uppercase font-bold text-neutral-600 tracking-[0.2em]">Region</span>
                      <select 
                        value={dist.region.id}
                        onChange={(e) => updateDistSettings(dist.id, 'region', REGIONS.find(r => r.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-lg px-3 py-2 text-[9px] font-mono text-white outline-none focus:border-blue-500/40 appearance-none cursor-pointer"
                      >
                        {REGIONS.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                      </select>
                    </div>
                  </div>

                  <div className="flex items-center gap-3 shrink-0 pt-4 md:pt-0">
                    <input 
                      type="number"
                      min="0"
                      value={dist.count}
                      onChange={(e) => updateDistCount(dist.id, e.target.value)}
                      className="w-14 bg-black border border-white/10 rounded-lg px-2 py-2 text-center text-[11px] font-mono text-white outline-none focus:border-violet-500/50 transition-all"
                    />
                    <span className="text-[7px] font-mono text-neutral-700 uppercase tracking-widest">Qty</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="lg:col-span-4 flex flex-col justify-between py-2">
            <div className="bg-neutral-900/30 border border-white/5 rounded-2xl p-6 space-y-8">
              <div className="space-y-4">
                <label className="text-[8px] font-bold uppercase tracking-[0.4em] text-neutral-600 block">Total Scale</label>
                <div className="flex justify-between items-baseline">
                  <span className="text-5xl font-serif text-white tracking-tighter tabular-nums">{totalNodes}</span>
                  <span className="text-[8px] font-mono text-neutral-700 tracking-[0.2em] uppercase">Instances</span>
                </div>
                <div className="relative h-1 w-full bg-neutral-900 rounded-full overflow-hidden">
                    <input 
                        type="range"
                        min="1"
                        max="100"
                        value={totalNodes}
                        onChange={(e) => setTotalNodes(parseInt(e.target.value))}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                    />
                    <div 
                        className="absolute left-0 top-0 h-full factory-gradient-bg transition-all"
                        style={{ width: `${(totalNodes/100)*100}%` }}
                    />
                </div>
              </div>

              <div className="space-y-4 pt-6 border-t border-white/5">
                <div className="flex justify-between items-center text-[8px] font-mono uppercase tracking-widest">
                   <span className="text-neutral-500">Allocated</span>
                   <span className={isValid ? "text-blue-400 font-bold" : "text-neutral-400"}>{currentAssigned} / {totalNodes}</span>
                </div>
                {!isValid && (
                  <div className="text-right">
                    <span className="text-[8px] font-mono text-violet-400 uppercase tracking-widest">
                      {remaining > 0 ? `Pending: ${remaining} nodes` : `Excess: ${Math.abs(remaining)} nodes`}
                    </span>
                  </div>
                )}
              </div>

              <button 
                onClick={handleDeploy}
                disabled={!isValid}
                className={`w-full py-4 text-[10px] font-bold uppercase tracking-[0.4em] rounded-xl transition-all flex items-center justify-center gap-3 relative group overflow-hidden ${
                  isValid 
                  ? 'bg-white text-black hover:scale-[1.02] active:scale-[0.98]' 
                  : 'bg-neutral-800 text-neutral-600 cursor-not-allowed'
                }`}
              >
                {isValid && <div className="absolute inset-0 factory-gradient-bg opacity-0 group-hover:opacity-10 transition-opacity"></div>}
                <span className="relative z-10">{isValid ? 'Initialize ADD' : 'Config Incomplete'}</span>
              </button>
            </div>

            <div className="flex items-center gap-2 opacity-30 mt-6 px-2">
              <div className="w-1 h-1 bg-emerald-500 rounded-full shadow-[0_0_8px_#059669]"></div>
              <span className="text-[7px] font-mono text-neutral-500 uppercase tracking-widest leading-none">Status: Ready for Provisioning</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

