          </div>
        </div>

        {/* Chat Switcher */}
        <div className="flex items-center gap-2 bg-black/40 rounded-lg px-2 py-1 border border-white/5">
          <button onClick={() => cycleChat(-1)} className="p-1 text-neutral-500 hover:text-white transition-all"><Icon name="chevron-right" size={12} className="rotate-180" /></button>
          <span className="text-[9px] font-mono font-bold text-neutral-400 px-1 min-w-[3.5rem] text-center">
            {chatIndex + 1} / {instance.chats.length}
          </span>
          <button onClick={() => cycleChat(1)} className="p-1 text-neutral-500 hover:text-white transition-all"><Icon name="chevron-right" size={12} /></button>
          <div className="w-px h-3 bg-white/10 mx-1"></div>
          <button onClick={onNewChat} className={`p-1 text-neutral-500 transition-all hover:text-orange-400`}><Icon name="close" size={12} className="rotate-45" /></button>
        </div>

        <div className="flex items-center gap-2">
          <button onClick={() => setShowDetails(!showDetails)} className={`p-2 rounded-lg transition-all ${showDetails ? 'text-orange-400 bg-orange-400/10' : 'text-neutral-500 hover:text-white'}`}>
            <Icon name="CONFIG" size={14} />
          </button>
          <button onClick={onToggleFullscreen} className="p-2 text-neutral-500 hover:text-white transition-all">
            <Icon name={isFullscreen ? "close" : "security"} size={16} />
          </button>
        </div>
      </div>

      <div className="flex-1 relative overflow-hidden flex flex-col">
