                <div><span className="text-[8px] uppercase text-neutral-500 block">Memory</span><span className="text-xs font-mono">{instance.ram}</span></div>
                <div><span className="text-[8px] uppercase text-neutral-500 block">Region</span><span className="text-xs font-mono">{instance.region}</span></div>
                <div><span className="text-[8px] uppercase text-neutral-500 block">Status</span><span className={`text-xs font-mono text-red-500`}>CONNECTED</span></div>
              </div>
            </div>
            <button onClick={() => setShowDetails(false)} className="w-full mt-6 py-2 bg-white/5 hover:bg-white/10 border border-white/10 text-[9px] font-bold uppercase tracking-widest rounded-lg transition-all">Close Specs</button>
          </div>
        )}

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-4 no-scrollbar font-mono text-[11px] leading-relaxed">
          {activeChat.messages.map((m, i) => (
