                <span className="uppercase">{m.role === 'user' ? 'Operator' : 'Agent_Core'}</span>
                <span>•</span>
                <span>{m.timestamp}</span>
              </div>
              {m.content}
            </div>
          ))}
          {activeChat.isThinking && (
            <div className={`text-orange-500/60 flex items-center gap-2 animate-pulse font-bold tracking-widest text-[10px]`}>
              INDUSTRIAL_SYNTHESIS_ACTIVE_
            </div>
