        <form 
          onSubmit={(e) => { e.preventDefault(); if (input.trim()) { onSend(activeChat.id, input); setInput(''); } }}
          className={`p-4 bg-black/60 border-t border-white/5 ${isFullscreen ? 'px-10 py-8' : ''}`}
        >
          <div className={`flex items-center gap-3 bg-white/5 border rounded-xl px-4 py-2 transition-all ${isFullscreen ? 'max-w-4xl mx-auto py-4 rounded-2xl' : ''} border-white/5 focus-within:border-orange-500/40`}>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Send instruction..."
              className="flex-1 bg-transparent border-none outline-none text-[12px] font-mono text-white placeholder:text-neutral-700"
            />
            <button type="submit" className={`transition-all text-orange-500 hover:text-orange-400`}>
              <Icon name="terminal" size={14} />
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

