        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-full max-w-2xl px-6 z-50 animate-in slide-in-from-bottom-10 duration-500">
          <div className="bg-neutral-900 border border-white/20 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/5 bg-white/5">
              <span className="text-[10px] font-bold uppercase tracking-[0.3em] factory-gradient-text">
                Bulk Action: {selectedIds.length} Nodes Selected
              </span>
              <div className="flex gap-2">
                <button onClick={() => setBulkMode('message')} className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-all ${bulkMode === 'message' ? 'bg-white text-black' : 'text-white hover:bg-white/10'}`}>Broadcast</button>
                <button onClick={() => setBulkMode('tag')} className={`text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-all ${bulkMode === 'tag' ? 'bg-white text-black' : 'text-white hover:bg-white/10'}`}>Add Tag</button>
                <button onClick={() => { setSelectedIds([]); setBulkMode(null); }} className="text-[9px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg hover:bg-red-500/20 text-red-400">Cancel</button>
              </div>
            </div>
            {bulkMode && (
              <form onSubmit={handleBulkAction} className="p-4 flex gap-4 animate-in fade-in duration-300">
                <input type="text" value={bulkValue} onChange={(e) => setBulkValue(e.target.value)} placeholder={bulkMode === 'message' ? "Command fleet..." : "Tag name..."} className="flex-1 bg-black/50 border border-white/10 rounded-xl px-5 py-3 text-xs font-mono text-white outline-none focus:border-orange-400 transition-all" autoFocus />
                <button type="submit" className="bg-white text-black px-6 rounded-xl text-[10px] font-bold uppercase tracking-widest">Execute</button>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default FactoryFloor;

import React, { useState, useRef, useEffect } from 'react';
import Icon from './Icon';
import { AgentInstance, ChatSession } from '../types';

interface TerminalPaneProps {
  instance: AgentInstance;
  onSend: (chatId: string, msg: string) => void;
  isSelected: boolean;
  onSelect: () => void;
  onNewChat: () => void;
  onSwitchChat: (chatId: string) => void;
  isFullscreen?: boolean;
  onToggleFullscreen?: () => void;
}

const TerminalPane: React.FC<TerminalPaneProps> = ({ 
  instance, onSend, isSelected, onSelect, onNewChat, onSwitchChat, isFullscreen, onToggleFullscreen 
}) => {
  const [input, setInput] = useState('');
  const [showDetails, setShowDetails] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const activeChat = instance.chats.find(c => c.id === instance.activeChatId) || instance.chats[0];
  const chatIndex = instance.chats.findIndex(c => c.id === activeChat.id);
  // Using light orange for brand Primary
  const brandPrimary = "orange-400";
  const brandSecondary = "red-600";

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [activeChat.messages, activeChat.isThinking]);

  const cycleChat = (dir: number) => {
    const nextIdx = (chatIndex + dir + instance.chats.length) % instance.chats.length;
    onSwitchChat(instance.chats[nextIdx].id);
  };

  return (
    <div className={`flex flex-col overflow-hidden transition-all duration-500 rounded-3xl ${
      isFullscreen ? 'h-full w-full bg-black border border-white/10 shadow-2xl' : 
      `h-[440px] bg-white/5 border ${isSelected ? `border-${brandPrimary} ring-1 ring-${brandPrimary}/50` : 'border-white/5 hover:border-white/20'}`
    }`}>
      {/* Header */}
      <div className={`h-14 px-4 border-b border-white/5 flex items-center justify-between shrink-0 bg-black/30 backdrop-blur-sm`}>
        <div className="flex items-center gap-3">
          {!isFullscreen && (
            <button 
              onClick={(e) => { e.stopPropagation(); onSelect(); }}
              className={`w-4 h-4 rounded border transition-all flex items-center justify-center ${
                isSelected ? `bg-${brandPrimary} border-${brandPrimary}` : 'border-white/20 hover:border-white/40'
              }`}
            >
              {isSelected && <Icon name="action" size={10} className="text-white" />}
            </button>
          )}

          <div className="flex flex-col">
            <div className="flex items-center gap-2">
              <div className={`w-1.5 h-1.5 rounded-full ${instance.status === 'online' || instance.status === 'running' ? `bg-orange-400 shadow-[0_0_8px_#fb923c]` : 'bg-yellow-500'}`}></div>
              <span className={`text-[10px] font-mono font-bold tracking-widest text-white`}>{instance.name}</span>
            </div>
            <div className="flex gap-1 mt-0.5">
              <span className={`text-[6px] font-mono font-bold uppercase text-orange-400 bg-orange-400/10 px-1 rounded`}>CORE_NODE</span>
              {instance.tags.slice(0, 2).map(tag => (
                <span key={tag} className={`text-[6px] font-mono font-bold uppercase text-red-400 bg-red-400/5 px-1 rounded`}>#{tag}</span>
              ))}
            </div>
          </div>
        </div>

        {/* Chat Switcher */}
        <div className="flex items-center gap-2 bg-black/40 rounded-lg px-2 py-1 border border-white/5">
          <button onClick={() => cycleChat(-1)} className="p-1 text-white hover:text-white transition-all"><Icon name="chevron-right" size={12} className="rotate-180" /></button>
          <span className="text-[9px] font-mono font-bold text-white px-1 min-w-[3.5rem] text-center">
            {chatIndex + 1} / {instance.chats.length}
          </span>
          <button onClick={() => cycleChat(1)} className="p-1 text-white hover:text-white transition-all"><Icon name="chevron-right" size={12} /></button>
          <div className="w-px h-3 bg-white/10 mx-1"></div>
          <button onClick={onNewChat} className={`p-1 text-white transition-all hover:text-orange-400`}><Icon name="close" size={12} className="rotate-45" /></button>
        </div>

        <div className="flex items-center gap-2">
          <button onClick={() => setShowDetails(!showDetails)} className={`p-2 rounded-lg transition-all ${showDetails ? 'text-orange-400 bg-orange-400/10' : 'text-white hover:text-white'}`}>
            <Icon name="CONFIG" size={14} />
          </button>
          <button onClick={onToggleFullscreen} className="p-2 text-white hover:text-white transition-all">
            <Icon name={isFullscreen ? "close" : "security"} size={16} />
          </button>
        </div>
      </div>

      <div className="flex-1 relative overflow-hidden flex flex-col">
        {showDetails && (
          <div className="absolute inset-0 z-20 bg-black/95 backdrop-blur-md p-6 animate-in fade-in duration-300">
            <div className="space-y-4">
              <h5 className={`text-[10px] font-bold uppercase tracking-[0.2em] border-b border-white/5 pb-2 text-orange-400`}>System Status</h5>
              <div className="grid grid-cols-2 gap-4">
                <div><span className="text-[8px] uppercase text-white block">vCPU</span><span className="text-xs font-mono text-white">{instance.vCPU}</span></div>
                <div><span className="text-[8px] uppercase text-white block">Memory</span><span className="text-xs font-mono text-white">{instance.ram}</span></div>
                <div><span className="text-[8px] uppercase text-white block">Region</span><span className="text-xs font-mono text-white">{instance.region}</span></div>
                <div><span className="text-[8px] uppercase text-white block">Status</span><span className={`text-xs font-mono text-red-500`}>CONNECTED</span></div>
              </div>
            </div>
            <button onClick={() => setShowDetails(false)} className="w-full mt-6 py-2 bg-white/5 hover:bg-white/10 border border-white/10 text-[9px] font-bold uppercase tracking-widest rounded-lg transition-all text-white">Close Specs</button>
          </div>
        )}

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-4 no-scrollbar font-mono text-[11px] leading-relaxed">
          {activeChat.messages.map((m, i) => (
            <div key={i} className={`animate-in fade-in slide-in-from-left-2 duration-300 ${m.role === 'user' ? 'text-orange-300' : 'text-white'}`}>
              <div className="flex items-center gap-2 text-[8px] mb-1">
                <span className="uppercase text-white font-bold">{m.role === 'user' ? 'Operator' : 'Agent_Core'}</span>
                <span className="text-white">•</span>
                <span className="text-white">{m.timestamp}</span>
              </div>
              {m.content}
            </div>
          ))}
          {activeChat.isThinking && (
            <div className={`text-orange-400 flex items-center gap-2 animate-pulse font-bold tracking-widest text-[10px]`}>
              INDUSTRIAL_SYNTHESIS_ACTIVE_
            </div>
          )}
        </div>

        <form 
          onSubmit={(e) => { e.preventDefault(); if (input.trim()) { onSend(activeChat.id, input); setInput(''); } }}
          className={`p-4 bg-black/60 border-t border-white/5 ${isFullscreen ? 'px-10 py-8' : ''}`}
        >
          <div className={`flex items-center gap-3 bg-white/5 border rounded-xl px-4 py-2 transition-all ${isFullscreen ? 'max-w-4xl mx-auto py-4 rounded-2xl' : ''} border-white/5 focus-within:border-orange-400/40`}>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Send instruction..."
              className="flex-1 bg-transparent border-none outline-none text-[12px] font-mono text-white placeholder:text-white/40"
            />
            <button type="submit" className={`transition-all text-orange-400 hover:text-orange-300`}>
              <Icon name="terminal" size={14} />
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default TerminalPane;

import React, { useState, useMemo } from 'react';
import { AGENT_PROVIDERS, COMPUTE_OPTIONS, REGIONS } from '../constants';
import Icon from './Icon';

interface DeployModalProps {
  onClose: () => void;
  onDeploy: (distributions: any[]) => void;
  initialCount: number;
}

interface Distribution {
  id: string;
  provider: typeof AGENT_PROVIDERS[0];
  compute: typeof COMPUTE_OPTIONS[0];
  region: typeof REGIONS[0];
  count: number;
}

const DeployModal: React.FC<DeployModalProps> = ({ onClose, onDeploy, initialCount }) => {
  const [totalNodes, setTotalNodes] = useState(initialCount);
  const [distributions, setDistributions] = useState<Distribution[]>([
    { 
      id: 'initial-dist', 
      provider: AGENT_PROVIDERS[0], 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[0], 
      count: initialCount 
    }
  ]);

  const addDistribution = () => {
    const usedProviderIds = distributions.map(d => d.provider.id);
    const nextProvider = AGENT_PROVIDERS.find(p => !usedProviderIds.includes(p.id)) 
      || AGENT_PROVIDERS[distributions.length % AGENT_PROVIDERS.length];

    const newDist: Distribution = { 
      id: Math.random().toString(36).substr(2, 9), 
      provider: nextProvider, 
      compute: COMPUTE_OPTIONS[0], 
      region: REGIONS[distributions.length % REGIONS.length], 
      count: 0 
    };

    setDistributions([...distributions, newDist]);
  };

  const removeDistribution = (id: string) => {
    if (distributions.length <= 1) return;
    setDistributions(distributions.filter(d => d.id !== id));
  };

  const updateDistCount = (id: string, val: string) => {
    const num = parseInt(val) || 0;
    setDistributions(distributions.map(d => d.id === id ? { ...d, count: Math.max(0, num) } : d));
  };

  const updateDistSettings = (id: string, field: keyof Distribution, value: any) => {
    setDistributions(distributions.map(d => d.id === id ? { ...d, [field]: value } : d));
  };

  const currentAssigned = useMemo(() => 
    distributions.reduce((sum, d) => sum + d.count, 0)
  , [distributions]);

  const remaining = totalNodes - currentAssigned;
  const isValid = currentAssigned === totalNodes;

  const handleDeploy = () => {
    if (!isValid) return;
    onDeploy(distributions.filter(d => d.count > 0));
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-4 overflow-y-auto selection:bg-white selection:text-black">
      <div className="w-full max-w-5xl bg-[#050505] border border-white/10 p-8 flex flex-col gap-6 animate-in fade-in zoom-in-95 duration-500 rounded-3xl shadow-[0_0_60px_rgba(0,0,0,1)]">

        <header className="flex justify-between items-center border-b border-white/5 pb-6">
          <div className="flex items-center gap-4">
            <h2 className="font-serif text-xl tracking-[0.3em] factory-gradient-text uppercase leading-none">Provisioning</h2>
            <div className="px-2 py-0.5 bg-white/5 border border-white/10 rounded-[4px] text-[7px] font-mono text-white uppercase tracking-widest">v4.0_MANUAL</div>
          </div>
          <button onClick={onClose} className="text-white hover:text-white transition-all p-2 hover:bg-white/5 rounded-full border border-transparent">
            <Icon name="close" size={18} />
          </button>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          <div className="lg:col-span-8 space-y-6">
            <div className="flex items-center justify-between">
              <label className="text-[8px] font-bold uppercase tracking-[0.4em] text-white">Node Configuration</label>
              <button 
                onClick={addDistribution}
                className="text-[8px] font-bold uppercase tracking-[0.2em] text-orange-400 hover:text-white transition-all"
              >
                + Add Group
              </button>
            </div>

            <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 no-scrollbar">
              {distributions.map((dist) => (
                <div key={dist.id} className="p-5 bg-white/5 border border-white/5 rounded-2xl flex flex-col md:flex-row items-end md:items-center gap-6 relative group hover:border-white/10 transition-all">
                  {distributions.length > 1 && (
                    <button 
                      onClick={() => removeDistribution(dist.id)}
                      className="absolute -top-2 -right-2 text-white hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-1.5 bg-[#050505] border border-white/10 rounded-full"
                    >
                      <Icon name="close" size={10} />
                    </button>
                  )}

                  <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-4 w-full">
                    <div className="space-y-1.5">
                      <span className="text-[7px] uppercase font-bold text-white tracking-[0.2em]">Engine</span>
                      <select 
                        value={dist.provider.id}
                        onChange={(e) => updateDistSettings(dist.id, 'provider', AGENT_PROVIDERS.find(p => p.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-lg px-3 py-2 text-[9px] font-mono text-white outline-none focus:border-orange-400/40 appearance-none cursor-pointer"
                      >
                        {AGENT_PROVIDERS.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                      </select>
                    </div>

                    <div className="space-y-1.5">
                      <span className="text-[7px] uppercase font-bold text-white tracking-[0.2em]">Layer</span>
                      <select 
                        value={dist.compute.id}
                        onChange={(e) => updateDistSettings(dist.id, 'compute', COMPUTE_OPTIONS.find(c => c.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-lg px-3 py-2 text-[9px] font-mono text-white outline-none focus:border-orange-400/40 appearance-none cursor-pointer"
                      >
                        {COMPUTE_OPTIONS.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>

                    <div className="space-y-1.5">
                      <span className="text-[7px] uppercase font-bold text-white tracking-[0.2em]">Region</span>
                      <select 
                        value={dist.region.id}
                        onChange={(e) => updateDistSettings(dist.id, 'region', REGIONS.find(r => r.id === e.target.value))}
                        className="w-full bg-black border border-white/5 rounded-lg px-3 py-2 text-[9px] font-mono text-white outline-none focus:border-orange-400/40 appearance-none cursor-pointer"
                      >
                        {REGIONS.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                      </select>
                    </div>
                  </div>

                  <div className="flex items-center gap-3 shrink-0 pt-4 md:pt-0">
                    <input 
                      type="number"
                      min="0"
                      value={dist.count}
                      onChange={(e) => updateDistCount(dist.id, e.target.value)}
                      className="w-14 bg-black border border-white/10 rounded-lg px-2 py-2 text-center text-[11px] font-mono text-white outline-none focus:border-red-500/50 transition-all"
                    />
                    <span className="text-[7px] font-mono text-white uppercase tracking-widest">Qty</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="lg:col-span-4 flex flex-col justify-between py-2">
            <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-8">
              <div className="space-y-4">
                <label className="text-[8px] font-bold uppercase tracking-[0.4em] text-white block">Total Scale</label>
                <div className="flex justify-between items-baseline">
                  <span className="text-5xl font-serif text-white tracking-tighter tabular-nums">{totalNodes}</span>
                  <span className="text-[8px] font-mono text-white tracking-[0.2em] uppercase">Instances</span>
                </div>
                <div className="relative h-1 w-full bg-black rounded-full overflow-hidden">
                    <input 
                        type="range"
                        min="1"
                        max="100"
                        value={totalNodes}
                        onChange={(e) => setTotalNodes(parseInt(e.target.value))}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                    />
                    <div 
                        className="absolute left-0 top-0 h-full bg-gradient-to-r from-orange-400 to-red-600 transition-all"
                        style={{ width: `${(totalNodes/100)*100}%` }}
                    />
                </div>
              </div>

              <div className="space-y-4 pt-6 border-t border-white/5">
                <div className="flex justify-between items-center text-[8px] font-mono uppercase tracking-widest">
                   <span className="text-white">Allocated</span>
                   <span className={isValid ? "text-orange-400 font-bold" : "text-white"}>{currentAssigned} / {totalNodes}</span>
                </div>
                {!isValid && (
                  <div className="text-right">
                    <span className="text-[8px] font-mono text-red-400 uppercase tracking-widest">
                      {remaining > 0 ? `Pending: ${remaining} nodes` : `Excess: ${Math.abs(remaining)} nodes`}
                    </span>
                  </div>
                )}
              </div>

              <button 
                onClick={handleDeploy}
                disabled={!isValid}
                className={`w-full py-4 text-[10px] font-bold uppercase tracking-[0.4em] rounded-xl transition-all flex items-center justify-center gap-3 relative group overflow-hidden ${
                  isValid 
                  ? 'bg-white text-black hover:scale-[1.02] active:scale-[0.98]' 
                  : 'bg-white/10 text-white cursor-not-allowed'
                }`}
              >
                {isValid && <div className="absolute inset-0 bg-gradient-to-r from-orange-400 to-red-600 opacity-0 group-hover:opacity-10 transition-opacity"></div>}
                <span className="relative z-10">{isValid ? 'Initialize ADD' : 'Config Incomplete'}</span>
              </button>
            </div>

            <div className="flex items-center gap-2 opacity-30 mt-6 px-2">
              <div className="w-1 h-1 bg-red-500 rounded-full shadow-[0_0_8px_#ef4444]"></div>
              <span className="text-[7px] font-mono text-white uppercase tracking-widest leading-none">Status: Ready for Provisioning</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DeployModal;
